SET default_table_access_method = "heap";


CREATE TABLE IF NOT EXISTS "public"."leases" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "account_id" "uuid" NOT NULL,
    "property_id" "uuid" NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "status" "text" DEFAULT 'draft'::"text" NOT NULL,
    "start_date" "date",
    "end_date" "date",
    "rent_amount" numeric(12,2),
    "rent_frequency" "text" DEFAULT 'monthly'::"text",
    "deposit_amount" numeric(12,2),
    "created_by" "uuid" DEFAULT "auth"."uid"(),
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "application_id" "uuid",
    "lease_start_date" "date",
    "lease_end_date" "date",
    "renewal_status" "text" DEFAULT 'active'::"text" NOT NULL,
    "notice_period_days" integer DEFAULT 30 NOT NULL,
    "auto_renew" boolean DEFAULT false NOT NULL,
    "notes" "text",
    CONSTRAINT "leases_date_order" CHECK (("lease_end_date" >= "lease_start_date")),
    CONSTRAINT "leases_renewal_status" CHECK (("renewal_status" = ANY (ARRAY['active'::"text", 'expiring_soon'::"text", 'renewal_in_progress'::"text", 'renewed'::"text", 'ended'::"text"])))
);


ALTER TABLE "public"."leases" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."accept_application_create_draft_lease"("p_application_id" "uuid", "p_start_date" "date" DEFAULT NULL::"date", "p_end_date" "date" DEFAULT NULL::"date", "p_rent_amount" numeric DEFAULT NULL::numeric, "p_deposit_amount" numeric DEFAULT NULL::numeric, "p_rent_frequency" "text" DEFAULT 'monthly'::"text") RETURNS "public"."leases"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_app record;
  v_lease public.leases;
  v_existing public.leases;
begin
  if p_application_id is null then
    raise exception 'application_id is required';
  end if;

  select
    a.id,
    a.account_id,
    a.property_id,
    a.tenant_id,
    a.status
  into v_app
  from public.rental_applications a
  where a.id = p_application_id;

  if not found then
    raise exception 'Application not found';
  end if;

  if public.account_role_for(v_app.account_id) not in ('owner','admin','staff') then
    raise exception 'Not permitted';
  end if;

  if v_app.status in ('withdrawn','rejected') then
    raise exception 'Cannot accept an application that is %', v_app.status;
  end if;

  -- Idempotent: if a draft lease already exists for this application, return it
  select * into v_existing
  from public.leases l
  where l.application_id = v_app.id
  limit 1;

  if found then
    return v_existing;
  end if;

  -- Prevent draft creation if property already has an ACTIVE lease
  if exists (
    select 1 from public.leases l
    where l.property_id = v_app.property_id
      and l.status = 'active'
  ) then
    raise exception 'Cannot create draft lease: active lease already exists for this property';
  end if;

  -- Move application to pending signing
  update public.rental_applications
  set status = 'accepted_pending_signing',
      updated_at = now()
  where id = v_app.id;

  -- Create a DRAFT lease linked to the application
  insert into public.leases (
    account_id,
    property_id,
    tenant_id,
    application_id,
    status,
    start_date,
    end_date,
    rent_amount,
    rent_frequency,
    deposit_amount,
    created_by,
    created_at,
    updated_at
  )
  values (
    v_app.account_id,
    v_app.property_id,
    v_app.tenant_id,
    v_app.id,
    'draft',
    p_start_date,
    p_end_date,
    p_rent_amount,
    p_rent_frequency,
    p_deposit_amount,
    auth.uid(),
    now(),
    now()
  )
  returning * into v_lease;

  -- OPTIONAL: legacy sync for your current UI (tenant -> property)
  -- Only do this if your current app still relies on tenants.property_id.
  -- Keeping it here is okay because lease isn't active yet; it just "reserves" the link.
  update public.tenants
  set property_id = v_app.property_id
  where id = v_app.tenant_id;

  return v_lease;
end;
$$;


