CREATE OR REPLACE FUNCTION "public"."account_invitations_validate"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_email text := lower(trim(coalesce(new.email, '')));
  v_existing_user_id uuid;
  v_is_owner_invite boolean := lower(coalesce(new.role::text, '')) = 'owner';
begin
  if v_email = '' then
    raise exception 'Missing email';
  end if;
  new.email := v_email;

  -- Only validate active invitations. Accepted/revoked rows are archival.
  if new.accepted_at is not null or new.revoked_at is not null then
    return new;
  end if;

  -- Per-account guard: do not invite the same email twice while invite is active.
  if exists (
    select 1
    from public.account_invitations ai
    where ai.account_id = new.account_id
      and lower(ai.email) = v_email
      and ai.accepted_at is null
      and ai.revoked_at is null
      and (tg_op = 'INSERT' or ai.id <> new.id)
  ) then
    raise exception 'This email already has an active invitation in this account';
  end if;

  -- Per-account guard: do not invite someone who is already a member in this account.
  select u.id
  into v_existing_user_id
  from auth.users u
  where lower(u.email) = v_email
  limit 1;

  if v_existing_user_id is not null and exists (
    select 1
    from public.account_members am
    where am.account_id = new.account_id
      and am.user_id = v_existing_user_id
  ) then
    raise exception 'This email already belongs to a member of this account';
  end if;

  -- Global landlord(owner) guard: one owner account per email.
  if v_is_owner_invite then
    if v_existing_user_id is not null and exists (
      select 1
      from public.account_members am
      where am.user_id = v_existing_user_id
        and public.account_member_effective_role(am.account_id, am.user_id) = 'owner'
    ) then
      raise exception 'This email is already used by an existing landlord account';
    end if;
  end if;

  return new;
end;
$$;


ALTER FUNCTION "public"."account_invitations_validate"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."account_member_effective_role"("p_account_id" "uuid", "p_user_id" "uuid" DEFAULT "auth"."uid"()) RETURNS "text"
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select coalesce(
    (
      case
        when nullif(lower(trim(r.name)), '') in ('owner', 'admin', 'staff', 'tenant', 'contractor')
          then nullif(lower(trim(r.name)), '')
        else null
      end
    ),
    lower(am.role::text)
  )
  from public.account_members am
  left join public.roles r
    on r.id = am.role_id
  where am.account_id = p_account_id
    and am.user_id = p_user_id
  limit 1;
$$;


ALTER FUNCTION "public"."account_member_effective_role"("p_account_id" "uuid", "p_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."account_member_has_permission"("p_account_id" "uuid", "p_permission_key" "text", "p_user_id" "uuid" DEFAULT "auth"."uid"()) RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_permission_key text := lower(trim(coalesce(p_permission_key, '')));
  v_role_id uuid;
  v_role_name text;
  v_effective_role text;
begin
  if p_account_id is null or p_user_id is null or v_permission_key = '' then
    return false;
  end if;

  v_role_id := public.account_member_role_id_for(p_account_id, p_user_id);

  if v_role_id is not null then
    select lower(trim(r.name))
      into v_role_name
    from public.roles r
    where r.id = v_role_id
      and r.account_id = p_account_id
    limit 1;

    if exists (
      select 1
      from public.role_permissions rp
      where rp.role_id = v_role_id
        and lower(trim(rp.permission_key)) = v_permission_key
    ) then
      return true;
    end if;

    if coalesce(v_role_name, '') not in ('owner', 'admin', 'staff') then
      return false;
    end if;
  end if;

  v_effective_role := public.account_member_effective_role(p_account_id, p_user_id);

  if v_effective_role = 'owner' then
    return v_permission_key in (
      'properties.read', 'properties.create', 'properties.update', 'properties.delete',
      'tenants.read', 'tenants.create', 'tenants.update', 'tenants.delete',
      'documents.read', 'documents.upload', 'documents.tag', 'documents.delete',
      'finance.read', 'finance.create', 'finance.update', 'finance.delete',
      'users.invite', 'users.role'
    );
  end if;

  if v_effective_role = 'admin' then
    return v_permission_key in (
      'properties.read', 'properties.create', 'properties.update',
      'tenants.read', 'tenants.create', 'tenants.update',
      'documents.read', 'documents.upload', 'documents.tag',
      'finance.read', 'finance.create', 'finance.update'
    );
  end if;

  if v_effective_role = 'staff' then
    return v_permission_key in (
      'properties.read',
      'tenants.read',
      'documents.read', 'documents.upload', 'documents.tag',
      'finance.read'
    );
  end if;

  return false;
end;
$$;


ALTER FUNCTION "public"."account_member_has_permission"("p_account_id" "uuid", "p_permission_key" "text", "p_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."account_member_permission_keys"("p_account_id" "uuid", "p_user_id" "uuid" DEFAULT "auth"."uid"()) RETURNS "text"[]
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_role_id uuid;
  v_role_name text;
  v_effective_role text;
  v_permission_keys text[];
  v_legacy_permission_keys text[];
begin
  if p_account_id is null or p_user_id is null then
    return array[]::text[];
  end if;

  v_role_id := public.account_member_role_id_for(p_account_id, p_user_id);

  if v_role_id is not null then
    select lower(trim(r.name))
      into v_role_name
    from public.roles r
    where r.id = v_role_id
      and r.account_id = p_account_id
    limit 1;

    select coalesce(
      array_agg(distinct lower(trim(rp.permission_key)) order by lower(trim(rp.permission_key))),
      array[]::text[]
    )
      into v_permission_keys
    from public.role_permissions rp
    where rp.role_id = v_role_id;

    if coalesce(v_role_name, '') not in ('owner', 'admin', 'staff') then
      return v_permission_keys;
    end if;
  end if;

  v_effective_role := public.account_member_effective_role(p_account_id, p_user_id);

  if v_effective_role = 'owner' then
    v_legacy_permission_keys := array[
      'documents.delete', 'documents.read', 'documents.tag', 'documents.upload',
      'finance.create', 'finance.delete', 'finance.read', 'finance.update',
      'properties.create', 'properties.delete', 'properties.read', 'properties.update',
      'tenants.create', 'tenants.delete', 'tenants.read', 'tenants.update',
      'users.invite', 'users.role'
    ];
  elsif v_effective_role = 'admin' then
    v_legacy_permission_keys := array[
      'documents.read', 'documents.tag', 'documents.upload',
      'finance.create', 'finance.read', 'finance.update',
      'properties.create', 'properties.read', 'properties.update',
      'tenants.create', 'tenants.read', 'tenants.update'
    ];
  elsif v_effective_role = 'staff' then
    v_legacy_permission_keys := array[
      'documents.read', 'documents.tag', 'documents.upload',
      'finance.read',
      'properties.read',
      'tenants.read'
    ];
  elsif v_effective_role = 'tenant' then
    v_legacy_permission_keys := array[
      'documents.read',
      'properties.read'
    ];
  else
    v_legacy_permission_keys := array[]::text[];
  end if;

  return array(
    select distinct permission_key
    from unnest(
      coalesce(v_permission_keys, array[]::text[]) ||
      coalesce(v_legacy_permission_keys, array[]::text[])
    ) as permission_key
    order by permission_key
  );
end;
$$;


