CREATE OR REPLACE FUNCTION "public"."account_member_role_id_for"("p_account_id" "uuid", "p_user_id" "uuid" DEFAULT "auth"."uid"()) RETURNS "uuid"
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select am.role_id
