CREATE OR REPLACE FUNCTION "public"."approve_application_create_lease"("p_application_id" "uuid", "p_start_date" "date" DEFAULT NULL::"date", "p_end_date" "date" DEFAULT NULL::"date", "p_rent_amount" numeric DEFAULT NULL::numeric, "p_deposit_amount" numeric DEFAULT NULL::numeric, "p_rent_frequency" "text" DEFAULT 'monthly'::"text", "p_activate" boolean DEFAULT true) RETURNS "public"."leases"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_app record;
  v_lease public.leases;
  v_new_status text;
begin
  if p_application_id is null then
    raise exception 'application_id is required';
  end if;

  -- Fetch application (account-scoped)
  select
    a.id,
    a.account_id,
    a.property_id,
    a.tenant_id,
    a.status
  into v_app
  from public.rental_applications a
  where a.id = p_application_id;

  if not found then
    raise exception 'Application not found';
  end if;

  -- Permission check: owner/admin/staff can approve
  if public.account_role_for(v_app.account_id) not in ('owner','admin','staff') then
    raise exception 'Not permitted';
  end if;

  -- Guardrails
  if v_app.status in ('withdrawn') then
    raise exception 'Cannot approve a withdrawn application';
  end if;

  -- If already approved, return existing lease if present (idempotent)
  if v_app.status = 'approved' then
    select l.* into v_lease
    from public.leases l
    where l.application_id = v_app.id
    limit 1;

    if found then
      return v_lease;
    end if;
    -- If no lease exists yet, continue and create it.
  end if;

  -- Ensure no active lease exists for this property
  -- (unique index also enforces, but we fail gracefully here)
  if exists (
    select 1
    from public.leases l
    where l.property_id = v_app.property_id
      and l.status = 'active'
  ) then
    raise exception 'An active lease already exists for this property';
  end if;

  v_new_status := case when p_activate then 'active' else 'draft' end;

  -- Transactional update + insert
  update public.rental_applications
  set status = 'approved',
      updated_at = now()
  where id = v_app.id;

  insert into public.leases (
    account_id,
    property_id,
    tenant_id,
    application_id,
    status,
    start_date,
    end_date,
    rent_amount,
    rent_frequency,
    deposit_amount,
    created_by,
    created_at,
    updated_at
  )
  values (
    v_app.account_id,
    v_app.property_id,
    v_app.tenant_id,
    v_app.id,
    v_new_status,
    p_start_date,
    p_end_date,
    p_rent_amount,
    p_rent_frequency,
    p_deposit_amount,
    auth.uid(),
    now(),
    now()
  )
  returning * into v_lease;

  -- Optional: keep your legacy "tenants.property_id" relationship in sync
  -- (Only if you still use it in the UI. Comment out if not needed.)
  update public.tenants
  set property_id = v_app.property_id
  where id = v_app.tenant_id;

  return v_lease;
end;
$$;


ALTER FUNCTION "public"."approve_application_create_lease"("p_application_id" "uuid", "p_start_date" "date", "p_end_date" "date", "p_rent_amount" numeric, "p_deposit_amount" numeric, "p_rent_frequency" "text", "p_activate" boolean) OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."document_templates" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "account_id" "uuid" NOT NULL,
    "country_code" "text" NOT NULL,
    "language" "text" DEFAULT 'en'::"text" NOT NULL,
    "template_type" "text" NOT NULL,
    "name" "text" NOT NULL,
    "description" "text",
    "storage_path" "text" NOT NULL,
    "mime_type" "text" NOT NULL,
    "size_bytes" integer DEFAULT 0 NOT NULL,
    "version" integer DEFAULT 1 NOT NULL,
    "status" "text" DEFAULT 'draft'::"text" NOT NULL,
    "upload_status" "text" DEFAULT 'stub'::"text" NOT NULL,
    "created_by" "uuid",
    "uploaded_by" "uuid",
    "uploaded_at" timestamp with time zone,
    "archived_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "document_templates_country_code_check" CHECK (("country_code" ~ '^[A-Z]{2}$'::"text")),
    CONSTRAINT "document_templates_language_check" CHECK (("language" ~ '^[a-z]{2}(-[A-Z]{2})?$'::"text")),
    CONSTRAINT "document_templates_mime_check" CHECK (("mime_type" = ANY (ARRAY['application/pdf'::"text", 'image/jpeg'::"text", 'image/png'::"text", 'image/webp'::"text", 'application/msword'::"text", 'application/vnd.openxmlformats-officedocument.wordprocessingml.document'::"text"]))),
    CONSTRAINT "document_templates_size_check" CHECK ((("size_bytes" >= 0) AND ("size_bytes" <= 10485760))),
    CONSTRAINT "document_templates_status_check" CHECK (("status" = ANY (ARRAY['draft'::"text", 'active'::"text", 'archived'::"text"]))),
    CONSTRAINT "document_templates_type_check" CHECK (("template_type" = ANY (ARRAY['tenancy_agreement'::"text", 'contractor_assignment'::"text", 'maintenance_access_consent'::"text", 'deposit_checklist'::"text", 'rent_receipt'::"text", 'guarantor_form'::"text", 'id_evidence'::"text", 'compliance_notice'::"text", 'other'::"text"]))),
    CONSTRAINT "document_templates_upload_status_check" CHECK (("upload_status" = ANY (ARRAY['stub'::"text", 'uploaded'::"text", 'failed'::"text"]))),
    CONSTRAINT "document_templates_version_check" CHECK (("version" >= 1))
);


ALTER TABLE "public"."document_templates" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."archive_document_template"("p_template_id" "uuid", "p_actor_user_id" "uuid" DEFAULT "auth"."uid"()) RETURNS "public"."document_templates"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_template public.document_templates;
  v_actor uuid := auth.uid();
begin
  if v_actor is null then
    raise exception 'Not authenticated';
  end if;

  if p_actor_user_id is not null and p_actor_user_id <> v_actor then
    raise exception 'Actor mismatch';
  end if;

  select * into v_template
  from public.document_templates
  where id = p_template_id;

  if not found then
    raise exception 'Template not found';
  end if;

  if not public.can_manage_document_templates(v_template.account_id, v_actor) then
    raise exception 'Not permitted';
  end if;

  update public.document_templates
  set status = 'archived',
      archived_at = coalesce(archived_at, now()),
      updated_at = now()
  where id = p_template_id
  returning * into v_template;

  return v_template;
end;
$$;


ALTER FUNCTION "public"."archive_document_template"("p_template_id" "uuid", "p_actor_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."assert_account_feature_access"("p_account_id" "uuid", "p_feature" "text") RETURNS "uuid"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_feature text := lower(trim(coalesce(p_feature, '')));
  v_required_plan text;
begin
  if p_account_id is null then
    raise exception 'Missing account id';
  end if;

  if nullif(v_feature, '') is null then
    raise exception 'Missing feature key';
  end if;

  if public.user_is_root_operator() then
    return p_account_id;
  end if;

  if public.account_has_feature(p_account_id, v_feature) then
    return p_account_id;
  end if;

  v_required_plan := public.account_feature_required_plan(v_feature);
  raise exception 'Feature % requires % plan or higher for this account', v_feature, v_required_plan;
end;
$$;


ALTER FUNCTION "public"."assert_account_feature_access"("p_account_id" "uuid", "p_feature" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."assert_account_feature_access"("p_account_id" "uuid", "p_feature" "text") IS 'Raises when the target account plan does not include the requested feature.';



CREATE OR REPLACE FUNCTION "public"."assert_account_property_capacity"("p_account_id" "uuid", "p_exclude_property_id" "uuid" DEFAULT NULL::"uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_limit integer;
  v_count integer;
begin
  if p_account_id is null then
    raise exception 'Missing account id';
  end if;

  v_limit := public.account_usage_limit(p_account_id, 'properties');
  if v_limit is null then
    return p_account_id;
  end if;

  select count(*)
  into v_count
  from public.properties p
  where p.account_id = p_account_id
    and (p_exclude_property_id is null or p.id <> p_exclude_property_id);

  if coalesce(v_count, 0) >= v_limit then
    raise exception 'Plan limit reached: this account allows up to % properties', v_limit;
  end if;

  return p_account_id;
end;
$$;


ALTER FUNCTION "public"."assert_account_property_capacity"("p_account_id" "uuid", "p_exclude_property_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."assert_account_property_capacity"("p_account_id" "uuid", "p_exclude_property_id" "uuid") IS 'Raises when a property create/move would exceed the current billing-plan property cap.';



CREATE OR REPLACE FUNCTION "public"."assert_manage_account_access"("p_account_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  if auth.uid() is null then
    raise exception using
      errcode = '28000',
      message = 'Not authenticated',
      detail = public.security_failure_context(
        'assert_manage_account_access',
        'missing_auth',
        p_account_id,
        'account',
        p_account_id
      ),
      hint = 'Authenticate before requesting an account-scoped manager surface.';
  end if;

  if p_account_id is null then
    raise exception using
      errcode = '22023',
      message = 'Missing account id',
      detail = public.security_failure_context(
        'assert_manage_account_access',
        'missing_account_id',
        null,
        'account',
        null
      ),
      hint = 'Pass a concrete account identifier before requesting an account-scoped manager surface.';
  end if;

  if not public.user_can_manage_account(p_account_id) then
    raise exception using
      errcode = '42501',
      message = 'Access denied',
      detail = public.security_failure_context(
        'assert_manage_account_access',
        'account_role_required',
        p_account_id,
        'account',
        p_account_id
      ),
      hint = 'Only owner, admin, staff, or root operators can access this account-scoped manager surface.';
  end if;

  return p_account_id;
end;
$$;


ALTER FUNCTION "public"."assert_manage_account_access"("p_account_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."assert_root_telemetry_access"("p_account_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  if p_account_id is null then
    raise exception 'Missing account id';
  end if;

  perform public.assert_account_feature_access(p_account_id, 'root_telemetry');

  if public.user_can_access_root_telemetry(p_account_id) then
    return p_account_id;
  end if;

  raise exception 'Only authorized root telemetry operators can access this account';
end;
$$;


ALTER FUNCTION "public"."assert_root_telemetry_access"("p_account_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."assert_root_telemetry_access"("p_account_id" "uuid") IS 'Raises when the signed-in user lacks root telemetry access for the given account.';



CREATE OR REPLACE FUNCTION "public"."assert_security_observability_feed_access"("p_account_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  if p_account_id is null then
    raise exception 'Missing account id';
  end if;

  if public.user_can_manage_account(p_account_id) then
    perform public.assert_account_feature_access(p_account_id, 'security_audit');
    return p_account_id;
  end if;

  if public.user_can_access_root_telemetry(p_account_id) then
    perform public.assert_account_feature_access(p_account_id, 'root_telemetry');
    return p_account_id;
  end if;

  raise exception 'Only authorized account operators can access this observability feed';
end;
$$;


ALTER FUNCTION "public"."assert_security_observability_feed_access"("p_account_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."assert_security_observability_feed_access"("p_account_id" "uuid") IS 'Raises when the signed-in user lacks manager or explicit support/root access for the hosted observability feed.';



CREATE OR REPLACE FUNCTION "public"."assert_tenant_scope_access"("p_account_id" "uuid", "p_tenant_id" "uuid" DEFAULT NULL::"uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_tenant_id uuid;
begin
  if auth.uid() is null then
    raise exception using
      errcode = '28000',
      message = 'Not authenticated',
      detail = public.security_failure_context(
        'assert_tenant_scope_access',
        'missing_auth',
        p_account_id,
        'tenant',
        p_tenant_id
      ),
      hint = 'Authenticate before requesting an account or tenant-scoped surface.';
  end if;

  if p_account_id is null then
    raise exception using
      errcode = '22023',
      message = 'Missing account id',
      detail = public.security_failure_context(
        'assert_tenant_scope_access',
        'missing_account_id',
        null,
        'tenant',
        p_tenant_id
      ),
      hint = 'Pass a concrete account identifier before requesting a tenant-scoped surface.';
  end if;

  if public.user_can_manage_account(p_account_id) then
    return p_tenant_id;
  end if;

  if p_tenant_id is null then
    raise exception using
      errcode = '42501',
      message = 'Access denied',
      detail = public.security_failure_context(
        'assert_tenant_scope_access',
        'tenant_scope_required',
        p_account_id,
        'tenant',
        null
      ),
      hint = 'Tenant-scoped callers must provide their own tenant identifier.';
  end if;

  select t.id
  into v_tenant_id
  from public.tenants t
  where t.id = p_tenant_id
    and t.account_id = p_account_id
    and t.user_id = auth.uid()
  limit 1;

  if v_tenant_id is null then
    raise exception using
      errcode = '42501',
      message = 'Access denied',
      detail = public.security_failure_context(
        'assert_tenant_scope_access',
        'tenant_scope_denied',
        p_account_id,
        'tenant',
        p_tenant_id
      ),
      hint = 'Tenants may only access their own tenant scope within the active account.';
  end if;

  return v_tenant_id;
end;
$$;


ALTER FUNCTION "public"."assert_tenant_scope_access"("p_account_id" "uuid", "p_tenant_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."assign_account_member_role_id"("p_account_id" "uuid", "p_target_user_id" "uuid", "p_role_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("ok" boolean, "account_id" "uuid", "user_id" "uuid", "legacy_role" "public"."account_role", "role_id" "uuid", "role_name" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_account_id uuid;
  v_legacy_role public.account_role;
  v_role_name text;
begin
  v_account_id := public.assert_manage_account_access(p_account_id);

  if p_target_user_id is null then
    raise exception 'target_user_id is required';
  end if;

  select am.role
    into v_legacy_role
  from public.account_members am
  where am.account_id = v_account_id
    and am.user_id = p_target_user_id;

  if v_legacy_role is null then
    raise exception 'Target user is not a member of this account';
  end if;

  if p_role_id is not null then
    select r.name
      into v_role_name
    from public.roles r
    where r.id = p_role_id
      and r.account_id = v_account_id;

    if v_role_name is null then
      raise exception 'Role not found in this account';
    end if;
  end if;

  update public.account_members am
  set role_id = p_role_id
  where am.account_id = v_account_id
    and am.user_id = p_target_user_id;

  return query
  select
    true as ok,
    v_account_id as account_id,
    p_target_user_id as user_id,
    v_legacy_role as legacy_role,
    p_role_id as role_id,
    v_role_name as role_name;
end;
$$;


ALTER FUNCTION "public"."assign_account_member_role_id"("p_account_id" "uuid", "p_target_user_id" "uuid", "p_role_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."assign_tenant"("p_property_id" "uuid", "p_tenant_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  -- Optional: permission gate (uncomment if your helper exists and is correct)
  -- if public.account_role_for((select account_id from properties where id = p_property_id)) not in ('owner','admin') then
  --   raise exception 'Not allowed';
  -- end if;

  -- Lock the property row so concurrent writes can't corrupt state
  perform 1 from properties where id = p_property_id for update;

  -- 1) Unassign any tenant currently on this property (both directions)
  update tenants
  set property_id = null
  where property_id = p_property_id;

  update properties
  set tenant_id = null
  where id = p_property_id;

  -- 2) If we're assigning a tenant, clear their existing property (both directions)
  if p_tenant_id is not null then
    -- Lock the tenant row too
    perform 1 from tenants where id = p_tenant_id for update;

    -- clear tenant's old property (property side)
    update properties
    set tenant_id = null
    where tenant_id = p_tenant_id;

    -- clear tenant's old property (tenant side)
    update tenants
    set property_id = null
    where id = p_tenant_id;

    -- 3) Assign
    update properties
    set tenant_id = p_tenant_id
    where id = p_property_id;

    update tenants
    set property_id = p_property_id
    where id = p_tenant_id;
  end if;

end;
$$;


ALTER FUNCTION "public"."assign_tenant"("p_property_id" "uuid", "p_tenant_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."attention_center_items"("p_account_id" "uuid", "p_limit" integer DEFAULT 60) RETURNS TABLE("item_key" "text", "item_type" "text", "bucket" "text", "property_label" "text", "tenant_label" "text", "entity_label" "text", "amount" numeric, "age_hours" integer, "due_days" integer, "link_path" "text", "source_table" "text", "sort_order" integer)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with cfg as (
    select greatest(1, least(coalesce(p_limit, 60), 200)) as max_items
  ),
  authz as materialized (
    select public.assert_manage_account_access(p_account_id) as account_id
  ),
  scoped_payments as (
    select
      p.id,
      p.amount,
      lower(coalesce(p.status, '')) as status,
      p.due_date,
      p.paid_at,
      p.tenant_id,
      p.property_id,
      coalesce(pr.address, '—') as property_label,
      coalesce(t.name, '—') as tenant_label
    from public.payments p
    cross join authz a
    left join public.properties pr on pr.id = p.property_id
    left join public.tenants t on t.id = p.tenant_id
    where p.account_id = a.account_id
  ),
  payment_items as (
    select
      'payment-overdue-' || sp.id::text as item_key,
      'overdue_rent'::text as item_type,
      'urgent'::text as bucket,
      sp.property_label,
      sp.tenant_label,
      ''::text as entity_label,
      coalesce(sp.amount, 0)::numeric as amount,
      greatest(0, ((current_date - sp.due_date) * 24))::int as age_hours,
      (sp.due_date - current_date)::int as due_days,
      case when sp.tenant_id is not null then '/tenants/' || sp.tenant_id::text else '/finance' end as link_path,
      'payments'::text as source_table,
      10 as sort_order
    from scoped_payments sp
    where sp.paid_at is null
      and (
        sp.status in ('overdue', 'zaległe', 'zalegle')
        or (sp.due_date is not null and sp.due_date < current_date)
      )

    union all

    select
      'payment-due-soon-' || sp.id::text,
      'due_soon_rent'::text,
      'upcoming'::text,
      sp.property_label,
      sp.tenant_label,
      ''::text,
      coalesce(sp.amount, 0)::numeric,
      null::int as age_hours,
      (sp.due_date - current_date)::int as due_days,
      case when sp.tenant_id is not null then '/tenants/' || sp.tenant_id::text else '/finance' end,
      'payments'::text,
      30 as sort_order
    from scoped_payments sp
    where sp.paid_at is null
      and sp.due_date is not null
      and sp.due_date >= current_date
      and sp.due_date <= current_date + interval '7 days'
      and sp.status not in ('paid', 'opłacone', 'oplacone')
  ),
  limited_payment_items as (
    select *
    from payment_items
    order by
      case bucket
        when 'urgent' then 1
        when 'action' then 2
        when 'upcoming' then 3
        else 4
      end,
      sort_order,
      coalesce(age_hours, 999999),
      coalesce(due_days, 999999),
      item_key
    limit (select max_items from cfg)
  ),
  scoped_requests as (
    select
      mr.id,
      mr.property_id,
      mr.reported_by_tenant_id,
      mr.title,
      lower(coalesce(mr.status, '')) as status,
      lower(coalesce(mr.priority, '')) as priority,
      mr.created_at,
      mr.updated_at,
      coalesce(pr.address, '—') as property_label,
      coalesce(t.name, '—') as tenant_label
    from public.maintenance_requests mr
    left join public.properties pr on pr.id = mr.property_id
    left join public.tenants t on t.id = mr.reported_by_tenant_id
    where mr.account_id = p_account_id
  ),
  scoped_work_orders as (
    select
      w.id,
      w.property_id,
      w.maintenance_request_id,
      w.contractor_user_id,
      w.contractor_name,
      w.acknowledgement_due_at,
      w.acknowledgement_status,
      lower(coalesce(w.status, '')) as status,
      w.scheduled_at,
      w.created_at,
      w.updated_at,
      coalesce(pr.address, '—') as property_label,
      coalesce(mr.title, '—') as request_title
    from public.work_orders w
    left join public.properties pr on pr.id = w.property_id
    left join public.maintenance_requests mr on mr.id = w.maintenance_request_id
    where w.account_id = p_account_id
  ),
  request_without_work_order as (
    select
      'maint-no-wo-' || sr.id::text as item_key,
      'request_without_work_order'::text as item_type,
      'action'::text as bucket,
      sr.property_label,
      sr.tenant_label,
      sr.title as entity_label,
      null::numeric as amount,
      floor(extract(epoch from (now() - sr.created_at)) / 3600)::int as age_hours,
      null::int as due_days,
      '/maintenance-inbox'::text as link_path,
      'maintenance_requests'::text as source_table,
      40 as sort_order
    from scoped_requests sr
    where sr.status not in ('closed', 'zamknięte', 'zamkniete', 'resolved', 'rozwiązane', 'rozwiazane')
      and not exists (
        select 1
        from scoped_work_orders swo
        where swo.maintenance_request_id = sr.id
      )
  ),
  triage_overdue as (
    select
      'maint-triage-' || sr.id::text as item_key,
      'triage_over_24h'::text as item_type,
      'urgent'::text as bucket,
      sr.property_label,
      sr.tenant_label,
      sr.title as entity_label,
      null::numeric as amount,
      floor(extract(epoch from (now() - sr.created_at)) / 3600)::int as age_hours,
      null::int as due_days,
      '/maintenance-inbox?status=open'::text as link_path,
      'maintenance_requests'::text as source_table,
      14 as sort_order
    from scoped_requests sr
    where sr.status in ('open')
      and sr.created_at <= now() - interval '24 hours'
      and not exists (
        select 1
        from scoped_work_orders swo
        where swo.maintenance_request_id = sr.id
      )
  ),
  high_priority_unresolved as (
    select
      'maint-high-' || sr.id::text as item_key,
      'high_priority_unresolved'::text as item_type,
      'urgent'::text as bucket,
      sr.property_label,
      sr.tenant_label,
      sr.title as entity_label,
      null::numeric as amount,
      floor(extract(epoch from (now() - sr.created_at)) / 3600)::int as age_hours,
      null::int as due_days,
      '/maintenance-inbox?priority=high,critical'::text as link_path,
      'maintenance_requests'::text as source_table,
      20 as sort_order
    from scoped_requests sr
    where sr.status not in ('closed', 'zamknięte', 'zamkniete', 'resolved', 'rozwiązane', 'rozwiazane')
      and sr.priority in ('high', 'urgent', 'critical', 'wysoki', 'krytyczny')
  ),
  stuck_waiting as (
    select
      'maint-waiting-' || sr.id::text as item_key,
      'stuck_waiting_over_48h'::text as item_type,
      'urgent'::text as bucket,
      sr.property_label,
      sr.tenant_label,
      sr.title as entity_label,
      null::numeric as amount,
      floor(extract(epoch from (now() - sr.updated_at)) / 3600)::int as age_hours,
      null::int as due_days,
      '/maintenance-inbox?status=waiting'::text as link_path,
      'maintenance_requests'::text as source_table,
      15 as sort_order
    from scoped_requests sr
    where sr.status in ('waiting')
      and sr.updated_at <= now() - interval '48 hours'
  ),
  limited_request_items as (
    select
      ranked.item_key,
      ranked.item_type,
      ranked.bucket,
      ranked.property_label,
      ranked.tenant_label,
      ranked.entity_label,
      ranked.amount,
      ranked.age_hours,
      ranked.due_days,
      ranked.link_path,
      ranked.source_table,
      ranked.sort_order
    from (
      select
        x.*,
        case x.bucket
          when 'urgent' then 1
          when 'action' then 2
          when 'upcoming' then 3
          else 4
        end as bucket_rank,
        coalesce(x.age_hours, 999999) as age_rank,
        coalesce(x.due_days, 999999) as due_rank
      from (
        select * from request_without_work_order
        union all select * from triage_overdue
        union all select * from high_priority_unresolved
        union all select * from stuck_waiting
      ) x
    ) ranked
    order by
      ranked.bucket_rank,
      ranked.sort_order,
      ranked.age_rank,
      ranked.due_rank,
      ranked.item_key
    limit (select max_items from cfg)
  ),
  work_order_without_contractor as (
    select
      'wo-no-contractor-' || swo.id::text as item_key,
      'work_order_without_contractor'::text as item_type,
      'action'::text as bucket,
      swo.property_label,
      ''::text as tenant_label,
      swo.request_title as entity_label,
      null::numeric as amount,
      floor(extract(epoch from (now() - coalesce(swo.updated_at, swo.created_at))) / 3600)::int as age_hours,
      null::int as due_days,
      '/work-orders/' || swo.id::text as link_path,
      'work_orders'::text as source_table,
      50 as sort_order
    from scoped_work_orders swo
    where swo.status not in ('completed', 'cancelled', 'zakończone', 'anulowane')
      and swo.contractor_user_id is null
      and nullif(coalesce(swo.contractor_name, ''), '') is null
  ),
  contractor_no_response as (
    select
      'wo-no-response-' || swo.id::text as item_key,
      'contractor_no_response'::text as item_type,
      'urgent'::text as bucket,
      swo.property_label,
      ''::text as tenant_label,
      swo.request_title as entity_label,
      null::numeric as amount,
      floor(extract(epoch from (now() - coalesce(swo.updated_at, swo.created_at))) / 3600)::int as age_hours,
      case when swo.scheduled_at is not null then (swo.scheduled_at::date - current_date)::int else null::int end as due_days,
      '/work-orders/' || swo.id::text as link_path,
      'work_orders'::text as source_table,
      25 as sort_order
    from scoped_work_orders swo
    where swo.status in ('assigned', 'przypisane')
      and (swo.contractor_user_id is not null or nullif(coalesce(swo.contractor_name, ''), '') is not null)
      and coalesce(lower(swo.acknowledgement_status), 'pending') <> 'acknowledged'
      and swo.acknowledgement_due_at is not null
      and swo.acknowledgement_due_at < now()
  ),
  work_order_overdue as (
    select
      'wo-overdue-' || swo.id::text as item_key,
      'work_order_overdue'::text as item_type,
      'urgent'::text as bucket,
      swo.property_label,
      ''::text as tenant_label,
      swo.request_title as entity_label,
      null::numeric as amount,
      floor(extract(epoch from (now() - coalesce(swo.updated_at, swo.created_at))) / 3600)::int as age_hours,
      (swo.scheduled_at::date - current_date)::int as due_days,
      '/work-orders/' || swo.id::text as link_path,
      'work_orders'::text as source_table,
      18 as sort_order
    from scoped_work_orders swo
    where swo.status not in ('completed', 'cancelled', 'zakończone', 'anulowane')
      and swo.scheduled_at is not null
      and swo.scheduled_at::date < current_date
  ),
  blocked_work_orders as (
    select
      'wo-blocked-' || swo.id::text as item_key,
      'work_order_blocked_follow_up'::text as item_type,
      'action'::text as bucket,
      swo.property_label,
      ''::text as tenant_label,
      swo.request_title as entity_label,
      null::numeric as amount,
      floor(extract(epoch from (now() - coalesce(swo.updated_at, swo.created_at))) / 3600)::int as age_hours,
      case when swo.scheduled_at is not null then (swo.scheduled_at::date - current_date)::int else null::int end as due_days,
      '/work-orders/' || swo.id::text as link_path,
      'work_orders'::text as source_table,
      32 as sort_order
    from scoped_work_orders swo
    where swo.status in ('blocked', 'zablokowane')
  ),
  stalled_work_orders as (
    select
      'wo-stalled-' || swo.id::text as item_key,
      'stalled_in_progress_repair'::text as item_type,
      'urgent'::text as bucket,
      swo.property_label,
      ''::text as tenant_label,
      swo.request_title as entity_label,
      null::numeric as amount,
      floor(extract(epoch from (now() - coalesce(swo.updated_at, swo.created_at))) / 3600)::int as age_hours,
      case when swo.scheduled_at is not null then (swo.scheduled_at::date - current_date)::int else null::int end as due_days,
      '/work-orders/' || swo.id::text as link_path,
      'work_orders'::text as source_table,
      17 as sort_order
    from scoped_work_orders swo
    where swo.status in ('in_progress', 'w trakcie', 'blocked', 'zablokowane')
      and coalesce(swo.updated_at, swo.created_at) <= now() - interval '72 hours'
  ),
  long_running_repairs as (
    select
      'wo-long-running-' || swo.id::text as item_key,
      'long_running_repair'::text as item_type,
      'action'::text as bucket,
      swo.property_label,
      ''::text as tenant_label,
      swo.request_title as entity_label,
      null::numeric as amount,
      floor(extract(epoch from (now() - swo.created_at)) / 3600)::int as age_hours,
      case when swo.scheduled_at is not null then (swo.scheduled_at::date - current_date)::int else null::int end as due_days,
      '/work-orders/' || swo.id::text as link_path,
      'work_orders'::text as source_table,
      44 as sort_order
    from scoped_work_orders swo
    where swo.status not in ('completed', 'cancelled', 'zakończone', 'anulowane')
      and swo.created_at <= now() - interval '14 days'
  ),
  repeated_repairs as (
    select
      'repeat-repairs-' || sr.property_id::text as item_key,
      'repeated_repairs_property'::text as item_type,
      'action'::text as bucket,
      max(sr.property_label) as property_label,
      ''::text as tenant_label,
      ''::text as entity_label,
      count(*)::numeric as amount,
      null::int as age_hours,
      null::int as due_days,
      '/properties/' || sr.property_id::text as link_path,
      'maintenance_requests'::text as source_table,
      46 as sort_order
    from scoped_requests sr
    where sr.property_id is not null
      and sr.created_at >= now() - interval '90 days'
    group by sr.property_id
    having count(*) >= 3
  ),
  recently_updated_open as (
    select
      'wo-recent-' || swo.id::text as item_key,
      'recently_updated_open'::text as item_type,
      'recent'::text as bucket,
      swo.property_label,
      ''::text as tenant_label,
      swo.request_title as entity_label,
      null::numeric as amount,
      floor(extract(epoch from (now() - coalesce(swo.updated_at, swo.created_at))) / 3600)::int as age_hours,
      case when swo.scheduled_at is not null then (swo.scheduled_at::date - current_date)::int else null::int end as due_days,
      '/work-orders/' || swo.id::text as link_path,
      'work_orders'::text as source_table,
      70 as sort_order
    from scoped_work_orders swo
    where swo.status in ('assigned', 'przypisane', 'in_progress', 'w trakcie')
      and coalesce(swo.updated_at, swo.created_at) >= now() - interval '72 hours'
  ),
  limited_work_order_items as (
    select
      ranked.item_key,
      ranked.item_type,
      ranked.bucket,
      ranked.property_label,
      ranked.tenant_label,
      ranked.entity_label,
      ranked.amount,
      ranked.age_hours,
      ranked.due_days,
      ranked.link_path,
      ranked.source_table,
      ranked.sort_order
    from (
      select
        x.*,
        case x.bucket
          when 'urgent' then 1
          when 'action' then 2
          when 'upcoming' then 3
          else 4
        end as bucket_rank,
        coalesce(x.age_hours, 999999) as age_rank,
        coalesce(x.due_days, 999999) as due_rank
      from (
        select * from work_order_without_contractor
        union all select * from contractor_no_response
        union all select * from work_order_overdue
        union all select * from blocked_work_orders
        union all select * from stalled_work_orders
        union all select * from long_running_repairs
        union all select * from repeated_repairs
        union all select * from recently_updated_open
      ) x
    ) ranked
    order by
      ranked.bucket_rank,
      ranked.sort_order,
      ranked.age_rank,
      ranked.due_rank,
      ranked.item_key
    limit (select max_items from cfg)
  ),
  lease_items as (
    select
      'lease-expired-' || l.id::text as item_key,
      'lease_expired'::text as item_type,
      'urgent'::text as bucket,
      coalesce(p.address, '—') as property_label,
      coalesce(t.name, '—') as tenant_label,
      ''::text as entity_label,
      null::numeric as amount,
      null::int as age_hours,
      (l.lease_end_date - current_date)::int as due_days,
      '/tenants/' || l.tenant_id::text as link_path,
      'leases'::text as source_table,
      12 as sort_order
    from public.leases l
    left join public.properties p on p.id = l.property_id
    left join public.tenants t on t.id = l.tenant_id
    where l.account_id = p_account_id
      and l.lease_end_date < current_date
      and lower(coalesce(l.renewal_status, 'active')) not in ('renewed', 'ended')

    union all

    select
      'lease-expiring-' || l.id::text,
      'lease_expiring_soon'::text,
      'upcoming'::text,
      coalesce(p.address, '—'),
      coalesce(t.name, '—'),
      ''::text,
      null::numeric,
      null::int,
      (l.lease_end_date - current_date)::int,
      '/tenants/' || l.tenant_id::text,
      'leases'::text,
      60 as sort_order
    from public.leases l
    left join public.properties p on p.id = l.property_id
    left join public.tenants t on t.id = l.tenant_id
    where l.account_id = p_account_id
      and l.lease_end_date >= current_date
      and l.lease_end_date <= current_date + interval '60 days'
      and lower(coalesce(l.renewal_status, 'active')) not in ('renewed', 'ended')

    union all

    select
      'lease-renewal-' || l.id::text,
      'lease_renewal_in_progress'::text,
      'action'::text,
      coalesce(p.address, '—'),
      coalesce(t.name, '—'),
      ''::text,
      null::numeric,
      null::int,
      (l.lease_end_date - current_date)::int,
      '/tenants/' || l.tenant_id::text,
      'leases'::text,
      45 as sort_order
    from public.leases l
    left join public.properties p on p.id = l.property_id
    left join public.tenants t on t.id = l.tenant_id
    where l.account_id = p_account_id
      and lower(coalesce(l.renewal_status, 'active')) = 'renewal_in_progress'
  ),
  limited_lease_items as (
    select *
    from lease_items
    order by
      case bucket
        when 'urgent' then 1
        when 'action' then 2
        when 'upcoming' then 3
        else 4
      end,
      sort_order,
      coalesce(age_hours, 999999),
      coalesce(due_days, 999999),
      item_key
    limit (select max_items from cfg)
  ),
  preventive_items as (
    select
      'preventive-overdue-' || pmt.id::text as item_key,
      'preventive_task_overdue'::text as item_type,
      'urgent'::text as bucket,
      coalesce(p.address, '—') as property_label,
      ''::text as tenant_label,
      pmt.title as entity_label,
      null::numeric as amount,
      null::int as age_hours,
      (pmt.next_due_date - current_date)::int as due_days,
      '/properties/' || pmt.property_id::text as link_path,
      'preventive_maintenance_tasks'::text as source_table,
      22 as sort_order
    from public.preventive_maintenance_tasks pmt
    left join public.properties p on p.id = pmt.property_id
    where pmt.account_id = p_account_id
      and lower(coalesce(pmt.status, 'active')) = 'active'
      and pmt.next_due_date < current_date

    union all

    select
      'preventive-due-soon-' || pmt.id::text,
      'preventive_task_due_soon'::text,
      'upcoming'::text,
      coalesce(p.address, '—'),
      ''::text,
      pmt.title,
      null::numeric,
      null::int,
      (pmt.next_due_date - current_date)::int,
      '/properties/' || pmt.property_id::text,
      'preventive_maintenance_tasks'::text,
      58 as sort_order
    from public.preventive_maintenance_tasks pmt
    left join public.properties p on p.id = pmt.property_id
    where pmt.account_id = p_account_id
      and lower(coalesce(pmt.status, 'active')) = 'active'
      and pmt.next_due_date >= current_date
      and pmt.next_due_date <= current_date + interval '14 days'
  ),
  limited_preventive_items as (
    select *
    from preventive_items
    order by
      case bucket
        when 'urgent' then 1
        when 'action' then 2
        when 'upcoming' then 3
        else 4
      end,
      sort_order,
      coalesce(age_hours, 999999),
      coalesce(due_days, 999999),
      item_key
    limit (select max_items from cfg)
  ),
  compliance_items as (
    select
      'compliance-overdue-' || c.id::text as item_key,
      'compliance_overdue'::text as item_type,
      'urgent'::text as bucket,
      coalesce(p.address, '—') as property_label,
      coalesce(t.name, '—') as tenant_label,
      c.title as entity_label,
      null::numeric as amount,
      null::int as age_hours,
      (c.due_date - current_date)::int as due_days,
      coalesce(
        case when c.property_id is not null then '/properties/' || c.property_id::text else null end,
        case when c.tenant_id is not null then '/tenants/' || c.tenant_id::text else null end,
        '/attention-center'
      ) as link_path,
      'compliance_items'::text as source_table,
      19 as sort_order
    from public.compliance_items c
    left join public.properties p on p.id = c.property_id
    left join public.tenants t on t.id = c.tenant_id
    where c.account_id = p_account_id
      and lower(coalesce(c.status, 'active')) = 'active'
      and c.due_date < current_date

    union all

    select
      'compliance-due-' || c.id::text,
      'compliance_due_soon'::text,
      'upcoming'::text,
      coalesce(p.address, '—'),
      coalesce(t.name, '—'),
      c.title,
      null::numeric,
      null::int,
      (c.due_date - current_date)::int,
      coalesce(
        case when c.property_id is not null then '/properties/' || c.property_id::text else null end,
        case when c.tenant_id is not null then '/tenants/' || c.tenant_id::text else null end,
        '/attention-center'
      ),
      'compliance_items'::text,
      57 as sort_order
    from public.compliance_items c
    left join public.properties p on p.id = c.property_id
    left join public.tenants t on t.id = c.tenant_id
    where c.account_id = p_account_id
      and lower(coalesce(c.status, 'active')) = 'active'
      and c.due_date >= current_date
      and c.due_date <= current_date + interval '30 days'
  ),
  compliance_missing_setup as (
    select
      'compliance-missing-calendar-' || p.id::text as item_key,
      'compliance_missing_setup'::text as item_type,
      'action'::text as bucket,
      coalesce(p.address, '—') as property_label,
      ''::text as tenant_label,
      'Compliance calendar not set up'::text as entity_label,
      null::numeric as amount,
      null::int as age_hours,
      null::int as due_days,
      '/properties/' || p.id::text as link_path,
      'compliance_items'::text as source_table,
      59 as sort_order
    from public.properties p
    where p.account_id = p_account_id
      and not exists (
        select 1
        from public.compliance_items c
        where c.account_id = p.account_id
          and c.property_id = p.id
      )
  ),
  limited_compliance_items as (
    select
      ranked.item_key,
      ranked.item_type,
      ranked.bucket,
      ranked.property_label,
      ranked.tenant_label,
      ranked.entity_label,
      ranked.amount,
      ranked.age_hours,
      ranked.due_days,
      ranked.link_path,
      ranked.source_table,
      ranked.sort_order
    from (
      select
        x.*,
        case x.bucket
          when 'urgent' then 1
          when 'action' then 2
          when 'upcoming' then 3
          else 4
        end as bucket_rank,
        coalesce(x.age_hours, 999999) as age_rank,
        coalesce(x.due_days, 999999) as due_rank
      from (
        select * from compliance_items
        union all select * from compliance_missing_setup
      ) x
    ) ranked
    order by
      ranked.bucket_rank,
      ranked.sort_order,
      ranked.age_rank,
      ranked.due_rank,
      ranked.item_key
    limit (select max_items from cfg)
  ),
  notification_items as (
    select
      'notification-' || n.id::text as item_key,
      'notification_alert'::text as item_type,
      'recent'::text as bucket,
      ''::text as property_label,
      ''::text as tenant_label,
      coalesce(n.title, 'Alert') as entity_label,
      null::numeric as amount,
      floor(extract(epoch from (now() - n.created_at)) / 3600)::int as age_hours,
      null::int as due_days,
      coalesce(n.link_path, '') as link_path,
      'notifications'::text as source_table,
      80 as sort_order
    from public.notifications n
    where n.account_id = p_account_id
      and coalesce(n.is_read, false) = false
  ),
  limited_notification_items as (
    select *
    from notification_items
    order by
      case bucket
        when 'urgent' then 1
        when 'action' then 2
        when 'upcoming' then 3
        else 4
      end,
      sort_order,
      coalesce(age_hours, 999999),
      coalesce(due_days, 999999),
      item_key
    limit (select max_items from cfg)
  ),
  unioned as (
    select * from limited_payment_items
    union all select * from limited_request_items
    union all select * from limited_work_order_items
    union all select * from limited_lease_items
    union all select * from limited_preventive_items
    union all select * from limited_compliance_items
    union all select * from limited_notification_items
  ),
  ordered as (
    select
      u.*,
      case u.bucket
        when 'urgent' then 1
        when 'action' then 2
        when 'upcoming' then 3
        else 4
      end as bucket_rank,
      coalesce(u.age_hours, 999999) as age_rank,
      coalesce(u.due_days, 999999) as due_rank
    from unioned u
  )
  select
    o.item_key,
    o.item_type,
    o.bucket,
    o.property_label,
    o.tenant_label,
    o.entity_label,
    o.amount,
    o.age_hours,
    o.due_days,
    o.link_path,
    o.source_table,
    o.sort_order
  from ordered o
  cross join authz a
  order by
    o.bucket_rank,
    o.sort_order,
    o.age_rank,
    o.due_rank,
    o.item_key
  limit (select max_items from cfg);
$$;


ALTER FUNCTION "public"."attention_center_items"("p_account_id" "uuid", "p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."audit_work_order_status_change"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'auth'
    AS $$
begin
  if new.status is distinct from old.status then
    insert into public.work_order_audit_log (
      work_order_id,
      account_id,
      actor_user_id,
      action,
      old_value,
      new_value
    )
    values (
      new.id,
      new.account_id,
      auth.uid(),
      'status_changed',
      jsonb_build_object('status', old.status),
      jsonb_build_object('status', new.status)
    );
  end if;

  return new;
end;
$$;


