CREATE OR REPLACE FUNCTION "public"."can_access_account"("p_account_id" "uuid") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select exists (
    select 1
    from public.account_members am
    where am.account_id = p_account_id
      and am.user_id = auth.uid()
  );
$$;


ALTER FUNCTION "public"."can_access_account"("p_account_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."can_access_document_storage"("p_account_id" "uuid", "p_document_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
declare
  v_user_id uuid := auth.uid();
  v_allowed boolean := false;
begin
  select exists (
    select 1
    from public.documents d
    where d.id = p_document_id
      and d.account_id = p_account_id
      and (
        public.account_member_effective_role(d.account_id, v_user_id) = any (array['owner','admin'])
        or (
          public.account_member_effective_role(d.account_id, v_user_id) = 'staff'
          and d.visibility <> 'owner_admin'
        )
        or (
          d.visibility = 'tenant'
          and exists (
            select 1
            from public.tenants t
            where t.account_id = d.account_id
              and t.user_id = v_user_id
              and t.archived_at is null
              and t.id = d.tenant_id
          )
        )
      )
  ) into v_allowed;

  if v_allowed then
    return true;
  end if;

  if to_regclass('public.document_request_uploads') is not null
    and to_regclass('public.document_requests') is not null
    and to_regprocedure('public.is_document_request_target(uuid, uuid)') is not null
  then
    execute $request_access$
      select exists (
        select 1
        from public.documents d
        join public.document_request_uploads dru on dru.document_id = d.id
        join public.document_requests dr on dr.id = dru.request_id
        where d.id = $1
          and d.account_id = $2
          and public.is_document_request_target(dr.id, $3)
      )
    $request_access$
    into v_allowed
    using p_document_id, p_account_id, v_user_id;
  end if;

  return coalesce(v_allowed, false);
end;
$_$;


ALTER FUNCTION "public"."can_access_document_storage"("p_account_id" "uuid", "p_document_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."can_access_document_template_storage"("p_account_id" "uuid", "p_template_id" "uuid") RETURNS boolean
