    CONSTRAINT "work_orders_status_check" CHECK (("status" = ANY (ARRAY['assigned'::"text", 'in_progress'::"text", 'completed'::"text", 'blocked'::"text", 'cancelled'::"text"])))
);


ALTER TABLE "public"."work_orders" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."contractor_update_work_order"("p_work_order_id" "uuid", "p_status" "text" DEFAULT NULL::"text", "p_notes" "text" DEFAULT NULL::"text", "p_scheduled_at" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS "public"."work_orders"
    LANGUAGE "plpgsql"
    AS $$
declare
  v_row public.work_orders;
begin
  -- Must be the assigned contractor
  select *
  into v_row
  from public.work_orders
  where id = p_work_order_id
    and contractor_user_id = auth.uid();

  if not found then
    raise exception 'Not allowed or work order not found'
      using errcode = '42501';
  end if;

  update public.work_orders
  set
    status       = coalesce(lower(p_status), status),
    notes        = coalesce(p_notes, notes),
    scheduled_at = coalesce(p_scheduled_at, scheduled_at)
  where id = p_work_order_id
  returning * into v_row;

  return v_row;
end;
$$;


ALTER FUNCTION "public"."contractor_update_work_order"("p_work_order_id" "uuid", "p_status" "text", "p_notes" "text", "p_scheduled_at" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."contractor_update_work_order_status"("p_work_order_id" "uuid", "p_status" "text", "p_notes" "text" DEFAULT NULL::"text") RETURNS "public"."work_orders"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_wo public.work_orders;
begin
  if auth.uid() is null then
    raise exception using
      errcode = '28000',
      message = 'Not authenticated',
      detail = public.security_failure_context(
        'contractor_update_work_order_status',
        'missing_auth',
        null,
        'work_order',
        p_work_order_id
      ),
      hint = 'Authenticate as the assigned contractor before updating contractor workflow status.';
  end if;

  select *
  into v_wo
  from public.work_orders
  where id = p_work_order_id;

  if not found then
    raise exception using
      errcode = 'P0002',
      message = 'Work order not found',
      detail = public.security_failure_context(
        'contractor_update_work_order_status',
        'work_order_not_found',
        null,
        'work_order',
        p_work_order_id
      ),
      hint = 'Use an existing work order identifier from the current account scope.';
  end if;

  if v_wo.contractor_user_id is distinct from auth.uid() then
    raise exception using
      errcode = '42501',
      message = 'Not allowed (not assigned contractor)',
      detail = public.security_failure_context(
        'contractor_update_work_order_status',
        'not_assigned_contractor',
        v_wo.account_id,
        'work_order',
        p_work_order_id,
        jsonb_build_object('requested_status', lower(coalesce(p_status, '')))
      ),
      hint = 'Only the contractor assigned to this work order can update contractor workflow status.';
  end if;

  if p_status is null or p_status not in ('assigned', 'in_progress', 'completed', 'blocked', 'cancelled') then
    raise exception using
      errcode = '22023',
      message = format('Invalid status: %s', p_status),
      detail = public.security_failure_context(
        'contractor_update_work_order_status',
        'invalid_status',
        v_wo.account_id,
        'work_order',
        p_work_order_id,
        jsonb_build_object('requested_status', coalesce(p_status, ''))
      ),
      hint = 'Allowed contractor statuses are assigned, in_progress, completed, blocked, and cancelled.';
  end if;

  update public.work_orders
  set status = p_status,
      notes = coalesce(p_notes, notes),
      updated_at = now()
  where id = p_work_order_id
  returning * into v_wo;

  return v_wo;
end;
$$;


ALTER FUNCTION "public"."contractor_update_work_order_status"("p_work_order_id" "uuid", "p_status" "text", "p_notes" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."contractor_work_order_cards"("p_work_order_ids" "uuid"[] DEFAULT NULL::"uuid"[]) RETURNS TABLE("work_order_id" "uuid", "property_label" "text", "issue_title" "text", "issue_description" "text", "issue_priority" "text")
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select
    wo.id as work_order_id,
    trim(
      both ', '
      from concat(coalesce(p.address, ''), case when p.city is not null and p.city <> '' then ', ' || p.city else '' end)
    ) as property_label,
    mr.title as issue_title,
    mr.description as issue_description,
    mr.priority as issue_priority
  from public.work_orders wo
  left join public.properties p
    on p.id = wo.property_id
  left join public.maintenance_requests mr
    on mr.id = wo.maintenance_request_id
  where wo.contractor_user_id = auth.uid()
    and (p_work_order_ids is null or wo.id = any(p_work_order_ids));
$$;


ALTER FUNCTION "public"."contractor_work_order_cards"("p_work_order_ids" "uuid"[]) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_account_role"("p_account_id" "uuid", "p_name" "text", "p_permission_keys" "text"[] DEFAULT ARRAY[]::"text"[]) RETURNS TABLE("role_id" "uuid", "name" "text", "permission_keys" "text"[], "is_system" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
#variable_conflict use_column
declare
  v_account_id uuid;
  v_name text := lower(trim(coalesce(p_name, '')));
  v_role_id uuid;
begin
  v_account_id := public.assert_manage_account_access(p_account_id);

  if v_name = '' then
    raise exception 'Role name is required';
  end if;

  if v_name in ('owner', 'admin', 'staff') then
    raise exception 'System roles cannot be created via this flow';
  end if;

  insert into public.roles (account_id, name)
  values (v_account_id, v_name)
  returning id into v_role_id;

  insert into public.role_permissions (role_id, permission_key)
  select v_role_id, lower(trim(permission_key))
  from unnest(coalesce(p_permission_keys, array[]::text[])) permission_key
  where trim(coalesce(permission_key, '')) <> ''
  on conflict (role_id, permission_key) do nothing;

  return query
  select
    r.id as role_id,
    r.name,
    coalesce(
      array_agg(distinct lower(trim(rp.permission_key)) order by lower(trim(rp.permission_key)))
        filter (where rp.permission_key is not null),
      array[]::text[]
    ) as permission_keys,
    false as is_system
  from public.roles r
  left join public.role_permissions rp
    on rp.role_id = r.id
  where r.id = v_role_id
  group by r.id, r.name;
end;
$$;


ALTER FUNCTION "public"."create_account_role"("p_account_id" "uuid", "p_name" "text", "p_permission_keys" "text"[]) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_document_packet"("p_account_id" "uuid", "p_template_id" "uuid", "p_target_role" "text", "p_tenant_id" "uuid" DEFAULT NULL::"uuid", "p_contractor_id" "uuid" DEFAULT NULL::"uuid", "p_property_id" "uuid" DEFAULT NULL::"uuid", "p_packet_type" "text" DEFAULT 'agreement'::"text", "p_title" "text" DEFAULT NULL::"text", "p_message" "text" DEFAULT NULL::"text", "p_actor_user_id" "uuid" DEFAULT "auth"."uid"()) RETURNS "public"."document_packets"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor uuid := auth.uid();
  v_template public.document_templates;
  v_packet public.document_packets;
  v_user_id uuid;
  v_email text;
begin
  if v_actor is null then raise exception 'Not authenticated'; end if;
  if p_actor_user_id is not null and p_actor_user_id <> v_actor then raise exception 'Actor mismatch'; end if;
  if p_account_id is null then raise exception 'account_id is required'; end if;
  if not public.can_manage_document_packets(p_account_id, v_actor) then raise exception 'Not permitted'; end if;
  if nullif(trim(coalesce(p_title, '')), '') is null then raise exception 'Packet title is required'; end if;

  select * into v_template
  from public.document_templates
  where id = p_template_id
    and account_id = p_account_id
    and status = 'active'
    and upload_status = 'uploaded';
  if not found then raise exception 'Template not found'; end if;

  if p_target_role = 'tenant' then
    select t.user_id, t.email into v_user_id, v_email
    from public.tenants t
    where t.id = p_tenant_id and t.account_id = p_account_id and t.archived_at is null;
    if not found then raise exception 'Tenant not found'; end if;
  elsif p_target_role = 'contractor' then
    select c.user_id, c.email into v_user_id, v_email
    from public.contractors c
    where c.id = p_contractor_id and c.account_id = p_account_id and c.active = true;
    if not found then raise exception 'Contractor not found'; end if;
  else
    raise exception 'Invalid target_role';
  end if;

  if p_property_id is not null and not exists (
    select 1 from public.properties p where p.id = p_property_id and p.account_id = p_account_id
  ) then
    raise exception 'Property not found';
  end if;

  insert into public.document_packets (
    account_id,
    template_id,
    target_role,
    tenant_id,
    contractor_id,
    property_id,
    packet_type,
    title,
    message,
    created_by
  )
  values (
    p_account_id,
    p_template_id,
    p_target_role,
    p_tenant_id,
    p_contractor_id,
    p_property_id,
    p_packet_type,
    trim(p_title),
    nullif(trim(coalesce(p_message, '')), ''),
    v_actor
  )
  returning * into v_packet;

  insert into public.document_packet_recipients (
    account_id,
    packet_id,
    role,
    user_id,
    tenant_id,
    contractor_id,
    email
  )
  values (
    p_account_id,
    v_packet.id,
    p_target_role,
    v_user_id,
    p_tenant_id,
    p_contractor_id,
    v_email
  );

  insert into public.document_packet_events (
    account_id,
    packet_id,
    actor_user_id,
    event_type,
    message,
    metadata
  )
  values (
    p_account_id,
    v_packet.id,
    v_actor,
    'created',
    'Agreement packet created',
    jsonb_build_object('template_id', p_template_id, 'target_role', p_target_role)
  );

  return v_packet;
end;
$$;


