CREATE TABLE IF NOT EXISTS "public"."documents" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "owner_id" "uuid",
    "property_id" "uuid",
    "tenant_id" "uuid",
    "name" "text" NOT NULL,
    "storage_path" "text" NOT NULL,
    "mime_type" "text",
    "created_at" timestamp with time zone DEFAULT "now"(),
    "size_bytes" integer NOT NULL,
    "uploaded_by" "uuid" DEFAULT "auth"."uid"(),
    "tags" "public"."document_tag"[] DEFAULT '{}'::"public"."document_tag"[] NOT NULL,
    "account_id" "uuid" NOT NULL,
    "scope" "text" NOT NULL,
    "visibility" "text" DEFAULT 'staff'::"text" NOT NULL,
    "created_via" "text" DEFAULT 'legacy'::"text" NOT NULL,
    "created_by_user_id" "uuid",
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "upload_status" "text" DEFAULT 'stub'::"text" NOT NULL,
    "uploaded_at" timestamp with time zone,
    "original_filename" "text",
    "source" "text" DEFAULT 'landlord_upload'::"text" NOT NULL,
    "uploaded_by_role" "text",
    "uploaded_by_user_id" "uuid",
    "review_status" "text" DEFAULT 'accepted'::"text" NOT NULL,
    "review_note" "text",
    "reviewed_by" "uuid",
    "reviewed_at" timestamp with time zone,
    "tenant_highlight" "text" DEFAULT 'standard'::"text" NOT NULL,
    "tenant_highlight_note" "text",
    "tenant_highlight_rank" integer DEFAULT 100 NOT NULL,
    "tenant_highlight_updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "documents_mime_check" CHECK (("mime_type" = ANY (ARRAY['application/pdf'::"text", 'image/jpeg'::"text", 'image/png'::"text", 'image/webp'::"text", 'application/msword'::"text", 'application/vnd.openxmlformats-officedocument.wordprocessingml.document'::"text"]))),
    CONSTRAINT "documents_review_status_check" CHECK (("review_status" = ANY (ARRAY['pending_review'::"text", 'accepted'::"text", 'rejected'::"text"]))),
    CONSTRAINT "documents_scope_consistency_check" CHECK (((("scope" = 'property'::"text") AND ("property_id" IS NOT NULL) AND ("tenant_id" IS NULL)) OR (("scope" = 'tenant'::"text") AND ("tenant_id" IS NOT NULL) AND ("property_id" IS NULL)) OR (("scope" = 'shared'::"text") AND ("property_id" IS NOT NULL) AND ("tenant_id" IS NOT NULL)) OR (("scope" = 'account'::"text") AND ("property_id" IS NULL) AND ("tenant_id" IS NULL)))),
    CONSTRAINT "documents_size_check" CHECK (("size_bytes" <= 10485760)),
    CONSTRAINT "documents_source_check" CHECK (("source" = ANY (ARRAY['landlord_upload'::"text", 'tenant_upload'::"text", 'contractor_upload'::"text", 'template_generated'::"text", 'signature_completed'::"text"]))),
    CONSTRAINT "documents_tenant_highlight_check" CHECK (("tenant_highlight" = ANY (ARRAY['standard'::"text", 'current'::"text", 'action_required'::"text"]))),
    CONSTRAINT "documents_tenant_highlight_rank_check" CHECK ((("tenant_highlight_rank" >= 1) AND ("tenant_highlight_rank" <= 999))),
    CONSTRAINT "documents_upload_status_check" CHECK (("upload_status" = ANY (ARRAY['stub'::"text", 'uploaded'::"text", 'failed'::"text"]))),
    CONSTRAINT "documents_uploaded_by_role_check" CHECK ((("uploaded_by_role" IS NULL) OR ("uploaded_by_role" = ANY (ARRAY['owner'::"text", 'admin'::"text", 'staff'::"text", 'tenant'::"text", 'contractor'::"text"])))),
    CONSTRAINT "documents_visibility_check" CHECK (("visibility" = ANY (ARRAY['owner_admin'::"text", 'staff'::"text", 'tenant'::"text", 'private'::"text"])))
);


ALTER TABLE "public"."documents" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_document_request_upload_stub"("p_request_id" "uuid", "p_filename" "text", "p_mime_type" "text", "p_size_bytes" integer, "p_actor_user_id" "uuid" DEFAULT "auth"."uid"()) RETURNS "public"."documents"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor uuid := auth.uid();
  v_request public.document_requests;
  v_doc public.documents;
  v_doc_id uuid := gen_random_uuid();
  v_upload_id uuid := gen_random_uuid();
  v_safe_filename text;
  v_scope text;
  v_source text;
begin
  if v_actor is null then raise exception 'Not authenticated'; end if;
  if p_actor_user_id is not null and p_actor_user_id <> v_actor then raise exception 'Actor mismatch'; end if;

  select * into v_request from public.document_requests where id = p_request_id;
  if not found then raise exception 'Request not found'; end if;
  if v_request.status in ('accepted', 'cancelled') then raise exception 'Request is closed'; end if;
  if not public.is_document_request_target(p_request_id, v_actor) then raise exception 'Not permitted'; end if;

  if p_size_bytes is null or p_size_bytes <= 0 or p_size_bytes > 10485760 then
    raise exception 'Invalid file size';
  end if;

  if p_mime_type not in (
    'application/pdf',
    'image/jpeg',
    'image/png',
    'image/webp',
    'application/msword',
    'application/vnd.openxmlformats-officedocument.wordprocessingml.document'
  ) then
    raise exception 'Invalid mime_type: %', p_mime_type;
  end if;

  v_safe_filename := coalesce(nullif(trim(p_filename), ''), 'document');
  v_safe_filename := replace(v_safe_filename, '/', '_');
  v_safe_filename := replace(v_safe_filename, '\', '_');

  v_scope := case
    when v_request.tenant_id is not null and v_request.property_id is not null then 'shared'
    when v_request.tenant_id is not null then 'tenant'
    when v_request.property_id is not null then 'property'
    else 'account'
  end;

  v_source := case when v_request.target_role = 'tenant' then 'tenant_upload' else 'contractor_upload' end;

  insert into public.documents (
    id,
    account_id,
    scope,
    visibility,
    property_id,
    tenant_id,
    name,
    storage_path,
    mime_type,
    size_bytes,
    tags,
    created_via,
    created_by_user_id,
    uploaded_by,
    uploaded_by_user_id,
    uploaded_by_role,
    source,
    review_status,
    created_at,
    updated_at
  )
  values (
    v_doc_id,
    v_request.account_id,
    v_scope,
    'staff',
    v_request.property_id,
    v_request.tenant_id,
    v_safe_filename,
    v_request.account_id::text || '/' || v_doc_id::text || '/' || v_safe_filename,
    p_mime_type,
    p_size_bytes,
    '{}'::public.document_tag[],
    'document_request',
    v_actor,
    v_actor,
    v_actor,
    v_request.target_role,
    v_source,
    'pending_review',
    now(),
    now()
  )
  returning * into v_doc;

  insert into public.document_request_uploads (
    id,
    account_id,
    request_id,
    document_id,
    uploaded_by,
    uploaded_by_role,
    file_name,
    mime_type,
    size_bytes
  )
  values (
    v_upload_id,
    v_request.account_id,
    v_request.id,
    v_doc.id,
    v_actor,
    v_request.target_role,
    v_safe_filename,
    p_mime_type,
    p_size_bytes
  );

  update public.document_requests
  set status = 'uploaded'
  where id = v_request.id
    and status in ('requested', 'rejected');

  return v_doc;
end;
$$;


