CREATE OR REPLACE FUNCTION "public"."create_document_stub"("p_account_id" "uuid", "p_filename" "text") RETURNS TABLE("document_id" "uuid", "storage_path" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_document_id uuid;
  v_path text;
begin
  if public.account_role_for(p_account_id)
       not in ('owner','admin','staff') then
    raise exception 'Not permitted to create documents for this account';
  end if;

  v_document_id := gen_random_uuid();
  v_path := p_account_id::text || '/' || v_document_id::text || '/' || p_filename;

  insert into public.documents (id, account_id, storage_path)
  values (v_document_id, p_account_id, v_path);

  return query
  select v_document_id, v_path;
end;
$$;


