CREATE OR REPLACE FUNCTION "public"."create_document_template_stub"("p_account_id" "uuid", "p_country_code" "text", "p_language" "text", "p_template_type" "text", "p_name" "text", "p_description" "text" DEFAULT NULL::"text", "p_filename" "text" DEFAULT NULL::"text", "p_mime_type" "text" DEFAULT 'application/pdf'::"text", "p_size_bytes" integer DEFAULT 0, "p_actor_user_id" "uuid" DEFAULT "auth"."uid"()) RETURNS "public"."document_templates"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_template public.document_templates;
  v_id uuid := gen_random_uuid();
  v_actor uuid := auth.uid();
  v_country text := upper(trim(coalesce(p_country_code, '')));
  v_language text := lower(trim(coalesce(p_language, 'en')));
  v_filename text := public.sanitize_document_template_filename(p_filename);
begin
  if v_actor is null then
    raise exception 'Not authenticated';
  end if;

  if p_actor_user_id is not null and p_actor_user_id <> v_actor then
    raise exception 'Actor mismatch';
  end if;

  if p_account_id is null then
    raise exception 'account_id is required';
  end if;

  if not public.can_manage_document_templates(p_account_id, v_actor) then
    raise exception 'Not permitted';
  end if;

  if nullif(trim(coalesce(p_name, '')), '') is null then
    raise exception 'Template name is required';
  end if;

  insert into public.document_templates (
    id,
    account_id,
    country_code,
    language,
    template_type,
    name,
    description,
    storage_path,
    mime_type,
    size_bytes,
    created_by
  )
  values (
    v_id,
    p_account_id,
    v_country,
    v_language,
    p_template_type,
    trim(p_name),
    nullif(trim(coalesce(p_description, '')), ''),
    p_account_id::text || '/templates/' || v_id::text || '/' || v_filename,
    p_mime_type,
    coalesce(p_size_bytes, 0),
    v_actor
  )
  returning * into v_template;

  return v_template;
end;
$$;


