CREATE OR REPLACE FUNCTION "public"."create_lease_audit_finding"("p_account_id" "uuid", "p_lease_audit_id" "uuid", "p_risk_level" "text" DEFAULT 'medium'::"text", "p_clause_ref" "text" DEFAULT NULL::"text", "p_clause_text" "text" DEFAULT NULL::"text", "p_category" "text" DEFAULT NULL::"text", "p_explanation" "text" DEFAULT NULL::"text") RETURNS SETOF "public"."lease_audit_findings"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
