CREATE TABLE IF NOT EXISTS "public"."ledger_entries" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "account_id" "uuid" NOT NULL,
    "property_id" "uuid",
    "tenant_id" "uuid",
    "lease_id" "uuid",
    "entry_type" "text" NOT NULL,
    "direction" "text" NOT NULL,
    "amount" numeric(12,2) NOT NULL,
    "currency" "text" DEFAULT 'PLN'::"text" NOT NULL,
    "occurred_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "notes" "text",
    "created_by" "uuid" DEFAULT "auth"."uid"(),
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "external_ref" "text",
    "source_table" "text" NOT NULL,
    "source_id" "uuid" NOT NULL,
    CONSTRAINT "ledger_entries_amount_check" CHECK (("amount" > (0)::numeric)),
    CONSTRAINT "ledger_entries_direction_check" CHECK (("direction" = ANY (ARRAY['in'::"text", 'out'::"text"]))),
    CONSTRAINT "ledger_entries_entry_type_check" CHECK (("entry_type" = ANY (ARRAY['rent'::"text", 'payment'::"text", 'expense'::"text", 'deposit'::"text", 'refund'::"text", 'fee'::"text", 'invoice'::"text"])))
);

ALTER TABLE ONLY "public"."ledger_entries" FORCE ROW LEVEL SECURITY;


ALTER TABLE "public"."ledger_entries" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_ledger_entry"("p_account_id" "uuid", "p_entry_type" "text", "p_direction" "text", "p_amount" numeric, "p_currency" "text" DEFAULT 'PLN'::"text", "p_property_id" "uuid" DEFAULT NULL::"uuid", "p_tenant_id" "uuid" DEFAULT NULL::"uuid", "p_occurred_at" timestamp with time zone DEFAULT "now"(), "p_notes" "text" DEFAULT NULL::"text") RETURNS "public"."ledger_entries"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_role text;
  v_row public.ledger_entries;
begin
  v_role := public.account_role_for(p_account_id);
  if v_role not in ('owner','admin','staff') then
    raise exception 'Not permitted';
  end if;

  insert into public.ledger_entries (
    account_id, property_id, tenant_id,
    entry_type, direction, amount, currency,
    occurred_at, notes, created_by
  )
  values (
    p_account_id, p_property_id, p_tenant_id,
    p_entry_type, p_direction, p_amount, coalesce(p_currency,'PLN'),
    coalesce(p_occurred_at, now()), p_notes, auth.uid()
  )
  returning * into v_row;

  return v_row;
end;
$$;


