CREATE TABLE IF NOT EXISTS "public"."external_marketplace_jobs" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "account_id" "uuid" NOT NULL,
    "work_order_id" "uuid" NOT NULL,
    "provider_key" "text" NOT NULL,
    "country_code" "text" DEFAULT ''::"text" NOT NULL,
    "trade_category" "text" DEFAULT ''::"text" NOT NULL,
    "external_job_id" "text" DEFAULT ''::"text" NOT NULL,
    "external_reference" "text" DEFAULT ''::"text" NOT NULL,
    "external_url" "text" DEFAULT ''::"text" NOT NULL,
    "status" "text" DEFAULT 'draft'::"text" NOT NULL,
    "submission_mode" "text" DEFAULT 'manual'::"text" NOT NULL,
    "title" "text" DEFAULT ''::"text" NOT NULL,
    "description" "text" DEFAULT ''::"text" NOT NULL,
    "urgency" "text" DEFAULT ''::"text" NOT NULL,
    "postcode" "text" DEFAULT ''::"text" NOT NULL,
    "city" "text" DEFAULT ''::"text" NOT NULL,
    "property_label" "text" DEFAULT ''::"text" NOT NULL,
    "contact_name" "text" DEFAULT ''::"text" NOT NULL,
    "contact_email" "text" DEFAULT ''::"text" NOT NULL,
    "contact_phone" "text" DEFAULT ''::"text" NOT NULL,
    "consent_confirmed_at" timestamp with time zone,
    "submitted_at" timestamp with time zone,
    "last_synced_at" timestamp with time zone,
    "last_error" "text" DEFAULT ''::"text" NOT NULL,
    "request_payload" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "response_payload" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "metadata" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "created_by" "uuid" DEFAULT "auth"."uid"(),
    "updated_by" "uuid" DEFAULT "auth"."uid"(),
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "external_marketplace_jobs_status_check" CHECK (("status" = ANY (ARRAY['draft'::"text", 'ready_to_submit'::"text", 'submitted'::"text", 'acknowledged'::"text", 'matched'::"text", 'quote_received'::"text", 'appointment_scheduled'::"text", 'in_progress'::"text", 'completed'::"text", 'cancelled'::"text", 'failed'::"text", 'manual_follow_up'::"text"]))),
    CONSTRAINT "external_marketplace_jobs_submission_mode_check" CHECK (("submission_mode" = ANY (ARRAY['manual'::"text", 'api'::"text"])))
);


ALTER TABLE "public"."external_marketplace_jobs" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_marketplace_job"("p_account_id" "uuid", "p_work_order_id" "uuid", "p_provider_key" "text", "p_trade_category" "text" DEFAULT ''::"text", "p_contact_name" "text" DEFAULT ''::"text", "p_contact_email" "text" DEFAULT ''::"text", "p_contact_phone" "text" DEFAULT ''::"text", "p_consent_confirmed" boolean DEFAULT false, "p_title" "text" DEFAULT ''::"text", "p_description" "text" DEFAULT ''::"text", "p_urgency" "text" DEFAULT ''::"text", "p_postcode" "text" DEFAULT ''::"text", "p_city" "text" DEFAULT ''::"text", "p_property_label" "text" DEFAULT ''::"text", "p_request_payload" "jsonb" DEFAULT '{}'::"jsonb", "p_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS SETOF "public"."external_marketplace_jobs"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_account_id uuid;
  v_provider public.marketplace_providers%rowtype;
  v_job public.external_marketplace_jobs%rowtype;
begin
  v_account_id := public.assert_manage_account_access(p_account_id);

  select *
  into v_provider
  from public.marketplace_providers mp
  where mp.provider_key = p_provider_key;

  if v_provider.provider_key is null then
    raise exception 'Unknown marketplace provider';
  end if;

  if not exists (
    select 1
    from public.work_orders wo
    where wo.id = p_work_order_id
      and wo.account_id = v_account_id
  ) then
    raise exception 'Work order not found' using errcode = 'P0002';
  end if;

  insert into public.external_marketplace_jobs (
    account_id,
    work_order_id,
    provider_key,
    country_code,
    trade_category,
    external_job_id,
    external_reference,
    external_url,
    status,
    submission_mode,
    title,
    description,
    urgency,
    postcode,
    city,
    property_label,
    contact_name,
    contact_email,
    contact_phone,
    consent_confirmed_at,
    request_payload,
    metadata,
    created_by,
    updated_by
  )
  values (
    v_account_id,
    p_work_order_id,
    v_provider.provider_key,
    v_provider.country_code,
    coalesce(p_trade_category, ''),
    '',
    '',
    '',
    case when p_consent_confirmed then 'ready_to_submit' else 'draft' end,
    v_provider.submission_mode,
    coalesce(p_title, ''),
    coalesce(p_description, ''),
    coalesce(p_urgency, ''),
    coalesce(p_postcode, ''),
    coalesce(p_city, ''),
    coalesce(p_property_label, ''),
    case when p_consent_confirmed then coalesce(p_contact_name, '') else '' end,
    case when p_consent_confirmed then coalesce(p_contact_email, '') else '' end,
    case when p_consent_confirmed then coalesce(p_contact_phone, '') else '' end,
    case when p_consent_confirmed then now() else null end,
    coalesce(p_request_payload, '{}'::jsonb),
    coalesce(p_metadata, '{}'::jsonb),
    auth.uid(),
    auth.uid()
  )
  returning *
  into v_job;

  insert into public.external_marketplace_events (
    marketplace_job_id,
    account_id,
    work_order_id,
    event_type,
    payload,
    actor_user_id
  )
  values (
    v_job.id,
    v_job.account_id,
    v_job.work_order_id,
    'job_created',
    jsonb_build_object(
      'provider_key', v_job.provider_key,
      'status', v_job.status,
      'submission_mode', v_job.submission_mode
    ),
    auth.uid()
  );

  perform public.activity_log_write(
    v_job.account_id,
    'work_order',
    v_job.work_order_id,
    'marketplace_job_created',
    'provider_key',
    null,
    v_job.provider_key,
    jsonb_build_object(
      'table', 'external_marketplace_jobs',
      'marketplace_job_id', v_job.id,
      'provider_key', v_job.provider_key,
      'submission_mode', v_job.submission_mode,
      'status', v_job.status,
      'trade_category', v_job.trade_category
    )
  );

  perform public.marketplace_notify_managers(
    v_job.account_id,
    v_job.work_order_id,
    'marketplace_handoff_created',
    'Marketplace handoff created',
    coalesce(v_job.title, 'Work order handoff') || ' → ' || coalesce(v_provider.label, v_job.provider_key),
    jsonb_build_object(
      'marketplace_job_id', v_job.id,
      'provider_key', v_job.provider_key,
      'submission_mode', v_job.submission_mode,
      'status', v_job.status
    )
  );

  return query
  select *
  from public.external_marketplace_jobs j
  where j.id = v_job.id;
end;
$$;


ALTER FUNCTION "public"."create_marketplace_job"("p_account_id" "uuid", "p_work_order_id" "uuid", "p_provider_key" "text", "p_trade_category" "text", "p_contact_name" "text", "p_contact_email" "text", "p_contact_phone" "text", "p_consent_confirmed" boolean, "p_title" "text", "p_description" "text", "p_urgency" "text", "p_postcode" "text", "p_city" "text", "p_property_label" "text", "p_request_payload" "jsonb", "p_metadata" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_notifications"("p_account_id" "uuid", "p_recipient_user_ids" "uuid"[], "p_type" "text", "p_title" "text", "p_body" "text" DEFAULT NULL::"text", "p_entity_type" "text" DEFAULT NULL::"text", "p_entity_id" "uuid" DEFAULT NULL::"uuid", "p_link_path" "text" DEFAULT NULL::"text", "p_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_recipient_count integer := coalesce(array_length(p_recipient_user_ids, 1), 0);
begin
  begin
    perform public.assert_manage_account_access(p_account_id);
  exception
    when others then
      if sqlerrm = 'Access denied' then
        raise exception using
          errcode = '42501',
          message = 'Access denied',
          detail = public.security_failure_context(
            'create_notifications',
            'manage_account_required',
            p_account_id,
            'notification',
            p_entity_id,
            jsonb_build_object(
              'recipient_count', v_recipient_count,
              'notification_type', lower(coalesce(p_type, ''))
            )
          ),
          hint = 'Only owner, admin, or staff members for the target account can create notifications.';
      end if;
      raise;
  end;

  if p_recipient_user_ids is null or v_recipient_count = 0 then
    raise exception using
      errcode = '22023',
      message = 'Recipient list cannot be empty',
      detail = public.security_failure_context(
        'create_notifications',
        'empty_recipients',
        p_account_id,
        'notification',
        p_entity_id,
        jsonb_build_object(
          'recipient_count', v_recipient_count,
          'notification_type', lower(coalesce(p_type, ''))
        )
      ),
      hint = 'Provide at least one account-scoped recipient before calling create_notifications.';
  end if;

  if v_recipient_count > 250 then
    raise exception using
      errcode = '22023',
      message = 'Recipient list exceeds maximum size',
      detail = public.security_failure_context(
        'create_notifications',
        'recipient_count_exceeded',
        p_account_id,
        'notification',
        p_entity_id,
        jsonb_build_object(
          'recipient_count', v_recipient_count,
          'max_recipients', 250,
          'notification_type', lower(coalesce(p_type, ''))
        )
      ),
      hint = 'Split large notification batches into groups of 250 recipients or fewer.';
  end if;

  if exists (
    select 1
    from unnest(p_recipient_user_ids) uid
    left join public.account_members am
      on am.account_id = p_account_id
     and am.user_id = uid
    left join public.contractors c
      on c.account_id = p_account_id
     and c.user_id = uid
     and c.active = true
    left join public.tenants t
      on t.account_id = p_account_id
     and t.user_id = uid
    where uid is null
       or (
         am.user_id is null
         and c.user_id is null
         and t.user_id is null
       )
  ) then
    raise exception using
      errcode = '42501',
      message = 'One or more recipients are not part of this account',
      detail = public.security_failure_context(
        'create_notifications',
        'foreign_or_invalid_recipient',
        p_account_id,
        'notification',
        p_entity_id,
        jsonb_build_object(
          'recipient_count', v_recipient_count,
          'notification_type', lower(coalesce(p_type, ''))
        )
      ),
      hint = 'Notification recipients must already belong to the target account as members, active contractors, or tenants.';
  end if;

  insert into public.notifications (
    account_id,
    recipient_user_id,
    type,
    title,
    body,
    entity_type,
    entity_id,
    link_path,
    metadata
  )
  select
    p_account_id,
    r.uid,
    p_type,
    p_title,
    p_body,
    p_entity_type,
    p_entity_id,
    p_link_path,
    coalesce(p_metadata, '{}'::jsonb)
  from (
    select distinct uid
    from unnest(p_recipient_user_ids) as uid
    where uid is not null
  ) as r;
end;
$$;


ALTER FUNCTION "public"."create_notifications"("p_account_id" "uuid", "p_recipient_user_ids" "uuid"[], "p_type" "text", "p_title" "text", "p_body" "text", "p_entity_type" "text", "p_entity_id" "uuid", "p_link_path" "text", "p_metadata" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_notifications_system"("p_account_id" "uuid", "p_recipient_user_ids" "uuid"[], "p_type" "text", "p_title" "text", "p_body" "text" DEFAULT NULL::"text", "p_entity_type" "text" DEFAULT NULL::"text", "p_entity_id" "uuid" DEFAULT NULL::"uuid", "p_link_path" "text" DEFAULT NULL::"text", "p_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  if p_account_id is null then
    raise exception 'account_id is required';
  end if;

  if p_recipient_user_ids is null or array_length(p_recipient_user_ids, 1) is null then
    return;
  end if;

  if exists (
    select 1
    from unnest(p_recipient_user_ids) uid
    left join public.account_members am
      on am.account_id = p_account_id
     and am.user_id = uid
    left join public.contractors c
      on c.account_id = p_account_id
     and c.user_id = uid
     and c.active = true
    left join public.tenants t
      on t.account_id = p_account_id
     and t.user_id = uid
    where uid is null
       or (
         am.user_id is null
         and c.user_id is null
         and t.user_id is null
       )
  ) then
    raise exception 'One or more recipients are not part of this account';
  end if;

  insert into public.notifications (
    account_id,
    recipient_user_id,
    type,
    title,
    body,
    entity_type,
    entity_id,
    link_path,
    metadata
  )
  select
    p_account_id,
    r.uid,
    p_type,
    p_title,
    p_body,
    p_entity_type,
    p_entity_id,
    p_link_path,
    coalesce(p_metadata, '{}'::jsonb)
  from (
    select distinct uid
    from unnest(p_recipient_user_ids) as uid
    where uid is not null
  ) as r;
end;
$$;


ALTER FUNCTION "public"."create_notifications_system"("p_account_id" "uuid", "p_recipient_user_ids" "uuid"[], "p_type" "text", "p_title" "text", "p_body" "text", "p_entity_type" "text", "p_entity_id" "uuid", "p_link_path" "text", "p_metadata" "jsonb") OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."payments" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "owner_id" "uuid" NOT NULL,
    "property_id" "uuid" NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "amount" numeric(10,2) NOT NULL,
    "status" "text" NOT NULL,
    "due_date" "date" NOT NULL,
    "paid_at" "date",
    "created_at" timestamp with time zone DEFAULT "now"(),
    "account_id" "uuid" NOT NULL,
    "notes" "text",
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "currency" "text" DEFAULT 'PLN'::"text" NOT NULL,
    CONSTRAINT "payments_currency_check" CHECK (("currency" = ANY (ARRAY['PLN'::"text", 'EUR'::"text", 'GBP'::"text", 'USD'::"text", 'CZK'::"text", 'CHF'::"text", 'DKK'::"text", 'SEK'::"text", 'NOK'::"text", 'HUF'::"text", 'RON'::"text", 'BGN'::"text", 'CAD'::"text", 'AUD'::"text"]))),
    CONSTRAINT "payments_status_check" CHECK (("status" = ANY (ARRAY['due'::"text", 'paid'::"text", 'overdue'::"text", 'void'::"text"])))
);


ALTER TABLE "public"."payments" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_payment"("p_account_id" "uuid", "p_property_id" "uuid", "p_tenant_id" "uuid", "p_amount" numeric, "p_due_date" "date", "p_paid_at" "date" DEFAULT NULL::"date", "p_notes" "text" DEFAULT NULL::"text") RETURNS "public"."payments"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_owner_id    uuid;
  v_currency    text;
  v_row         public.payments;
begin
  if coalesce(public.account_role_for(p_account_id), '') not in ('owner', 'admin') then
    raise exception 'Not allowed';
  end if;

  select p.owner_id into v_owner_id
  from public.properties p
  where p.id = p_property_id
    and p.account_id = p_account_id;

  if v_owner_id is null then
    raise exception 'Property not found in this account';
  end if;

  if not exists (
    select 1 from public.tenants t
    where t.id = p_tenant_id
      and t.account_id = p_account_id
      and t.status = 'active'
  ) then
    raise exception 'Tenant not active in this account';
  end if;

  -- Inherit currency from the account so ledger entries are always correct
  select coalesce(a.currency, 'PLN') into v_currency
  from public.accounts a
  where a.id = p_account_id;

  insert into public.payments (
    owner_id, account_id, property_id, tenant_id,
    amount, due_date, paid_at, status, notes, currency
  ) values (
    v_owner_id, p_account_id, p_property_id, p_tenant_id,
    p_amount, p_due_date, p_paid_at,
    case when p_paid_at is not null then 'paid' else 'due' end,
    p_notes,
    v_currency
  )
  returning * into v_row;

  return v_row;
end;
$$;


ALTER FUNCTION "public"."create_payment"("p_account_id" "uuid", "p_property_id" "uuid", "p_tenant_id" "uuid", "p_amount" numeric, "p_due_date" "date", "p_paid_at" "date", "p_notes" "text") OWNER TO "postgres";


