    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "account_id" "uuid" NOT NULL,
    "property_id" "uuid",
    "tenant_id" "uuid",
    "lease_id" "uuid",
    "jurisdiction" "text" DEFAULT 'GB-ENG'::"text" NOT NULL,
    "pet_type" "text" NOT NULL,
    "pet_description" "text",
    "request_date" "date" NOT NULL,
    "status" "text" DEFAULT 'received'::"text" NOT NULL,
    "decision_date" "date",
    "refusal_reason" "text",
    "insurance_required" boolean DEFAULT false NOT NULL,
    "insurance_document_id" "uuid",
    "notes" "text",
    "created_by" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "pet_requests_pet_type_check" CHECK (("pet_type" = ANY (ARRAY['dog'::"text", 'cat'::"text", 'bird'::"text", 'reptile'::"text", 'other'::"text"]))),
    CONSTRAINT "pet_requests_status_check" CHECK (("status" = ANY (ARRAY['received'::"text", 'under_review'::"text", 'approved'::"text", 'refused'::"text", 'withdrawn'::"text"])))
);


ALTER TABLE "public"."pet_requests" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_pet_request"("p_account_id" "uuid", "p_property_id" "uuid" DEFAULT NULL::"uuid", "p_tenant_id" "uuid" DEFAULT NULL::"uuid", "p_lease_id" "uuid" DEFAULT NULL::"uuid", "p_pet_type" "text" DEFAULT 'other'::"text", "p_pet_description" "text" DEFAULT NULL::"text", "p_request_date" "date" DEFAULT CURRENT_DATE, "p_notes" "text" DEFAULT NULL::"text") RETURNS "public"."pet_requests"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_uid uuid := auth.uid();
  v_row public.pet_requests;
begin
  if v_uid is null then raise exception 'Not authenticated'; end if;
  perform public.assert_account_feature_access(p_account_id, 'renters_rights_readiness');
  if not public.is_account_manager(p_account_id, v_uid) then
    raise exception 'Access denied';
  end if;

  if p_pet_type not in ('dog','cat','bird','reptile','other') then
    raise exception 'Invalid pet_type: %', p_pet_type;
  end if;

  insert into public.pet_requests (
    account_id, property_id, tenant_id, lease_id,
    jurisdiction, pet_type, pet_description,
    request_date, status, notes, created_by
  ) values (
    p_account_id, p_property_id, p_tenant_id, p_lease_id,
    'GB-ENG', p_pet_type, p_pet_description,
    coalesce(p_request_date, current_date), 'received', p_notes, v_uid
  )
  returning * into v_row;

  perform public.log_security_event(
    p_account_id, 'pet_request_created', 'pet_request', v_row.id,
    jsonb_build_object(
      'pet_type',    p_pet_type,
      'tenant_id',   p_tenant_id,
      'property_id', p_property_id
    )
  );

  return v_row;
end;
$$;


ALTER FUNCTION "public"."create_pet_request"("p_account_id" "uuid", "p_property_id" "uuid", "p_tenant_id" "uuid", "p_lease_id" "uuid", "p_pet_type" "text", "p_pet_description" "text", "p_request_date" "date", "p_notes" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_self_serve_landlord_account"("p_account_name" "text" DEFAULT NULL::"text", "p_sandbox_mode" boolean DEFAULT false) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_uid uuid := auth.uid();
  v_email text;
  v_name text := trim(coalesce(p_account_name, ''));
  v_existing_owner_account_id uuid;
  v_existing_owner_account_name text;
  v_existing_any_non_owner boolean := false;
  v_existing_other_owner_user uuid;
  v_new_account_id uuid;
  v_sandbox_mode text;
  v_sandbox_lifecycle_status text;
  v_demo_expires_at timestamptz;
begin
  if v_uid is null then
    raise exception 'Not authenticated';
  end if;

  select lower(u.email::text)
  into v_email
  from auth.users u
  where u.id = v_uid
  limit 1;

  if coalesce(v_email, '') = '' then
    raise exception 'Authenticated email not found';
  end if;

  -- If the user is already owner somewhere, return existing (idempotent).
  select a.id, a.name
  into v_existing_owner_account_id, v_existing_owner_account_name
  from public.account_members am
  join public.accounts a on a.id = am.account_id
  where am.user_id = v_uid
    and public.account_member_effective_role(am.account_id, am.user_id) = 'owner'
  order by a.created_at asc nulls last, a.id
  limit 1;

  if v_existing_owner_account_id is not null then
    select
      coalesce(asp.mode, 'production'),
      coalesce(asp.lifecycle_status, 'active'),
      asp.demo_expires_at
    into v_sandbox_mode, v_sandbox_lifecycle_status, v_demo_expires_at
    from (select v_existing_owner_account_id as account_id) scope
    left join public.account_sandbox_profiles asp on asp.account_id = scope.account_id;

    return jsonb_build_object(
      'ok', true,
      'created', false,
      'account_id', v_existing_owner_account_id,
      'account_name', v_existing_owner_account_name,
      'role', 'owner',
      'sandbox_mode', v_sandbox_mode,
      'sandbox_lifecycle_status', v_sandbox_lifecycle_status,
      'demo_expires_at', v_demo_expires_at
    );
  end if;

  -- Guard: users already invited as non-owner cannot self-escalate to owner.
  select exists (
    select 1
    from public.account_members am
    where am.user_id = v_uid
      and public.account_member_effective_role(am.account_id, am.user_id) <> 'owner'
  )
  into v_existing_any_non_owner;

  if v_existing_any_non_owner then
    raise exception 'This user already belongs to an invited account; landlord self-signup is not allowed';
  end if;

  -- Guard: one landlord(owner) account per email across platform.
  select am.user_id
  into v_existing_other_owner_user
  from public.account_members am
  join auth.users u on u.id = am.user_id
  where lower(u.email::text) = v_email
    and public.account_member_effective_role(am.account_id, am.user_id) = 'owner'
    and am.user_id <> v_uid
  limit 1;

  if v_existing_other_owner_user is not null then
    raise exception 'This email is already used by an existing landlord account';
  end if;

  if v_name = '' then
    v_name := split_part(v_email, '@', 1);
  end if;

  insert into public.accounts(name, created_by)
  values (v_name, v_uid)
  returning id into v_new_account_id;

  insert into public.account_members(account_id, user_id, role)
  values (v_new_account_id, v_uid, 'owner')
  on conflict (account_id, user_id) do update set role = excluded.role;

  insert into public.account_sandbox_profiles(
    account_id,
    mode,
    lifecycle_status,
    seeded_fixture_version,
    demo_expires_at,
    created_by,
    updated_by
  )
  values (
    v_new_account_id,
    case when coalesce(p_sandbox_mode, false) then 'demo' else 'production' end,
    'active',
    null,
    case when coalesce(p_sandbox_mode, false) then now() + interval '14 days' else null end,
    v_uid,
    v_uid
  )
  on conflict (account_id) do nothing;

  if coalesce(p_sandbox_mode, false) then
    begin
      perform public.seed_demo_account_fixtures(v_new_account_id, false);
    exception
      when others then
        -- Keep account creation successful even if demo seeding needs a retry from onboarding.
        update public.account_sandbox_profiles
        set lifecycle_status = 'active',
            updated_by = v_uid
        where account_id = v_new_account_id;
    end;
  end if;

  select
    coalesce(asp.mode, 'production'),
    coalesce(asp.lifecycle_status, 'active'),
    asp.demo_expires_at
  into v_sandbox_mode, v_sandbox_lifecycle_status, v_demo_expires_at
  from (select v_new_account_id as account_id) scope
  left join public.account_sandbox_profiles asp on asp.account_id = scope.account_id;

  return jsonb_build_object(
    'ok', true,
    'created', true,
    'account_id', v_new_account_id,
    'account_name', v_name,
    'role', 'owner',
    'sandbox_mode', v_sandbox_mode,
    'sandbox_lifecycle_status', v_sandbox_lifecycle_status,
    'demo_expires_at', v_demo_expires_at
  );
end;
$$;


ALTER FUNCTION "public"."create_self_serve_landlord_account"("p_account_name" "text", "p_sandbox_mode" boolean) OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."compliance_items" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "account_id" "uuid" NOT NULL,
    "property_id" "uuid",
    "tenant_id" "uuid",
    "title" "text" NOT NULL,
    "category" "text" NOT NULL,
    "due_date" "date" NOT NULL,
    "status" "text" DEFAULT 'active'::"text" NOT NULL,
    "reminder_window_days" integer DEFAULT 30 NOT NULL,
    "notes" "text",
    "completed_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "recurrence_interval_months" integer DEFAULT 0 NOT NULL,
    "last_completed_at" timestamp with time zone,
    "jurisdiction" "text",
    "tax_filing_type" "text",
    "deadline_date" "date",
    "filed_at" timestamp with time zone,
    "filing_reference" "text",
    CONSTRAINT "compliance_items_jurisdiction_valid" CHECK ((("jurisdiction" IS NULL) OR ("jurisdiction" = ANY (ARRAY['GB'::"text", 'PL'::"text", 'DE'::"text"])))),
    CONSTRAINT "compliance_items_recurrence_interval_check" CHECK ((("recurrence_interval_months" >= 0) AND ("recurrence_interval_months" <= 60))),
    CONSTRAINT "compliance_items_reminder_window_check" CHECK ((("reminder_window_days" >= 0) AND ("reminder_window_days" <= 365))),
    CONSTRAINT "compliance_items_status_check" CHECK (("lower"("status") = ANY (ARRAY['active'::"text", 'completed'::"text", 'paused'::"text", 'cancelled'::"text"])))
);


ALTER TABLE "public"."compliance_items" OWNER TO "postgres";


COMMENT ON COLUMN "public"."compliance_items"."jurisdiction" IS 'ISO country code for tax jurisdiction: GB, PL, DE';



COMMENT ON COLUMN "public"."compliance_items"."tax_filing_type" IS 'Filing type key e.g. vat_return, income_tax, ptc, grundsteuer';



COMMENT ON COLUMN "public"."compliance_items"."deadline_date" IS 'Statutory or self-imposed filing deadline';



COMMENT ON COLUMN "public"."compliance_items"."filed_at" IS 'Timestamp the filing was marked as submitted';



COMMENT ON COLUMN "public"."compliance_items"."filing_reference" IS 'Reference number returned by HMRC/US/DE authority or accountant';



CREATE OR REPLACE FUNCTION "public"."create_tax_item"("p_account_id" "uuid", "p_title" "text", "p_jurisdiction" "text", "p_deadline_date" "date", "p_tax_filing_type" "text" DEFAULT NULL::"text", "p_recurrence_interval_months" integer DEFAULT 0, "p_notes" "text" DEFAULT NULL::"text", "p_property_id" "uuid" DEFAULT NULL::"uuid") RETURNS SETOF "public"."compliance_items"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_account_id uuid := public.assert_manage_account_access(p_account_id);
begin
  perform public.assert_account_feature_access(v_account_id, 'tax_readiness_dashboard');

  return query
  insert into public.compliance_items (
    account_id, property_id, title, category,
    due_date, deadline_date, jurisdiction,
    tax_filing_type, recurrence_interval_months, notes, status
  )
  values (
    v_account_id,
    p_property_id,
    trim(p_title),
    'tax',
    p_deadline_date,
    p_deadline_date,
    upper(left(trim(p_jurisdiction), 2)),
    nullif(trim(coalesce(p_tax_filing_type, '')), ''),
    greatest(0, least(60, coalesce(p_recurrence_interval_months, 0))),
    nullif(trim(coalesce(p_notes, '')), ''),
    'active'
  )
  returning *;
end;
$$;


