CREATE OR REPLACE FUNCTION "public"."current_profile_role"() RETURNS "text"
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public', 'extensions'
    AS $$
  select coalesce(
    (select role from public.profiles where id = auth.uid()),
    'staff'
  );
$$;


ALTER FUNCTION "public"."current_profile_role"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."custom_field_set_updated_at"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
begin
  new.updated_at := now();
  return new;
end;
$$;


ALTER FUNCTION "public"."custom_field_set_updated_at"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."dashboard_hub_extras"("p_account_id" "uuid", "p_tenant_id" "uuid" DEFAULT NULL::"uuid", "p_horizon_days" integer DEFAULT 1) RETURNS TABLE("item_key" "text", "item_type" "text", "count_value" bigint, "property_label" "text", "city" "text", "days_vacant" integer, "link_path" "text", "sort_order" integer)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with cfg as (
    select greatest(1, least(coalesce(p_horizon_days, 1), 30)) as horizon_days
  ),
  tenant_auth as (
    select public.assert_tenant_scope_access(p_account_id, p_tenant_id) as tenant_id
  ),
  authz as (
    select
      case
        when tenant_auth.tenant_id is null then public.assert_manage_account_access(p_account_id)
        else p_account_id
      end as account_id,
      tenant_auth.tenant_id
    from tenant_auth
  ),
  tenant_scope as (
    select t.property_id
    from tenants t
    cross join authz a
    where t.id = a.tenant_id
      and t.account_id = a.account_id
    limit 1
  ),
  due_soon as (
    select count(*)::bigint as due_soon_count
    from payments p
    cross join authz a
    where p.account_id = a.account_id
      and (
        a.tenant_id is null
        or p.tenant_id = a.tenant_id
      )
      and lower(coalesce(p.status, '')) not in ('paid', 'oplacone', 'opłacone')
      and p.due_date is not null
      and p.due_date >= current_date
      and p.due_date <= current_date + ((select horizon_days from cfg) || ' days')::interval
  ),
  preventive_due_soon as (
    select count(*)::bigint as task_count
    from public.preventive_maintenance_tasks t
    cross join authz a
    where t.account_id = a.account_id
      and (
        a.tenant_id is null
        or t.property_id = (select property_id from tenant_scope)
      )
      and lower(coalesce(t.status, 'active')) = 'active'
      and t.next_due_date is not null
      and t.next_due_date >= current_date
      and t.next_due_date <= current_date + interval '14 days'
  ),
  preventive_overdue as (
    select count(*)::bigint as task_count
    from public.preventive_maintenance_tasks t
    cross join authz a
    where t.account_id = a.account_id
      and (
        a.tenant_id is null
        or t.property_id = (select property_id from tenant_scope)
      )
      and lower(coalesce(t.status, 'active')) = 'active'
      and t.next_due_date is not null
      and t.next_due_date < current_date
  ),
  blocked_work_orders as (
    select count(*)::bigint as blocked_count
    from public.work_orders_with_flags w
    cross join authz a
    where w.account_id = a.account_id
      and (
        a.tenant_id is null
        or w.property_id = (select property_id from tenant_scope)
      )
      and lower(coalesce(w.status, '')) in ('blocked', 'zablokowane')
  ),
  contractor_ack_overdue as (
    select count(*)::bigint as overdue_count
    from public.work_orders w
    cross join authz a
    where w.account_id = a.account_id
      and (
        a.tenant_id is null
        or w.property_id = (select property_id from tenant_scope)
      )
      and (w.contractor_user_id is not null or nullif(coalesce(w.contractor_name, ''), '') is not null)
      and lower(coalesce(w.status, '')) not in ('completed', 'cancelled', 'zakończone', 'anulowane')
      and coalesce(lower(w.acknowledgement_status), 'pending') <> 'acknowledged'
      and w.acknowledgement_due_at is not null
      and w.acknowledgement_due_at < now()
  ),
  compliance_overdue as (
    select count(*)::bigint as item_count
    from public.compliance_items c
    cross join authz a
    where c.account_id = a.account_id
      and (
        a.tenant_id is null
        or c.property_id = (select property_id from tenant_scope)
      )
      and lower(coalesce(c.status, 'active')) = 'active'
      and c.due_date < current_date
  ),
  compliance_due_soon as (
    select count(*)::bigint as item_count
    from public.compliance_items c
    cross join authz a
    where c.account_id = a.account_id
      and (
        a.tenant_id is null
        or c.property_id = (select property_id from tenant_scope)
      )
      and lower(coalesce(c.status, 'active')) = 'active'
      and c.due_date >= current_date
      and c.due_date <= current_date + interval '30 days'
  ),
  compliance_missing_setup as (
    select count(*)::bigint as property_count
    from public.properties p
    cross join authz a
    where p.account_id = a.account_id
      and (
        a.tenant_id is null
        or p.id = (select property_id from tenant_scope)
      )
      and not exists (
        select 1
        from public.compliance_items c
        where c.account_id = p.account_id
          and c.property_id = p.id
      )
  ),
  vacant_long as (
    select
      p.id,
      p.address,
      p.city,
      floor(
        extract(
          epoch from (
            now() - coalesce(
              (
                select max(t.created_at)
                from tenants t
                where t.property_id = p.id
                  and t.account_id = a.account_id
              ),
              p.created_at
            )
          )
        ) / 86400
      )::int as days_vacant
    from properties p
    cross join authz a
    where p.account_id = a.account_id
      and (
        a.tenant_id is null
        or p.id = (select property_id from tenant_scope)
      )
      and not exists (
        select 1
        from tenants t
        where t.property_id = p.id
          and t.account_id = a.account_id
      )
    order by days_vacant desc, p.address
    limit 1
  )
  select
    'vacant-long'::text as item_key,
    'vacant_long_summary'::text as item_type,
    null::bigint as count_value,
    vl.address as property_label,
    vl.city,
    vl.days_vacant,
    '/properties?status=vacant&aging=14d'::text as link_path,
    10 as sort_order
  from vacant_long vl
  where vl.days_vacant > 30

  union all

  select
    'due-soon'::text as item_key,
    'due_soon_summary'::text as item_type,
    ds.due_soon_count as count_value,
    null::text as property_label,
    null::text as city,
    null::int as days_vacant,
    ('/finance?status=due&range=' || case when (select horizon_days from cfg) <= 1 then '1d' else '7d' end)::text as link_path,
    20 as sort_order
  from due_soon ds
  where ds.due_soon_count > 0

  union all

  select
    'contractor-ack-overdue'::text,
    'contractor_ack_overdue_summary'::text,
    cao.overdue_count,
    null::text,
    null::text,
    null::int,
    '/attention-center'::text,
    16 as sort_order
  from contractor_ack_overdue cao
  where cao.overdue_count > 0

  union all

  select
    'compliance-overdue'::text,
    'compliance_overdue_summary'::text,
    co.item_count,
    null::text,
    null::text,
    null::int,
    '/attention-center'::text,
    17 as sort_order
  from compliance_overdue co
  where co.item_count > 0

  union all

  select
    'preventive-overdue'::text,
    'preventive_overdue_summary'::text,
    po.task_count,
    null::text,
    null::text,
    null::int,
    '/maintenance-kpi'::text,
    18 as sort_order
  from preventive_overdue po
  where po.task_count > 0

  union all

  select
    'compliance-due-soon'::text,
    'compliance_due_summary'::text,
    cds.item_count,
    null::text,
    null::text,
    null::int,
    '/attention-center'::text,
    19 as sort_order
  from compliance_due_soon cds
  where cds.item_count > 0

  union all

  select
    'compliance-missing-setup'::text,
    'compliance_missing_setup_summary'::text,
    cms.property_count,
    null::text,
    null::text,
    null::int,
    '/attention-center'::text,
    21 as sort_order
  from compliance_missing_setup cms
  where cms.property_count > 0

  union all

  select
    'preventive-due-soon'::text,
    'preventive_due_summary'::text,
    pd.task_count,
    null::text,
    null::text,
    null::int,
    '/maintenance-kpi'::text,
    22 as sort_order
  from preventive_due_soon pd
  where pd.task_count > 0

  union all

  select
    'blocked-work-orders'::text,
    'blocked_work_order_summary'::text,
    bwo.blocked_count,
    null::text,
    null::text,
    null::int,
    '/maintenance-inbox?woStatus=blocked'::text,
    24 as sort_order
  from blocked_work_orders bwo
  where bwo.blocked_count > 0

  order by sort_order;
$$;


ALTER FUNCTION "public"."dashboard_hub_extras"("p_account_id" "uuid", "p_tenant_id" "uuid", "p_horizon_days" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."dashboard_snapshot"("p_account_id" "uuid", "p_tenant_id" "uuid" DEFAULT NULL::"uuid", "p_horizon_days" integer DEFAULT 1) RETURNS TABLE("property_count" bigint, "occupied_count" bigint, "vacant_count" bigint, "occupancy_rate" integer, "tenant_paid_total" numeric, "tenant_due_total" numeric, "tenant_overdue_total" numeric, "tenant_due_overdue_count" bigint, "overdue_amount" numeric, "due_soon_count" bigint, "due_soon_amount" numeric, "overdue_current_window_amount" numeric, "overdue_previous_window_amount" numeric, "open_requests" bigint, "open_high_priority" bigint, "waiting_over_48h" bigint, "unassigned_work_orders" bigint)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with cfg as (
    select greatest(1, least(coalesce(p_horizon_days, 1), 30)) as horizon_days
  ),
  tenant_auth as (
    select public.assert_tenant_scope_access(p_account_id, p_tenant_id) as tenant_id
  ),
  authz as (
    select
      case
        when tenant_auth.tenant_id is null then public.assert_manage_account_access(p_account_id)
        else p_account_id
      end as account_id,
      tenant_auth.tenant_id
    from tenant_auth
  ),
  tenant_scope as (
    select t.property_id
    from tenants t
    cross join authz a
    where t.id = a.tenant_id
      and t.account_id = a.account_id
    limit 1
  ),
  scoped_properties as (
    select
      p.id,
      coalesce(p.rent, 0) as rent
    from properties p
    cross join authz a
    where p.account_id = a.account_id
      and (
        a.tenant_id is null
        or p.id = (select property_id from tenant_scope)
      )
  ),
  occupied_properties as (
    select sp.id
    from scoped_properties sp
    where exists (
      select 1
      from tenants t
      where t.property_id = sp.id
        and t.account_id = (select account_id from authz)
    )
  ),
  scoped_payments as (
    select
      p.property_id,
      p.tenant_id,
      coalesce(p.amount, 0) as amount,
      lower(coalesce(p.status, '')) as status_norm,
      p.paid_at,
      p.due_date
    from payments p
    cross join authz a
    where p.account_id = a.account_id
      and (
        a.tenant_id is null
        or p.tenant_id = a.tenant_id
      )
  ),
  payment_rows as (
    select
      sp.property_id,
      sp.tenant_id,
      sp.amount,
      sp.status_norm,
      sp.paid_at,
      sp.due_date,
      (
        sp.paid_at is not null
        or sp.status_norm in ('paid', 'oplacone', 'opłacone')
      ) as is_paid,
      date_trunc(
        'month',
        coalesce(sp.due_date::timestamp, sp.paid_at::timestamp, current_date::timestamp)
      ) as cycle_month
    from scoped_payments sp
  ),
  payment_cycles as (
    select
      prx.property_id,
      prx.tenant_id,
      prx.cycle_month,
      greatest(
        coalesce(max(pr.rent), 0),
        coalesce(max(prx.amount), 0)
      ) as billed_amount,
      coalesce(
        sum(
          case
            when prx.is_paid then prx.amount else 0
          end
        ),
        0
      ) as paid_amount,
      min(
        case
          when not prx.is_paid then prx.due_date
          else null
        end
      ) as open_due_date,
      coalesce(
        bool_or(
          not prx.is_paid
          and (
            prx.status_norm in ('overdue', 'zalegle', 'zaległe')
            or (prx.due_date is not null and prx.due_date < current_date)
          )
        ),
        false
      ) as has_overdue
    from payment_rows prx
    left join scoped_properties pr
      on pr.id = prx.property_id
    group by prx.property_id, prx.tenant_id, prx.cycle_month
  ),
  scoped_requests as (
    select
      lower(coalesce(r.status, '')) as status_norm,
      lower(coalesce(r.priority, '')) as priority_norm,
      r.created_at
    from maintenance_requests r
    cross join authz a
    where r.account_id = a.account_id
      and (
        a.tenant_id is null
        or r.property_id = (select property_id from tenant_scope)
      )
  ),
  scoped_work_orders as (
    select
      lower(coalesce(w.status, '')) as status_norm,
      w.contractor_user_id
    from work_orders_with_flags w
    cross join authz a
    where w.account_id = a.account_id
      and (
        a.tenant_id is null
        or w.property_id = (select property_id from tenant_scope)
      )
  ),
  finance as (
    select
      coalesce(sum(pc.paid_amount), 0) as tenant_paid_total,
      coalesce(
        sum(
          case
            when greatest(pc.billed_amount - pc.paid_amount, 0) > 0
             and not pc.has_overdue
            then greatest(pc.billed_amount - pc.paid_amount, 0)
            else 0
          end
        ),
        0
      ) as tenant_due_total,
      coalesce(
        sum(
          case
            when greatest(pc.billed_amount - pc.paid_amount, 0) > 0
             and pc.has_overdue
            then greatest(pc.billed_amount - pc.paid_amount, 0)
            else 0
          end
        ),
        0
      ) as tenant_overdue_total,
      coalesce(sum(case when greatest(pc.billed_amount - pc.paid_amount, 0) > 0 then 1 else 0 end), 0) as tenant_due_overdue_count,
      coalesce(
        sum(
          case
            when greatest(pc.billed_amount - pc.paid_amount, 0) > 0
             and pc.has_overdue
            then greatest(pc.billed_amount - pc.paid_amount, 0)
            else 0
          end
        ),
        0
      ) as overdue_amount,
      coalesce(
        sum(
          case
            when greatest(pc.billed_amount - pc.paid_amount, 0) > 0
             and pc.open_due_date is not null
             and pc.open_due_date >= current_date
             and pc.open_due_date <= current_date + ((select horizon_days from cfg) || ' days')::interval
            then 1
            else 0
          end
        ),
        0
      ) as due_soon_count,
      coalesce(
        sum(
          case
            when greatest(pc.billed_amount - pc.paid_amount, 0) > 0
             and pc.open_due_date is not null
             and pc.open_due_date >= current_date
             and pc.open_due_date <= current_date + ((select horizon_days from cfg) || ' days')::interval
            then greatest(pc.billed_amount - pc.paid_amount, 0)
            else 0
          end
        ),
        0
      ) as due_soon_amount,
      coalesce(
        sum(
          case
            when greatest(pc.billed_amount - pc.paid_amount, 0) > 0
             and pc.has_overdue
             and pc.open_due_date is not null
             and pc.open_due_date <= current_date
             and current_date - pc.open_due_date <= 7
            then greatest(pc.billed_amount - pc.paid_amount, 0)
            else 0
          end
        ),
        0
      ) as overdue_current_window_amount,
      coalesce(
        sum(
          case
            when greatest(pc.billed_amount - pc.paid_amount, 0) > 0
             and pc.has_overdue
             and pc.open_due_date is not null
             and current_date - pc.open_due_date > 7
             and current_date - pc.open_due_date <= 14
            then greatest(pc.billed_amount - pc.paid_amount, 0)
            else 0
          end
        ),
        0
      ) as overdue_previous_window_amount
    from payment_cycles pc
  ),
  maintenance as (
    select
      (select count(*) from scoped_requests where status_norm not in ('closed', 'zamkniete', 'zamknięte')) as open_requests,
      (
        select count(*)
        from scoped_requests
        where status_norm not in ('closed', 'zamkniete', 'zamknięte')
          and priority_norm in ('high', 'critical', 'wysoki', 'krytyczny')
      ) as open_high_priority,
      (
        select count(*)
        from scoped_requests
        where status_norm = 'waiting'
          and created_at <= now() - interval '48 hours'
      ) as waiting_over_48h,
      (
        select count(*)
        from scoped_work_orders
        where status_norm in ('assigned', 'in_progress', 'blocked')
          and contractor_user_id is null
      ) as unassigned_work_orders
  )
  select
    (select count(*) from scoped_properties) as property_count,
    (select count(*) from occupied_properties) as occupied_count,
    greatest((select count(*) from scoped_properties) - (select count(*) from occupied_properties), 0) as vacant_count,
    case
      when (select count(*) from scoped_properties) = 0 then 0
      else round(
        ((select count(*) from occupied_properties)::numeric / (select count(*) from scoped_properties)::numeric) * 100
      )::int
    end as occupancy_rate,
    finance.tenant_paid_total,
    finance.tenant_due_total,
    finance.tenant_overdue_total,
    finance.tenant_due_overdue_count,
    finance.overdue_amount,
    finance.due_soon_count,
    finance.due_soon_amount,
    finance.overdue_current_window_amount,
    finance.overdue_previous_window_amount,
    maintenance.open_requests,
    maintenance.open_high_priority,
    maintenance.waiting_over_48h,
    maintenance.unassigned_work_orders
  from finance, maintenance;
$$;


ALTER FUNCTION "public"."dashboard_snapshot"("p_account_id" "uuid", "p_tenant_id" "uuid", "p_horizon_days" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."delete_document_and_audit"("p_document_id" "uuid", "p_actor_user_id" "uuid" DEFAULT "auth"."uid"()) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_doc public.documents;
  v_actor_user_id uuid := auth.uid();
begin
  if p_document_id is null then
    raise exception 'document_id is required';
  end if;

  if v_actor_user_id is null then
    raise exception 'Not authenticated';
  end if;

  if p_actor_user_id is not null and p_actor_user_id <> v_actor_user_id then
    raise exception 'Actor mismatch';
  end if;

  select * into v_doc
  from public.documents
  where id = p_document_id;

  if not found then
    raise exception 'Document not found';
  end if;

  if not public.account_member_has_permission(v_doc.account_id, 'documents.delete', v_actor_user_id) then
    raise exception 'Not permitted';
  end if;

  insert into public.document_audit_log (
    document_id,
    action,
    performed_by,
    performed_at,
    account_id,
    property_id,
    tenant_id,
    created_at
  )
  values (
    v_doc.id,
    'delete',
    v_actor_user_id,
    now(),
    v_doc.account_id,
    v_doc.property_id,
    v_doc.tenant_id,
    now()
  );

  delete from public.documents where id = v_doc.id;
end;
$$;


ALTER FUNCTION "public"."delete_document_and_audit"("p_document_id" "uuid", "p_actor_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."delete_lease_audit_finding"("p_id" "uuid", "p_account_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_account_id uuid := public.assert_manage_account_access(p_account_id);
begin
  perform public.assert_account_feature_access(v_account_id, 'ai_lease_auditor');

  delete from public.lease_audit_findings
  where id         = p_id
    and account_id = v_account_id;
end;
$$;


ALTER FUNCTION "public"."delete_lease_audit_finding"("p_id" "uuid", "p_account_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."delete_lease_audit_finding"("p_id" "uuid", "p_account_id" "uuid") IS 'Hard-deletes a lease audit finding after verifying ai_lease_auditor entitlement.';



CREATE OR REPLACE FUNCTION "public"."delete_payment"("p_account_id" "uuid", "p_payment_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_account_id uuid;
begin
  select account_id into v_account_id
  from public.payments
  where id = p_payment_id
    and account_id = p_account_id;

  if v_account_id is null then
    raise exception 'Payment not found';
  end if;

  if coalesce(public.account_role_for(v_account_id), '') <> 'owner' then
    raise exception 'Not allowed';
  end if;

  delete from public.payments
  where id = p_payment_id
    and account_id = p_account_id;
end;
$$;


ALTER FUNCTION "public"."delete_payment"("p_account_id" "uuid", "p_payment_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."delete_tax_item"("p_id" "uuid", "p_account_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_account_id uuid := public.assert_manage_account_access(p_account_id);
begin
  perform public.assert_account_feature_access(v_account_id, 'tax_readiness_dashboard');

  delete from public.compliance_items
  where id         = p_id
    and account_id = v_account_id
    and category   = 'tax';
end;
$$;


ALTER FUNCTION "public"."delete_tax_item"("p_id" "uuid", "p_account_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."delete_tax_item"("p_id" "uuid", "p_account_id" "uuid") IS 'Deletes a tax item after verifying entitlement.';



CREATE OR REPLACE FUNCTION "public"."delete_tax_record"("p_id" "uuid", "p_account_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_account_id uuid := public.assert_manage_account_access(p_account_id);
begin
  perform public.assert_account_feature_access(v_account_id, 'tax_readiness_dashboard');

  delete from public.tax_records
  where id         = p_id
    and account_id = v_account_id;
end;
$$;


