CREATE OR REPLACE FUNCTION "public"."document_notify_uploaded"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_recipients uuid[];
  v_safe_recipients uuid[];
  v_title text;
  v_body text;
  v_uploader uuid;
  v_tenant_user uuid;
  v_name text;
  v_uid uuid;
  v_window_seconds integer := 60;
begin
  if new.upload_status is distinct from 'uploaded' then
    return new;
  end if;

  if tg_op = 'UPDATE' and old.upload_status = 'uploaded' then
    return new;
  end if;

  if new.account_id is null then
    return new;
  end if;

  v_name := coalesce(nullif(new.original_filename, ''), new.name, 'Dokument');
  v_title := 'Dodano dokument';
  v_body := 'Plik: ' || v_name;

  v_uploader := coalesce(new.created_by_user_id, new.uploaded_by);

  if coalesce(new.visibility, '') = 'private' then
    if v_uploader is not null then
      v_recipients := array[v_uploader];
    else
      return new;
    end if;
  else
    select array_agg(am.user_id)
      into v_recipients
    from public.account_members am
    where am.account_id = new.account_id;
  end if;

  if coalesce(new.visibility, '') = 'tenant' and new.tenant_id is not null then
    select t.user_id
      into v_tenant_user
    from public.tenants t
    where t.id = new.tenant_id
      and t.account_id = new.account_id
    limit 1;

    if v_tenant_user is not null then
      if v_recipients is null then
        v_recipients := array[v_tenant_user];
      elsif not (v_tenant_user = any(v_recipients)) then
        v_recipients := v_recipients || v_tenant_user;
      end if;
    end if;
  end if;

  if v_recipients is null or array_length(v_recipients, 1) is null then
    return new;
  end if;

  select array_agg(distinct uid)
    into v_safe_recipients
  from unnest(v_recipients) as uid
  where uid is not null
    and (
      exists (
        select 1
        from public.account_members am
        where am.account_id = new.account_id
          and am.user_id = uid
      )
      or exists (
        select 1
        from public.tenants t
        where t.account_id = new.account_id
          and t.user_id = uid
          and coalesce(t.status, '') <> 'archived'
      )
      or exists (
        select 1
        from public.contractors c
        where c.account_id = new.account_id
          and c.user_id = uid
          and coalesce(c.active, false) = true
      )
    );

  if v_safe_recipients is null or array_length(v_safe_recipients, 1) is null then
    return new;
  end if;

  foreach v_uid in array v_safe_recipients loop
    if public.should_send_notification(
      new.account_id,
      v_uid,
      'document_uploaded',
      'document',
      new.id,
      v_window_seconds
    ) then
      perform public.create_notifications_system(
        new.account_id,
        array[v_uid],
        'document_uploaded',
        v_title,
        v_body,
        'document',
        new.id,
        '/documents',
        jsonb_build_object(
          'document_id', new.id,
          'property_id', new.property_id,
          'tenant_id', new.tenant_id,
          'scope', new.scope,
          'visibility', new.visibility,
          'name', v_name
        )
      );
    end if;
  end loop;

  return new;
end;
$$;


ALTER FUNCTION "public"."document_notify_uploaded"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."documents_notify_uploaded_trg_fn"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
declare
  v_recipients uuid[];
  v_safe_recipients uuid[];
  v_title text;
  v_body text;
  v_uploader uuid;
  v_tenant_user uuid;
  v_name text;
  v_uid uuid;
  v_window int := 60; -- seconds: adjust if desired
begin
  -- Only notify when the doc becomes uploaded
  if new.upload_status is distinct from 'uploaded' then
    return new;
  end if;

  -- If it was already uploaded, skip
  if tg_op = 'UPDATE' and old.upload_status = 'uploaded' then
    return new;
  end if;

  if new.account_id is null then
    return new;
  end if;

  v_name := coalesce(nullif(new.original_filename, ''), new.name, 'Dokument');
  v_title := 'Dodano dokument';
  v_body := 'Plik: ' || v_name;

  v_uploader := coalesce(new.created_by_user_id, new.uploaded_by);

  -- Private => only uploader
  if coalesce(new.visibility, '') = 'private' then
    if v_uploader is not null then
      v_recipients := array[v_uploader];
    else
      return new;
    end if;
  else
    select array_agg(am.user_id)
      into v_recipients
    from public.account_members am
    where am.account_id = new.account_id;
  end if;

  -- If visible to tenant, add tenant's user_id
  if coalesce(new.visibility, '') = 'tenant' and new.tenant_id is not null then
    select t.user_id into v_tenant_user
    from public.tenants t
    where t.id = new.tenant_id
      and t.account_id = new.account_id
    limit 1;

    if v_tenant_user is not null then
      if v_recipients is null then
        v_recipients := array[v_tenant_user];
      elsif not (v_tenant_user = any(v_recipients)) then
        v_recipients := v_recipients || v_tenant_user;
      end if;
    end if;
  end if;

  if v_recipients is null or array_length(v_recipients, 1) is null then
    return new;
  end if;

  select array_agg(distinct uid)
    into v_safe_recipients
  from unnest(v_recipients) as uid
  where uid is not null
    and (
      exists (
        select 1
        from public.account_members am
        where am.account_id = new.account_id
          and am.user_id = uid
      )
      or exists (
        select 1
        from public.tenants t
        where t.account_id = new.account_id
          and t.user_id = uid
          and coalesce(t.status, '') <> 'archived'
      )
      or exists (
        select 1
        from public.contractors c
        where c.account_id = new.account_id
          and c.user_id = uid
          and coalesce(c.active, false) = true
      )
    );

  if v_safe_recipients is null or array_length(v_safe_recipients, 1) is null then
    return new;
  end if;

  -- Throttled per-recipient
  foreach v_uid in array v_recipients loop
    if not public.should_throttle_notification(
      new.account_id, v_uid,
      'document_uploaded',
      'document', new.id,
      v_window
    ) then
      perform public.create_notifications_system(
        new.account_id,
        array[v_uid],
        'document_uploaded',
        v_title,
        v_body,
        'document',
        new.id,
        '/documents',
        jsonb_build_object(
          'document_id', new.id,
          'property_id', new.property_id,
          'tenant_id', new.tenant_id,
          'scope', new.scope,
          'visibility', new.visibility,
          'name', v_name
        )
      );
    end if;
  end loop;

  return new;
end;
$$;


ALTER FUNCTION "public"."documents_notify_uploaded_trg_fn"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."edge_record_marketplace_submission_result"("p_account_id" "uuid", "p_marketplace_job_id" "uuid", "p_actor_user_id" "uuid", "p_outcome" "text", "p_external_job_id" "text" DEFAULT ''::"text", "p_external_reference" "text" DEFAULT ''::"text", "p_external_url" "text" DEFAULT ''::"text", "p_last_error" "text" DEFAULT ''::"text", "p_response_payload" "jsonb" DEFAULT '{}'::"jsonb") RETURNS SETOF "public"."external_marketplace_jobs"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_job public.external_marketplace_jobs%rowtype;
  v_previous_status text;
  v_event_type text;
  v_notification_type text;
  v_notification_title text;
  v_notification_body text;
begin
  if p_outcome not in ('submitted', 'failed', 'manual_follow_up') then
    raise exception 'Unsupported marketplace submission outcome';
  end if;

  select j.status
  into v_previous_status
  from public.external_marketplace_jobs j
  where j.id = p_marketplace_job_id
    and j.account_id = p_account_id;

  update public.external_marketplace_jobs j
  set status = p_outcome,
      submitted_at = case when p_outcome = 'submitted' then coalesce(j.submitted_at, now()) else j.submitted_at end,
      last_synced_at = now(),
      external_job_id = case when coalesce(p_external_job_id, '') = '' then j.external_job_id else p_external_job_id end,
      external_reference = case when coalesce(p_external_reference, '') = '' then j.external_reference else p_external_reference end,
      external_url = case when coalesce(p_external_url, '') = '' then j.external_url else p_external_url end,
      last_error = case when p_outcome = 'submitted' then '' else coalesce(p_last_error, '') end,
      response_payload = case
        when p_response_payload is null or p_response_payload = '{}'::jsonb then j.response_payload
        else p_response_payload
      end,
      updated_by = p_actor_user_id,
      updated_at = now()
  where j.id = p_marketplace_job_id
    and j.account_id = p_account_id
  returning *
  into v_job;

  if v_job.id is null then
    raise exception 'Marketplace job not found' using errcode = 'P0002';
  end if;

  if p_outcome = 'submitted' then
    v_event_type := 'job_submitted';
    v_notification_type := 'marketplace_handoff_submitted';
    v_notification_title := 'Marketplace handoff submitted';
    v_notification_body := coalesce(v_job.title, 'Work order handoff') || ' submitted to ' || coalesce(v_job.provider_key, 'marketplace');
  else
    v_event_type := 'status_updated';
    v_notification_type := 'marketplace_handoff_status_changed';
    v_notification_title := 'Marketplace handoff status changed';
    v_notification_body := coalesce(v_job.title, 'Work order handoff') || ' status: ' || v_job.status;
  end if;

  insert into public.external_marketplace_events (
    marketplace_job_id,
    account_id,
    work_order_id,
    event_type,
    payload,
    actor_user_id
  )
  values (
    v_job.id,
    v_job.account_id,
    v_job.work_order_id,
    v_event_type,
    jsonb_build_object(
      'status', v_job.status,
      'external_job_id', v_job.external_job_id,
      'external_reference', v_job.external_reference,
      'external_url', v_job.external_url,
      'last_error', v_job.last_error,
      'payload', coalesce(p_response_payload, '{}'::jsonb)
    ),
    p_actor_user_id
  );

  if p_outcome = 'submitted' then
    perform public.activity_log_write(
      v_job.account_id,
      'work_order',
      v_job.work_order_id,
      'marketplace_job_submitted',
      'status',
      v_previous_status,
      v_job.status,
      jsonb_build_object(
        'table', 'external_marketplace_jobs',
        'marketplace_job_id', v_job.id,
        'provider_key', v_job.provider_key,
        'external_job_id', v_job.external_job_id,
        'external_reference', v_job.external_reference,
        'external_url', v_job.external_url,
        'payload', coalesce(p_response_payload, '{}'::jsonb)
      )
    );
  else
    perform public.activity_log_write(
      v_job.account_id,
      'work_order',
      v_job.work_order_id,
      'marketplace_job_status_changed',
      'status',
      v_previous_status,
      v_job.status,
      jsonb_build_object(
        'table', 'external_marketplace_jobs',
        'marketplace_job_id', v_job.id,
        'provider_key', v_job.provider_key,
        'status', v_job.status,
        'last_error', v_job.last_error,
        'payload', coalesce(p_response_payload, '{}'::jsonb)
      )
    );
  end if;

  perform public.marketplace_notify_managers(
    v_job.account_id,
    v_job.work_order_id,
    v_notification_type,
    v_notification_title,
    v_notification_body,
    jsonb_build_object(
      'marketplace_job_id', v_job.id,
      'provider_key', v_job.provider_key,
      'status', v_job.status,
      'old_status', v_previous_status,
      'external_job_id', v_job.external_job_id,
      'external_reference', v_job.external_reference,
      'external_url', v_job.external_url
    )
  );

  return query
  select *
  from public.external_marketplace_jobs j
  where j.id = v_job.id;
end;
$$;


ALTER FUNCTION "public"."edge_record_marketplace_submission_result"("p_account_id" "uuid", "p_marketplace_job_id" "uuid", "p_actor_user_id" "uuid", "p_outcome" "text", "p_external_job_id" "text", "p_external_reference" "text", "p_external_url" "text", "p_last_error" "text", "p_response_payload" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."enforce_work_order_status_transition"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
declare
  v_old text := lower(coalesce(old.status, 'assigned'));
  v_new text := lower(coalesce(new.status, 'assigned'));
begin
  -- Only enforce when status changes
  if v_new is not distinct from v_old then
    return new;
  end if;

  if not public.work_order_can_transition(v_old, v_new) then
    raise exception 'Invalid status transition: % -> %', v_old, v_new
      using errcode = 'P0001';
  end if;

  -- Normalize persisted value
  new.status := v_new;
  return new;
end;
$$;


ALTER FUNCTION "public"."enforce_work_order_status_transition"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."ensure_default_system_account_roles"("p_account_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  if p_account_id is null then
    raise exception 'account_id is required';
  end if;

  perform public.ensure_system_account_role(p_account_id, 'owner'::public.account_role);
  perform public.ensure_system_account_role(p_account_id, 'admin'::public.account_role);
  perform public.ensure_system_account_role(p_account_id, 'staff'::public.account_role);
end;
$$;


ALTER FUNCTION "public"."ensure_default_system_account_roles"("p_account_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."ensure_system_account_role"("p_account_id" "uuid", "p_role" "public"."account_role") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_role_id uuid;
  v_role_name text := lower(trim(p_role::text));
begin
  if p_account_id is null then
    raise exception 'account_id is required';
  end if;

  if v_role_name not in ('owner', 'admin', 'staff') then
    return null;
  end if;

  select r.id
    into v_role_id
  from public.roles r
  where r.account_id = p_account_id
    and lower(trim(r.name)) = v_role_name
  limit 1;

  if v_role_id is not null then
    return v_role_id;
  end if;

  insert into public.roles (account_id, name)
  values (p_account_id, v_role_name)
  returning id into v_role_id;

  insert into public.role_permissions (role_id, permission_key)
  select v_role_id, permission_key
  from (
    values
      ('owner', 'properties.read'),
      ('owner', 'properties.create'),
      ('owner', 'properties.update'),
      ('owner', 'properties.delete'),
      ('owner', 'tenants.read'),
      ('owner', 'tenants.create'),
      ('owner', 'tenants.update'),
      ('owner', 'tenants.delete'),
      ('owner', 'documents.read'),
      ('owner', 'documents.upload'),
      ('owner', 'documents.tag'),
      ('owner', 'documents.delete'),
      ('owner', 'finance.read'),
      ('owner', 'finance.create'),
      ('owner', 'finance.update'),
      ('owner', 'finance.delete'),
      ('owner', 'users.invite'),
      ('owner', 'users.role'),
      ('admin', 'properties.read'),
      ('admin', 'properties.create'),
      ('admin', 'properties.update'),
      ('admin', 'tenants.read'),
      ('admin', 'tenants.create'),
      ('admin', 'tenants.update'),
      ('admin', 'documents.read'),
      ('admin', 'documents.upload'),
      ('admin', 'documents.tag'),
      ('admin', 'finance.read'),
      ('admin', 'finance.create'),
      ('admin', 'finance.update'),
      ('staff', 'properties.read'),
      ('staff', 'tenants.read'),
      ('staff', 'documents.read'),
      ('staff', 'documents.upload'),
      ('staff', 'documents.tag'),
      ('staff', 'finance.read')
  ) as seed(role_name, permission_key)
  where seed.role_name = v_role_name
  on conflict (role_id, permission_key) do nothing;

  return v_role_id;
end;
$$;


ALTER FUNCTION "public"."ensure_system_account_role"("p_account_id" "uuid", "p_role" "public"."account_role") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."finalize_document_request_upload"("p_document_id" "uuid", "p_size_bytes" integer, "p_mime_type" "text", "p_original_filename" "text" DEFAULT NULL::"text", "p_actor_user_id" "uuid" DEFAULT "auth"."uid"()) RETURNS "public"."documents"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor uuid := auth.uid();
  v_doc public.documents;
  v_upload public.document_request_uploads;
  v_request public.document_requests;
  v_safe_name text;
begin
  if v_actor is null then raise exception 'Not authenticated'; end if;
  if p_actor_user_id is not null and p_actor_user_id <> v_actor then raise exception 'Actor mismatch'; end if;

  select * into v_doc from public.documents where id = p_document_id;
  if not found then raise exception 'Document not found'; end if;

  select * into v_upload from public.document_request_uploads where document_id = p_document_id;
  if not found then raise exception 'Upload not found'; end if;

  select * into v_request from public.document_requests where id = v_upload.request_id;
  if not found then raise exception 'Request not found'; end if;

  if not public.is_document_request_target(v_request.id, v_actor) then raise exception 'Not permitted'; end if;

  v_safe_name := coalesce(nullif(trim(p_original_filename), ''), v_doc.name);
  v_safe_name := replace(v_safe_name, '/', '_');
  v_safe_name := replace(v_safe_name, '\', '_');

  update public.documents
  set upload_status = 'uploaded',
      uploaded_at = now(),
      size_bytes = p_size_bytes,
      mime_type = p_mime_type,
      original_filename = coalesce(original_filename, v_safe_name),
      name = v_safe_name,
      uploaded_by = v_actor,
      uploaded_by_user_id = v_actor,
      uploaded_by_role = v_request.target_role,
      review_status = 'pending_review',
      updated_at = now()
  where id = p_document_id
  returning * into v_doc;

  update public.document_request_uploads
  set file_name = v_safe_name,
      mime_type = p_mime_type,
      size_bytes = p_size_bytes,
      review_status = 'pending_review'
  where id = v_upload.id;

  insert into public.document_audit_log (
    document_id,
    action,
    performed_by,
    performed_at,
    account_id,
    property_id,
    tenant_id,
    created_at
  )
  values (
    v_doc.id,
    'upload',
    v_actor,
    now(),
    v_doc.account_id,
    v_doc.property_id,
    v_doc.tenant_id,
    now()
  );

  return v_doc;
end;
$$;


ALTER FUNCTION "public"."finalize_document_request_upload"("p_document_id" "uuid", "p_size_bytes" integer, "p_mime_type" "text", "p_original_filename" "text", "p_actor_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."finalize_document_template_upload"("p_template_id" "uuid", "p_size_bytes" integer, "p_mime_type" "text", "p_actor_user_id" "uuid" DEFAULT "auth"."uid"()) RETURNS "public"."document_templates"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_template public.document_templates;
  v_actor uuid := auth.uid();
begin
  if v_actor is null then
    raise exception 'Not authenticated';
  end if;

  if p_actor_user_id is not null and p_actor_user_id <> v_actor then
    raise exception 'Actor mismatch';
  end if;

  select * into v_template
  from public.document_templates
  where id = p_template_id;

  if not found then
    raise exception 'Template not found';
  end if;

  if not public.can_manage_document_templates(v_template.account_id, v_actor) then
    raise exception 'Not permitted';
  end if;

  if p_size_bytes is null or p_size_bytes <= 0 or p_size_bytes > 10485760 then
    raise exception 'Invalid file size';
  end if;

  update public.document_templates
  set upload_status = 'uploaded',
      status = 'active',
      size_bytes = p_size_bytes,
      mime_type = p_mime_type,
      uploaded_by = v_actor,
      uploaded_at = now(),
      updated_at = now()
  where id = p_template_id
  returning * into v_template;

  return v_template;
end;
$$;


ALTER FUNCTION "public"."finalize_document_template_upload"("p_template_id" "uuid", "p_size_bytes" integer, "p_mime_type" "text", "p_actor_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."finalize_document_upload"("p_document_id" "uuid", "p_size_bytes" integer, "p_mime_type" "text", "p_original_filename" "text" DEFAULT NULL::"text", "p_tags" "public"."document_tag"[] DEFAULT NULL::"public"."document_tag"[], "p_actor_user_id" "uuid" DEFAULT "auth"."uid"()) RETURNS "public"."documents"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_doc public.documents;
  v_role text;
  v_safe_name text;
begin
  if p_document_id is null then
    raise exception 'document_id is required';
  end if;

  if p_actor_user_id is null then
    raise exception 'Not authenticated: actor_user_id is required';
  end if;

  select * into v_doc
  from public.documents
  where id = p_document_id;

  if not found then
    raise exception 'Document not found';
  end if;

  v_role := public.account_role_for(v_doc.account_id);
  if coalesce(v_role, '') not in ('owner','admin','staff') then
    raise exception 'Not permitted';
  end if;

  if p_size_bytes is null or p_size_bytes <= 0 then
    raise exception 'size_bytes must be > 0';
  end if;

  if p_size_bytes > 10485760 then
    raise exception 'File too large (max 10MB)';
  end if;

  if p_mime_type not in (
    'application/pdf',
    'image/jpeg',
    'image/png',
    'image/webp',
    'application/msword',
    'application/vnd.openxmlformats-officedocument.wordprocessingml.document'
  ) then
    raise exception 'Invalid mime_type: %', p_mime_type;
  end if;

  v_safe_name := coalesce(nullif(trim(p_original_filename), ''), v_doc.name);
  v_safe_name := replace(v_safe_name, '/', '_');
  v_safe_name := replace(v_safe_name, '\', '_');

  update public.documents
  set upload_status = 'uploaded',
      uploaded_at = now(),
      size_bytes = p_size_bytes,
      mime_type = p_mime_type,
      original_filename = coalesce(original_filename, v_safe_name),
      name = v_safe_name,
      tags = coalesce(p_tags, tags),
      uploaded_by = coalesce(uploaded_by, p_actor_user_id),
      created_by_user_id = coalesce(created_by_user_id, p_actor_user_id),
      updated_at = now()
  where id = p_document_id
  returning * into v_doc;

  insert into public.document_audit_log (
    document_id,
    action,
    performed_by,
    performed_at,
    account_id,
    property_id,
    tenant_id,
    created_at
  )
  values (
    v_doc.id,
    'upload',
    p_actor_user_id,
    now(),
    v_doc.account_id,
    v_doc.property_id,
    v_doc.tenant_id,
    now()
  );

  return v_doc;
end;
$$;


ALTER FUNCTION "public"."finalize_document_upload"("p_document_id" "uuid", "p_size_bytes" integer, "p_mime_type" "text", "p_original_filename" "text", "p_tags" "public"."document_tag"[], "p_actor_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."finance_snapshot"("p_account_id" "uuid", "p_tenant_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("total_income" numeric, "overdue_income" numeric, "due_soon_income" numeric, "outstanding_income" numeric, "property_finance" "jsonb", "account_currency" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_tenant_id      uuid;
  v_account_currency text;
begin
  v_tenant_id := public.assert_tenant_scope_access(p_account_id, p_tenant_id);

  -- Resolve the account's configured currency (falls back to 'PLN' for legacy rows)
  select coalesce(a.currency, 'PLN') into v_account_currency
  from public.accounts a
  where a.id = p_account_id;

  return query
  with tenant_scope as (
    select t.property_id
    from public.tenants t
    where t.id = v_tenant_id
      and t.account_id = p_account_id
    limit 1
  ),
  scoped_properties as (
    select
      pr.id,
      pr.address,
      pr.city,
      pr.tenant_id,
      coalesce(pr.rent, 0) as rent
    from properties pr
    where pr.account_id = p_account_id
      and (
        v_tenant_id is null
        or pr.id = (select property_id from tenant_scope)
      )
  ),
  property_occupancy as (
    select
      sp.id as property_id,
      (
        sp.tenant_id is not null
        or exists (
          select 1
          from public.tenants t
          where t.account_id = p_account_id
            and t.property_id = sp.id
            and t.archived_at is null
        )
      ) as has_assigned_tenant
    from scoped_properties sp
  ),
  scoped_payments as (
    select
      p.id,
      p.property_id,
      p.tenant_id,
      coalesce(p.amount, 0) as amount,
      lower(coalesce(p.status, '')) as status_norm,
      p.paid_at,
      p.due_date
    from payments p
    where p.account_id = p_account_id
      and (
        v_tenant_id is null
        or p.tenant_id = v_tenant_id
      )
  ),
  payment_rows as (
    select
      sp.id,
      sp.property_id,
      sp.tenant_id,
      sp.amount,
      sp.status_norm,
      sp.paid_at,
      sp.due_date,
      (
        sp.paid_at is not null
        or sp.status_norm in ('paid', 'oplacone', 'opłacone')
      ) as is_paid,
      date_trunc(
        'month',
        coalesce(sp.due_date::timestamp, sp.paid_at::timestamp, current_date::timestamp)
      ) as cycle_month
    from scoped_payments sp
  ),
  payment_cycles as (
    select
      prx.property_id,
      prx.tenant_id,
      prx.cycle_month,
      -- A-2: billed_amount = contractual rent only, never inflated by payment amounts
      coalesce(max(pr.rent), 0) as billed_amount,
      coalesce(
        sum(
          case
            when prx.is_paid then prx.amount else 0
          end
        ),
        0
      ) as paid_amount,
      min(
        case
          when not prx.is_paid then prx.due_date
          else null
        end
      ) as open_due_date,
      coalesce(
        bool_or(
          not prx.is_paid
          and (
            prx.status_norm in ('overdue', 'zalegle', 'zaległe')
            or (prx.due_date is not null and prx.due_date < current_date)
          )
        ),
        false
      ) as has_overdue
    from payment_rows prx
    left join scoped_properties pr
      on pr.id = prx.property_id
    group by prx.property_id, prx.tenant_id, prx.cycle_month
  ),
  finance_totals as (
    select
      -- A-4: total_income = cash received in the current calendar month (MTD),
      -- computed from paid_at dates rather than cycle_month so late payments
      -- are attributed to when money was actually received.
      coalesce((
        select sum(pr2.amount)
        from payment_rows pr2
        where pr2.is_paid
          and pr2.paid_at is not null
          and pr2.paid_at >= date_trunc('month', current_date)::date
          and pr2.paid_at <= current_date
      ), 0) as total_income,
      coalesce(
        sum(
          case
            when greatest(pc.billed_amount - pc.paid_amount, 0) > 0
             and pc.has_overdue
            then greatest(pc.billed_amount - pc.paid_amount, 0)
            else 0
          end
        ),
        0
      ) as overdue_income,
      coalesce(
        sum(
          case
            when greatest(pc.billed_amount - pc.paid_amount, 0) > 0
             and pc.open_due_date is not null
             and pc.open_due_date >= current_date
             and pc.open_due_date <= current_date + interval '7 days'
            then greatest(pc.billed_amount - pc.paid_amount, 0)
            else 0
          end
        ),
        0
      ) as due_soon_income,
      coalesce(
        sum(greatest(pc.billed_amount - pc.paid_amount, 0)),
        0
      ) as outstanding_income
    from payment_cycles pc
  ),
  property_rows as (
    select
      pr.id as property_id,
      pr.address,
      pr.city,
      pr.rent,
      po.has_assigned_tenant,
      coalesce(bool_or(pc.property_id is not null), false) as has_payment_cycle,
      coalesce(
        sum(
          case
            when pc.cycle_month = date_trunc('month', current_date::timestamp)
            then pc.paid_amount
            else 0
          end
        ),
        0
      ) as paid,
      case
        when po.has_assigned_tenant or coalesce(bool_or(pc.property_id is not null), false) then
          greatest(
            pr.rent - coalesce(
              sum(
                case
                  when pc.cycle_month = date_trunc('month', current_date::timestamp)
                  then pc.paid_amount
                  else 0
                end
              ),
              0
            ),
            0
          )
        else 0
      end as remaining,
      case
        when po.has_assigned_tenant or coalesce(bool_or(pc.property_id is not null), false) then
          coalesce(
            bool_or(
              greatest(pc.billed_amount - pc.paid_amount, 0) > 0
              and pc.has_overdue
            ),
            false
          )
        else false
      end as has_overdue_balance
    from scoped_properties pr
    join property_occupancy po
      on po.property_id = pr.id
    left join payment_cycles pc
      on pc.property_id = pr.id
    group by pr.id, pr.address, pr.city, pr.rent, po.has_assigned_tenant
  ),
  property_status_rows as (
    select
      property_id,
      address,
      city,
      rent,
      paid,
      remaining,
      case
        when not has_assigned_tenant and not has_payment_cycle then 'vacant'
        when remaining <= 0 then 'paid'
        when has_overdue_balance then 'overdue'
        when paid > 0 then 'partial'
        else 'pending'
      end as payment_status
    from property_rows
  ),
  property_json as (
    select coalesce(
      jsonb_agg(
        jsonb_build_object(
          'propertyId', property_id,
          'address', address,
          'city', city,
          'rent', rent,
          'paid', paid,
          'remaining', remaining,
          'paymentStatus', payment_status
        )
        order by address
      ),
      '[]'::jsonb
    ) as property_finance
    from property_status_rows
  )
  select
    finance_totals.total_income,
    finance_totals.overdue_income,
    finance_totals.due_soon_income,
    finance_totals.outstanding_income,
    property_json.property_finance,
    v_account_currency
  from finance_totals, property_json;
end;
$$;


ALTER FUNCTION "public"."finance_snapshot"("p_account_id" "uuid", "p_tenant_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_documents_notify_uploaded"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_recipients uuid[];
  v_safe_recipients uuid[];
  v_title text;
  v_body text;
  v_uploader uuid;
  v_tenant_user uuid;
  v_name text;
  v_vars jsonb;
begin
  if new.upload_status is distinct from 'uploaded' then
    return new;
  end if;

  if tg_op = 'UPDATE' and old.upload_status = 'uploaded' then
    return new;
  end if;

  if new.account_id is null then
    return new;
  end if;

  v_name := coalesce(nullif(new.original_filename, ''), new.name, 'Dokument');
  v_uploader := coalesce(new.created_by_user_id, new.uploaded_by);

  if coalesce(new.visibility, '') = 'private' then
    if v_uploader is not null then
      v_recipients := array[v_uploader];
    else
      return new;
    end if;
  else
    select array_agg(am.user_id)
      into v_recipients
    from public.account_members am
    where am.account_id = new.account_id;
  end if;

  if coalesce(new.visibility, '') = 'tenant' and new.tenant_id is not null then
    select t.user_id
      into v_tenant_user
    from public.tenants t
    where t.id = new.tenant_id
      and t.account_id = new.account_id
    limit 1;

    if v_tenant_user is not null then
      if v_recipients is null then
        v_recipients := array[v_tenant_user];
      elsif not (v_tenant_user = any(v_recipients)) then
        v_recipients := v_recipients || v_tenant_user;
      end if;
    end if;
  end if;

  if v_recipients is null or array_length(v_recipients, 1) is null then
    return new;
  end if;

  select array_agg(distinct uid)
    into v_safe_recipients
  from unnest(v_recipients) as uid
  where uid is not null
    and (
      exists (
        select 1
        from public.account_members am
        where am.account_id = new.account_id
          and am.user_id = uid
      )
      or exists (
        select 1
        from public.tenants t
        where t.account_id = new.account_id
          and t.user_id = uid
          and coalesce(t.status, '') <> 'archived'
      )
      or exists (
        select 1
        from public.contractors c
        where c.account_id = new.account_id
          and c.user_id = uid
          and coalesce(c.active, false) = true
      )
    );

  if v_safe_recipients is null or array_length(v_safe_recipients, 1) is null then
    return new;
  end if;

  v_vars := jsonb_build_object(
    'name', v_name,
    'document_id', new.id,
    'property_id', new.property_id,
    'tenant_id', new.tenant_id,
    'scope', new.scope,
    'visibility', new.visibility
  );

  select t.title, t.body
    into v_title, v_body
  from public.get_notification_text(new.account_id, 'document_uploaded', v_vars) t;

  perform public.create_notifications_system(
    new.account_id,
    v_safe_recipients,
    'document_uploaded',
    v_title,
    v_body,
    'document',
    new.id,
    '/documents?doc=' || new.id::text,
    v_vars
  );

  return new;
end;
$$;


ALTER FUNCTION "public"."fn_documents_notify_uploaded"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_account_ai_usage_summary"("p_account_id" "uuid", "p_period" "text") RETURNS TABLE("period_key" "text", "plan" "text", "monthly_limit" integer, "total_prompt_runs" bigint, "total_input_tokens" bigint, "total_output_tokens" bigint, "total_estimated_cost" numeric, "feature_key" "text", "feature_prompt_runs" bigint, "feature_input_tokens" bigint, "feature_output_tokens" bigint, "feature_cost" numeric)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
declare
  v_account_id uuid := public.assert_manage_account_access(p_account_id);
  v_period     text := lower(trim(coalesce(p_period, to_char(now(), 'YYYY-MM'))));
  v_plan       text;
  v_limit      integer;
begin
  -- Validate period format: must be YYYY-MM
  if v_period !~ '^\d{4}-\d{2}$' then
    raise exception 'p_period must be in YYYY-MM format, got: %', p_period;
  end if;

  v_plan  := public.account_subscription_plan(v_account_id);
  v_limit := public.ai_monthly_call_limit_for_plan(v_plan);

  return query
  with monthly_rows as (
    select
      m.feature_key,
      sum(m.prompt_runs)       as feat_runs,
      sum(m.input_tokens)      as feat_input,
      sum(m.output_tokens)     as feat_output,
      sum(m.estimated_cost)    as feat_cost
    from public.ai_usage_meter m
    where m.account_id = v_account_id
      -- daily rows only (YYYY-MM-DD); YYYY-MM-__ excludes legacy YYYY-MM aggregates
      and m.period_key like v_period || '-__'
    group by m.feature_key
  ),
  -- totals is a plain aggregate — always returns exactly one row even when
  -- monthly_rows is empty, which means this query always returns at least
  -- one row so callers can read the correct plan and limit for zero-usage months.
  totals as (
    select
      coalesce(sum(feat_runs),   0) as tot_runs,
      coalesce(sum(feat_input),  0) as tot_input,
      coalesce(sum(feat_output), 0) as tot_output,
      coalesce(sum(feat_cost),   0) as tot_cost
    from monthly_rows
  ),
  -- feature_or_sentinel: when there is no usage data, emit a single null-
  -- feature row so the CROSS JOIN with totals still produces output.
  feature_or_sentinel as (
    select mr.feature_key, mr.feat_runs, mr.feat_input, mr.feat_output, mr.feat_cost
    from monthly_rows mr
    union all
    select null::text, 0, 0, 0, 0::numeric
    where not exists (select 1 from monthly_rows)
  )
  select
    v_period                                    as period_key,
    v_plan                                      as plan,
    v_limit                                     as monthly_limit,
    t.tot_runs::bigint                          as total_prompt_runs,
    t.tot_input::bigint                         as total_input_tokens,
    t.tot_output::bigint                        as total_output_tokens,
    t.tot_cost                                  as total_estimated_cost,
    f.feature_key,
    f.feat_runs::bigint                         as feature_prompt_runs,
    f.feat_input::bigint                        as feature_input_tokens,
    f.feat_output::bigint                       as feature_output_tokens,
    f.feat_cost                                 as feature_cost
  from feature_or_sentinel f
  cross join totals t
  order by f.feat_runs desc nulls last;
end;
$_$;


ALTER FUNCTION "public"."get_account_ai_usage_summary"("p_account_id" "uuid", "p_period" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."get_account_ai_usage_summary"("p_account_id" "uuid", "p_period" "text") IS 'Returns per-feature and aggregate AI usage for an account in a calendar month (p_period = YYYY-MM). Requires manage role. Always returns at least one row (with null feature_key) so callers get correct plan/limit for zero-usage months. Sums daily rows only (period_key YYYY-MM-DD); monthly total is account-wide.';



CREATE OR REPLACE FUNCTION "public"."get_account_owner_contact"("p_account_id" "uuid") RETURNS TABLE("owner_user_id" "uuid", "owner_email" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_uid uuid := auth.uid();
  v_has_direct_access boolean := false;
  v_is_root_operator boolean := false;
begin
  if v_uid is null then
    raise exception 'Not authenticated';
  end if;

  select exists (
    select 1
    from public.account_members am
    where am.account_id = p_account_id
      and am.user_id = v_uid
  )
  into v_has_direct_access;

  select exists (
    select 1
    from public.account_members am
    join public.accounts a on a.id = am.account_id
    where am.user_id = v_uid
      and coalesce(a.is_root, false) = true
  )
  into v_is_root_operator;

  if not v_has_direct_access and not v_is_root_operator then
    raise exception 'Access denied';
  end if;

  return query
  with owner_member as (
    select
      am.user_id as owner_user_id,
      lower(u.email::text) as owner_email
    from public.account_members am
    join auth.users u on u.id = am.user_id
    where am.account_id = p_account_id
      and public.account_member_effective_role(am.account_id, am.user_id) = 'owner'
    order by am.user_id
    limit 1
  ),
  owner_creator as (
    select
      a.created_by as owner_user_id,
      lower(u.email::text) as owner_email
    from public.accounts a
    join auth.users u on u.id = a.created_by
    where a.id = p_account_id
    limit 1
  )
  select *
  from owner_member
  union all
  select *
  from owner_creator
  where not exists (select 1 from owner_member)
  limit 1;
end;
$$;


ALTER FUNCTION "public"."get_account_owner_contact"("p_account_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_account_sandbox_status"("p_account_id" "uuid") RETURNS TABLE("account_id" "uuid", "mode" "text", "lifecycle_status" "text", "seeded_fixture_version" "text", "demo_expires_at" timestamp with time zone, "reset_requested_at" timestamp with time zone, "reset_completed_at" timestamp with time zone, "is_demo" boolean, "reset_pending" boolean)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  perform public.assert_manage_account_access(p_account_id);

  if not exists (select 1 from public.accounts a where a.id = p_account_id) then
    raise exception 'Account not found';
  end if;

  return query
  select
    p_account_id,
    coalesce(asp.mode, 'production') as mode,
    coalesce(asp.lifecycle_status, 'active') as lifecycle_status,
    asp.seeded_fixture_version,
    asp.demo_expires_at,
    asp.reset_requested_at,
    asp.reset_completed_at,
    coalesce(asp.mode, 'production') = 'demo' as is_demo,
    coalesce(asp.lifecycle_status, 'active') in ('reset_requested', 'resetting') as reset_pending
  from (select p_account_id as account_id) scope
  left join public.account_sandbox_profiles asp on asp.account_id = scope.account_id;
end;
$$;


ALTER FUNCTION "public"."get_account_sandbox_status"("p_account_id" "uuid") OWNER TO "postgres";


