CREATE TABLE IF NOT EXISTS "public"."document_extractions" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "account_id" "uuid" NOT NULL,
    "document_id" "uuid" NOT NULL,
    "extractor" "text" NOT NULL,
    "language_hint" "text",
    "status" "text" DEFAULT 'pending'::"text" NOT NULL,
    "text_content" "text",
    "markdown_content" "text",
    "structured_payload" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "confidence_score" numeric(5,4),
    "source_hash" "text" NOT NULL,
    "page_count" integer,
    "character_count" integer,
    "error_message" "text",
    "created_by" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "completed_at" timestamp with time zone,
    CONSTRAINT "document_extractions_extractor_check" CHECK (("extractor" = ANY (ARRAY['native_pdf'::"text", 'docling'::"text", 'ocrmypdf_tesseract'::"text", 'paddleocr'::"text", 'olmocr'::"text", 'manual'::"text"]))),
    CONSTRAINT "document_extractions_status_check" CHECK (("status" = ANY (ARRAY['pending'::"text", 'processing'::"text", 'completed'::"text", 'failed'::"text", 'stale'::"text"])))
);


ALTER TABLE "public"."document_extractions" OWNER TO "postgres";


COMMENT ON TABLE "public"."document_extractions" IS 'Extracted text / markdown produced by the document extraction worker. Source material for AI features (Lease Auditor, document summaries, etc.). text_content and markdown_content are NEVER exposed to tenant/contractor roles — the RLS policy (user_can_manage_account) enforces this. Populated by scripts/documentExtraction/worker.js, not by the React frontend.';



COMMENT ON COLUMN "public"."document_extractions"."structured_payload" IS 'Extractor-specific metadata: quality_flag, recommended_extractor, page_breakdown, language_detected, word_count, etc.';



COMMENT ON COLUMN "public"."document_extractions"."source_hash" IS 'SHA-256 hex digest of the raw file bytes at time of extraction. Uniqueness constraint on (account_id, document_id, extractor, source_hash) ensures a changed document triggers a new row rather than overwriting.';



CREATE OR REPLACE FUNCTION "public"."get_document_extraction"("p_account_id" "uuid", "p_document_id" "uuid", "p_extractor" "text" DEFAULT NULL::"text") RETURNS SETOF "public"."document_extractions"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_account_id uuid := public.assert_manage_account_access(p_account_id);
begin
  perform public.assert_account_feature_access(v_account_id, 'document_extraction');

  if not exists (
    select 1 from public.documents
    where id = p_document_id
      and account_id = v_account_id
  ) then
    raise exception 'Document not found';
  end if;

  return query
  select * from public.document_extractions
  where account_id  = v_account_id
    and document_id = p_document_id
    and (p_extractor is null or extractor = p_extractor)
  order by
    case status
      when 'completed'  then 1
      when 'processing' then 2
      when 'pending'    then 3
      when 'stale'      then 4
      else                   5
    end asc,
    created_at desc
  limit 1;
end;
$$;


ALTER FUNCTION "public"."get_document_extraction"("p_account_id" "uuid", "p_document_id" "uuid", "p_extractor" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."get_document_extraction"("p_account_id" "uuid", "p_document_id" "uuid", "p_extractor" "text") IS 'Read-only: returns the best available extraction for a document. Priority: completed > processing > pending > stale > failed. Does not log extraction_viewed — call log_document_extraction_viewed separately when the user explicitly opens the text preview.';



CREATE OR REPLACE FUNCTION "public"."get_finance_summary"("p_account_id" "uuid") RETURNS TABLE("total_in" numeric, "total_out" numeric, "net" numeric, "payments_in" numeric)
    LANGUAGE "sql" STABLE
    AS $$
  select
    coalesce(sum(case when direction = 'in'  then amount end), 0)::numeric as total_in,
    coalesce(sum(case when direction = 'out' then amount end), 0)::numeric as total_out,
    coalesce(sum(case when direction = 'in'  then amount else -amount end), 0)::numeric as net,
    coalesce(sum(case when entry_type='payment' and direction='in' then amount end), 0)::numeric as payments_in
  from public.ledger_entries
  where account_id = p_account_id;
$$;


