CREATE OR REPLACE FUNCTION "public"."get_my_lease"("p_account_id" "uuid") RETURNS TABLE("id" "uuid", "account_id" "uuid", "property_id" "uuid", "tenant_id" "uuid", "lease_start_date" "date", "lease_end_date" "date", "renewal_status" "text", "notice_period_days" integer, "auto_renew" boolean, "notes" "text", "created_at" timestamp with time zone, "updated_at" timestamp with time zone, "property_address" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select
    l.id,
    l.account_id,
    l.property_id,
    l.tenant_id,
    l.lease_start_date,
    l.lease_end_date,
    lower(coalesce(l.renewal_status, 'active')) as renewal_status,
    coalesce(l.notice_period_days, 30) as notice_period_days,
    coalesce(l.auto_renew, false) as auto_renew,
    l.notes,
    l.created_at,
    l.updated_at,
    coalesce(p.address, '') as property_address
  from public.leases l
  join public.tenants t
    on t.id = l.tenant_id
   and t.user_id = auth.uid()
   and t.account_id = p_account_id
  left join public.properties p
    on p.id = l.property_id
  where l.account_id = p_account_id
  order by
    case lower(coalesce(l.renewal_status, 'active'))
      when 'renewal_in_progress' then 1
      when 'active' then 2
      when 'expiring_soon' then 3
      when 'renewed' then 4
      when 'ended' then 5
      else 6
    end,
    l.lease_end_date desc nulls last
  limit 1;
$$;


ALTER FUNCTION "public"."get_my_lease"("p_account_id" "uuid") OWNER TO "postgres";


