    p.id as payment_id,
    p.property_id,
    p.amount,
    p.status,
    p.due_date,
    p.paid_at,
    p.created_at
  from public.payments p
  join public.tenants t
    on t.id = p.tenant_id
   and t.account_id = p.account_id
  where p.account_id = p_account_id
    and t.user_id = auth.uid()
    and t.archived_at is null
  order by
    (case when p.paid_at is null then 0 else 1 end),
    p.due_date nulls last,
    p.created_at desc;
$$;


