CREATE OR REPLACE FUNCTION "public"."get_work_order_fulfilment_route"("p_account_id" "uuid", "p_work_order_id" "uuid") RETURNS TABLE("account_id" "uuid", "work_order_id" "uuid", "route" "text", "updated_at" timestamp with time zone, "is_persisted" boolean)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_account_id uuid;
begin
  v_account_id := public.assert_manage_account_access(p_account_id);

  if not exists (
    select 1
    from public.work_orders wo
    where wo.id = p_work_order_id
      and wo.account_id = v_account_id
  ) then
    raise exception 'Work order not found' using errcode = 'P0002';
  end if;

  if exists (
    select 1
    from public.work_order_fulfilment_routes r
    where r.work_order_id = p_work_order_id
      and r.account_id = v_account_id
  ) then
    return query
    select
      r.account_id,
      r.work_order_id,
      r.route,
      r.updated_at,
      true as is_persisted
    from public.work_order_fulfilment_routes r
    where r.work_order_id = p_work_order_id
      and r.account_id = v_account_id;
    return;
  end if;

  return query
  select
    v_account_id,
    p_work_order_id,
    'internal'::text,
    null::timestamptz,
    false as is_persisted;
end;
$$;


ALTER FUNCTION "public"."get_work_order_fulfilment_route"("p_account_id" "uuid", "p_work_order_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."handle_new_user"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
begin
  begin
    insert into public.profiles (id, role)
    values (new.id, 'staff')
    on conflict (id) do nothing;
  exception
    when others then
      -- Profile bootstrap should never block auth signup.
      -- The account can still self-provision on first app login, and support can backfill profiles if needed.
      null;
  end;

  return new;
end;
$$;


