CREATE OR REPLACE FUNCTION "public"."import_document_packet_signed_document"("p_packet_id" "uuid", "p_storage_path" "text", "p_filename" "text", "p_size_bytes" integer, "p_mime_type" "text" DEFAULT 'application/pdf'::"text") RETURNS "public"."documents"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_packet public.document_packets;
  v_document public.documents;
  v_scope text;
  v_visibility text;
  v_actor uuid;
  v_name text;
begin
  if coalesce(auth.role(), '') <> 'service_role' then raise exception 'Not permitted'; end if;
  if p_packet_id is null then raise exception 'packet_id is required'; end if;
  if nullif(trim(coalesce(p_storage_path, '')), '') is null then raise exception 'storage_path is required'; end if;
  if nullif(trim(coalesce(p_filename, '')), '') is null then raise exception 'filename is required'; end if;
  if coalesce(p_size_bytes, 0) <= 0 then raise exception 'size_bytes must be > 0'; end if;
  if p_mime_type not in (
    'application/pdf',
    'image/jpeg',
    'image/png',
    'image/webp',
    'application/msword',
    'application/vnd.openxmlformats-officedocument.wordprocessingml.document'
  ) then
    raise exception 'Invalid mime_type: %', p_mime_type;
  end if;

  select * into v_packet
  from public.document_packets
  where id = p_packet_id;
  if not found then raise exception 'Packet not found'; end if;

  v_name := replace(replace(trim(p_filename), '/', '_'), '\', '_');
  v_actor := coalesce(v_packet.sent_by, v_packet.created_by);

  if v_packet.tenant_id is not null and v_packet.property_id is not null then
    v_scope := 'shared';
    v_visibility := 'tenant';
  elsif v_packet.tenant_id is not null then
    v_scope := 'tenant';
    v_visibility := 'tenant';
  elsif v_packet.property_id is not null then
    v_scope := 'property';
    v_visibility := 'staff';
  else
    v_scope := 'account';
    v_visibility := 'staff';
  end if;

  insert into public.documents (
    account_id,
    property_id,
    tenant_id,
    name,
    original_filename,
    storage_path,
    mime_type,
    size_bytes,
    scope,
    visibility,
    created_via,
    created_by_user_id,
    uploaded_by,
    upload_status,
    uploaded_at,
    source,
    review_status,
    tags
  )
  values (
    v_packet.account_id,
    v_packet.property_id,
    v_packet.tenant_id,
    v_name,
    v_name,
    trim(p_storage_path),
    p_mime_type,
    p_size_bytes,
    v_scope,
    v_visibility,
    'signature_provider',
    v_actor,
    v_actor,
    'uploaded',
    now(),
    'signature_completed',
    'accepted',
    '{}'::public.document_tag[]
  )
  returning * into v_document;

  insert into public.document_audit_log (
    document_id,
    action,
    performed_by,
    performed_at,
    account_id,
    property_id,
    tenant_id,
    created_at
  )
  values (
    v_document.id,
    'upload',
    v_actor,
    now(),
    v_document.account_id,
    v_document.property_id,
    v_document.tenant_id,
    now()
  );

  return v_document;
end;
$$;


ALTER FUNCTION "public"."import_document_packet_signed_document"("p_packet_id" "uuid", "p_storage_path" "text", "p_filename" "text", "p_size_bytes" integer, "p_mime_type" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."increment_ai_usage_meter"("p_account_id" "uuid", "p_feature_key" "text", "p_period_key" "text", "p_prompt_runs" integer DEFAULT 0, "p_input_tokens" bigint DEFAULT 0, "p_output_tokens" bigint DEFAULT 0) RETURNS "void"
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  insert into public.ai_usage_meter (
    account_id,
    feature_key,
    period_key,
    prompt_runs,
    input_tokens,
    output_tokens,
    estimated_cost
  )
  values (
    p_account_id,
    p_feature_key,
    p_period_key,
    p_prompt_runs,
    p_input_tokens,
    p_output_tokens,
    round(
      (p_input_tokens::numeric  / 1000000) * 0.4 +
      (p_output_tokens::numeric / 1000000) * 1.6,
      6
    )
  )
  on conflict (account_id, feature_key, period_key) do update
    set
      prompt_runs    = ai_usage_meter.prompt_runs    + excluded.prompt_runs,
      input_tokens   = ai_usage_meter.input_tokens   + excluded.input_tokens,
      output_tokens  = ai_usage_meter.output_tokens  + excluded.output_tokens,
      estimated_cost = round(
        ((ai_usage_meter.input_tokens  + excluded.input_tokens)::numeric  / 1000000) * 0.4 +
        ((ai_usage_meter.output_tokens + excluded.output_tokens)::numeric / 1000000) * 1.6,
        6
      );
$$;


ALTER FUNCTION "public"."increment_ai_usage_meter"("p_account_id" "uuid", "p_feature_key" "text", "p_period_key" "text", "p_prompt_runs" integer, "p_input_tokens" bigint, "p_output_tokens" bigint) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."increment_ai_usage_meter"("p_account_id" "uuid", "p_feature_key" "text", "p_period_key" "text", "p_prompt_runs" integer, "p_input_tokens" bigint, "p_output_tokens" bigint) IS 'Atomically adds to ai_usage_meter counters using ON CONFLICT DO UPDATE += excluded. Called by Edge Functions before the AI model call (prompt_runs=1, tokens=0) to pre-reserve the quota slot, then again after the call (prompt_runs=0, actual tokens) to record token usage. Both calls are atomic; there is no read-modify-write race.';



