CREATE OR REPLACE FUNCTION "public"."is_active_tenant_in_account"("p_account_id" "uuid") RETURNS boolean
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  select exists (
    select 1
    from public.tenants t
    where t.user_id = auth.uid()
      and t.account_id = p_account_id
      and t.archived_at is null
      and t.status = any (array['active'::text, 'accepted_pending_signing'::text])
  );
$$;


