CREATE OR REPLACE FUNCTION "public"."lease_attention_items"("p_account_id" "uuid", "p_limit" integer DEFAULT 10, "p_expiring_days" integer DEFAULT 60) RETURNS TABLE("item_key" "text", "item_type" "text", "property_label" "text", "tenant_label" "text", "lease_end_date" "date", "days_until_end" integer, "link_path" "text", "sort_order" integer)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with cfg as (
    select
      greatest(1, least(coalesce(p_limit, 10), 50)) as max_items,
      greatest(1, least(coalesce(p_expiring_days, 60), 365)) as expiring_days
  ),
  authz as (
    select public.assert_manage_account_access(p_account_id) as account_id
  ),
  scoped_leases as (
    select
      l.id,
      l.tenant_id,
      l.lease_end_date,
      lower(coalesce(l.renewal_status, 'active')) as renewal_status,
      coalesce(p.address, '—') as property_label,
      coalesce(t.name, '—') as tenant_label,
      (l.lease_end_date - current_date)::int as days_until_end
    from public.leases l
    cross join authz a
    left join public.properties p on p.id = l.property_id
    left join public.tenants t on t.id = l.tenant_id
    where l.account_id = a.account_id
  ),
  items as (
    select
      'lease-expired-' || sl.id::text as item_key,
      'lease_expired'::text as item_type,
      sl.property_label,
      sl.tenant_label,
      sl.lease_end_date,
      sl.days_until_end,
      ('/tenants/' || sl.tenant_id::text) as link_path,
      10 as sort_order
    from scoped_leases sl
    where sl.lease_end_date < current_date
      and sl.renewal_status not in ('renewed', 'ended')

    union all

    select
      'lease-expiring-' || sl.id::text as item_key,
      'lease_expiring_soon'::text as item_type,
      sl.property_label,
      sl.tenant_label,
      sl.lease_end_date,
      sl.days_until_end,
      ('/tenants/' || sl.tenant_id::text) as link_path,
      20 as sort_order
    from scoped_leases sl
    where sl.lease_end_date >= current_date
      and sl.lease_end_date <= current_date + (select expiring_days from cfg)
      and sl.renewal_status not in ('renewed', 'ended')

    union all

    select
      'lease-renewal-' || sl.id::text as item_key,
      'lease_renewal_in_progress'::text as item_type,
      sl.property_label,
      sl.tenant_label,
      sl.lease_end_date,
      sl.days_until_end,
      ('/tenants/' || sl.tenant_id::text) as link_path,
      30 as sort_order
    from scoped_leases sl
    where sl.renewal_status = 'renewal_in_progress'
  )
  select
    i.item_key,
    i.item_type,
    i.property_label,
    i.tenant_label,
    i.lease_end_date,
    i.days_until_end,
    i.link_path,
    i.sort_order
  from items i
  order by 8, 5 asc nulls last, 1
  limit (select max_items from cfg);
$$;


ALTER FUNCTION "public"."lease_attention_items"("p_account_id" "uuid", "p_limit" integer, "p_expiring_days" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."link_pet_request_document"("p_request_id" "uuid", "p_account_id" "uuid", "p_document_id" "uuid") RETURNS "public"."pet_requests"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_uid uuid := auth.uid();
  v_row public.pet_requests;
begin
  if v_uid is null then raise exception 'Not authenticated'; end if;
  perform public.assert_account_feature_access(p_account_id, 'renters_rights_readiness');
  if not public.is_account_manager(p_account_id, v_uid) then
    raise exception 'Access denied';
  end if;

  if p_document_id is null then
    raise exception 'Document ID is required';
  end if;

  update public.pet_requests
  set
    insurance_document_id = p_document_id,
    updated_at            = now()
  where id = p_request_id and account_id = p_account_id
  returning * into v_row;

  if v_row.id is null then
    raise exception 'Pet request not found';
  end if;

  perform public.log_security_event(
    p_account_id, 'pet_request_document_linked', 'pet_request', p_request_id,
    jsonb_build_object('document_id', p_document_id)
  );

  return v_row;
end;
$$;


ALTER FUNCTION "public"."link_pet_request_document"("p_request_id" "uuid", "p_account_id" "uuid", "p_document_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."list_account_members_for_role_assignment"("p_account_id" "uuid") RETURNS TABLE("user_id" "uuid", "email" "text", "legacy_role" "public"."account_role", "role_id" "uuid", "role_name" "text")
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public', 'auth'
    AS $$
  select
    am.user_id,
    lower(coalesce(u.email, '')) as email,
    am.role as legacy_role,
    am.role_id,
    r.name as role_name
  from public.account_members am
  left join auth.users u
    on u.id = am.user_id
  left join public.roles r
    on r.id = am.role_id
  where am.account_id = public.assert_manage_account_access(p_account_id)
  order by lower(coalesce(u.email, '')), am.user_id;
$$;


ALTER FUNCTION "public"."list_account_members_for_role_assignment"("p_account_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."list_account_password_security"("p_account_id" "uuid") RETURNS TABLE("user_id" "uuid", "email" "text", "display_name" "text", "role" "text", "password_policy_version" integer, "password_strength_status" "text", "password_last_set_at" timestamp with time zone, "mfa_enrolled" boolean)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  if not public.is_account_manager(p_account_id) then
    raise exception 'Access denied';
  end if;

  return query
  select
    am.user_id,
    au.email::text,
    coalesce(
      nullif(trim(au.raw_user_meta_data->>'full_name'), ''),
      au.email
    )::text                                              as display_name,
    coalesce(am.role, 'staff')::text                   as role,
    coalesce(usp.password_policy_version, 0)           as password_policy_version,
    coalesce(usp.password_strength_status, 'unknown')  as password_strength_status,
    usp.password_last_set_at,
    coalesce(usp.mfa_enrolled, false)                  as mfa_enrolled
  from public.account_members am
  join auth.users au on au.id = am.user_id
  left join public.user_security_profile usp on usp.user_id = am.user_id
  where am.account_id = p_account_id
  order by
    -- worst status first so the top of the list needs attention
    case coalesce(usp.password_strength_status, 'unknown')
      when 'reset_required' then 0
      when 'legacy_weak'    then 1
      when 'unknown'        then 2
      else                       3
    end,
    au.email;
end;
$$;


ALTER FUNCTION "public"."list_account_password_security"("p_account_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."list_account_roles"("p_account_id" "uuid") RETURNS TABLE("role_id" "uuid", "name" "text", "permission_keys" "text"[], "member_count" bigint, "is_system" boolean)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with scoped_roles as (
    select r.id, r.name
    from public.roles r
    where r.account_id = public.assert_manage_account_access(p_account_id)
  )
  select
    r.id as role_id,
    r.name,
    coalesce(
      array_agg(distinct lower(trim(rp.permission_key)) order by lower(trim(rp.permission_key)))
        filter (where rp.permission_key is not null),
      array[]::text[]
    ) as permission_keys,
    count(distinct am.user_id)::bigint as member_count,
    lower(trim(r.name)) in ('owner', 'admin', 'staff') as is_system
  from scoped_roles r
  left join public.role_permissions rp
    on rp.role_id = r.id
  left join public.account_members am
    on am.account_id = p_account_id
   and am.role_id = r.id
  group by r.id, r.name
  order by lower(trim(r.name));
$$;


ALTER FUNCTION "public"."list_account_roles"("p_account_id" "uuid") OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."document_extraction_runs" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "account_id" "uuid" NOT NULL,
    "document_id" "uuid" NOT NULL,
    "extraction_id" "uuid",
    "extractor" "text" NOT NULL,
    "status" "text" DEFAULT 'queued'::"text" NOT NULL,
    "started_at" timestamp with time zone,
    "completed_at" timestamp with time zone,
    "error_message" "text",
    "metadata" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "created_by" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "document_extraction_runs_status_check" CHECK (("status" = ANY (ARRAY['queued'::"text", 'processing'::"text", 'completed'::"text", 'failed'::"text", 'skipped'::"text"])))
);


ALTER TABLE "public"."document_extraction_runs" OWNER TO "postgres";


COMMENT ON TABLE "public"."document_extraction_runs" IS 'Append-only log of extraction attempts. Queued rows are polled and processed by the document extraction worker. status=queued → processing → completed | failed | skipped. The worker uses the service_role key to update this table.';



COMMENT ON COLUMN "public"."document_extraction_runs"."extractor" IS 'Requested extractor (may be ''auto'' when the router decides at runtime). Resolved extractor is stored in document_extractions.extractor.';



COMMENT ON COLUMN "public"."document_extraction_runs"."metadata" IS 'Worker-populated metadata: source_hash, actual_extractor_used, pdf_page_count, ocr_available, quality_flag, etc.';



CREATE OR REPLACE FUNCTION "public"."list_document_extraction_runs"("p_account_id" "uuid", "p_document_id" "uuid" DEFAULT NULL::"uuid", "p_status" "text" DEFAULT NULL::"text", "p_limit" integer DEFAULT 50, "p_offset" integer DEFAULT 0) RETURNS SETOF "public"."document_extraction_runs"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_account_id uuid := public.assert_manage_account_access(p_account_id);
begin
  perform public.assert_account_feature_access(v_account_id, 'document_extraction');
  return query
  select * from public.document_extraction_runs
  where account_id = v_account_id
    and (p_document_id is null or document_id = p_document_id)
    and (p_status      is null or status      = p_status)
  order by created_at desc
  limit p_limit offset p_offset;
end;
$$;


