CREATE OR REPLACE FUNCTION "public"."list_pet_requests"("p_account_id" "uuid", "p_status" "text" DEFAULT NULL::"text", "p_limit" integer DEFAULT 100, "p_offset" integer DEFAULT 0) RETURNS TABLE("id" "uuid", "account_id" "uuid", "property_id" "uuid", "tenant_id" "uuid", "lease_id" "uuid", "jurisdiction" "text", "pet_type" "text", "pet_description" "text", "request_date" "date", "decision_due_date" "date", "status" "text", "decision_date" "date", "refusal_reason" "text", "insurance_required" boolean, "insurance_document_id" "uuid", "notes" "text", "created_by" "uuid", "created_at" timestamp with time zone, "updated_at" timestamp with time zone, "tenant_name" "text", "property_address" "text")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  PERFORM public.assert_account_feature_access(p_account_id, 'renters_rights_readiness');

  IF NOT public.is_account_manager(p_account_id, auth.uid()) THEN
    RAISE EXCEPTION 'Access denied';
  END IF;

  RETURN QUERY
  SELECT
    pr.id, pr.account_id, pr.property_id, pr.tenant_id, pr.lease_id,
    pr.jurisdiction, pr.pet_type, pr.pet_description, pr.request_date,
    (pr.request_date + interval '28 days')::date AS decision_due_date,
    pr.status, pr.decision_date, pr.refusal_reason, pr.insurance_required,
    pr.insurance_document_id, pr.notes, pr.created_by, pr.created_at, pr.updated_at,
    coalesce(tn.name, '—')     AS tenant_name,
    coalesce(prop.address,'—') AS property_address
  FROM public.pet_requests pr
  LEFT JOIN public.tenants    tn   ON tn.id   = pr.tenant_id
  LEFT JOIN public.properties prop ON prop.id = pr.property_id
  WHERE pr.account_id = p_account_id
    AND (p_status IS NULL OR pr.status = p_status)
  ORDER BY
    CASE
      WHEN pr.status IN ('received','under_review')
           AND (pr.request_date + interval '28 days')::date < current_date THEN 1
      WHEN pr.status IN ('received','under_review') THEN 2
      WHEN pr.status = 'approved'  THEN 3
      WHEN pr.status = 'refused'   THEN 4
      WHEN pr.status = 'withdrawn' THEN 5
      ELSE 6
    END,
    pr.request_date ASC
  LIMIT  greatest(1, least(coalesce(p_limit,  100), 500))
  OFFSET greatest(0, coalesce(p_offset, 0));
END;
$$;


