CREATE OR REPLACE FUNCTION "public"."log_document_extraction_viewed"("p_account_id" "uuid", "p_document_id" "uuid", "p_extraction_id" "uuid" DEFAULT NULL::"uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
