  end if;

  insert into public.document_audit_log (
    document_id, action, performed_by, performed_at,
    account_id, created_at
  ) values (
    p_document_id,
    'extraction_viewed',
    auth.uid(),
    now(),
    v_account_id,
    now()
  );
end;
$$;


