CREATE OR REPLACE FUNCTION "public"."log_security_event"("p_account_id" "uuid", "p_action" "text", "p_entity_type" "text", "p_entity_id" "uuid" DEFAULT NULL::"uuid", "p_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_account_id uuid;
  v_actor_user_id uuid;
  v_row_id uuid;
  v_existing_row_id uuid;
  v_action text;
  v_entity_type text;
  v_is_service_role boolean := coalesce(auth.role(), '') = 'service_role';
begin
  v_actor_user_id := auth.uid();

  v_action := lower(trim(coalesce(p_action, '')));
  v_entity_type := lower(trim(coalesce(p_entity_type, '')));

  if nullif(v_action, '') is null then
    raise exception 'Missing action';
  end if;

  if nullif(v_entity_type, '') is null then
    raise exception 'Missing entity type';
  end if;

  if p_account_id is null then
    raise exception 'Missing account id';
  end if;

  if v_is_service_role then
    v_account_id := p_account_id;
  elsif public.user_can_manage_account(p_account_id) then
    v_account_id := p_account_id;
  elsif v_actor_user_id is not null
    and exists (
      select 1
      from public.account_members am
      where am.account_id = p_account_id
        and am.user_id = v_actor_user_id
    )
  then
    if v_action = 'invite_accepted' and v_entity_type in ('account_invitation', 'account_invitations') then
      if not exists (
        select 1
        from public.account_invitations ai
        where ai.id = p_entity_id
          and ai.account_id = p_account_id
          and ai.accepted_by = v_actor_user_id
          and ai.accepted_at is not null
      ) then
        raise exception 'Access denied';
      end if;

      select sal.id
      into v_existing_row_id
      from public.security_audit_ledger sal
      where sal.account_id = p_account_id
        and sal.actor_user_id = v_actor_user_id
        and sal.action = v_action
        and sal.entity_id is not distinct from p_entity_id
      order by sal.created_at desc
      limit 1;

      if v_existing_row_id is not null then
        return v_existing_row_id;
      end if;

      v_account_id := p_account_id;
    elsif v_action = 'role_changed'
      and v_entity_type = 'account_member'
      and p_entity_id = v_actor_user_id
      and coalesce(p_metadata->>'change_source', '') = 'invite_acceptance'
    then
      if not exists (
        select 1
        where public.account_member_effective_role(p_account_id, v_actor_user_id)
          = lower(coalesce(p_metadata->>'new_role', ''))
      ) then
        raise exception 'Access denied';
      end if;

      if not exists (
        select 1
        from public.account_invitations ai
        where ai.id::text = coalesce(p_metadata->>'invite_id', '')
          and ai.account_id = p_account_id
          and ai.accepted_by = v_actor_user_id
          and ai.accepted_at is not null
      ) then
        raise exception 'Access denied';
      end if;

      select sal.id
      into v_existing_row_id
      from public.security_audit_ledger sal
      where sal.account_id = p_account_id
        and sal.actor_user_id = v_actor_user_id
        and sal.action = v_action
        and sal.entity_id is not distinct from p_entity_id
        and coalesce(sal.metadata->>'change_source', '') = 'invite_acceptance'
        and coalesce(sal.metadata->>'new_role', '') = coalesce(p_metadata->>'new_role', '')
      order by sal.created_at desc
      limit 1;

      if v_existing_row_id is not null then
        return v_existing_row_id;
      end if;

      v_account_id := p_account_id;
    else
      raise exception 'Access denied';
    end if;
  else
    raise exception 'Access denied';
  end if;

  insert into public.security_audit_ledger (
    account_id,
    actor_user_id,
    action,
    entity_type,
    entity_id,
    metadata
  )
  values (
    v_account_id,
    v_actor_user_id,
    v_action,
    v_entity_type,
    p_entity_id,
    coalesce(p_metadata, '{}'::jsonb)
  )
  returning id into v_row_id;

  return v_row_id;
end;
$$;


ALTER FUNCTION "public"."log_security_event"("p_account_id" "uuid", "p_action" "text", "p_entity_type" "text", "p_entity_id" "uuid", "p_metadata" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."log_security_event"("p_account_id" "uuid", "p_action" "text", "p_entity_type" "text", "p_entity_id" "uuid", "p_metadata" "jsonb") IS 'Canonical append-only writer for security_audit_ledger rows. Validates manager/root access for the target account, allows tightly scoped self-service invite acceptance logging, and records auth.uid() as actor_user_id when available.';



CREATE OR REPLACE FUNCTION "public"."maintenance_attention_needed"("p_account_id" "uuid") RETURNS TABLE("item_type" "text", "maintenance_request_id" "uuid", "work_order_id" "uuid", "request_status" "text", "work_order_status" "text", "priority" "text", "title" "text", "property_label" "text", "created_at" timestamp with time zone, "age_hours" numeric)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with req as (
    select
      mr.id,
      mr.status,
      mr.priority,
      mr.title,
      mr.created_at,
      mr.property_id
    from public.maintenance_requests mr
    where mr.account_id = p_account_id
  ),
  wo as (
    select
      w.id,
      w.status,
      w.contractor_user_id,
      w.maintenance_request_id,
      w.created_at
    from public.work_orders w
    where w.account_id = p_account_id
  ),
  req_with_property as (
    select
      r.id,
      r.status,
      r.priority,
      r.title,
      r.created_at,
      coalesce(
        concat_ws(', ', p.address, p.city),
        r.property_id::text
      ) as property_label
    from req r
    left join public.properties p
      on p.id = r.property_id
     and p.account_id = p_account_id
  )

  -- 1) waiting > 48h
  select
    'stuck_waiting_over_48h'::text as item_type,
    r.id::uuid as maintenance_request_id,
    null::uuid as work_order_id,
    r.status::text as request_status,
    null::text as work_order_status,
    r.priority::text as priority,
    r.title::text as title,
    r.property_label::text as property_label,
    r.created_at::timestamptz as created_at,
    round((extract(epoch from (now() - r.created_at)) / 3600.0)::numeric, 1) as age_hours
  from req_with_property r
  where lower(coalesce(r.status::text, '')) = 'waiting'
    and r.created_at < now() - interval '48 hours'

  union all

  -- 2) high priority unresolved
  select
    'high_priority_unresolved'::text as item_type,
    r.id::uuid as maintenance_request_id,
    null::uuid as work_order_id,
    r.status::text as request_status,
    null::text as work_order_status,
    r.priority::text as priority,
    r.title::text as title,
    r.property_label::text as property_label,
    r.created_at::timestamptz as created_at,
    round((extract(epoch from (now() - r.created_at)) / 3600.0)::numeric, 1) as age_hours
  from req_with_property r
  where lower(coalesce(r.status::text, '')) <> 'closed'
    and lower(coalesce(r.priority::text, '')) in ('high', 'urgent')

  union all

  -- 3) request without work order
  select
    'request_without_work_order'::text as item_type,
    r.id::uuid as maintenance_request_id,
    null::uuid as work_order_id,
    r.status::text as request_status,
    null::text as work_order_status,
    r.priority::text as priority,
    r.title::text as title,
    r.property_label::text as property_label,
    r.created_at::timestamptz as created_at,
    round((extract(epoch from (now() - r.created_at)) / 3600.0)::numeric, 1) as age_hours
  from req_with_property r
  where lower(coalesce(r.status::text, '')) <> 'closed'
    and not exists (
      select 1
      from wo
      where wo.maintenance_request_id = r.id
    )

  union all

  -- 4) work order without contractor
  select
    'work_order_without_contractor'::text as item_type,
    r.id::uuid as maintenance_request_id,
    w.id::uuid as work_order_id,
    r.status::text as request_status,
    w.status::text as work_order_status,
    r.priority::text as priority,
    r.title::text as title,
    r.property_label::text as property_label,
    least(r.created_at, w.created_at)::timestamptz as created_at,
    round((extract(epoch from (now() - least(r.created_at, w.created_at))) / 3600.0)::numeric, 1) as age_hours
  from wo w
  join req_with_property r
    on r.id = w.maintenance_request_id
  where lower(coalesce(w.status::text, '')) in ('assigned', 'in_progress')
    and w.contractor_user_id is null

  order by created_at asc;
$$;


ALTER FUNCTION "public"."maintenance_attention_needed"("p_account_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."maintenance_dashboard_stats"("p_account_id" "uuid") RETURNS TABLE("open_requests" bigint, "active_work_orders" bigint, "awaiting_action" bigint, "resolved_pending_closure" bigint, "open_high_priority" bigint, "stuck_waiting_over_48h" bigint, "requests_without_work_order" bigint, "work_orders_without_contractor" bigint)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with req as (
    select
      mr.id,
      mr.status,
      mr.priority,
      mr.created_at
    from public.maintenance_requests mr
    where mr.account_id = p_account_id
  ),
  wo as (
    select
      w.id,
      w.status,
      w.contractor_user_id,
      w.maintenance_request_id,
      w.created_at
    from public.work_orders w
    where w.account_id = p_account_id
  )
  select
    (
      select count(*)
      from req
      where lower(coalesce(status, '')) <> 'closed'
    ) as open_requests,

    (
      select count(*)
      from wo
      where lower(coalesce(status, '')) = 'in_progress'
    ) as active_work_orders,

    (
      select count(*)
      from req
      where lower(coalesce(status, '')) = 'waiting'
    ) as awaiting_action,

    (
      select count(*)
      from req
      where lower(coalesce(status, '')) = 'resolved'
    ) as resolved_pending_closure,

    (
      select count(*)
      from req
      where lower(coalesce(status, '')) <> 'closed'
        and lower(coalesce(priority, '')) in ('high', 'urgent')
    ) as open_high_priority,

    (
      select count(*)
      from req
      where lower(coalesce(status, '')) = 'waiting'
        and created_at < now() - interval '48 hours'
    ) as stuck_waiting_over_48h,

    (
      select count(*)
      from req r
      where lower(coalesce(r.status, '')) <> 'closed'
        and not exists (
          select 1
          from wo
          where wo.maintenance_request_id = r.id
        )
    ) as requests_without_work_order,

    (
      select count(*)
      from wo
      where lower(coalesce(status, '')) in ('assigned', 'in_progress')
        and contractor_user_id is null
    ) as work_orders_without_contractor
$$;


ALTER FUNCTION "public"."maintenance_dashboard_stats"("p_account_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."maintenance_kpi_snapshot"("p_account_id" "uuid") RETURNS TABLE("open_requests" bigint, "active_work_orders" bigint, "awaiting_action" bigint, "resolved_pending_closure" bigint, "open_high_priority" bigint, "triage_over_24h" bigint, "contractor_ack_overdue" bigint, "stalled_repairs" bigint, "long_running_repairs" bigint, "repeat_repair_properties" bigint, "req_by_status" "jsonb", "wo_by_status" "jsonb", "aging" "jsonb")
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with authz as (
    select
      public.assert_manage_account_access(p_account_id) as account_id,
      public.assert_account_feature_access(p_account_id, 'maintenance_kpi') as feature_account_id
  ),
  req as (
    select
      id,
      property_id,
      lower(coalesce(status, '')) as status_norm,
      lower(coalesce(priority, '')) as priority_norm,
      created_at,
      updated_at
    from maintenance_requests
    cross join authz a
    where maintenance_requests.account_id = a.account_id
  ),
  wo as (
    select
      id,
      property_id,
      maintenance_request_id,
      contractor_user_id,
      contractor_name,
      acknowledgement_due_at,
      acknowledged_at,
      lower(coalesce(acknowledgement_status, '')) as acknowledgement_status_norm,
      lower(coalesce(status, '')) as status_norm,
      created_at,
      updated_at
    from work_orders
    where work_orders.account_id = p_account_id
  ),
  recent_repair_properties as (
    select property_id
    from req
    where property_id is not null
      and created_at >= now() - interval '90 days'
    group by property_id
    having count(*) >= 3
  ),
  status_counts as (
    select
      jsonb_build_object(
        'open', (select count(*) from req where status_norm = 'open'),
        'in_progress', (select count(*) from req where status_norm = 'in_progress'),
        'waiting', (select count(*) from req where status_norm = 'waiting'),
        'resolved', (select count(*) from req where status_norm = 'resolved'),
        'closed', (select count(*) from req where status_norm = 'closed')
      ) as req_by_status,
      jsonb_build_object(
        'assigned', (select count(*) from wo where status_norm = 'assigned'),
        'in_progress', (select count(*) from wo where status_norm = 'in_progress'),
        'completed', (select count(*) from wo where status_norm = 'completed'),
        'cancelled', (select count(*) from wo where status_norm = 'cancelled')
      ) as wo_by_status
  ),
  aging_counts as (
    select jsonb_build_object(
      'b0_24',
        (
          select count(*)
          from req
          where status_norm in ('open', 'in_progress', 'waiting', 'otwarte', 'w trakcie', 'oczekuje')
            and created_at > now() - interval '24 hours'
        ),
      'b24_48',
        (
          select count(*)
          from req
          where status_norm in ('open', 'in_progress', 'waiting', 'otwarte', 'w trakcie', 'oczekuje')
            and created_at <= now() - interval '24 hours'
            and created_at > now() - interval '48 hours'
        ),
      'b48_72',
        (
          select count(*)
          from req
          where status_norm in ('open', 'in_progress', 'waiting', 'otwarte', 'w trakcie', 'oczekuje')
            and created_at <= now() - interval '48 hours'
            and created_at > now() - interval '72 hours'
        ),
      'b72_plus',
        (
          select count(*)
          from req
          where status_norm in ('open', 'in_progress', 'waiting', 'otwarte', 'w trakcie', 'oczekuje')
            and created_at <= now() - interval '72 hours'
        )
    ) as aging
  )
  select
    (
      select count(*)
      from req
      where status_norm in ('open', 'in_progress', 'waiting', 'otwarte', 'w trakcie', 'oczekuje')
    ) as open_requests,
    (
      select count(*)
      from wo
      where status_norm in ('assigned', 'in_progress', 'blocked', 'przypisane', 'w trakcie', 'zablokowane')
    ) as active_work_orders,
    (select count(*) from req where status_norm = 'waiting') as awaiting_action,
    (select count(*) from req where status_norm = 'resolved') as resolved_pending_closure,
    (
      select count(*)
      from req
      where status_norm in ('open', 'in_progress', 'waiting', 'otwarte', 'w trakcie', 'oczekuje')
        and priority_norm in ('high', 'urgent')
    ) as open_high_priority,
    (
      select count(*)
      from req r
      where r.status_norm = 'open'
        and r.created_at <= now() - interval '24 hours'
        and not exists (
          select 1
          from wo
          where wo.maintenance_request_id = r.id
        )
    ) as triage_over_24h,
    (
      select count(*)
      from wo
      where status_norm in ('assigned', 'in_progress', 'blocked', 'przypisane', 'w trakcie', 'zablokowane')
        and (contractor_user_id is not null or nullif(coalesce(contractor_name, ''), '') is not null)
        and acknowledgement_due_at is not null
        and acknowledgement_due_at < now()
        and acknowledgement_status_norm <> 'acknowledged'
        and acknowledged_at is null
    ) as contractor_ack_overdue,
    (
      select count(*)
      from wo
      where status_norm in ('in_progress', 'w trakcie', 'blocked', 'zablokowane')
        and coalesce(updated_at, created_at) <= now() - interval '72 hours'
    ) as stalled_repairs,
    (
      select count(*)
      from wo
      where status_norm in ('assigned', 'in_progress', 'blocked', 'przypisane', 'w trakcie', 'zablokowane')
        and created_at <= now() - interval '14 days'
    ) as long_running_repairs,
    (select count(*) from recent_repair_properties) as repeat_repair_properties,
    status_counts.req_by_status,
    status_counts.wo_by_status,
    aging_counts.aging
  from status_counts, aging_counts;
$$;


ALTER FUNCTION "public"."maintenance_kpi_snapshot"("p_account_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."mark_document_extraction_stale"("p_account_id" "uuid", "p_document_id" "uuid") RETURNS SETOF "public"."document_extractions"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_account_id uuid := public.assert_manage_account_access(p_account_id);
  v_doc        public.documents;
begin
  perform public.assert_account_feature_access(v_account_id, 'document_extraction');

  select * into v_doc
  from public.documents
  where id = p_document_id
    and account_id = v_account_id;

  if not found then
    raise exception 'Document not found';
  end if;

  update public.document_extractions
  set status     = 'stale',
      updated_at = now()
  where document_id = p_document_id
    and account_id  = v_account_id
    and status in ('completed', 'pending', 'processing');

  insert into public.document_audit_log (
    document_id, action, performed_by, performed_at,
    account_id, property_id, tenant_id, created_at
  ) values (
    p_document_id,
    'extraction_marked_stale',
    auth.uid(),
    now(),
    v_account_id,
    v_doc.property_id,
    v_doc.tenant_id,
    now()
  );

  return query
  select * from public.document_extractions
  where document_id = p_document_id
    and account_id  = v_account_id
  order by created_at desc;
end;
$$;


ALTER FUNCTION "public"."mark_document_extraction_stale"("p_account_id" "uuid", "p_document_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."mark_document_extraction_stale"("p_account_id" "uuid", "p_document_id" "uuid") IS 'Marks completed/pending/processing extractions for a document as stale. Call this when a document is replaced so the AI Lease Auditor does not consume outdated extracted text.';



CREATE OR REPLACE FUNCTION "public"."mark_document_packet_viewed"("p_packet_id" "uuid", "p_actor_user_id" "uuid" DEFAULT "auth"."uid"()) RETURNS "public"."document_packets"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor uuid := auth.uid();
  v_packet public.document_packets;
begin
  if v_actor is null then raise exception 'Not authenticated'; end if;
  if p_actor_user_id is not null and p_actor_user_id <> v_actor then raise exception 'Actor mismatch'; end if;

  select * into v_packet from public.document_packets where id = p_packet_id;
  if not found then raise exception 'Packet not found'; end if;
  if not public.is_document_packet_recipient(p_packet_id, v_actor) then raise exception 'Not permitted'; end if;
  if v_packet.status not in ('sent', 'viewed') then raise exception 'Packet is not ready to view'; end if;

  update public.document_packet_recipients
  set status = case when status = 'sent' then 'viewed' else status end,
      viewed_at = coalesce(viewed_at, now())
  where packet_id = p_packet_id
    and account_id = v_packet.account_id
    and public.is_document_packet_recipient(packet_id, v_actor);

  if v_packet.status = 'sent' then
    update public.document_packets
    set status = 'viewed'
    where id = p_packet_id
    returning * into v_packet;

    insert into public.document_packet_events (account_id, packet_id, actor_user_id, event_type, message)
    values (v_packet.account_id, v_packet.id, v_actor, 'viewed', 'Agreement packet viewed');
  end if;

  select * into v_packet from public.document_packets where id = p_packet_id;
  return v_packet;
end;
$$;


ALTER FUNCTION "public"."mark_document_packet_viewed"("p_packet_id" "uuid", "p_actor_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."mark_marketplace_job_submitted"("p_account_id" "uuid", "p_marketplace_job_id" "uuid", "p_external_job_id" "text" DEFAULT ''::"text", "p_external_reference" "text" DEFAULT ''::"text", "p_external_url" "text" DEFAULT ''::"text", "p_response_payload" "jsonb" DEFAULT '{}'::"jsonb") RETURNS SETOF "public"."external_marketplace_jobs"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_account_id uuid;
  v_job public.external_marketplace_jobs%rowtype;
begin
  v_account_id := public.assert_manage_account_access(p_account_id);

  update public.external_marketplace_jobs j
  set status = 'submitted',
      submitted_at = coalesce(j.submitted_at, now()),
      external_job_id = case when coalesce(p_external_job_id, '') = '' then j.external_job_id else p_external_job_id end,
      external_reference = case when coalesce(p_external_reference, '') = '' then j.external_reference else p_external_reference end,
      external_url = case when coalesce(p_external_url, '') = '' then j.external_url else p_external_url end,
      last_error = '',
      response_payload = case
        when p_response_payload is null or p_response_payload = '{}'::jsonb then j.response_payload
        else p_response_payload
      end,
      updated_by = auth.uid(),
      updated_at = now()
  where j.id = p_marketplace_job_id
    and j.account_id = v_account_id
  returning *
  into v_job;

  if v_job.id is null then
    raise exception 'Marketplace job not found' using errcode = 'P0002';
  end if;

  insert into public.external_marketplace_events (
    marketplace_job_id,
    account_id,
    work_order_id,
    event_type,
    payload,
    actor_user_id
  )
  values (
    v_job.id,
    v_job.account_id,
    v_job.work_order_id,
    'job_submitted',
    jsonb_build_object(
      'external_job_id', v_job.external_job_id,
      'external_reference', v_job.external_reference,
      'external_url', v_job.external_url
    ),
    auth.uid()
  );

  perform public.activity_log_write(
    v_job.account_id,
    'work_order',
    v_job.work_order_id,
    'marketplace_job_submitted',
    'status',
    null,
    v_job.status,
    jsonb_build_object(
      'table', 'external_marketplace_jobs',
      'marketplace_job_id', v_job.id,
      'provider_key', v_job.provider_key,
      'external_job_id', v_job.external_job_id,
      'external_reference', v_job.external_reference,
      'external_url', v_job.external_url
    )
  );

  perform public.marketplace_notify_managers(
    v_job.account_id,
    v_job.work_order_id,
    'marketplace_handoff_submitted',
    'Marketplace handoff submitted',
    coalesce(v_job.title, 'Work order handoff') || ' submitted to ' || coalesce(v_job.provider_key, 'marketplace'),
    jsonb_build_object(
      'marketplace_job_id', v_job.id,
      'provider_key', v_job.provider_key,
      'external_job_id', v_job.external_job_id,
      'external_reference', v_job.external_reference,
      'external_url', v_job.external_url
    )
  );

  return query
  select *
  from public.external_marketplace_jobs j
  where j.id = v_job.id;
end;
$$;


ALTER FUNCTION "public"."mark_marketplace_job_submitted"("p_account_id" "uuid", "p_marketplace_job_id" "uuid", "p_external_job_id" "text", "p_external_reference" "text", "p_external_url" "text", "p_response_payload" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."mark_payment_paid"("p_account_id" "uuid", "p_payment_id" "uuid", "p_paid_at" "date" DEFAULT CURRENT_DATE) RETURNS "public"."payments"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_pay  public.payments;
  v_role text;
begin
  select * into v_pay
  from public.payments
  where id = p_payment_id
    and account_id = p_account_id;

  if not found then
    raise exception 'Payment not found';
  end if;

  v_role := public.account_role_for(v_pay.account_id);
  if coalesce(v_role, '') not in ('owner', 'admin') then
    raise exception 'Not permitted';
  end if;

  update public.payments
  set paid_at = coalesce(p_paid_at, current_date),
      status  = 'paid'
  where id = p_payment_id
    and account_id = p_account_id
  returning * into v_pay;

  return v_pay;
end;
$$;


ALTER FUNCTION "public"."mark_payment_paid"("p_account_id" "uuid", "p_payment_id" "uuid", "p_paid_at" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."mark_payment_unpaid"("p_account_id" "uuid", "p_payment_id" "uuid") RETURNS "public"."payments"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_row public.payments;
begin
  select * into v_row
  from public.payments
  where id = p_payment_id
    and account_id = p_account_id;

  if v_row.id is null then
    raise exception 'Payment not found';
  end if;

  if coalesce(public.account_role_for(v_row.account_id), '') not in ('owner', 'admin') then
    raise exception 'Not allowed';
  end if;

  update public.payments
  set paid_at = null,
      status  = case
                  when due_date < current_date then 'overdue'
                  else 'due'
                end
  where id = p_payment_id
    and account_id = p_account_id
  returning * into v_row;

  return v_row;
end;
$$;


ALTER FUNCTION "public"."mark_payment_unpaid"("p_account_id" "uuid", "p_payment_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."mark_tax_item_filed"("p_id" "uuid", "p_account_id" "uuid", "p_filed_at" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_filing_reference" "text" DEFAULT NULL::"text") RETURNS SETOF "public"."compliance_items"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_account_id uuid := public.assert_manage_account_access(p_account_id);
  v_now        timestamptz := coalesce(p_filed_at, now());
begin
  perform public.assert_account_feature_access(v_account_id, 'tax_readiness_dashboard');

  -- Insert audit row before the update so it's recorded even if update fails
  insert into public.compliance_audit_log (
    account_id, item_id, action, performed_by, metadata
  ) values (
    v_account_id,
    p_id,
    'mark_filed',
    auth.uid(),
    jsonb_build_object(
      'filed_at', v_now,
      'filing_reference', nullif(trim(coalesce(p_filing_reference, '')), '')
    )
  );

  return query
  update public.compliance_items
  set
    filed_at          = v_now,
    filing_reference  = nullif(trim(coalesce(p_filing_reference, '')), ''),
    status            = 'completed',
    completed_at      = v_now,
    last_completed_at = v_now,
    updated_at        = v_now
  where id         = p_id
    and account_id = v_account_id
    and category   = 'tax'
  returning *;
end;
$$;


ALTER FUNCTION "public"."mark_tax_item_filed"("p_id" "uuid", "p_account_id" "uuid", "p_filed_at" timestamp with time zone, "p_filing_reference" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."mark_tax_item_filed"("p_id" "uuid", "p_account_id" "uuid", "p_filed_at" timestamp with time zone, "p_filing_reference" "text") IS 'Marks a tax item as filed after verifying entitlement. Appends a row to compliance_audit_log for traceability. Resolves L-010.';



