CREATE OR REPLACE FUNCTION "public"."marketplace_notify_managers"("p_account_id" "uuid", "p_work_order_id" "uuid", "p_type" "text", "p_title" "text", "p_body" "text", "p_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_recipient_user_ids uuid[];
begin
  v_recipient_user_ids := public.marketplace_manager_recipient_ids(p_account_id, auth.uid());

  if coalesce(array_length(v_recipient_user_ids, 1), 0) = 0 then
    return;
  end if;

  perform public.create_notifications_system(
    p_account_id,
    v_recipient_user_ids,
    p_type,
    p_title,
    p_body,
    'work_order',
    p_work_order_id,
    '/work-orders/' || p_work_order_id::text,
    coalesce(p_metadata, '{}'::jsonb)
  );
end;
$$;


