CREATE OR REPLACE FUNCTION "public"."notifications_mark_all_read"("p_account_id" "uuid" DEFAULT NULL::"uuid") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_count integer := 0;
begin
  -- Optional: if account_id is provided, only mark notifications in that account
  if p_account_id is not null then
    update public.notifications n
    set is_read = true,
        read_at = now()
    where n.recipient_user_id = auth.uid()
      and n.account_id = p_account_id
      and n.is_read = false;

  else
    update public.notifications n
    set is_read = true,
        read_at = now()
    where n.recipient_user_id = auth.uid()
      and n.is_read = false;
  end if;

  get diagnostics v_count = row_count;
  return v_count;
end;
$$;


