CREATE OR REPLACE FUNCTION "public"."playbook_status_snapshot"("p_account_id" "uuid", "p_recent_limit" integer DEFAULT 12) RETURNS TABLE("settings" "jsonb", "open_run_counts" "jsonb", "recent_runs" "jsonb", "recent_resolved_runs" "jsonb", "recent_executions" "jsonb", "open_runs" integer, "last_run_at" timestamp with time zone, "last_run_status" "text")
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with cfg as (
    select greatest(1, least(coalesce(p_recent_limit, 12), 50)) as recent_limit
  ),
  authz as (
    select
      public.assert_manage_account_access(p_account_id) as account_id,
      public.assert_account_feature_access(p_account_id, 'playbooks') as feature_account_id
  ),
  settings_rows as (
    select
      ars.rule_id,
      ars.enabled,
      ars.config,
      ars.updated_at
    from public.automation_rule_settings ars
    cross join authz a
    where ars.account_id = a.account_id
  ),
  open_run_count_rows as (
    select
      ar.rule_id,
      count(*)::int as run_count
    from public.automation_runs ar
    where ar.account_id = p_account_id
      and lower(coalesce(ar.state, 'open')) = 'open'
    group by ar.rule_id
  ),
  recent_run_rows as (
    select
      ar.id,
      ar.rule_id,
      ar.source_key,
      ar.state,
      ar.severity,
      ar.title,
      ar.body,
      ar.entity_type,
      ar.entity_id,
      ar.link_path,
      ar.details,
      ar.first_triggered_at,
      ar.last_triggered_at,
      ar.resolved_at,
      ar.created_at,
      ar.updated_at
    from public.automation_runs ar
    where ar.account_id = p_account_id
    order by ar.last_triggered_at desc nulls last, ar.created_at desc
    limit (select recent_limit from cfg)
  ),
  recent_resolved_rows as (
    select
      ar.id,
      ar.rule_id,
      ar.source_key,
      ar.state,
      ar.severity,
      ar.title,
      ar.body,
      ar.entity_type,
      ar.entity_id,
      ar.link_path,
      ar.details,
      ar.first_triggered_at,
      ar.last_triggered_at,
      ar.resolved_at,
      ar.created_at,
      ar.updated_at
    from public.automation_runs ar
    where ar.account_id = p_account_id
      and lower(coalesce(ar.state, 'open')) = 'resolved'
    order by ar.resolved_at desc nulls last, ar.last_triggered_at desc nulls last
    limit (select recent_limit from cfg)
  ),
  recent_execution_rows as (
    select
      ael.id,
      ael.rule_id,
      ael.event_key,
      ael.execution_type,
      ael.status,
      ael.entity_type,
      ael.entity_id,
      ael.title,
      ael.details,
      ael.executed_at,
      ael.created_at
    from public.automation_execution_log ael
    where ael.account_id = p_account_id
    order by ael.executed_at desc nulls last, ael.created_at desc
    limit (select recent_limit from cfg)
  ),
  latest_sync as (
    select
      ael.executed_at,
      ael.status
    from public.automation_execution_log ael
    where ael.account_id = p_account_id
      and ael.execution_type in ('rule_evaluated', 'rule_evaluated_dry_run', 'account_sync_failed')
    order by ael.executed_at desc nulls last, ael.created_at desc
    limit 1
  )
  select
    coalesce(
      (
        select jsonb_agg(
          jsonb_build_object(
            'rule_id', sr.rule_id,
            'enabled', sr.enabled,
            'config', sr.config,
            'updated_at', sr.updated_at
          )
          order by sr.rule_id
        )
        from settings_rows sr
      ),
      '[]'::jsonb
    ) as settings,
    coalesce(
      (
        select jsonb_object_agg(orc.rule_id, orc.run_count)
        from open_run_count_rows orc
      ),
      '{}'::jsonb
    ) as open_run_counts,
    coalesce(
      (
        select jsonb_agg(to_jsonb(rr) order by rr.last_triggered_at desc nulls last, rr.created_at desc)
        from recent_run_rows rr
      ),
      '[]'::jsonb
    ) as recent_runs,
    coalesce(
      (
        select jsonb_agg(to_jsonb(rrr) order by rrr.resolved_at desc nulls last, rrr.last_triggered_at desc nulls last)
        from recent_resolved_rows rrr
      ),
      '[]'::jsonb
    ) as recent_resolved_runs,
    coalesce(
      (
        select jsonb_agg(to_jsonb(rex) order by rex.executed_at desc nulls last, rex.created_at desc)
        from recent_execution_rows rex
      ),
      '[]'::jsonb
    ) as recent_executions,
    coalesce(
      (
        select sum(orc.run_count)::int
        from open_run_count_rows orc
      ),
      0
    ) as open_runs,
    (select ls.executed_at from latest_sync ls) as last_run_at,
    coalesce((select ls.status from latest_sync ls), 'recorded') as last_run_status;
$$;


ALTER FUNCTION "public"."playbook_status_snapshot"("p_account_id" "uuid", "p_recent_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."portfolio_attention_items"("p_account_id" "uuid", "p_tenant_id" "uuid" DEFAULT NULL::"uuid", "p_limit" integer DEFAULT 10) RETURNS TABLE("item_key" "text", "item_type" "text", "property_label" "text", "city" "text", "amount" numeric, "days_vacant" integer, "request_title" "text", "link_path" "text", "sort_order" integer)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with cfg as (
    select greatest(1, least(coalesce(p_limit, 10), 50)) as max_items
  ),
  tenant_auth as (
    select public.assert_tenant_scope_access(p_account_id, p_tenant_id) as tenant_id
  ),
  authz as (
    select
      case
        when tenant_auth.tenant_id is null then public.assert_manage_account_access(p_account_id)
        else p_account_id
      end as account_id,
      tenant_auth.tenant_id
    from tenant_auth
  ),
  tenant_scope as (
    select t.property_id
    from tenants t
    cross join authz a
    where t.id = a.tenant_id
      and t.account_id = a.account_id
    limit 1
  ),
  scoped_properties as (
    select
      p.id,
      p.address,
      p.city,
      p.created_at,
      not exists (
        select 1
        from tenants t
        where t.property_id = p.id
          and t.account_id = a.account_id
      ) as is_vacant
    from properties p
    cross join authz a
    where p.account_id = a.account_id
      and (
        a.tenant_id is null
        or p.id = (select property_id from tenant_scope)
      )
  ),
  vacant_properties as (
    select
      sp.id,
      sp.address,
      sp.city,
      floor(
        extract(
          epoch from (
            now() - coalesce(
              (
                select max(t.created_at)
                from tenants t
                where t.property_id = sp.id
                  and t.account_id = (select account_id from authz)
              ),
              sp.created_at
            )
          )
        ) / 86400
      )::int as days_vacant
    from scoped_properties sp
    where sp.is_vacant
  ),
  overdue_payments as (
    select
      p.id,
      coalesce(pr.address, '—') as property_label,
      coalesce(pr.city, '') as city,
      coalesce(p.amount, 0) as amount
    from payments p
    cross join authz a
    left join properties pr on pr.id = p.property_id and pr.account_id = a.account_id
    where p.account_id = a.account_id
      and (
        a.tenant_id is null
        or p.tenant_id = a.tenant_id
      )
      and (
        lower(coalesce(p.status, '')) in ('overdue', 'zalegle', 'zaległe')
        or (
          lower(coalesce(p.status, '')) not in ('paid', 'oplacone', 'opłacone')
          and p.due_date is not null
          and p.due_date < current_date
        )
      )
    order by p.due_date asc nulls last, p.created_at desc nulls last
    limit 4
  ),
  due_soon_payments as (
    select
      p.id,
      coalesce(pr.address, '—') as property_label,
      coalesce(pr.city, '') as city,
      coalesce(p.amount, 0) as amount
    from payments p
    cross join authz a
    left join properties pr on pr.id = p.property_id and pr.account_id = a.account_id
    where p.account_id = a.account_id
      and (
        a.tenant_id is null
        or p.tenant_id = a.tenant_id
      )
      and lower(coalesce(p.status, '')) not in ('paid', 'oplacone', 'opłacone')
      and p.due_date is not null
      and p.due_date >= current_date
      and p.due_date <= current_date + interval '7 days'
    order by p.due_date asc, p.created_at desc nulls last
    limit 4
  ),
  high_priority_requests as (
    select
      r.id,
      r.title
    from maintenance_requests r
    cross join authz a
    where r.account_id = a.account_id
      and (
        a.tenant_id is null
        or r.property_id = (select property_id from tenant_scope)
      )
      and lower(coalesce(r.status, '')) not in ('closed', 'zamkniete', 'zamknięte')
      and lower(coalesce(r.priority, '')) in ('high', 'urgent', 'critical', 'wysoki', 'krytyczny')
    order by r.created_at desc
    limit 4
  ),
  items as (
    select *
    from (
      select
        'vacant-' || vp.id::text as item_key,
        'vacant'::text as item_type,
        vp.address as property_label,
        vp.city,
        null::numeric as amount,
        vp.days_vacant,
        null::text as request_title,
        '/properties?status=vacant'::text as link_path,
        10 as sort_order
      from vacant_properties vp
      order by vp.days_vacant desc, vp.address
      limit 4
    ) vacant_items

    union all

    select *
    from (
      select
        'vacant-long-' || vp.id::text as item_key,
        'vacant_long'::text as item_type,
        vp.address as property_label,
        vp.city,
        null::numeric as amount,
        vp.days_vacant,
        null::text as request_title,
        '/properties?status=vacant&aging=14d'::text as link_path,
        20 as sort_order
      from vacant_properties vp
      where vp.days_vacant > 30
      order by vp.days_vacant desc, vp.address
      limit 4
    ) vacant_long_items

    union all

    select
      'overdue-' || op.id::text as item_key,
      'overdue_payment'::text as item_type,
      op.property_label,
      op.city,
      op.amount,
      null::int as days_vacant,
      null::text as request_title,
      '/finance?status=overdue'::text as link_path,
      30 as sort_order
    from overdue_payments op

    union all

    select
      'due-soon-' || dp.id::text as item_key,
      'due_soon_payment'::text as item_type,
      dp.property_label,
      dp.city,
      dp.amount,
      null::int as days_vacant,
      null::text as request_title,
      '/finance?status=due&range=7d'::text as link_path,
      40 as sort_order
    from due_soon_payments dp

    union all

    select
      'high-priority-' || r.id::text as item_key,
      'high_priority_request'::text as item_type,
      null::text as property_label,
      null::text as city,
      null::numeric as amount,
      null::int as days_vacant,
      coalesce(r.title, r.id::text) as request_title,
      '/maintenance-inbox?priority=high,critical'::text as link_path,
      50 as sort_order
    from high_priority_requests r
  )
  select
    i.item_key,
    i.item_type,
    i.property_label,
    i.city,
    i.amount,
    i.days_vacant,
    i.request_title,
    i.link_path,
    i.sort_order
  from items i
  order by i.sort_order, i.item_key
  limit (select max_items from cfg);
$$;


ALTER FUNCTION "public"."portfolio_attention_items"("p_account_id" "uuid", "p_tenant_id" "uuid", "p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."portfolio_health_snapshot"("p_account_id" "uuid", "p_tenant_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("property_count" bigint, "occupied_count" bigint, "vacant_count" bigint, "occupancy_rate" integer, "paid_amount" numeric, "due_amount" numeric, "overdue_amount" numeric, "due_soon_amount" numeric, "outstanding_amount" numeric, "overdue_0_7_amount" numeric, "overdue_8_30_amount" numeric, "overdue_30_plus_amount" numeric, "open_requests" bigint, "high_priority_open_requests" bigint, "waiting_over_48h" bigint, "active_work_orders" bigint, "work_orders_without_contractor" bigint, "contractor_ack_overdue" bigint, "stalled_repairs" bigint, "long_running_repairs" bigint, "repeat_repair_properties" bigint, "recent_open_created" bigint, "prev_open_created" bigint, "outstanding_current_month" numeric, "outstanding_previous_month" numeric)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with authz as (
    select
      p_account_id as account_id,
      public.assert_account_feature_access(p_account_id, 'portfolio_health') as feature_account_id,
      public.assert_tenant_scope_access(p_account_id, p_tenant_id) as tenant_id
  ),
  tenant_scope as (
    select t.property_id
    from tenants t
    cross join authz a
    where t.id = a.tenant_id
      and t.account_id = a.account_id
    limit 1
  ),
  scoped_properties as (
    select p.id
    from properties p
    where p.account_id = p_account_id
      and (
        (select tenant_id from authz) is null
        or p.id = (select property_id from tenant_scope)
      )
  ),
  occupied_properties as (
    select sp.id
    from scoped_properties sp
    where exists (
      select 1
      from tenants t
      where t.property_id = sp.id
    )
  ),
  scoped_payments as (
    select
      p.property_id,
      p.tenant_id,
      coalesce(p.amount, 0) as amount,
      lower(coalesce(p.status, '')) as status_norm,
      p.paid_at,
      p.due_date
    from payments p
    where p.account_id = p_account_id
      and (
        (select tenant_id from authz) is null
        or p.tenant_id = (select tenant_id from authz)
      )
  ),
  payment_rows as (
    select
      sp.property_id,
      sp.tenant_id,
      sp.amount,
      sp.status_norm,
      sp.paid_at,
      sp.due_date,
      (
        sp.paid_at is not null
        or sp.status_norm in ('paid', 'oplacone', 'opłacone')
      ) as is_paid,
      date_trunc(
        'month',
        coalesce(sp.due_date::timestamp, sp.paid_at::timestamp, current_date::timestamp)
      ) as cycle_month
    from scoped_payments sp
  ),
  payment_cycles as (
    select
      prx.property_id,
      prx.tenant_id,
      prx.cycle_month,
      greatest(
        coalesce(max(pr.rent), 0),
        coalesce(max(prx.amount), 0)
      ) as billed_amount,
      coalesce(
        sum(
          case
            when prx.is_paid then prx.amount else 0
          end
        ),
        0
      ) as paid_amount,
      min(
        case
          when not prx.is_paid then prx.due_date
          else null
        end
      ) as open_due_date,
      coalesce(
        bool_or(
          not prx.is_paid
          and (
            prx.status_norm in ('overdue', 'zalegle', 'zaległe')
            or (prx.due_date is not null and prx.due_date < current_date)
          )
        ),
        false
      ) as has_overdue
    from payment_rows prx
    left join properties pr
      on pr.id = prx.property_id
    group by prx.property_id, prx.tenant_id, prx.cycle_month
  ),
  scoped_requests as (
    select
      r.id,
      r.property_id,
      lower(coalesce(r.status, '')) as status_norm,
      lower(coalesce(r.priority, '')) as priority_norm,
      r.created_at
    from maintenance_requests r
    where r.account_id = p_account_id
      and (
        (select tenant_id from authz) is null
        or r.property_id = (select property_id from tenant_scope)
      )
  ),
  scoped_work_orders as (
    select
      w.property_id,
      lower(coalesce(w.status, '')) as status_norm,
      w.contractor_user_id,
      w.contractor_name,
      w.acknowledgement_due_at,
      w.acknowledged_at,
      lower(coalesce(w.acknowledgement_status, '')) as acknowledgement_status_norm,
      w.created_at,
      w.updated_at
    from work_orders w
    where w.account_id = p_account_id
      and (
        (select tenant_id from authz) is null
        or w.property_id = (select property_id from tenant_scope)
      )
  ),
  repeat_repair_properties as (
    select sr.property_id
    from scoped_requests sr
    where sr.property_id is not null
      and sr.created_at >= now() - interval '90 days'
    group by sr.property_id
    having count(*) >= 3
  ),
  finance as (
    select
      coalesce(sum(pc.paid_amount), 0) as paid_amount,
      coalesce(
        sum(
          case
            when greatest(pc.billed_amount - pc.paid_amount, 0) > 0
             and not pc.has_overdue
            then greatest(pc.billed_amount - pc.paid_amount, 0)
            else 0
          end
        ),
        0
      ) as due_amount,
      coalesce(
        sum(
          case
            when greatest(pc.billed_amount - pc.paid_amount, 0) > 0
             and pc.has_overdue
            then greatest(pc.billed_amount - pc.paid_amount, 0)
            else 0
          end
        ),
        0
      ) as overdue_amount,
      coalesce(
        sum(
          case
            when greatest(pc.billed_amount - pc.paid_amount, 0) > 0
             and pc.open_due_date is not null
             and pc.open_due_date >= current_date
             and pc.open_due_date <= current_date + interval '7 days'
            then greatest(pc.billed_amount - pc.paid_amount, 0)
            else 0
          end
        ),
        0
      ) as due_soon_amount,
      coalesce(sum(greatest(pc.billed_amount - pc.paid_amount, 0)), 0) as outstanding_amount,
      coalesce(
        sum(
          case
            when greatest(pc.billed_amount - pc.paid_amount, 0) > 0
             and pc.has_overdue
             and pc.open_due_date is not null
             and pc.open_due_date <= current_date
             and current_date - pc.open_due_date <= 7
            then greatest(pc.billed_amount - pc.paid_amount, 0)
            else 0
          end
        ),
        0
      ) as overdue_0_7_amount,
      coalesce(
        sum(
          case
            when greatest(pc.billed_amount - pc.paid_amount, 0) > 0
             and pc.has_overdue
             and pc.open_due_date is not null
             and pc.open_due_date <= current_date
             and current_date - pc.open_due_date between 8 and 30
            then greatest(pc.billed_amount - pc.paid_amount, 0)
            else 0
          end
        ),
        0
      ) as overdue_8_30_amount,
      coalesce(
        sum(
          case
            when greatest(pc.billed_amount - pc.paid_amount, 0) > 0
             and pc.has_overdue
             and pc.open_due_date is not null
             and pc.open_due_date <= current_date
             and current_date - pc.open_due_date >= 31
            then greatest(pc.billed_amount - pc.paid_amount, 0)
            else 0
          end
        ),
        0
      ) as overdue_30_plus_amount,
      coalesce(
        sum(
          case
            when greatest(pc.billed_amount - pc.paid_amount, 0) > 0
             and pc.cycle_month = date_trunc('month', current_date::timestamp)
            then greatest(pc.billed_amount - pc.paid_amount, 0)
            else 0
          end
        ),
        0
      ) as outstanding_current_month,
      coalesce(
        sum(
          case
            when greatest(pc.billed_amount - pc.paid_amount, 0) > 0
             and pc.cycle_month = date_trunc('month', current_date::timestamp - interval '1 month')
            then greatest(pc.billed_amount - pc.paid_amount, 0)
            else 0
          end
        ),
        0
      ) as outstanding_previous_month
    from payment_cycles pc
  ),
  maintenance as (
    select
      (
        select count(*)
        from scoped_requests
        where status_norm in ('open', 'in_progress', 'waiting', 'otwarte', 'w trakcie', 'oczekuje')
      ) as open_requests,
      (
        select count(*)
        from scoped_requests
        where status_norm in ('open', 'in_progress', 'waiting', 'otwarte', 'w trakcie', 'oczekuje')
          and priority_norm in ('high', 'critical', 'wysoki', 'krytyczny')
      ) as high_priority_open_requests,
      (
        select count(*)
        from scoped_requests
        where status_norm = 'waiting'
          and created_at <= now() - interval '48 hours'
      ) as waiting_over_48h,
      (
        select count(*)
        from scoped_work_orders
        where status_norm in ('assigned', 'in_progress', 'blocked', 'przypisane', 'w trakcie', 'zablokowane')
      ) as active_work_orders,
      (
        select count(*)
        from scoped_work_orders
        where status_norm in ('assigned', 'in_progress', 'blocked', 'przypisane', 'w trakcie', 'zablokowane')
          and contractor_user_id is null
      ) as work_orders_without_contractor,
      (
        select count(*)
        from scoped_work_orders
        where status_norm in ('assigned', 'in_progress', 'blocked', 'przypisane', 'w trakcie', 'zablokowane')
          and (contractor_user_id is not null or nullif(coalesce(contractor_name, ''), '') is not null)
          and acknowledgement_due_at is not null
          and acknowledgement_due_at < now()
          and acknowledgement_status_norm <> 'acknowledged'
          and acknowledged_at is null
      ) as contractor_ack_overdue,
      (
        select count(*)
        from scoped_work_orders
        where status_norm in ('in_progress', 'w trakcie', 'blocked', 'zablokowane')
          and coalesce(updated_at, created_at) <= now() - interval '72 hours'
      ) as stalled_repairs,
      (
        select count(*)
        from scoped_work_orders
        where status_norm in ('assigned', 'in_progress', 'blocked', 'przypisane', 'w trakcie', 'zablokowane')
          and created_at <= now() - interval '14 days'
      ) as long_running_repairs,
      (select count(*) from repeat_repair_properties) as repeat_repair_properties,
      (
        select count(*)
        from scoped_requests
        where created_at >= now() - interval '7 days'
      ) as recent_open_created,
      (
        select count(*)
        from scoped_requests
        where created_at < now() - interval '7 days'
          and created_at >= now() - interval '14 days'
      ) as prev_open_created
  )
  select
    (select count(*) from scoped_properties) as property_count,
    (select count(*) from occupied_properties) as occupied_count,
    greatest((select count(*) from scoped_properties) - (select count(*) from occupied_properties), 0) as vacant_count,
    case
      when (select count(*) from scoped_properties) = 0 then 0
      else round(
        ((select count(*) from occupied_properties)::numeric / (select count(*) from scoped_properties)::numeric) * 100
      )::int
    end as occupancy_rate,
    finance.paid_amount,
    finance.due_amount,
    finance.overdue_amount,
    finance.due_soon_amount,
    finance.outstanding_amount,
    finance.overdue_0_7_amount,
    finance.overdue_8_30_amount,
    finance.overdue_30_plus_amount,
    maintenance.open_requests,
    maintenance.high_priority_open_requests,
    maintenance.waiting_over_48h,
    maintenance.active_work_orders,
    maintenance.work_orders_without_contractor,
    maintenance.contractor_ack_overdue,
    maintenance.stalled_repairs,
    maintenance.long_running_repairs,
    maintenance.repeat_repair_properties,
    maintenance.recent_open_created,
    maintenance.prev_open_created,
    finance.outstanding_current_month,
    finance.outstanding_previous_month
  from finance, maintenance;
$$;


ALTER FUNCTION "public"."portfolio_health_snapshot"("p_account_id" "uuid", "p_tenant_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."portfolio_weekly_summary"("p_account_id" "uuid") RETURNS TABLE("occupancy_rate" integer, "open_requests" bigint, "waiting_over_48h" bigint, "overdue_balance" numeric)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with authz as (
    select public.assert_manage_account_access(p_account_id) as account_id
  ),
  props as (
    select p.id
    from properties p
    cross join authz a
    where p.account_id = a.account_id
  ),
  occupied as (
    select p.id
    from props p
    where exists (
      select 1 from tenants t where t.property_id = p.id
    )
  ),
  req as (
    select status, created_at
    from maintenance_requests
    where account_id = p_account_id
  ),
  pay as (
    select amount, status, due_date
    from payments
    where account_id = p_account_id
  )
  select
    case
      when (select count(*) from props) = 0 then 0
      else round(((select count(*) from occupied)::numeric / (select count(*) from props)::numeric) * 100)::int
    end as occupancy_rate,
    (select count(*) from req where lower(coalesce(status, '')) <> 'closed') as open_requests,
    (
      select count(*)
      from req
      where lower(coalesce(status, '')) = 'waiting'
        and created_at <= now() - interval '48 hours'
    ) as waiting_over_48h,
    (
      select coalesce(sum(amount), 0)
      from pay
      where (
          lower(coalesce(status, '')) in ('overdue', 'zalegle', 'zaległe', 'due', 'oczekujace', 'oczekujące', 'pending')
        )
        and (
          lower(coalesce(status, '')) in ('overdue', 'zalegle', 'zaległe')
          or due_date < now()::date
        )
    ) as overdue_balance;
$$;


ALTER FUNCTION "public"."portfolio_weekly_summary"("p_account_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."prepare_document_packet_signature"("p_packet_id" "uuid", "p_signature_provider" "text" DEFAULT NULL::"text", "p_signature_template_id" "text" DEFAULT NULL::"text", "p_actor_user_id" "uuid" DEFAULT "auth"."uid"()) RETURNS "public"."document_packets"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor uuid := auth.uid();
  v_packet public.document_packets;
  v_settings public.document_signature_provider_settings;
  v_provider text;
  v_template_id text;
begin
  if v_actor is null then raise exception 'Not authenticated'; end if;
  if p_actor_user_id is not null and p_actor_user_id <> v_actor then raise exception 'Actor mismatch'; end if;

  select * into v_packet
  from public.document_packets
  where id = p_packet_id;
  if not found then raise exception 'Packet not found'; end if;
  if not public.can_manage_document_packets(v_packet.account_id, v_actor) then raise exception 'Not permitted'; end if;
  if v_packet.status in ('completed', 'voided') then raise exception 'Packet cannot be prepared for signing from current status'; end if;

  select * into v_settings
  from public.document_signature_provider_settings
  where account_id = v_packet.account_id
    and is_enabled = true;
  if not found then raise exception 'Signature provider is not configured'; end if;

  v_provider := lower(trim(coalesce(p_signature_provider, v_settings.provider)));
  if v_provider <> v_settings.provider then raise exception 'Signature provider mismatch'; end if;

  v_template_id := nullif(trim(coalesce(p_signature_template_id, v_settings.default_signature_template_id, '')), '');
  if v_template_id is null then raise exception 'Signature template id is required'; end if;

  update public.document_packets
  set signature_provider = v_provider,
      signature_template_id = v_template_id,
      signature_status = 'ready',
      signature_error = null,
      signature_synced_at = now()
  where id = p_packet_id
  returning * into v_packet;

  insert into public.document_packet_events (
    account_id,
    packet_id,
    actor_user_id,
    event_type,
    message,
    metadata
  )
  values (
    v_packet.account_id,
    v_packet.id,
    v_actor,
    'signature_ready',
    'Agreement packet prepared for external signing',
    jsonb_build_object('provider', v_provider, 'signature_template_id', v_template_id)
  );

  return v_packet;
end;
$$;


ALTER FUNCTION "public"."prepare_document_packet_signature"("p_packet_id" "uuid", "p_signature_provider" "text", "p_signature_template_id" "text", "p_actor_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."prevent_closing_if_work_order_open"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
begin
  -- Status values are canonical English codes; locale labels are presentation-only.
  if lower(new.status) = 'closed' then
    if exists (
      select 1
      from work_orders
      where maintenance_request_id = new.id
        and status != 'completed'
    ) then
      raise exception 'Cannot close request while work order is not completed';
    end if;
  end if;

  return new;
end;
$$;


ALTER FUNCTION "public"."prevent_closing_if_work_order_open"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."prevent_closing_request_with_open_work_orders"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
begin
  if new.status = 'closed'
     and coalesce(old.status, '') is distinct from 'closed' then

    if exists (
      select 1
      from public.work_orders wo
      where wo.maintenance_request_id = new.id
        and coalesce(wo.status, '') not in ('completed', 'cancelled')
    ) then
      raise exception 'Cannot close maintenance request while linked work orders are not completed or cancelled.';
    end if;

  end if;

  return new;
end;
$$;


ALTER FUNCTION "public"."prevent_closing_request_with_open_work_orders"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."prevent_ledger_update_delete"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
begin
  if current_setting('oasis.allow_ledger_sync', true) = 'on' then
    return coalesce(new, old);
  end if;

  raise exception
    'ledger_entries is append-only. Use reversal entries instead.';
end;
$$;


ALTER FUNCTION "public"."prevent_ledger_update_delete"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."preventive_maintenance_attention"("p_account_id" "uuid", "p_due_soon_days" integer DEFAULT 14, "p_limit" integer DEFAULT 25) RETURNS TABLE("item_key" "text", "item_type" "text", "property_id" "uuid", "property_label" "text", "title" "text", "category" "text", "next_due_date" "date", "days_until_due" integer, "assigned_to_label" "text", "link_path" "text", "sort_order" integer)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with cfg as (
    select
      greatest(1, least(coalesce(p_due_soon_days, 14), 90)) as due_soon_days,
      greatest(1, least(coalesce(p_limit, 25), 200)) as max_items
  ),
  authz as (
    select public.assert_manage_account_access(p_account_id) as account_id
  ),
  scoped_tasks as (
    select
      t.id,
      t.property_id,
      coalesce(p.address, '—') as property_label,
      t.title,
      t.category,
      t.next_due_date,
      (t.next_due_date - current_date)::int as days_until_due,
      coalesce(c.name, '') as assigned_to_label
    from public.preventive_maintenance_tasks t
    cross join authz a
    left join public.properties p on p.id = t.property_id
    left join public.contractors c on c.id = t.assigned_to_contractor_id
    where t.account_id = a.account_id
      and lower(coalesce(t.status, 'active')) = 'active'
  ),
  items as (
    select
      'preventive-overdue-' || st.id::text as item_key,
      'preventive_task_overdue'::text as item_type,
      st.property_id,
      st.property_label,
      st.title,
      st.category,
      st.next_due_date,
      st.days_until_due,
      st.assigned_to_label,
      ('/properties/' || st.property_id::text)::text as link_path,
      20 as sort_order
    from scoped_tasks st
    where st.next_due_date < current_date

    union all

    select
      'preventive-due-soon-' || st.id::text,
      'preventive_task_due_soon'::text,
      st.property_id,
      st.property_label,
      st.title,
      st.category,
      st.next_due_date,
      st.days_until_due,
      st.assigned_to_label,
      ('/properties/' || st.property_id::text)::text,
      40 as sort_order
    from scoped_tasks st, cfg
    where st.next_due_date >= current_date
      and st.next_due_date <= current_date + (cfg.due_soon_days || ' days')::interval
  )
  select
    i.item_key,
    i.item_type,
    i.property_id,
    i.property_label,
    i.title,
    i.category,
    i.next_due_date,
    i.days_until_due,
    i.assigned_to_label,
    i.link_path,
    i.sort_order
  from items i
  order by i.sort_order, i.next_due_date asc nulls last, i.title, i.item_key
  limit (select max_items from cfg);
$$;


ALTER FUNCTION "public"."preventive_maintenance_attention"("p_account_id" "uuid", "p_due_soon_days" integer, "p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."preventive_maintenance_next_due_date"("p_frequency" "text", "p_frequency_interval_days" integer, "p_completed_at" "date") RETURNS "date"
    LANGUAGE "sql" IMMUTABLE
    AS $$
  select
    case lower(coalesce(p_frequency, 'quarterly'))
      when 'monthly' then (p_completed_at + interval '1 month')::date
      when 'quarterly' then (p_completed_at + interval '3 months')::date
      when 'yearly' then (p_completed_at + interval '1 year')::date
      when 'custom' then (p_completed_at + (greatest(coalesce(p_frequency_interval_days, 1), 1) || ' days')::interval)::date
      else (p_completed_at + interval '3 months')::date
    end
$$;


ALTER FUNCTION "public"."preventive_maintenance_next_due_date"("p_frequency" "text", "p_frequency_interval_days" integer, "p_completed_at" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."property_operational_health_snapshot"("p_account_id" "uuid", "p_property_id" "uuid" DEFAULT NULL::"uuid", "p_limit" integer DEFAULT 200) RETURNS TABLE("property_id" "uuid", "property_label" "text", "score" integer, "category" "text", "reasons" "jsonb", "overdue_rent_amount" numeric, "open_request_count" bigint, "active_work_order_count" bigint, "stalled_repair_count" bigint, "ack_overdue_count" bigint, "long_running_repair_count" bigint, "requests_90_count" bigint, "overdue_preventive_count" bigint, "due_soon_preventive_count" bigint, "overdue_compliance_count" bigint, "due_soon_compliance_count" bigint, "missing_compliance_count" bigint, "expired_lease_count" bigint, "expiring_lease_count" bigint, "renewal_in_progress_count" bigint, "recent_operating_expenses" numeric, "recent_maintenance_cost" numeric, "tenant_count" bigint)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with recommended_compliance(category) as (
    values
      ('gas_safety'::text),
      ('epc_expiry'::text),
      ('insurance_renewal'::text),
      ('electrical_inspection'::text),
      ('fire_alarm_inspection'::text),
      ('smoke_alarm_check'::text),
      ('landlord_licensing'::text)
  ),
  authz as (
    select public.assert_manage_account_access(p_account_id) as account_id
  ),
  scoped_properties as (
    select
      p.id,
      coalesce(p.address, '') as property_label,
      coalesce(p.rent, 0)::numeric as monthly_rent
    from public.properties p
    cross join authz a
    where p.account_id = a.account_id
      and (p_property_id is null or p.id = p_property_id)
    order by p.address asc
    limit greatest(coalesce(p_limit, 200), 1)
  ),
  payment_signals as (
    select
      sp.id as property_id,
      coalesce(sum(
        case
          when pay.paid_at is null
           and (
             lower(coalesce(pay.status, '')) in ('overdue', 'zaległe', 'zalegle')
             or (pay.due_date is not null and pay.due_date < current_date)
           )
          then coalesce(pay.amount, 0)
          else 0
        end
      ), 0)::numeric as overdue_rent_amount
    from scoped_properties sp
    left join public.payments pay
      on pay.account_id = p_account_id
     and pay.property_id = sp.id
    group by sp.id
  ),
  request_signals as (
    select
      sp.id as property_id,
      count(*) filter (
        where lower(coalesce(r.status, '')) in ('open', 'in_progress', 'waiting', 'otwarte', 'w trakcie', 'oczekuje')
      )::bigint as open_request_count,
      count(*) filter (
        where r.created_at >= now() - interval '90 days'
      )::bigint as requests_90_count
    from scoped_properties sp
    left join public.maintenance_requests r
      on r.account_id = p_account_id
     and r.property_id = sp.id
    group by sp.id
  ),
  work_order_signals as (
    select
      sp.id as property_id,
      count(*) filter (
        where lower(coalesce(w.status, '')) in ('assigned', 'in_progress', 'blocked', 'przypisane', 'w trakcie', 'zablokowane')
      )::bigint as active_work_order_count,
      count(*) filter (
        where lower(coalesce(w.status, '')) in ('in_progress', 'w trakcie', 'blocked', 'zablokowane')
          and coalesce(w.updated_at, w.created_at) <= now() - interval '5 days'
      )::bigint as stalled_repair_count,
      count(*) filter (
        where lower(coalesce(w.status, '')) in ('assigned', 'in_progress', 'blocked', 'przypisane', 'w trakcie', 'zablokowane')
          and coalesce(lower(w.acknowledgement_status), 'pending') not in ('acknowledged', 'not_required')
          and w.acknowledgement_due_at is not null
          and w.acknowledgement_due_at < now()
      )::bigint as ack_overdue_count,
      count(*) filter (
        where lower(coalesce(w.status, '')) in ('assigned', 'in_progress', 'blocked', 'przypisane', 'w trakcie', 'zablokowane')
          and w.created_at <= now() - interval '14 days'
      )::bigint as long_running_repair_count,
      coalesce(sum(
        case
          when coalesce(w.updated_at, w.created_at) >= now() - interval '90 days'
          then coalesce(w.invoice_amount, 0)
          else 0
        end
      ), 0)::numeric as recent_maintenance_cost
    from scoped_properties sp
    left join public.work_orders w
      on w.account_id = p_account_id
     and w.property_id = sp.id
    group by sp.id
  ),
  preventive_signals as (
    select
      sp.id as property_id,
      count(*) filter (
        where lower(coalesce(t.status, '')) = 'active'
          and t.next_due_date < current_date
      )::bigint as overdue_preventive_count,
      count(*) filter (
        where lower(coalesce(t.status, '')) = 'active'
          and t.next_due_date >= current_date
          and t.next_due_date <= current_date + 14
      )::bigint as due_soon_preventive_count
    from scoped_properties sp
    left join public.preventive_maintenance_tasks t
      on t.account_id = p_account_id
     and t.property_id = sp.id
    group by sp.id
  ),
  compliance_signals as (
    select
      sp.id as property_id,
      count(*) filter (
        where lower(coalesce(c.status, '')) not in ('completed', 'cancelled')
          and c.due_date < current_date
      )::bigint as overdue_compliance_count,
      count(*) filter (
        where lower(coalesce(c.status, '')) not in ('completed', 'cancelled')
          and c.due_date >= current_date
          and c.due_date <= current_date + greatest(coalesce(c.reminder_window_days, 30), 0)
      )::bigint as due_soon_compliance_count
    from scoped_properties sp
    left join public.compliance_items c
      on c.account_id = p_account_id
     and c.property_id = sp.id
    group by sp.id
  ),
  missing_compliance_signals as (
    select
      sp.id as property_id,
      case
        when count(ci.id) filter (
          where lower(coalesce(ci.status, '')) not in ('completed', 'cancelled')
        ) = 0 then 1::bigint
        else greatest(
          count(rc.category)::bigint -
          count(distinct case
            when lower(coalesce(ci.status, '')) not in ('completed', 'cancelled') then lower(coalesce(ci.category, ''))
            else null
          end)::bigint,
          0::bigint
        )
      end as missing_compliance_count
    from scoped_properties sp
    cross join recommended_compliance rc
    left join public.compliance_items ci
      on ci.account_id = p_account_id
     and ci.property_id = sp.id
    group by sp.id
  ),
  lease_signals as (
    select
      sp.id as property_id,
      count(*) filter (
        where (
          lower(coalesce(l.renewal_status, '')) = 'ended'
          or l.lease_end_date < current_date
        )
        and lower(coalesce(l.renewal_status, '')) <> 'renewed'
      )::bigint as expired_lease_count,
      count(*) filter (
        where lower(coalesce(l.renewal_status, '')) not in ('ended', 'renewed')
          and l.lease_end_date >= current_date
          and l.lease_end_date <= current_date + 60
      )::bigint as expiring_lease_count,
      count(*) filter (
        where lower(coalesce(l.renewal_status, '')) = 'renewal_in_progress'
      )::bigint as renewal_in_progress_count
    from scoped_properties sp
    left join public.leases l
      on l.account_id = p_account_id
     and l.property_id = sp.id
    group by sp.id
  ),
  tenant_signals as (
    select
      sp.id as property_id,
      count(t.id)::bigint as tenant_count
    from scoped_properties sp
    left join public.tenants t
      on t.account_id = p_account_id
     and t.property_id = sp.id
    group by sp.id
  ),
  expense_signals as (
    select
      sp.id as property_id,
      coalesce(sum(
        case
          when e.expense_date >= current_date - 90 then coalesce(e.amount, 0)
          else 0
        end
      ), 0)::numeric as recent_operating_expenses
    from scoped_properties sp
    left join public.property_operating_expenses e
      on e.account_id = p_account_id
     and e.property_id = sp.id
    group by sp.id
  ),
  assembled as (
    select
      sp.id as property_id,
      sp.property_label,
      sp.monthly_rent,
      coalesce(pay.overdue_rent_amount, 0)::numeric as overdue_rent_amount,
      coalesce(req.open_request_count, 0)::bigint as open_request_count,
      coalesce(wo.active_work_order_count, 0)::bigint as active_work_order_count,
      coalesce(wo.stalled_repair_count, 0)::bigint as stalled_repair_count,
      coalesce(wo.ack_overdue_count, 0)::bigint as ack_overdue_count,
      coalesce(wo.long_running_repair_count, 0)::bigint as long_running_repair_count,
      coalesce(req.requests_90_count, 0)::bigint as requests_90_count,
      coalesce(pm.overdue_preventive_count, 0)::bigint as overdue_preventive_count,
      coalesce(pm.due_soon_preventive_count, 0)::bigint as due_soon_preventive_count,
      coalesce(cs.overdue_compliance_count, 0)::bigint as overdue_compliance_count,
      coalesce(cs.due_soon_compliance_count, 0)::bigint as due_soon_compliance_count,
      coalesce(mc.missing_compliance_count, 0)::bigint as missing_compliance_count,
      coalesce(ls.expired_lease_count, 0)::bigint as expired_lease_count,
      coalesce(ls.expiring_lease_count, 0)::bigint as expiring_lease_count,
      coalesce(ls.renewal_in_progress_count, 0)::bigint as renewal_in_progress_count,
      coalesce(es.recent_operating_expenses, 0)::numeric as recent_operating_expenses,
      coalesce(wo.recent_maintenance_cost, 0)::numeric as recent_maintenance_cost,
      coalesce(ts.tenant_count, 0)::bigint as tenant_count
    from scoped_properties sp
    left join payment_signals pay on pay.property_id = sp.id
    left join request_signals req on req.property_id = sp.id
    left join work_order_signals wo on wo.property_id = sp.id
    left join preventive_signals pm on pm.property_id = sp.id
    left join compliance_signals cs on cs.property_id = sp.id
    left join missing_compliance_signals mc on mc.property_id = sp.id
    left join lease_signals ls on ls.property_id = sp.id
    left join tenant_signals ts on ts.property_id = sp.id
    left join expense_signals es on es.property_id = sp.id
  ),
  scored as (
    select
      a.*,
      greatest(
        0,
        100
        - (
          case
            when a.overdue_rent_amount > 0 and a.monthly_rent > 0 and a.overdue_rent_amount >= a.monthly_rent then 30
            when a.overdue_rent_amount > 0 then 22
            else 0
          end
          + case
              when (a.open_request_count + a.active_work_order_count) >= 4 then 10
              when (a.open_request_count + a.active_work_order_count) >= 2 then 6
              when (a.open_request_count + a.active_work_order_count) > 0 then 3
              else 0
            end
          + least(18, a.stalled_repair_count * 9)
          + least(16, a.ack_overdue_count * 8)
          + least(12, a.long_running_repair_count * 6)
          + case when a.requests_90_count >= 3 then 8 else 0 end
          + case
              when a.overdue_preventive_count > 0 then 8
              when a.due_soon_preventive_count > 0 then 3
              else 0
            end
          + case
              when a.overdue_compliance_count > 0 then 12
              when a.due_soon_compliance_count > 0 then 4
              else 0
            end
          + case when a.missing_compliance_count > 0 then 6 else 0 end
          + case
              when a.expired_lease_count > 0 then 15
              when a.expiring_lease_count > 0 then 6
              when a.renewal_in_progress_count > 0 then 4
              else 0
            end
          + case
              when a.monthly_rent > 0 and (a.recent_operating_expenses + a.recent_maintenance_cost) >= (a.monthly_rent * 2) then 6
              else 0
            end
          + case when a.tenant_count = 0 then 4 else 0 end
        )
      )::integer as score
    from assembled a
  )
  select
    s.property_id,
    s.property_label,
    s.score,
    case
      when s.score >= 85 then 'healthy'
      when s.score >= 60 then 'attention_needed'
      else 'high_risk'
    end as category,
    (
      select coalesce(jsonb_agg(reason order by (reason->>'penalty')::int desc), '[]'::jsonb)
      from (
        select jsonb_build_object('key', 'overdue_rent', 'penalty',
          case
            when s.overdue_rent_amount > 0 and s.monthly_rent > 0 and s.overdue_rent_amount >= s.monthly_rent then 30
            else 22
          end,
          'amount', s.overdue_rent_amount
        ) as reason
        where s.overdue_rent_amount > 0

        union all
        select jsonb_build_object('key', 'maintenance_pressure', 'penalty',
          case
            when (s.open_request_count + s.active_work_order_count) >= 4 then 10
            when (s.open_request_count + s.active_work_order_count) >= 2 then 6
            else 3
          end,
          'count', (s.open_request_count + s.active_work_order_count)
        )
        where (s.open_request_count + s.active_work_order_count) > 0

        union all
        select jsonb_build_object('key', 'stalled_repairs', 'penalty', least(18, s.stalled_repair_count * 9), 'count', s.stalled_repair_count)
        where s.stalled_repair_count > 0

        union all
        select jsonb_build_object('key', 'contractor_ack_overdue', 'penalty', least(16, s.ack_overdue_count * 8), 'count', s.ack_overdue_count)
        where s.ack_overdue_count > 0

        union all
        select jsonb_build_object('key', 'long_running_repairs', 'penalty', least(12, s.long_running_repair_count * 6), 'count', s.long_running_repair_count)
        where s.long_running_repair_count > 0

        union all
        select jsonb_build_object('key', 'repeat_repairs', 'penalty', 8, 'count', s.requests_90_count)
        where s.requests_90_count >= 3

        union all
        select jsonb_build_object('key', 'preventive_overdue', 'penalty', 8, 'count', s.overdue_preventive_count)
        where s.overdue_preventive_count > 0

        union all
        select jsonb_build_object('key', 'preventive_due_soon', 'penalty', 3, 'count', s.due_soon_preventive_count)
        where s.overdue_preventive_count = 0 and s.due_soon_preventive_count > 0

        union all
        select jsonb_build_object('key', 'compliance_overdue', 'penalty', 12, 'count', s.overdue_compliance_count)
        where s.overdue_compliance_count > 0

        union all
        select jsonb_build_object('key', 'compliance_due_soon', 'penalty', 4, 'count', s.due_soon_compliance_count)
        where s.overdue_compliance_count = 0 and s.due_soon_compliance_count > 0

        union all
        select jsonb_build_object('key', 'compliance_missing_setup', 'penalty', 6, 'count', s.missing_compliance_count)
        where s.missing_compliance_count > 0

        union all
        select jsonb_build_object('key', 'lease_expired', 'penalty', 15)
        where s.expired_lease_count > 0

        union all
        select jsonb_build_object('key', 'lease_expiring', 'penalty', 6)
        where s.expired_lease_count = 0 and s.expiring_lease_count > 0

        union all
        select jsonb_build_object('key', 'lease_renewal_in_progress', 'penalty', 4)
        where s.expired_lease_count = 0 and s.expiring_lease_count = 0 and s.renewal_in_progress_count > 0

        union all
        select jsonb_build_object('key', 'operating_cost_pressure', 'penalty', 6, 'amount', (s.recent_operating_expenses + s.recent_maintenance_cost))
        where s.monthly_rent > 0 and (s.recent_operating_expenses + s.recent_maintenance_cost) >= (s.monthly_rent * 2)

        union all
        select jsonb_build_object('key', 'vacant_property', 'penalty', 4)
        where s.tenant_count = 0
      ) reasons(reason)
    ) as reasons,
    s.overdue_rent_amount,
    s.open_request_count,
    s.active_work_order_count,
    s.stalled_repair_count,
    s.ack_overdue_count,
    s.long_running_repair_count,
    s.requests_90_count,
    s.overdue_preventive_count,
    s.due_soon_preventive_count,
    s.overdue_compliance_count,
    s.due_soon_compliance_count,
    s.missing_compliance_count,
    s.expired_lease_count,
    s.expiring_lease_count,
    s.renewal_in_progress_count,
    s.recent_operating_expenses,
    s.recent_maintenance_cost,
    s.tenant_count
  from scored s
  order by s.score asc, s.property_label asc;
$$;


ALTER FUNCTION "public"."property_operational_health_snapshot"("p_account_id" "uuid", "p_property_id" "uuid", "p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."purge_demo_account_fixtures"("p_account_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  perform public.sandbox_exec_if_relation_exists(
    'public.document_packet_events',
    format('delete from public.document_packet_events where account_id = %L::uuid', p_account_id)
  );
  perform public.sandbox_exec_if_relation_exists(
    'public.document_packet_recipients',
    format('delete from public.document_packet_recipients where account_id = %L::uuid', p_account_id)
  );
  perform public.sandbox_exec_if_relation_exists(
    'public.document_packets',
    format('delete from public.document_packets where account_id = %L::uuid', p_account_id)
  );
  perform public.sandbox_exec_if_relation_exists(
    'public.document_request_uploads',
    format('delete from public.document_request_uploads where account_id = %L::uuid', p_account_id)
  );
  perform public.sandbox_exec_if_relation_exists(
    'public.document_requests',
    format('delete from public.document_requests where account_id = %L::uuid', p_account_id)
  );
  perform public.sandbox_exec_if_relation_exists(
    'public.documents',
    format('delete from public.documents where account_id = %L::uuid', p_account_id)
  );
  perform public.sandbox_exec_if_relation_exists(
    'public.notifications',
    format('delete from public.notifications where account_id = %L::uuid', p_account_id)
  );
  perform public.sandbox_exec_if_relation_exists(
    'public.automation_execution_log',
    format('delete from public.automation_execution_log where account_id = %L::uuid', p_account_id)
  );
  perform public.sandbox_exec_if_relation_exists(
    'public.payment_events',
    format('delete from public.payment_events where account_id = %L::uuid', p_account_id)
  );

  delete from public.work_orders where account_id = p_account_id;
  delete from public.maintenance_requests where account_id = p_account_id;
  delete from public.leases where account_id = p_account_id;
  delete from public.compliance_items where account_id = p_account_id;
  delete from public.property_operating_expenses where account_id = p_account_id;
  delete from public.property_financial_profiles where account_id = p_account_id;
  delete from public.payments where account_id = p_account_id;
  delete from public.contractors where account_id = p_account_id;
  delete from public.tenants where account_id = p_account_id;
  delete from public.properties where account_id = p_account_id;
end;
$$;


ALTER FUNCTION "public"."purge_demo_account_fixtures"("p_account_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."record_api_rate_limit_attempt"("p_surface" "text", "p_account_id" "uuid" DEFAULT NULL::"uuid", "p_actor_user_id" "uuid" DEFAULT NULL::"uuid", "p_identifier_hash" "text" DEFAULT NULL::"text", "p_window_seconds" integer DEFAULT 3600, "p_max_attempts" integer DEFAULT 10, "p_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_surface text := nullif(trim(coalesce(p_surface, '')), '');
  v_identifier_hash text := nullif(trim(coalesce(p_identifier_hash, '')), '');
  v_window_seconds integer := greatest(coalesce(p_window_seconds, 3600), 1);
  v_max_attempts integer := greatest(coalesce(p_max_attempts, 10), 1);
  v_metadata jsonb := coalesce(p_metadata, '{}'::jsonb);
  v_attempt_count integer;
  v_allowed boolean;
  v_retry_after_seconds integer := 0;
  v_correlation_id text := nullif(v_metadata->>'correlation_id', '');
begin
  if v_surface is null then
    raise exception 'surface is required'
      using errcode = '22023';
  end if;

  perform pg_advisory_xact_lock(
    hashtext(v_surface),
    hashtext(
      coalesce(p_account_id::text, 'global')
      || ':' || coalesce(p_actor_user_id::text, 'actorless')
      || ':' || coalesce(v_identifier_hash, 'identifierless')
    )
  );

  select count(*)::integer + 1
    into v_attempt_count
  from public.api_rate_limit_events e
  where e.surface = v_surface
    and e.created_at >= now() - make_interval(secs => v_window_seconds)
    and e.account_id is not distinct from p_account_id
    and e.actor_user_id is not distinct from p_actor_user_id
    and e.identifier_hash is not distinct from v_identifier_hash;

  v_allowed := v_attempt_count <= v_max_attempts;

  if not v_allowed then
    select greatest(
      1,
      ceil(extract(epoch from (min(e.created_at) + make_interval(secs => v_window_seconds) - now())))::integer
    )
      into v_retry_after_seconds
    from public.api_rate_limit_events e
    where e.surface = v_surface
      and e.created_at >= now() - make_interval(secs => v_window_seconds)
      and e.account_id is not distinct from p_account_id
      and e.actor_user_id is not distinct from p_actor_user_id
      and e.identifier_hash is not distinct from v_identifier_hash;
  end if;

  insert into public.api_rate_limit_events (
    account_id,
    actor_user_id,
    surface,
    identifier_hash,
    window_seconds,
    max_attempts,
    attempt_count,
    allowed,
    metadata
  )
  values (
    p_account_id,
    p_actor_user_id,
    v_surface,
    v_identifier_hash,
    v_window_seconds,
    v_max_attempts,
    v_attempt_count,
    v_allowed,
    v_metadata
  );

  if not v_allowed then
    insert into public.security_observability_events (
      account_id,
      actor_user_id,
      actor_role,
      category,
      kind,
      surface,
      reason,
      outcome,
      code,
      guard_denied,
      correlation_id,
      source,
      metadata
    )
    values (
      p_account_id,
      p_actor_user_id,
      'edge_function',
      'api_rate_limit',
      'authorization_denied',
      v_surface,
      'rate_limit_exceeded',
      'denied',
      '429',
      true,
      v_correlation_id,
      'edge_function',
      jsonb_strip_nulls(
        jsonb_build_object(
          'window_seconds', v_window_seconds,
          'max_attempts', v_max_attempts,
          'attempt_count', v_attempt_count,
          'retry_after_seconds', v_retry_after_seconds,
          'limit_scope', v_metadata->>'limit_scope'
        )
      )
    );
  end if;

  return jsonb_build_object(
    'allowed', v_allowed,
    'surface', v_surface,
    'attempt_count', v_attempt_count,
    'max_attempts', v_max_attempts,
    'window_seconds', v_window_seconds,
    'retry_after_seconds', v_retry_after_seconds
  );
end;
$$;


ALTER FUNCTION "public"."record_api_rate_limit_attempt"("p_surface" "text", "p_account_id" "uuid", "p_actor_user_id" "uuid", "p_identifier_hash" "text", "p_window_seconds" integer, "p_max_attempts" integer, "p_metadata" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."record_auth_rate_limit_attempt"("p_email_hash" "text", "p_surface" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_email_hash     text    := nullif(trim(coalesce(p_email_hash, '')), '');
  v_surface        text    := nullif(trim(lower(coalesce(p_surface, ''))), '');
  v_window_seconds integer;
  v_max_attempts   integer;
  v_attempt_count  integer;
  v_allowed        boolean;
  v_retry_after    integer := 0;
begin
  -- Only permit known auth surfaces
  case v_surface
    when 'auth_login'  then v_window_seconds := 900;  v_max_attempts := 5;
    when 'auth_reset'  then v_window_seconds := 3600; v_max_attempts := 3;
    when 'auth_signup' then v_window_seconds := 3600; v_max_attempts := 10;
    when 'auth_invite' then v_window_seconds := 1800; v_max_attempts := 5;
    else
      raise exception 'Unknown auth surface: %', coalesce(p_surface, '(null)')
        using errcode = '22023';
  end case;

  if v_email_hash is null then
    raise exception 'email_hash is required'
      using errcode = '22023';
  end if;

  -- Advisory lock to prevent double-counting under concurrent requests
  perform pg_advisory_xact_lock(
    hashtext(v_surface),
    hashtext(v_email_hash)
  );

  -- Count recent attempts for this surface + identifier
  select count(*)::integer + 1
    into v_attempt_count
  from public.api_rate_limit_events e
  where e.surface          = v_surface
    and e.identifier_hash  = v_email_hash
    and e.actor_user_id    is null
    and e.account_id       is null
    and e.created_at       >= now() - make_interval(secs => v_window_seconds);

  v_allowed := v_attempt_count <= v_max_attempts;

  -- Compute retry-after when denied
  if not v_allowed then
    select greatest(
      1,
      ceil(
        extract(epoch from
          (min(e.created_at) + make_interval(secs => v_window_seconds) - now())
        )
      )::integer
    )
      into v_retry_after
    from public.api_rate_limit_events e
    where e.surface         = v_surface
      and e.identifier_hash = v_email_hash
      and e.actor_user_id   is null
      and e.account_id      is null
      and e.created_at      >= now() - make_interval(secs => v_window_seconds);
  end if;

  -- Record the attempt
  insert into public.api_rate_limit_events (
    surface, identifier_hash,
    window_seconds, max_attempts,
    attempt_count, allowed,
    metadata
  )
  values (
    v_surface, v_email_hash,
    v_window_seconds, v_max_attempts,
    v_attempt_count, v_allowed,
    jsonb_build_object('via', 'auth_rate_limit')
  );

  -- Log denied attempts to the security observability stream
  if not v_allowed then
    insert into public.security_observability_events (
      category, kind, surface, reason, outcome, code, guard_denied,
      source, metadata
    )
    values (
      'api_rate_limit',
      'authorization_denied',
      v_surface,
      'rate_limit_exceeded',
      'denied',
      '429',
      true,
      'auth_client',
      jsonb_build_object(
        'window_seconds',    v_window_seconds,
        'max_attempts',      v_max_attempts,
        'attempt_count',     v_attempt_count,
        'retry_after_seconds', v_retry_after
      )
    );
  end if;

  return jsonb_build_object(
    'allowed',              v_allowed,
    'surface',              v_surface,
    'attempt_count',        v_attempt_count,
    'max_attempts',         v_max_attempts,
    'window_seconds',       v_window_seconds,
    'retry_after_seconds',  v_retry_after
  );
end;
$$;


ALTER FUNCTION "public"."record_auth_rate_limit_attempt"("p_email_hash" "text", "p_surface" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."record_document_packet_signature_submission"("p_packet_id" "uuid", "p_provider" "text", "p_submission_id" "text", "p_signature_status" "text" DEFAULT 'pending'::"text") RETURNS "public"."document_packets"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_packet public.document_packets;
  v_status text := lower(trim(coalesce(p_signature_status, 'pending')));
  v_provider text := lower(trim(coalesce(p_provider, '')));
begin
  if coalesce(auth.role(), '') <> 'service_role' then raise exception 'Not permitted'; end if;
  if v_status not in ('requested', 'pending', 'completed', 'failed', 'cancelled') then raise exception 'Invalid signature status'; end if;
  if v_provider not in ('docuseal', 'opensign', 'libresign', 'manual') then raise exception 'Unsupported signature provider'; end if;
  if nullif(trim(coalesce(p_submission_id, '')), '') is null then raise exception 'signature_submission_id is required'; end if;

  select * into v_packet
  from public.document_packets
  where id = p_packet_id;
  if not found then raise exception 'Packet not found'; end if;
  if coalesce(v_packet.signature_provider, v_provider) <> v_provider then raise exception 'Signature provider mismatch'; end if;

  update public.document_packets
  set signature_provider = v_provider,
      signature_submission_id = trim(p_submission_id),
      signature_status = v_status,
      signature_requested_at = coalesce(signature_requested_at, now()),
      signature_synced_at = now(),
      signature_error = null,
      status = case when status = 'draft' then 'sent' else status end,
      sent_at = case when sent_at is null then now() else sent_at end
  where id = p_packet_id
  returning * into v_packet;

  update public.document_packet_recipients
  set status = case when status = 'pending' then 'sent' else status end
  where packet_id = p_packet_id;

  insert into public.document_packet_events (account_id, packet_id, event_type, message, metadata)
  values (
    v_packet.account_id,
    v_packet.id,
    'signature_requested',
    'External signature submission recorded',
    jsonb_build_object('provider', v_provider, 'signature_status', v_status)
  );

  return v_packet;
end;
$$;


ALTER FUNCTION "public"."record_document_packet_signature_submission"("p_packet_id" "uuid", "p_provider" "text", "p_submission_id" "text", "p_signature_status" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."record_own_strong_password"() RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_user_id uuid := auth.uid();
  v_account_id uuid;
begin
  if v_user_id is null then
    raise exception 'Not authenticated';
  end if;

  select account_id into v_account_id
  from public.account_members
  where user_id = v_user_id
  order by created_at
  limit 1;

  insert into public.user_security_profile (
    user_id, account_id,
    password_policy_version, password_strength_status,
    password_last_set_at
  )
  values (
    v_user_id, v_account_id,
    1, 'strong',
    now()
  )
  on conflict (user_id) do update
  set
    password_policy_version  = 1,
    password_strength_status = 'strong',
    password_last_set_at     = now(),
    updated_at               = now();

  if v_account_id is not null then
    perform public.log_security_event(
      v_account_id,
      'auth_password_policy_v1_accepted',
      'user',
      v_user_id,
      jsonb_build_object('policy_version', 1, 'flow', 'self')
    );
  end if;
end;
$$;


ALTER FUNCTION "public"."record_own_strong_password"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."record_security_denied_event"("p_event" "text", "p_account_id" "uuid" DEFAULT NULL::"uuid", "p_entity_type" "text" DEFAULT NULL::"text", "p_entity_id" "uuid" DEFAULT NULL::"uuid", "p_reason" "text" DEFAULT NULL::"text", "p_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor_user_id uuid := auth.uid();
  v_event text := lower(trim(coalesce(p_event, '')));
  v_reason text := lower(trim(coalesce(p_reason, '')));
  v_entity_type text := nullif(lower(trim(coalesce(p_entity_type, ''))), '');
  v_account_id uuid;
  v_metadata jsonb := coalesce(p_metadata, '{}'::jsonb);
  v_existing_id uuid;
  v_row_id uuid;
begin
  if v_actor_user_id is null then
    raise exception 'Not authenticated';
  end if;

  if nullif(v_event, '') is null then
    raise exception 'Missing event';
  end if;

  if nullif(v_reason, '') is null then
    raise exception 'Missing reason';
  end if;

  if jsonb_typeof(v_metadata) is distinct from 'object' then
    v_metadata := '{}'::jsonb;
  end if;

  v_metadata := jsonb_strip_nulls(
    v_metadata
      - 'token'
      - 'inviteToken'
      - 'email'
      - 'body'
      - 'fileName'
      - 'filename'
      - 'metadata'
      - 'originalFilename'
      - 'rawPayload'
      - 'accessToken'
      - 'password'
      - 'path'
      - 'signedUrl'
      - 'storagePath'
      - 'firstName'
      - 'first_name'
      - 'lastName'
      - 'last_name'
      - 'phone'
      - 'phoneNumber'
      - 'phone_number'
      - 'contactPhone'
      - 'contact_phone'
      - 'address'
      - 'propertyAddress'
      - 'property_address'
  );

  v_account_id := public.resolve_security_denied_event_account_id(
    p_account_id,
    v_entity_type,
    p_entity_id
  );

  if p_account_id is not null and v_account_id is distinct from p_account_id then
    raise exception 'Access denied';
  end if;

  if not public.actor_can_record_security_denied_event(v_account_id) then
    raise exception 'Access denied';
  end if;

  select sde.id
  into v_existing_id
  from public.security_denied_events sde
  where sde.actor_user_id = v_actor_user_id
    and sde.event = v_event
    and sde.reason = v_reason
    and sde.account_id is not distinct from v_account_id
    and sde.entity_type is not distinct from v_entity_type
    and sde.entity_id is not distinct from p_entity_id
    and sde.created_at >= now() - interval '30 seconds'
  order by sde.created_at desc
  limit 1;

  if v_existing_id is not null then
    return v_existing_id;
  end if;

  insert into public.security_denied_events (
    account_id,
    actor_user_id,
    actor_role,
    event,
    outcome,
    reason,
    entity_type,
    entity_id,
    metadata
  )
  values (
    v_account_id,
    v_actor_user_id,
    public.security_denied_event_actor_role(v_account_id),
    v_event,
    'denied',
    v_reason,
    v_entity_type,
    p_entity_id,
    v_metadata
  )
  returning id into v_row_id;

  return v_row_id;
end;
$$;


ALTER FUNCTION "public"."record_security_denied_event"("p_event" "text", "p_account_id" "uuid", "p_entity_type" "text", "p_entity_id" "uuid", "p_reason" "text", "p_metadata" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."record_security_denied_event"("p_event" "text", "p_account_id" "uuid", "p_entity_type" "text", "p_entity_id" "uuid", "p_reason" "text", "p_metadata" "jsonb") IS 'Durably records a small scrubbed denied-event after the original auth failure has already been returned to the caller in a separate transaction.';



CREATE OR REPLACE FUNCTION "public"."record_strong_password"("p_account_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_user_id uuid := auth.uid();
begin
  if v_user_id is null then
    raise exception 'Not authenticated';
  end if;

  -- Caller must be a member of the given account
  if not exists (
    select 1 from public.account_members
    where account_id = p_account_id
      and user_id    = v_user_id
  ) then
    raise exception 'Not a member of this account';
  end if;

  insert into public.user_security_profile (
    user_id, account_id,
    password_policy_version, password_strength_status,
    password_last_set_at
  )
  values (
    v_user_id, p_account_id,
    1, 'strong',
    now()
  )
  on conflict (user_id) do update
  set
    account_id              = p_account_id,
    password_policy_version = 1,
    password_strength_status = 'strong',
    password_last_set_at    = now(),
    updated_at              = now();

  -- Append to security audit trail
  perform public.log_security_event(
    p_account_id,
    'auth_password_policy_v1_accepted',
    'user',
    v_user_id,
    jsonb_build_object('policy_version', 1)
  );
end;
$$;


ALTER FUNCTION "public"."record_strong_password"("p_account_id" "uuid") OWNER TO "postgres";


