CREATE TABLE IF NOT EXISTS "public"."rental_applications" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "account_id" "uuid" NOT NULL,
    "property_id" "uuid" NOT NULL,
    "tenant_id" "uuid" NOT NULL,
    "status" "text" DEFAULT 'new'::"text" NOT NULL,
    "rejection_reason" "text",
    "score" numeric,
    "created_by" "uuid" DEFAULT "auth"."uid"(),
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "rental_applications_status_check" CHECK (("status" = ANY (ARRAY['new'::"text", 'screening'::"text", 'shortlisted'::"text", 'accepted_pending_signing'::"text", 'approved'::"text", 'rejected'::"text", 'withdrawn'::"text"])))
);


ALTER TABLE "public"."rental_applications" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."reject_application"("p_application_id" "uuid", "p_rejection_reason" "text" DEFAULT NULL::"text", "p_cancel_linked_draft_lease" boolean DEFAULT true) RETURNS "public"."rental_applications"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_app record;
  v_lease record;
  v_out public.rental_applications;
begin
  if p_application_id is null then
    raise exception 'application_id is required';
  end if;

  select a.* into v_app
  from public.rental_applications a
  where a.id = p_application_id;

  if not found then
    raise exception 'Application not found';
  end if;

  if public.account_role_for(v_app.account_id) not in ('owner','admin','staff') then
    raise exception 'Not permitted';
  end if;

  if v_app.status in ('withdrawn','rejected') then
    -- idempotent: return current row
    select * into v_out from public.rental_applications where id = p_application_id;
    return v_out;
  end if;

  if v_app.status = 'approved' then
    raise exception 'Cannot reject an approved application';
  end if;

  -- If there is an active lease for this application/property, block reject
  if exists (
    select 1
    from public.leases l
    where (l.application_id = v_app.id or l.property_id = v_app.property_id)
      and l.status = 'active'
  ) then
    raise exception 'Cannot reject: an active lease exists for this property/application';
  end if;

  -- Optionally cancel any linked draft lease
  if p_cancel_linked_draft_lease then
    select * into v_lease
    from public.leases l
    where l.application_id = v_app.id
    limit 1;

    if found and v_lease.status = 'draft' then
      update public.leases
      set status = 'cancelled',
          updated_at = now()
      where id = v_lease.id;

      -- OPTIONAL legacy unreserve: only clear tenant.property_id if it matches the property
      update public.tenants
      set property_id = null
      where id = v_app.tenant_id
        and property_id = v_app.property_id;
    end if;
  end if;

  update public.rental_applications
  set status = 'rejected',
      rejection_reason = p_rejection_reason,
      updated_at = now()
  where id = v_app.id
  returning * into v_out;

  return v_out;
end;
$$;


ALTER FUNCTION "public"."reject_application"("p_application_id" "uuid", "p_rejection_reason" "text", "p_cancel_linked_draft_lease" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."render_template"("p_template" "text", "p_vars" "jsonb") RETURNS "text"
    LANGUAGE "plpgsql" IMMUTABLE
    AS $$
declare
  k text;
  out text := coalesce(p_template, '');
begin
  if out = '' or p_vars is null then
    return out;
  end if;

  for k in select jsonb_object_keys(p_vars)
  loop
    out := replace(out, '{{' || k || '}}', coalesce(p_vars->>k, ''));
  end loop;

  return out;
end;
$$;


ALTER FUNCTION "public"."render_template"("p_template" "text", "p_vars" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."reopen_application"("p_application_id" "uuid", "p_target_status" "text" DEFAULT 'screening'::"text", "p_clear_rejection_reason" boolean DEFAULT true) RETURNS "public"."rental_applications"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_app public.rental_applications;
  v_out public.rental_applications;
begin
  if p_application_id is null then
    raise exception 'application_id is required';
  end if;

  -- Validate target status (only allow sensible pipeline states)
  if p_target_status not in ('new','screening','shortlisted','accepted_pending_signing') then
    raise exception 'Invalid target_status: %', p_target_status;
  end if;

  select * into v_app
  from public.rental_applications
  where id = p_application_id;

  if not found then
    raise exception 'Application not found';
  end if;

  if public.account_role_for(v_app.account_id) not in ('owner','admin','staff') then
    raise exception 'Not permitted';
  end if;

  -- Only reopen if it was rejected/withdrawn
  if v_app.status not in ('rejected','withdrawn') then
    -- idempotent: return current row
    return v_app;
  end if;

  -- Do not reopen if already resulted in active lease (property or application)
  if exists (
    select 1
    from public.leases l
    where (l.application_id = v_app.id or l.property_id = v_app.property_id)
      and l.status = 'active'
  ) then
    raise exception 'Cannot reopen: active lease exists for this property/application';
  end if;

  update public.rental_applications
  set status = p_target_status,
      rejection_reason = case when p_clear_rejection_reason then null else rejection_reason end,
      updated_at = now()
  where id = v_app.id
  returning * into v_out;

  return v_out;
end;
$$;


ALTER FUNCTION "public"."reopen_application"("p_application_id" "uuid", "p_target_status" "text", "p_clear_rejection_reason" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."reopen_payment"("p_payment_id" "uuid", "p_account_id" "uuid" DEFAULT NULL::"uuid") RETURNS "public"."payments"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_pay  public.payments;
  v_role text;
begin
  select * into v_pay
  from public.payments
  where id = p_payment_id
    and (p_account_id is null or account_id = p_account_id);

  if not found then
    raise exception 'Payment not found';
  end if;

  v_role := public.account_role_for(v_pay.account_id);
  if coalesce(v_role, '') not in ('owner', 'admin') then
    raise exception 'Not permitted';
  end if;

  update public.payments
  set paid_at = null,
      status  = case
                  when due_date < current_date then 'overdue'
                  else 'due'
                end
  where id = p_payment_id
  returning * into v_pay;

  return v_pay;
end;
$$;


ALTER FUNCTION "public"."reopen_payment"("p_payment_id" "uuid", "p_account_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."repair_document_template_stub_path"("p_template_id" "uuid", "p_filename" "text", "p_actor_user_id" "uuid" DEFAULT "auth"."uid"()) RETURNS "public"."document_templates"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_template public.document_templates;
  v_actor uuid := auth.uid();
  v_filename text := public.sanitize_document_template_filename(p_filename);
begin
  if v_actor is null then
    raise exception 'Not authenticated';
  end if;

  if p_actor_user_id is not null and p_actor_user_id <> v_actor then
    raise exception 'Actor mismatch';
  end if;

  select *
    into v_template
  from public.document_templates
  where id = p_template_id;

  if not found then
    raise exception 'Template not found';
  end if;

  if not public.can_manage_document_templates(v_template.account_id, v_actor) then
    raise exception 'Not permitted';
  end if;

  if v_template.upload_status <> 'stub' then
    raise exception 'Template upload already finalized';
  end if;

  update public.document_templates
  set storage_path = v_template.account_id::text || '/templates/' || v_template.id::text || '/' || v_filename,
      updated_at = now()
  where id = v_template.id
  returning * into v_template;

  return v_template;
end;
$$;


ALTER FUNCTION "public"."repair_document_template_stub_path"("p_template_id" "uuid", "p_filename" "text", "p_actor_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."request_document_extraction"("p_account_id" "uuid", "p_document_id" "uuid", "p_extractor" "text" DEFAULT 'auto'::"text", "p_language_hint" "text" DEFAULT NULL::"text") RETURNS "public"."document_extraction_runs"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_account_id uuid := public.assert_manage_account_access(p_account_id);
  v_doc        public.documents;
  v_extractor  text := lower(trim(coalesce(p_extractor, 'auto')));
  v_run        public.document_extraction_runs;
begin
  perform public.assert_account_feature_access(v_account_id, 'document_extraction');

  select * into v_doc
  from public.documents
  where id = p_document_id
    and account_id = v_account_id
    and upload_status = 'uploaded';

  if not found then
    raise exception 'Document not found or not yet uploaded';
  end if;

  if v_extractor not in (
    'auto', 'native_pdf', 'ocrmypdf_tesseract',
    'docling', 'paddleocr', 'olmocr', 'manual'
  ) then
    raise exception 'Invalid extractor: %. Valid values: auto, native_pdf, ocrmypdf_tesseract, docling, paddleocr, olmocr, manual', v_extractor;
  end if;

  insert into public.document_extraction_runs (
    account_id, document_id, extractor, status, metadata, created_by
  ) values (
    v_account_id,
    p_document_id,
    v_extractor,
    'queued',
    jsonb_build_object(
      'language_hint', p_language_hint,
      'mime_type',     v_doc.mime_type,
      'requested_at',  now()
    ),
    auth.uid()
  )
  returning * into v_run;

  insert into public.document_audit_log (
    document_id, action, performed_by, performed_at,
    account_id, property_id, tenant_id, created_at
  ) values (
    p_document_id,
    'extraction_requested',
    auth.uid(),
    now(),
    v_account_id,
    v_doc.property_id,
    v_doc.tenant_id,
    now()
  );

  return v_run;
end;
$$;


ALTER FUNCTION "public"."request_document_extraction"("p_account_id" "uuid", "p_document_id" "uuid", "p_extractor" "text", "p_language_hint" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."request_document_extraction"("p_account_id" "uuid", "p_document_id" "uuid", "p_extractor" "text", "p_language_hint" "text") IS 'Queues a document extraction run. The extraction worker polls document_extraction_runs for status=queued rows. Requires document_extraction feature access (growth tier minimum). p_extractor=auto (default) lets the worker pick the best extractor at runtime.';



