CREATE OR REPLACE FUNCTION "public"."request_security_audit_export"("p_account_id" "uuid", "p_filter_criteria" "jsonb" DEFAULT '{}'::"jsonb", "p_format" "text" DEFAULT 'csv'::"text", "p_retention_days" integer DEFAULT NULL::integer) RETURNS "public"."security_audit_export_jobs"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_account_id uuid;
  v_format text := lower(trim(coalesce(p_format, 'csv')));
  v_config public.account_security_settings;
  v_retention_days integer;
  v_filter_criteria jsonb := coalesce(p_filter_criteria, '{}'::jsonb);
  v_job public.security_audit_export_jobs;
begin
  v_account_id := public.assert_manage_account_access(p_account_id);

  select *
  into v_config
  from public.account_security_settings
  where account_id = v_account_id;

  v_retention_days := greatest(
    1,
    least(
      coalesce(p_retention_days, v_config.export_retention_days, 14),
      30
    )
  );

  if v_format <> 'csv' then
    raise exception 'Unsupported export format';
  end if;

  insert into public.security_audit_export_jobs (
    account_id,
    requested_by_user_id,
    export_kind,
    format,
    status,
    filter_criteria,
    expires_at
  )
  values (
    v_account_id,
    auth.uid(),
    'security_audit_csv',
    v_format,
    'queued',
    v_filter_criteria,
    now() + make_interval(days => v_retention_days)
  )
  returning * into v_job;

  return v_job;
end;
$$;


ALTER FUNCTION "public"."request_security_audit_export"("p_account_id" "uuid", "p_filter_criteria" "jsonb", "p_format" "text", "p_retention_days" integer) OWNER TO "postgres";


