CREATE OR REPLACE FUNCTION "public"."request_security_audit_export"("p_account_id" "uuid", "p_filter_criteria" "jsonb" DEFAULT '{}'::"jsonb", "p_format" "text" DEFAULT 'csv'::"text", "p_retention_days" integer DEFAULT 14, "p_requested_label" "text" DEFAULT NULL::"text") RETURNS "public"."security_audit_export_jobs"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_account_id uuid;
  v_format text := lower(trim(coalesce(p_format, 'csv')));
  v_retention_days integer := greatest(1, least(coalesce(p_retention_days, 14), 30));
  v_filter_criteria jsonb := coalesce(p_filter_criteria, '{}'::jsonb);
  v_requested_label text := nullif(left(trim(coalesce(p_requested_label, '')), 80), '');
