  insert into public.security_audit_export_jobs (
    account_id,
    requested_by_user_id,
    requested_label,
    export_kind,
    format,
    status,
    filter_criteria,
    expires_at
  )
  values (
    v_account_id,
    auth.uid(),
    v_requested_label,
    'security_audit_csv',
    v_format,
    'queued',
    v_filter_criteria,
    now() + make_interval(days => v_retention_days)
  )
  returning * into v_job;

  return v_job;
end;
$$;


