CREATE OR REPLACE FUNCTION "public"."review_document_request_upload"("p_upload_id" "uuid", "p_review_status" "text", "p_review_note" "text" DEFAULT NULL::"text", "p_actor_user_id" "uuid" DEFAULT "auth"."uid"()) RETURNS "public"."document_request_uploads"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor uuid := auth.uid();
  v_upload public.document_request_uploads;
begin
  if v_actor is null then raise exception 'Not authenticated'; end if;
  if p_actor_user_id is not null and p_actor_user_id <> v_actor then raise exception 'Actor mismatch'; end if;
  if p_review_status not in ('accepted', 'rejected') then raise exception 'Invalid review status'; end if;

  select * into v_upload from public.document_request_uploads where id = p_upload_id;
  if not found then raise exception 'Upload not found'; end if;

  if not public.can_manage_document_requests(v_upload.account_id, v_actor) then raise exception 'Not permitted'; end if;

  update public.document_request_uploads
  set review_status = p_review_status,
      review_note = nullif(trim(coalesce(p_review_note, '')), ''),
      reviewed_by = v_actor,
      reviewed_at = now()
  where id = p_upload_id
  returning * into v_upload;

  update public.documents
  set review_status = p_review_status,
      review_note = nullif(trim(coalesce(p_review_note, '')), ''),
      reviewed_by = v_actor,
      reviewed_at = now(),
      updated_at = now()
  where id = v_upload.document_id;

  update public.document_requests
  set status = p_review_status,
      reviewed_by = v_actor,
      reviewed_at = now()
  where id = v_upload.request_id;

  return v_upload;
end;
$$;


ALTER FUNCTION "public"."review_document_request_upload"("p_upload_id" "uuid", "p_review_status" "text", "p_review_note" "text", "p_actor_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."rls_auto_enable"() RETURNS "event_trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'pg_catalog'
    AS $$
DECLARE
  cmd record;
BEGIN
  FOR cmd IN
    SELECT *
    FROM pg_event_trigger_ddl_commands()
    WHERE command_tag IN ('CREATE TABLE', 'CREATE TABLE AS', 'SELECT INTO')
      AND object_type IN ('table','partitioned table')
  LOOP
     IF cmd.schema_name IS NOT NULL AND cmd.schema_name IN ('public') AND cmd.schema_name NOT IN ('pg_catalog','information_schema') AND cmd.schema_name NOT LIKE 'pg_toast%' AND cmd.schema_name NOT LIKE 'pg_temp%' THEN
      BEGIN
        EXECUTE format('alter table if exists %s enable row level security', cmd.object_identity);
        RAISE LOG 'rls_auto_enable: enabled RLS on %', cmd.object_identity;
      EXCEPTION
        WHEN OTHERS THEN
          RAISE LOG 'rls_auto_enable: failed to enable RLS on %', cmd.object_identity;
      END;
     ELSE
        RAISE LOG 'rls_auto_enable: skip % (either system schema or not in enforced list: %.)', cmd.object_identity, cmd.schema_name;
     END IF;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."rls_auto_enable"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."root_delete_account"("p_root_account_id" "uuid", "p_target_account_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_uid uuid := auth.uid();
  v_member_role text;
  v_is_root boolean := false;
begin
  if v_uid is null then
    raise exception 'Not authenticated';
  end if;

  if p_target_account_id is null then
    raise exception 'Missing target account';
  end if;

  v_member_role := public.account_member_effective_role(p_root_account_id, v_uid);

  if v_member_role is null then
    raise exception 'Not a member of root account';
  end if;

  if v_member_role <> 'owner' then
    raise exception 'Only root owner can delete accounts';
  end if;

  select coalesce(a.is_root, false)
  into v_is_root
  from public.accounts a
  where a.id = p_root_account_id
  limit 1;

  if not v_is_root then
    raise exception 'Account is not root';
  end if;

  if p_target_account_id = p_root_account_id then
    raise exception 'Cannot delete root account';
  end if;

  delete from public.accounts a
  where a.id = p_target_account_id;

  if not found then
    raise exception 'Target account not found';
  end if;

  perform public.log_security_event(
    p_root_account_id,
    'account_deleted',
    'account',
    p_target_account_id,
    jsonb_build_object(
      'target_account_id', p_target_account_id,
      'root_account_id', p_root_account_id
    )
  );

  return jsonb_build_object(
    'ok', true,
    'account_id', p_target_account_id
  );
exception
  when foreign_key_violation then
    raise exception 'Cannot delete account with related data; disable it instead';
end;
$$;


ALTER FUNCTION "public"."root_delete_account"("p_root_account_id" "uuid", "p_target_account_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."root_list_accounts"("p_root_account_id" "uuid") RETURNS TABLE("id" "uuid", "name" "text", "is_root" boolean, "is_disabled" boolean, "disabled_at" timestamp with time zone, "created_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_uid uuid := auth.uid();
  v_member_role text;
  v_is_root boolean := false;
  v_previous_disabled boolean;
begin
  if v_uid is null then
    raise exception 'Not authenticated';
  end if;

  v_member_role := public.account_member_effective_role(p_root_account_id, v_uid);

  if v_member_role is null then
    raise exception 'Not a member of root account';
  end if;

  if v_member_role <> 'owner' then
    raise exception 'Only root owner can list accounts';
  end if;

  select coalesce(a.is_root, false)
  into v_is_root
  from public.accounts a
  where a.id = p_root_account_id
  limit 1;

  if not v_is_root then
    raise exception 'Account is not root';
  end if;

  return query
  select
    a.id,
    a.name,
    coalesce(a.is_root, false) as is_root,
    coalesce(a.is_disabled, false) as is_disabled,
    a.disabled_at,
    a.created_at
  from public.accounts a
  order by a.created_at desc nulls last, a.id;
end;
$$;


ALTER FUNCTION "public"."root_list_accounts"("p_root_account_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."root_set_account_disabled"("p_root_account_id" "uuid", "p_target_account_id" "uuid", "p_disabled" boolean) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_uid uuid := auth.uid();
  v_member_role text;
  v_is_root boolean := false;
  v_previous_disabled boolean := false;
begin
  if v_uid is null then
    raise exception 'Not authenticated';
  end if;

  if p_target_account_id is null then
    raise exception 'Missing target account';
  end if;

  v_member_role := public.account_member_effective_role(p_root_account_id, v_uid);

  if v_member_role is null then
    raise exception 'Not a member of root account';
  end if;

  if v_member_role <> 'owner' then
    raise exception 'Only root owner can update account status';
  end if;

  select coalesce(a.is_root, false)
  into v_is_root
  from public.accounts a
  where a.id = p_root_account_id
  limit 1;

  if not v_is_root then
    raise exception 'Account is not root';
  end if;

  if p_target_account_id = p_root_account_id then
    raise exception 'Cannot disable root account';
  end if;

  select coalesce(a.is_disabled, false)
  into v_previous_disabled
  from public.accounts a
  where a.id = p_target_account_id
  limit 1;

  update public.accounts a
  set
    is_disabled = coalesce(p_disabled, false),
    disabled_at = case when coalesce(p_disabled, false) then now() else null end
  where a.id = p_target_account_id;

  if not found then
    raise exception 'Target account not found';
  end if;

  if coalesce(v_previous_disabled, false) is distinct from coalesce(p_disabled, false) then
    perform public.log_security_event(
      p_target_account_id,
      case when coalesce(p_disabled, false) then 'account_disabled' else 'account_enabled' end,
      'account',
      p_target_account_id,
      jsonb_build_object(
        'target_account_id', p_target_account_id,
        'root_account_id', p_root_account_id,
        'old_is_disabled', coalesce(v_previous_disabled, false),
        'new_is_disabled', coalesce(p_disabled, false)
      )
    );
  end if;

  return jsonb_build_object(
    'ok', true,
    'account_id', p_target_account_id,
    'is_disabled', coalesce(p_disabled, false)
  );
end;
$$;


ALTER FUNCTION "public"."root_set_account_disabled"("p_root_account_id" "uuid", "p_target_account_id" "uuid", "p_disabled" boolean) OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."support_account_capabilities" (
    "user_id" "uuid" NOT NULL,
    "account_id" "uuid" NOT NULL,
    "capability" "text" NOT NULL,
    "granted_by_user_id" "uuid",
    "notes" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "expires_at" timestamp with time zone,
    "revoked_at" timestamp with time zone,
    CONSTRAINT "support_account_capabilities_capability_check" CHECK ((NULLIF(TRIM(BOTH FROM "capability"), ''::"text") IS NOT NULL))
);


ALTER TABLE "public"."support_account_capabilities" OWNER TO "postgres";


COMMENT ON TABLE "public"."support_account_capabilities" IS 'Explicit future-support account capabilities that are intentionally separate from landlord/staff memberships.';



CREATE OR REPLACE FUNCTION "public"."root_telemetry_support_access_grant"("p_account_id" "uuid", "p_user_email" "text", "p_notes" "text" DEFAULT NULL::"text", "p_expires_at" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS "public"."support_account_capabilities"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_user_id uuid;
  v_clean_email text := lower(trim(coalesce(p_user_email, '')));
  v_row public.support_account_capabilities;
begin
  if not public.user_is_root_operator() then
    raise exception 'Only root operators can manage support telemetry access';
  end if;

  perform public.assert_account_feature_access(p_account_id, 'root_telemetry');

  if p_account_id is null then
    raise exception 'Missing account id';
  end if;

  if v_clean_email = '' then
    raise exception 'Missing support user email';
  end if;

  if p_expires_at is not null and p_expires_at <= now() then
    raise exception 'Expiry must be in the future';
  end if;

  if not exists (select 1 from public.accounts where id = p_account_id) then
    raise exception 'Account not found';
  end if;

  select u.id
  into v_user_id
  from auth.users u
  where lower(trim(coalesce(u.email, ''))) = v_clean_email
  limit 1;

  if v_user_id is null then
    raise exception 'Support user not found';
  end if;

  insert into public.support_account_capabilities (
    user_id,
    account_id,
    capability,
    granted_by_user_id,
    notes,
    expires_at,
    revoked_at
  )
  values (
    v_user_id,
    p_account_id,
    'root_telemetry',
    auth.uid(),
    nullif(trim(coalesce(p_notes, '')), ''),
    p_expires_at,
    null
  )
  on conflict (user_id, account_id, capability)
  do update
    set granted_by_user_id = auth.uid(),
        notes = excluded.notes,
        expires_at = excluded.expires_at,
        revoked_at = null,
        created_at = now()
  returning * into v_row;

  return v_row;
end;
$$;


ALTER FUNCTION "public"."root_telemetry_support_access_grant"("p_account_id" "uuid", "p_user_email" "text", "p_notes" "text", "p_expires_at" timestamp with time zone) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."root_telemetry_support_access_grant"("p_account_id" "uuid", "p_user_email" "text", "p_notes" "text", "p_expires_at" timestamp with time zone) IS 'Root-only grant or refresh of root telemetry support access for a support user identified by email.';



CREATE OR REPLACE FUNCTION "public"."root_telemetry_support_access_list"("p_account_id" "uuid") RETURNS TABLE("user_id" "uuid", "user_email" "text", "capability" "text", "notes" "text", "granted_by_user_id" "uuid", "granted_by_email" "text", "created_at" timestamp with time zone, "expires_at" timestamp with time zone, "revoked_at" timestamp with time zone)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with authz as (
    select public.assert_account_feature_access(p_account_id, 'root_telemetry') as account_id
    where public.user_is_root_operator()
  )
  select
    sac.user_id,
    coalesce(u.email, '') as user_email,
    sac.capability,
    sac.notes,
    sac.granted_by_user_id,
    coalesce(grantor.email, '') as granted_by_email,
    sac.created_at,
    sac.expires_at,
    sac.revoked_at
  from public.support_account_capabilities sac
  join authz a on a.account_id = sac.account_id
  left join auth.users u on u.id = sac.user_id
  left join auth.users grantor on grantor.id = sac.granted_by_user_id
  where sac.account_id = a.account_id
  order by
    case when sac.revoked_at is null then 0 else 1 end,
    sac.created_at desc;
$$;


ALTER FUNCTION "public"."root_telemetry_support_access_list"("p_account_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."root_telemetry_support_access_list"("p_account_id" "uuid") IS 'Root-only listing of support telemetry capability grants for a specific account.';



CREATE OR REPLACE FUNCTION "public"."root_telemetry_support_access_revoke"("p_account_id" "uuid", "p_user_id" "uuid") RETURNS "public"."support_account_capabilities"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_row public.support_account_capabilities;
begin
  if not public.user_is_root_operator() then
    raise exception 'Only root operators can manage support telemetry access';
  end if;

  perform public.assert_account_feature_access(p_account_id, 'root_telemetry');

  if p_account_id is null then
    raise exception 'Missing account id';
  end if;

  if p_user_id is null then
    raise exception 'Missing support user id';
  end if;

  update public.support_account_capabilities sac
  set revoked_at = now()
  where sac.account_id = p_account_id
    and sac.user_id = p_user_id
    and lower(sac.capability) = 'root_telemetry'
    and sac.revoked_at is null
  returning * into v_row;

  if v_row.user_id is null then
    raise exception 'Active support telemetry grant not found';
  end if;

  return v_row;
end;
$$;


ALTER FUNCTION "public"."root_telemetry_support_access_revoke"("p_account_id" "uuid", "p_user_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."root_telemetry_support_access_revoke"("p_account_id" "uuid", "p_user_id" "uuid") IS 'Root-only revocation of active root telemetry support access for a specific user and account.';



CREATE OR REPLACE FUNCTION "public"."root_telemetry_support_operator_directory"("p_account_id" "uuid", "p_query" "text" DEFAULT NULL::"text", "p_limit" integer DEFAULT 10) RETURNS TABLE("user_id" "uuid", "user_email" "text", "source" "text", "has_root_telemetry" boolean, "current_account_granted" boolean, "current_expires_at" timestamp with time zone, "last_telemetry_access_at" timestamp with time zone)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public', 'auth'
    AS $$
  with authz as (
    select public.assert_account_feature_access(p_account_id, 'root_telemetry') as account_id
    where public.user_is_root_operator()
  ),
  cfg as (
    select
      nullif(lower(trim(coalesce(p_query, ''))), '') as q,
      greatest(1, least(coalesce(p_limit, 10), 25)) as row_limit
  ),
  candidates as (
    select
      u.id as user_id,
      lower(trim(coalesce(u.email, ''))) as user_email,
      case
        when exists (
          select 1
          from public.support_account_capabilities sac
          where sac.user_id = u.id
        ) then 'existing_grant'
        else 'support_metadata'
      end as source,
      exists (
        select 1
        from public.support_account_capabilities sac
        where sac.user_id = u.id
          and lower(sac.capability) = 'root_telemetry'
          and sac.revoked_at is null
          and (sac.expires_at is null or sac.expires_at > now())
      ) as has_root_telemetry
    from auth.users u
    cross join authz
    cross join cfg
    where nullif(lower(trim(coalesce(u.email, ''))), '') is not null
      and (
        coalesce((u.raw_app_meta_data ->> 'support_operator')::boolean, false)
        or coalesce((u.raw_user_meta_data ->> 'support_operator')::boolean, false)
        or coalesce((u.raw_app_meta_data ->> 'root_telemetry_access')::boolean, false)
        or coalesce((u.raw_user_meta_data ->> 'root_telemetry_access')::boolean, false)
        or coalesce(u.raw_app_meta_data -> 'oasis_support_roles', '[]'::jsonb) ?| array['telemetry', 'root_telemetry']
        or coalesce(u.raw_user_meta_data -> 'oasis_support_roles', '[]'::jsonb) ?| array['telemetry', 'root_telemetry']
        or exists (
          select 1
          from public.support_account_capabilities sac
          where sac.user_id = u.id
        )
      )
      and (
        cfg.q is null
        or lower(trim(coalesce(u.email, ''))) like '%' || cfg.q || '%'
      )
  )
  select
    c.user_id,
    c.user_email,
    c.source,
    c.has_root_telemetry,
    exists (
      select 1
      from public.support_account_capabilities sac
      where sac.user_id = c.user_id
        and sac.account_id = (select account_id from authz)
        and lower(sac.capability) = 'root_telemetry'
        and sac.revoked_at is null
        and (sac.expires_at is null or sac.expires_at > now())
    ) as current_account_granted,
    (
      select sac.expires_at
      from public.support_account_capabilities sac
      where sac.user_id = c.user_id
        and sac.account_id = (select account_id from authz)
        and lower(sac.capability) = 'root_telemetry'
        and sac.revoked_at is null
      order by sac.created_at desc
      limit 1
    ) as current_expires_at,
    (
      select max(e.created_at)
      from public.security_observability_events e
      where e.account_id = (select account_id from authz)
        and e.actor_user_id = c.user_id
        and lower(coalesce(e.category, '')) = 'root_telemetry'
    ) as last_telemetry_access_at
  from candidates c
  order by
    current_account_granted desc,
    c.has_root_telemetry desc,
    c.source asc,
    c.user_email asc
  limit (select row_limit from cfg);
$$;


ALTER FUNCTION "public"."root_telemetry_support_operator_directory"("p_account_id" "uuid", "p_query" "text", "p_limit" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."root_telemetry_support_operator_directory"("p_account_id" "uuid", "p_query" "text", "p_limit" integer) IS 'Root-only searchable directory of known support operators with account-aware grant and recent telemetry usage context.';



CREATE OR REPLACE FUNCTION "public"."safe_uuid"("p" "text") RETURNS "uuid"
    LANGUAGE "plpgsql" IMMUTABLE
    AS $_$
begin
  if p is null then
    return null;
  end if;

  if p ~* '^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$' then
    return p::uuid;
  end if;

  return null;
exception when others then
  return null;
end;
$_$;


ALTER FUNCTION "public"."safe_uuid"("p" "text") OWNER TO "postgres";


