CREATE TABLE IF NOT EXISTS "public"."security_anomaly_alerts" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "account_id" "uuid" NOT NULL,
    "alert_type" "text" NOT NULL,
    "severity" "text" DEFAULT 'action'::"text" NOT NULL,
    "status" "text" DEFAULT 'open'::"text" NOT NULL,
    "actor_user_id" "uuid",
    "entity_type" "text",
    "entity_id" "uuid",
    "title" "text" NOT NULL,
    "summary" "text" NOT NULL,
    "metadata" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "dedupe_key" "text" NOT NULL,
    "alert_count" integer DEFAULT 1 NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "last_seen_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "acknowledged_at" timestamp with time zone,
    "resolved_at" timestamp with time zone,
    "classification" "text",
    "classified_by_user_id" "uuid",
    "classified_at" timestamp with time zone,
    "assigned_to_user_id" "uuid",
    "assigned_by_user_id" "uuid",
    "assigned_at" timestamp with time zone,
    "acknowledged_by_user_id" "uuid",
    "resolved_by_user_id" "uuid",
    "resolution_note" "text",
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "security_anomaly_alerts_alert_count_check" CHECK (("alert_count" >= 1)),
    CONSTRAINT "security_anomaly_alerts_classification_check" CHECK ((("classification" IS NULL) OR ("lower"("classification") = ANY (ARRAY['suspicious'::"text", 'expected'::"text", 'false_positive'::"text", 'informational'::"text"])))),
    CONSTRAINT "security_anomaly_alerts_severity_check" CHECK (("lower"("severity") = ANY (ARRAY['info'::"text", 'action'::"text", 'urgent'::"text"]))),
    CONSTRAINT "security_anomaly_alerts_status_check" CHECK (("lower"("status") = ANY (ARRAY['open'::"text", 'acknowledged'::"text", 'resolved'::"text"])))
);


ALTER TABLE "public"."security_anomaly_alerts" OWNER TO "postgres";


COMMENT ON TABLE "public"."security_anomaly_alerts" IS 'Open internal security anomaly alerts derived from security_audit_ledger patterns.';



COMMENT ON COLUMN "public"."security_anomaly_alerts"."metadata" IS 'Compact anomaly payload with thresholds, detection window, count details, and review filter hints.';



COMMENT ON COLUMN "public"."security_anomaly_alerts"."classification" IS 'Analyst classification for the current alert lifecycle.';



COMMENT ON COLUMN "public"."security_anomaly_alerts"."resolution_note" IS 'Optional analyst note captured at resolution time.';



CREATE OR REPLACE FUNCTION "public"."security_anomaly_alert_apply"("p_alert_id" "uuid", "p_operation" "text", "p_classification" "text" DEFAULT NULL::"text", "p_assigned_to_user_id" "uuid" DEFAULT NULL::"uuid", "p_resolution_note" "text" DEFAULT NULL::"text") RETURNS "public"."security_anomaly_alerts"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor_user_id uuid := auth.uid();
  v_operation text := lower(trim(coalesce(p_operation, '')));
  v_classification text := nullif(lower(trim(coalesce(p_classification, ''))), '');
  v_resolution_note text := nullif(trim(coalesce(p_resolution_note, '')), '');
  v_alert public.security_anomaly_alerts;
  v_updated public.security_anomaly_alerts;
  v_assignee_role text;
begin
  if v_actor_user_id is null then
    raise exception 'Not authenticated';
  end if;

  if p_alert_id is null then
    raise exception 'Missing alert id';
  end if;

  if v_operation not in ('acknowledge', 'classify', 'assign', 'resolve') then
    raise exception 'Unsupported operation';
  end if;

  select *
  into v_alert
  from public.security_anomaly_alerts
  where id = p_alert_id
  for update;

  if v_alert.id is null then
    raise exception 'Alert not found';
  end if;

  perform public.assert_manage_account_access(v_alert.account_id);
  perform public.assert_account_feature_access(v_alert.account_id, 'security_audit');

  if v_operation = 'acknowledge' then
    if lower(v_alert.status) <> 'open' then
      raise exception 'Only open alerts can be acknowledged';
    end if;

    update public.security_anomaly_alerts
    set
      status = 'acknowledged',
      acknowledged_by_user_id = v_actor_user_id,
      acknowledged_at = now()
    where id = v_alert.id
    returning * into v_updated;

    perform public.log_security_event(
      v_alert.account_id,
      'security_alert_acknowledged',
      'security_alert',
      v_alert.id,
      jsonb_build_object(
        'alert_type', v_alert.alert_type,
        'title', v_alert.title,
        'old_status', v_alert.status,
        'new_status', v_updated.status
      )
    );
  elsif v_operation = 'classify' then
    if lower(v_alert.status) = 'resolved' then
      raise exception 'Resolved alerts cannot be reclassified';
    end if;

    if v_classification is null or v_classification not in ('suspicious', 'expected', 'false_positive', 'informational') then
      raise exception 'Invalid classification';
    end if;

    update public.security_anomaly_alerts
    set
      classification = v_classification,
      classified_by_user_id = v_actor_user_id,
      classified_at = now()
    where id = v_alert.id
    returning * into v_updated;

    perform public.log_security_event(
      v_alert.account_id,
      'security_alert_classified',
      'security_alert',
      v_alert.id,
      jsonb_build_object(
        'alert_type', v_alert.alert_type,
        'title', v_alert.title,
        'old_classification', v_alert.classification,
        'new_classification', v_updated.classification
      )
    );
  elsif v_operation = 'assign' then
    if lower(v_alert.status) = 'resolved' then
      raise exception 'Resolved alerts cannot be reassigned';
    end if;

    if p_assigned_to_user_id is not null then
      select public.account_member_effective_role(v_alert.account_id, p_assigned_to_user_id)
      into v_assignee_role;

      if v_assignee_role is null or v_assignee_role not in ('owner', 'admin', 'staff') then
        raise exception 'Assignee must be a privileged account member';
      end if;
    end if;

    update public.security_anomaly_alerts
    set
      assigned_to_user_id = p_assigned_to_user_id,
      assigned_by_user_id = case when p_assigned_to_user_id is null then null else v_actor_user_id end,
      assigned_at = case when p_assigned_to_user_id is null then null else now() end
    where id = v_alert.id
    returning * into v_updated;

    perform public.log_security_event(
      v_alert.account_id,
      'security_alert_assigned',
      'security_alert',
      v_alert.id,
      jsonb_build_object(
        'alert_type', v_alert.alert_type,
        'title', v_alert.title,
        'old_assigned_to_user_id', v_alert.assigned_to_user_id,
        'new_assigned_to_user_id', v_updated.assigned_to_user_id
      )
    );
  else
    if lower(v_alert.status) = 'resolved' then
      raise exception 'Alert is already resolved';
    end if;

    update public.security_anomaly_alerts
    set
      status = 'resolved',
      resolved_by_user_id = v_actor_user_id,
      resolved_at = now(),
      resolution_note = v_resolution_note
    where id = v_alert.id
    returning * into v_updated;

    perform public.log_security_event(
      v_alert.account_id,
      'security_alert_resolved',
      'security_alert',
      v_alert.id,
      jsonb_build_object(
        'alert_type', v_alert.alert_type,
        'title', v_alert.title,
        'old_status', v_alert.status,
        'new_status', v_updated.status,
        'resolution_note', coalesce(v_updated.resolution_note, '')
      )
    );
  end if;

  return v_updated;
end;
$$;


ALTER FUNCTION "public"."security_anomaly_alert_apply"("p_alert_id" "uuid", "p_operation" "text", "p_classification" "text", "p_assigned_to_user_id" "uuid", "p_resolution_note" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."security_anomaly_alert_apply"("p_alert_id" "uuid", "p_operation" "text", "p_classification" "text", "p_assigned_to_user_id" "uuid", "p_resolution_note" "text") IS 'Applies a privileged analyst lifecycle action to a security anomaly alert and records the action in security_audit_ledger.';



CREATE OR REPLACE FUNCTION "public"."security_audit_detect_anomalies"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_target_user_id uuid := nullif(coalesce(new.metadata->>'target_user_id', ''), '')::uuid;
  v_role_change_target_count integer := 0;
  v_role_change_account_count integer := 0;
  v_doc_delete_actor_count integer := 0;
  v_doc_delete_account_count integer := 0;
  v_actor_member_role text := null;
  v_actor_is_tenant boolean := false;
  v_actor_is_contractor boolean := false;
begin
  if new.account_id is null then
    return new;
  end if;

  if new.action = 'role_changed' then
    if coalesce(new.metadata->>'change_source', '') = 'invite_acceptance' then
      return new;
    end if;

    if v_target_user_id is not null then
      select count(*)
      into v_role_change_target_count
      from public.security_audit_ledger sal
      where sal.account_id = new.account_id
        and sal.action = 'role_changed'
        and coalesce(sal.metadata->>'change_source', '') <> 'invite_acceptance'
        and coalesce(sal.metadata->>'target_user_id', '') = v_target_user_id::text
        and sal.created_at >= now() - interval '30 minutes';
    end if;

    select count(*)
    into v_role_change_account_count
    from public.security_audit_ledger sal
    where sal.account_id = new.account_id
      and sal.action = 'role_changed'
      and coalesce(sal.metadata->>'change_source', '') <> 'invite_acceptance'
      and sal.created_at >= now() - interval '30 minutes';

    if v_role_change_target_count >= 3 then
      perform public.upsert_security_anomaly_alert(
        new.account_id,
        'repeated_role_changes',
        'action',
        'Repeated role changes detected',
        'Multiple role changes were recorded for the same account member within 30 minutes.',
        new.actor_user_id,
        'account_member',
        v_target_user_id,
        'repeated_role_changes:target:' || v_target_user_id::text,
        jsonb_build_object(
          'detection_window_minutes', 30,
          'threshold', 3,
          'event_count', v_role_change_target_count,
          'target_user_id', v_target_user_id,
          'latest_event_id', new.id,
          'recommended_filters', jsonb_build_object(
            'action', 'role_changed',
            'actorUserId', coalesce(new.actor_user_id::text, ''),
            'entityType', 'account_member',
            'entityId', v_target_user_id::text
          )
        )
      );
    elsif v_role_change_account_count >= 5 then
      perform public.upsert_security_anomaly_alert(
        new.account_id,
        'repeated_role_changes',
        'action',
        'High volume of role changes detected',
        'Multiple role changes were recorded across the account within 30 minutes.',
        new.actor_user_id,
        'account',
        new.account_id,
        'repeated_role_changes:account',
        jsonb_build_object(
          'detection_window_minutes', 30,
          'threshold', 5,
          'event_count', v_role_change_account_count,
          'latest_event_id', new.id,
          'recommended_filters', jsonb_build_object(
            'action', 'role_changed'
          )
        )
      );
    end if;
  elsif new.action = 'document_deleted' then
    if new.actor_user_id is not null then
      select count(*)
      into v_doc_delete_actor_count
      from public.security_audit_ledger sal
      where sal.account_id = new.account_id
        and sal.action = 'document_deleted'
        and sal.actor_user_id = new.actor_user_id
        and sal.created_at >= now() - interval '15 minutes';
    end if;

    select count(*)
    into v_doc_delete_account_count
    from public.security_audit_ledger sal
    where sal.account_id = new.account_id
      and sal.action = 'document_deleted'
      and sal.created_at >= now() - interval '15 minutes';

    if v_doc_delete_actor_count >= 5 and new.actor_user_id is not null then
      perform public.upsert_security_anomaly_alert(
        new.account_id,
        'document_deletion_burst',
        'urgent',
        'Document deletion burst detected',
        'A single actor deleted multiple documents in a short time window.',
        new.actor_user_id,
        'document',
        new.entity_id,
        'document_deletion_burst:actor:' || new.actor_user_id::text,
        jsonb_build_object(
          'detection_window_minutes', 15,
          'threshold', 5,
          'event_count', v_doc_delete_actor_count,
          'latest_event_id', new.id,
          'recommended_filters', jsonb_build_object(
            'action', 'document_deleted',
            'actorUserId', new.actor_user_id::text
          )
        )
      );
    elsif v_doc_delete_account_count >= 10 then
      perform public.upsert_security_anomaly_alert(
        new.account_id,
        'document_deletion_burst',
        'urgent',
        'Account-wide document deletion burst detected',
        'Document deletions spiked across the account in a short time window.',
        new.actor_user_id,
        'account',
        new.account_id,
        'document_deletion_burst:account',
        jsonb_build_object(
          'detection_window_minutes', 15,
          'threshold', 10,
          'event_count', v_doc_delete_account_count,
          'latest_event_id', new.id,
          'recommended_filters', jsonb_build_object(
            'action', 'document_deleted'
          )
        )
      );
    end if;
  end if;

  if new.actor_user_id is not null and new.action in (
    'role_changed',
    'account_disabled',
    'account_enabled',
    'account_deleted',
    'account_invitation_created',
    'landlord_invitation_created'
  ) then
    select public.account_member_effective_role(new.account_id, new.actor_user_id)
    into v_actor_member_role;

    if v_actor_member_role is null then
      select exists (
        select 1
        from public.tenants t
        where t.account_id = new.account_id
          and t.user_id = new.actor_user_id
      ) into v_actor_is_tenant;

      select exists (
        select 1
        from public.contractors c
        where c.account_id = new.account_id
          and c.user_id = new.actor_user_id
      ) into v_actor_is_contractor;
    end if;

    if v_actor_member_role = 'staff'
      or v_actor_is_tenant
      or v_actor_is_contractor
    then
      perform public.upsert_security_anomaly_alert(
        new.account_id,
        'cross_role_admin_activity',
        case when v_actor_is_tenant or v_actor_is_contractor then 'urgent' else 'action' end,
        'Review cross-role administrative activity',
        'A privileged administrative security event was recorded for an actor whose role should be reviewed.',
        new.actor_user_id,
        new.entity_type,
        new.entity_id,
        'cross_role_admin_activity:' || new.actor_user_id::text || ':' || new.action,
        jsonb_build_object(
          'actor_role', coalesce(v_actor_member_role, case when v_actor_is_tenant then 'tenant' when v_actor_is_contractor then 'contractor' else null end),
          'action', new.action,
          'latest_event_id', new.id,
          'recommended_filters', jsonb_build_object(
            'action', new.action,
            'actorUserId', new.actor_user_id::text
          )
        )
      );
    end if;
  end if;

  return new;
end;
$$;


ALTER FUNCTION "public"."security_audit_detect_anomalies"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."security_audit_detect_anomalies"() IS 'Lightweight trigger-based anomaly detection for repeated role changes, document deletion bursts, and cross-role administrative activity.';



