CREATE OR REPLACE FUNCTION "public"."security_audit_log_account_invitation_create"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_action text := case
    when lower(coalesce(new.role::text, '')) = 'owner' then 'landlord_invitation_created'
    else 'account_invitation_created'
  end;
begin
  if new.accepted_at is not null or new.revoked_at is not null then
    return new;
  end if;

  perform public.log_security_event(
    new.account_id,
    v_action,
    'account_invitation',
    new.id,
    jsonb_strip_nulls(
      jsonb_build_object(
        'invite_id', new.id,
        'email', lower(coalesce(new.email, '')),
        'invited_role', lower(coalesce(new.role::text, '')),
        'invited_by', new.invited_by,
        'account_id', new.account_id
      )
    )
  );

  return new;
end;
$$;


