CREATE OR REPLACE FUNCTION "public"."security_audit_log_document_delete"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_doc jsonb := to_jsonb(old);
begin
  perform public.log_security_event(
    nullif(v_doc->>'account_id', '')::uuid,
    'document_deleted',
    'document',
    old.id,
    jsonb_strip_nulls(
      jsonb_build_object(
        'document_id', old.id,
        'storage_path', v_doc->>'storage_path',
        'property_id', v_doc->>'property_id',
        'tenant_id', v_doc->>'tenant_id',
        'scope', v_doc->>'scope',
        'visibility', v_doc->>'visibility',
        'deletion_source', 'documents_delete'
      )
    )
  );

  return old;
end;
$$;


