CREATE OR REPLACE FUNCTION "public"."security_failure_context"("p_event" "text", "p_reason" "text", "p_account_id" "uuid" DEFAULT NULL::"uuid", "p_entity_type" "text" DEFAULT NULL::"text", "p_entity_id" "uuid" DEFAULT NULL::"uuid", "p_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "text"
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  select jsonb_strip_nulls(
    jsonb_build_object(
      'event', nullif(trim(coalesce(p_event, '')), ''),
      'reason', nullif(trim(coalesce(p_reason, '')), ''),
      'account_id', p_account_id,
      'entity_type', nullif(trim(coalesce(lower(p_entity_type), '')), ''),
      'entity_id', p_entity_id,
      'actor_user_id', auth.uid()
    ) || coalesce(p_metadata, '{}'::jsonb)
  )::text;
$$;


ALTER FUNCTION "public"."security_failure_context"("p_event" "text", "p_reason" "text", "p_account_id" "uuid", "p_entity_type" "text", "p_entity_id" "uuid", "p_metadata" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."security_failure_context"("p_event" "text", "p_reason" "text", "p_account_id" "uuid", "p_entity_type" "text", "p_entity_id" "uuid", "p_metadata" "jsonb") IS 'Formats safe structured detail payloads for security-sensitive denied-path and validation exceptions.';



CREATE OR REPLACE FUNCTION "public"."security_observability_burst_rollup"("p_account_id" "uuid", "p_since" timestamp with time zone, "p_until" timestamp with time zone, "p_surface" "text" DEFAULT NULL::"text") RETURNS TABLE("surface" "text", "reason" "text", "burst_count" bigint, "denials" bigint, "failures" bigint, "slow_count" bigint, "latest_seen_at" timestamp with time zone)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with authz as (
    select public.assert_root_telemetry_access(p_account_id) as account_id
  ),
  filtered as (
    select
      e.surface,
      coalesce(nullif(e.reason, ''), e.kind) as reason_key,
      e.kind,
      e.created_at
    from public.security_observability_events e
    cross join authz a
    where e.account_id = a.account_id
      and e.created_at >= p_since
      and e.created_at < p_until
      and e.kind in ('authorization_denied', 'unexpected_security_failure', 'latency_threshold_exceeded')
      and (nullif(lower(trim(coalesce(p_surface, ''))), '') is null or e.surface = lower(trim(p_surface)))
  )
  select
    f.surface,
    f.reason_key as reason,
    count(*) as burst_count,
    count(*) filter (where f.kind = 'authorization_denied') as denials,
    count(*) filter (where f.kind = 'unexpected_security_failure') as failures,
    count(*) filter (where f.kind = 'latency_threshold_exceeded') as slow_count,
    max(f.created_at) as latest_seen_at
  from filtered f
  group by f.surface, f.reason_key
  having count(*) >= 2
  order by count(*) desc, max(f.created_at) desc;
$$;


ALTER FUNCTION "public"."security_observability_burst_rollup"("p_account_id" "uuid", "p_since" timestamp with time zone, "p_until" timestamp with time zone, "p_surface" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."security_observability_burst_rollup"("p_account_id" "uuid", "p_since" timestamp with time zone, "p_until" timestamp with time zone, "p_surface" "text") IS 'Root/support-safe aggregated burst-pressure rollup for repeated denial, failure, and slow-threshold signals over a bounded time range.';



CREATE OR REPLACE FUNCTION "public"."security_observability_event_feed"("p_account_id" "uuid", "p_category" "text" DEFAULT NULL::"text", "p_kind" "text" DEFAULT NULL::"text", "p_surface" "text" DEFAULT NULL::"text", "p_limit" integer DEFAULT 100, "p_since" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_until" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS TABLE("id" "uuid", "account_id" "uuid", "actor_user_id" "uuid", "actor_role" "text", "category" "text", "kind" "text", "surface" "text", "reason" "text", "outcome" "text", "code" "text", "guard_denied" boolean, "entity_type" "text", "entity_id" "uuid", "correlation_id" "text", "source" "text", "metadata" "jsonb", "created_at" timestamp with time zone)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with authz as (
    select public.assert_security_observability_feed_access(p_account_id) as account_id
  ),
  cfg as (
    select greatest(1, least(coalesce(p_limit, 100), 200)) as row_limit
  )
  select
    e.id,
    e.account_id,
    e.actor_user_id,
    e.actor_role,
    e.category,
    e.kind,
    e.surface,
    e.reason,
    e.outcome,
    e.code,
    e.guard_denied,
    e.entity_type,
    e.entity_id,
    e.correlation_id,
    e.source,
    e.metadata,
    e.created_at
  from public.security_observability_events e
  cross join authz a
  where e.account_id = a.account_id
    and (nullif(lower(trim(coalesce(p_category, ''))), '') is null or e.category = lower(trim(p_category)))
    and (nullif(lower(trim(coalesce(p_kind, ''))), '') is null or e.kind = lower(trim(p_kind)))
    and (nullif(lower(trim(coalesce(p_surface, ''))), '') is null or e.surface = lower(trim(p_surface)))
    and (p_since is null or e.created_at >= p_since)
    and (p_until is null or e.created_at < p_until)
  order by e.created_at desc
  limit (select row_limit from cfg);
$$;


ALTER FUNCTION "public"."security_observability_event_feed"("p_account_id" "uuid", "p_category" "text", "p_kind" "text", "p_surface" "text", "p_limit" integer, "p_since" timestamp with time zone, "p_until" timestamp with time zone) OWNER TO "postgres";


