CREATE OR REPLACE FUNCTION "public"."security_observability_latency_rollup"("p_account_id" "uuid", "p_since" timestamp with time zone, "p_until" timestamp with time zone, "p_surface" "text" DEFAULT NULL::"text") RETURNS TABLE("surface" "text", "sample_count" bigint, "slow_count" bigint, "p50_duration_ms" numeric, "p95_duration_ms" numeric, "max_duration_ms" numeric, "target_ms" integer, "latest_seen_at" timestamp with time zone)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with authz as (
    select public.assert_root_telemetry_access(p_account_id) as account_id
  ),
  filtered as (
    select
      e.surface,
      e.kind,
      e.created_at,
      nullif(e.metadata->>'duration_ms', '')::numeric as duration_ms,
      nullif(coalesce(e.metadata->>'target_ms', e.metadata->>'threshold_ms'), '')::integer as target_ms
    from public.security_observability_events e
    cross join authz a
    where e.account_id = a.account_id
      and e.created_at >= p_since
      and e.created_at < p_until
      and e.kind in ('latency_sample', 'latency_threshold_exceeded')
      and (nullif(lower(trim(coalesce(p_surface, ''))), '') is null or e.surface = lower(trim(p_surface)))
  )
  select
    f.surface,
    count(*) filter (where f.kind = 'latency_sample') as sample_count,
    count(*) filter (where f.kind = 'latency_threshold_exceeded') as slow_count,
    percentile_disc(0.5) within group (order by f.duration_ms)
      filter (where f.kind = 'latency_sample' and f.duration_ms is not null) as p50_duration_ms,
    percentile_disc(0.95) within group (order by f.duration_ms)
      filter (where f.kind = 'latency_sample' and f.duration_ms is not null) as p95_duration_ms,
    max(f.duration_ms) as max_duration_ms,
    max(f.target_ms) as target_ms,
    max(f.created_at) as latest_seen_at
  from filtered f
  group by f.surface
  order by
    count(*) filter (where f.kind = 'latency_threshold_exceeded') desc,
    percentile_disc(0.95) within group (order by f.duration_ms)
      filter (where f.kind = 'latency_sample' and f.duration_ms is not null) desc nulls last,
    max(f.created_at) desc;
$$;


ALTER FUNCTION "public"."security_observability_latency_rollup"("p_account_id" "uuid", "p_since" timestamp with time zone, "p_until" timestamp with time zone, "p_surface" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."security_observability_latency_rollup"("p_account_id" "uuid", "p_since" timestamp with time zone, "p_until" timestamp with time zone, "p_surface" "text") IS 'Root/support-safe aggregated latency rollup for hosted telemetry over a bounded time range.';



CREATE OR REPLACE FUNCTION "public"."security_observability_trend_series"("p_account_id" "uuid", "p_since" timestamp with time zone, "p_until" timestamp with time zone, "p_bucket_minutes" integer DEFAULT 10) RETURNS TABLE("bucket_start" timestamp with time zone, "total_signals" bigint, "denials" bigint, "failures" bigint, "slow_count" bigint)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with authz as (
    select public.assert_root_telemetry_access(p_account_id) as account_id
  ),
  cfg as (
    select greatest(1, least(coalesce(p_bucket_minutes, 10), 1440)) as bucket_minutes
  ),
  buckets as (
    select generate_series(
      p_since,
      p_until - make_interval(mins => (select bucket_minutes from cfg)),
      make_interval(mins => (select bucket_minutes from cfg))
    ) as bucket_start
  ),
  grouped as (
    select
      date_bin(make_interval(mins => (select bucket_minutes from cfg)), e.created_at, p_since) as bucket_start,
      count(*) as total_signals,
      count(*) filter (where e.kind = 'authorization_denied') as denials,
      count(*) filter (where e.kind = 'unexpected_security_failure') as failures,
      count(*) filter (where e.kind = 'latency_threshold_exceeded') as slow_count
    from public.security_observability_events e
    cross join authz a
    where e.account_id = a.account_id
      and e.created_at >= p_since
      and e.created_at < p_until
      and e.kind in ('authorization_denied', 'unexpected_security_failure', 'latency_threshold_exceeded')
    group by 1
  )
  select
    b.bucket_start,
    coalesce(g.total_signals, 0) as total_signals,
    coalesce(g.denials, 0) as denials,
    coalesce(g.failures, 0) as failures,
    coalesce(g.slow_count, 0) as slow_count
  from buckets b
  left join grouped g on g.bucket_start = b.bucket_start
  order by b.bucket_start asc;
$$;


ALTER FUNCTION "public"."security_observability_trend_series"("p_account_id" "uuid", "p_since" timestamp with time zone, "p_until" timestamp with time zone, "p_bucket_minutes" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."security_observability_trend_series"("p_account_id" "uuid", "p_since" timestamp with time zone, "p_until" timestamp with time zone, "p_bucket_minutes" integer) IS 'Root/support-safe bucketed signal trend series for hosted observability telemetry over a bounded time range.';



CREATE OR REPLACE FUNCTION "public"."security_root_telemetry_active_alerts"("p_account_id" "uuid", "p_status" "text" DEFAULT 'active'::"text", "p_limit" integer DEFAULT 5, "p_offset" integer DEFAULT 0) RETURNS TABLE("id" "uuid", "account_id" "uuid", "alert_type" "text", "severity" "text", "status" "text", "actor_user_id" "uuid", "entity_type" "text", "entity_id" "uuid", "title" "text", "summary" "text", "metadata" "jsonb", "alert_count" integer, "created_at" timestamp with time zone, "last_seen_at" timestamp with time zone, "total_count" bigint)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with authz as (
    select public.assert_root_telemetry_access(p_account_id) as account_id
  ),
  cfg as (
    select
      greatest(1, least(coalesce(p_limit, 5), 25)) as row_limit,
      greatest(coalesce(p_offset, 0), 0) as row_offset,
      nullif(lower(trim(coalesce(p_status, 'active'))), '') as requested_status
  ),
  filtered as (
    select
      saa.id,
      saa.account_id,
      saa.alert_type,
      saa.severity,
      saa.status,
      saa.actor_user_id,
      saa.entity_type,
      saa.entity_id,
      saa.title,
      saa.summary,
      saa.metadata,
      saa.alert_count,
      saa.created_at,
      saa.last_seen_at
    from public.security_anomaly_alerts saa
    cross join authz a
    cross join cfg c
    where saa.account_id = a.account_id
      and (
        c.requested_status is null
        or (c.requested_status = 'active' and lower(saa.status) in ('open', 'acknowledged'))
        or lower(saa.status) = c.requested_status
      )
  )
  select
    f.id,
    f.account_id,
    f.alert_type,
    f.severity,
    f.status,
    f.actor_user_id,
    f.entity_type,
    f.entity_id,
    f.title,
    f.summary,
    f.metadata,
    f.alert_count,
    f.created_at,
    f.last_seen_at,
    count(*) over () as total_count
  from filtered f
  order by f.last_seen_at desc
  limit (select row_limit from cfg)
  offset (select row_offset from cfg);
$$;


ALTER FUNCTION "public"."security_root_telemetry_active_alerts"("p_account_id" "uuid", "p_status" "text", "p_limit" integer, "p_offset" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."security_root_telemetry_active_alerts"("p_account_id" "uuid", "p_status" "text", "p_limit" integer, "p_offset" integer) IS 'Root/support-safe anomaly alert feed for root telemetry surfaces, with bounded pagination and total count.';



