CREATE OR REPLACE FUNCTION "public"."set_document_access"("p_document_id" "uuid", "p_scope" "text", "p_visibility" "text", "p_property_id" "uuid" DEFAULT NULL::"uuid", "p_tenant_id" "uuid" DEFAULT NULL::"uuid", "p_actor_user_id" "uuid" DEFAULT "auth"."uid"()) RETURNS "public"."documents"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_doc public.documents;
  v_role text;
begin
  if p_document_id is null then
    raise exception 'document_id is required';
  end if;

  if p_actor_user_id is null then
    raise exception 'Not authenticated';
  end if;

  select * into v_doc
  from public.documents
  where id = p_document_id;

  if not found then
    raise exception 'Document not found';
  end if;

  v_role := public.account_role_for(v_doc.account_id);
  if v_role not in ('owner','admin','staff') then
    raise exception 'Not permitted';
  end if;

  -- Validate enum-ish values (match your check constraints)
  if p_scope not in ('property','tenant','shared','account') then
    raise exception 'Invalid scope: %', p_scope;
  end if;

  if p_visibility not in ('owner_admin','staff','tenant','private') then
    raise exception 'Invalid visibility: %', p_visibility;
  end if;

  -- Enforce consistency by constructing IDs from scope
  update public.documents
  set
    scope = p_scope,
    visibility = p_visibility,
    property_id = case when p_scope in ('property','shared') then p_property_id else null end,
    tenant_id   = case when p_scope in ('tenant','shared') then p_tenant_id else null end,
    updated_at = now()
  where id = p_document_id
  returning * into v_doc;

  return v_doc;
end;
$$;


