CREATE OR REPLACE FUNCTION "public"."set_document_tags"("p_document_id" "uuid", "p_tags" "public"."document_tag"[], "p_actor_user_id" "uuid" DEFAULT "auth"."uid"()) RETURNS "public"."documents"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_doc public.documents;
  v_actor_user_id uuid := auth.uid();
begin
  if p_document_id is null then
    raise exception 'document_id is required';
  end if;

  if v_actor_user_id is null then
    raise exception 'Not authenticated';
  end if;

  if p_actor_user_id is not null and p_actor_user_id <> v_actor_user_id then
    raise exception 'Actor mismatch';
  end if;

  select * into v_doc
  from public.documents
  where id = p_document_id;

  if not found then
    raise exception 'Document not found';
  end if;

  if not public.account_member_has_permission(v_doc.account_id, 'documents.tag', v_actor_user_id) then
    raise exception 'Not permitted';
  end if;

  update public.documents
  set tags = coalesce(p_tags, '{}'::public.document_tag[]),
      updated_at = now()
  where id = p_document_id
  returning * into v_doc;

  insert into public.document_audit_log (
    document_id,
    action,
    performed_by,
    performed_at,
    account_id,
    property_id,
    tenant_id,
    created_at
  )
  values (
    v_doc.id,
    'update_tags',
    v_actor_user_id,
    now(),
    v_doc.account_id,
    v_doc.property_id,
    v_doc.tenant_id,
    now()
  );

  return v_doc;
end;
$$;


ALTER FUNCTION "public"."set_document_tags"("p_document_id" "uuid", "p_tags" "public"."document_tag"[], "p_actor_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."set_document_tenant_highlight"("p_document_id" "uuid", "p_tenant_highlight" "text" DEFAULT 'standard'::"text", "p_tenant_highlight_note" "text" DEFAULT NULL::"text", "p_tenant_highlight_rank" integer DEFAULT NULL::integer, "p_actor_user_id" "uuid" DEFAULT "auth"."uid"()) RETURNS "public"."documents"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_doc public.documents;
  v_role text;
begin
  if p_document_id is null then
    raise exception 'document_id is required';
  end if;

  if p_actor_user_id is null then
    raise exception 'Not authenticated';
  end if;

  select * into v_doc
  from public.documents
  where id = p_document_id;

  if not found then
    raise exception 'Document not found';
  end if;

  v_role := public.account_role_for(v_doc.account_id);
  if v_role not in ('owner', 'admin', 'staff') then
    raise exception 'Not permitted';
  end if;

  if coalesce(v_doc.visibility, '') <> 'tenant' then
    raise exception 'Tenant highlight can be set only for tenant-visible documents';
  end if;

  if p_tenant_highlight not in ('standard', 'current', 'action_required') then
    raise exception 'Invalid tenant_highlight: %', p_tenant_highlight;
  end if;

  if p_tenant_highlight_rank is not null and (p_tenant_highlight_rank < 1 or p_tenant_highlight_rank > 999) then
    raise exception 'Invalid tenant_highlight_rank: %', p_tenant_highlight_rank;
  end if;

  update public.documents
  set
    tenant_highlight = p_tenant_highlight,
    tenant_highlight_note = nullif(trim(coalesce(p_tenant_highlight_note, '')), ''),
    tenant_highlight_rank = coalesce(
      p_tenant_highlight_rank,
      tenant_highlight_rank,
      case
        when p_tenant_highlight = 'action_required' then 10
        when p_tenant_highlight = 'current' then 50
        else 100
      end
    ),
    tenant_highlight_updated_at = now(),
    updated_at = now()
  where id = p_document_id
  returning * into v_doc;

  insert into public.document_audit_log (
    document_id,
    action,
    performed_by,
    performed_at,
    account_id,
    property_id,
    tenant_id,
    created_at
  )
  values (
    v_doc.id,
    'update_tags',
    p_actor_user_id,
    now(),
    v_doc.account_id,
    v_doc.property_id,
    v_doc.tenant_id,
    now()
  );

  return v_doc;
end;
$$;


