CREATE OR REPLACE FUNCTION "public"."set_work_order_fulfilment_route"("p_account_id" "uuid", "p_work_order_id" "uuid", "p_route" "text") RETURNS TABLE("account_id" "uuid", "work_order_id" "uuid", "route" "text", "updated_at" timestamp with time zone, "is_persisted" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_account_id uuid;
begin
  v_account_id := public.assert_manage_account_access(p_account_id);

  if p_route not in ('internal', 'marketplace', 'hybrid', 'undecided') then
    raise exception 'Unsupported fulfilment route';
  end if;

  if not exists (
    select 1
    from public.work_orders wo
    where wo.id = p_work_order_id
      and wo.account_id = v_account_id
  ) then
    raise exception 'Work order not found' using errcode = 'P0002';
  end if;

  insert into public.work_order_fulfilment_routes (
    work_order_id,
    account_id,
    route,
    updated_by
  )
  values (
    p_work_order_id,
    v_account_id,
    p_route,
    auth.uid()
  )
  on conflict on constraint work_order_fulfilment_routes_pkey do update
  set route = excluded.route,
      account_id = excluded.account_id,
      updated_by = auth.uid(),
      updated_at = now();

  perform public.activity_log_write(
    v_account_id,
    'work_order',
    p_work_order_id,
    'marketplace_route_changed',
    'fulfilment_route',
    null,
    p_route,
    jsonb_build_object(
      'table', 'work_order_fulfilment_routes',
      'route', p_route
    )
  );

  return query
  select
    r.account_id as account_id,
    r.work_order_id as work_order_id,
    r.route as route,
    r.updated_at as updated_at,
    true as is_persisted
  from public.work_order_fulfilment_routes r
  where r.work_order_id = p_work_order_id
    and r.account_id = v_account_id;
end;
$$;


ALTER FUNCTION "public"."set_work_order_fulfilment_route"("p_account_id" "uuid", "p_work_order_id" "uuid", "p_route" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."should_send_notification"("p_account_id" "uuid", "p_recipient_user_id" "uuid", "p_type" "text", "p_entity_type" "text", "p_entity_id" "uuid", "p_window_seconds" integer DEFAULT 90) RETURNS boolean
    LANGUAGE "plpgsql" STABLE
    AS $$
declare
  v_exists boolean;
begin
  select true
    into v_exists
  from public.notifications n
  where n.account_id = p_account_id
    and n.recipient_user_id = p_recipient_user_id
    and n.type = p_type
    and n.entity_type = p_entity_type
    and n.entity_id = p_entity_id
    and n.created_at >= now() - make_interval(secs => p_window_seconds)
  limit 1;

  return not coalesce(v_exists, false);
end;
$$;


