CREATE OR REPLACE FUNCTION "public"."should_throttle_notification"("p_account_id" "uuid", "p_recipient_user_id" "uuid", "p_type" "text", "p_entity_type" "text" DEFAULT NULL::"text", "p_entity_id" "uuid" DEFAULT NULL::"uuid", "p_window_seconds" integer DEFAULT 30) RETURNS boolean
    LANGUAGE "sql" STABLE
    AS $$
  select exists (
    select 1
    from public.notifications n
    where n.account_id = p_account_id
      and n.recipient_user_id = p_recipient_user_id
      and n.type = p_type
      and coalesce(n.entity_type, '') = coalesce(p_entity_type, '')
      and coalesce(
            n.entity_id,
            '00000000-0000-0000-0000-000000000000'::uuid
          )
          =
          coalesce(
            p_entity_id,
            '00000000-0000-0000-0000-000000000000'::uuid
          )
      -- ✅ FIX: notifications table has NO updated_at
      -- created_at is correct and immutable
      and n.created_at > now() - make_interval(
            secs => greatest(p_window_seconds, 1)
          )
  );
$$;


