CREATE OR REPLACE FUNCTION "public"."sync_document_packet_signature_status"("p_packet_id" "uuid", "p_submission_id" "text", "p_signature_status" "text", "p_completed_document_id" "uuid" DEFAULT NULL::"uuid", "p_error" "text" DEFAULT NULL::"text") RETURNS "public"."document_packets"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_packet public.document_packets;
  v_status text := lower(trim(coalesce(p_signature_status, '')));
  v_event text := 'signature_synced';
begin
  if coalesce(auth.role(), '') <> 'service_role' then raise exception 'Not permitted'; end if;
  if v_status not in ('requested', 'pending', 'completed', 'failed', 'cancelled') then raise exception 'Invalid signature status'; end if;

  select * into v_packet
  from public.document_packets
  where id = p_packet_id
    and (p_submission_id is null or signature_submission_id = p_submission_id);
  if not found then raise exception 'Packet not found'; end if;

  if p_completed_document_id is not null and not exists (
    select 1
    from public.documents d
    where d.id = p_completed_document_id
      and d.account_id = v_packet.account_id
  ) then
    raise exception 'Completed document not found';
  end if;

  if v_status = 'completed' then
    v_event := 'signature_completed';
  elsif v_status = 'failed' then
    v_event := 'signature_failed';
  end if;

  update public.document_packets
  set signature_status = v_status,
      signature_completed_document_id = case when v_status = 'completed' then p_completed_document_id else signature_completed_document_id end,
      signature_synced_at = now(),
      signature_error = nullif(trim(coalesce(p_error, '')), ''),
      status = case when v_status = 'completed' then 'completed' else status end,
      completed_at = case when v_status = 'completed' then coalesce(completed_at, now()) else completed_at end
  where id = p_packet_id
  returning * into v_packet;

  if v_status = 'completed' then
    update public.document_packet_recipients
    set status = 'completed',
        viewed_at = coalesce(viewed_at, now()),
        completed_at = coalesce(completed_at, now())
    where packet_id = p_packet_id
      and status <> 'voided';
  end if;

  insert into public.document_packet_events (account_id, packet_id, event_type, message, metadata)
  values (
    v_packet.account_id,
    v_packet.id,
    v_event,
    'External signature status synced',
    jsonb_build_object('signature_status', v_status, 'has_completed_document', p_completed_document_id is not null)
  );

  return v_packet;
end;
$$;


ALTER FUNCTION "public"."sync_document_packet_signature_status"("p_packet_id" "uuid", "p_submission_id" "text", "p_signature_status" "text", "p_completed_document_id" "uuid", "p_error" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."sync_maintenance_request_from_work_orders"("p_request_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_total int;
  v_assigned int;
  v_in_progress int;
  v_completed int;
  v_cancelled int;
begin
  if p_request_id is null then
    return;
  end if;

  select
    count(*) as total,
    count(*) filter (where coalesce(status,'') = 'assigned') as assigned_cnt,
    count(*) filter (where coalesce(status,'') = 'in_progress') as in_progress_cnt,
    count(*) filter (where coalesce(status,'') = 'completed') as completed_cnt,
    count(*) filter (where coalesce(status,'') = 'cancelled') as cancelled_cnt
  into v_total, v_assigned, v_in_progress, v_completed, v_cancelled
  from public.work_orders
  where maintenance_request_id = p_request_id;

  if v_total = 0 then
    return;
  end if;

  -- Don't auto-change closed requests
  if exists (
    select 1
    from public.maintenance_requests mr
    where mr.id = p_request_id
      and mr.status = 'closed'
  ) then
    return;
  end if;

  -- Priority order
  if v_in_progress > 0 then
    update public.maintenance_requests
    set status = 'in_progress',
        updated_at = now()
    where id = p_request_id
      and status in ('open','waiting','in_progress'); -- don't reopen resolved
    return;
  end if;

  if v_assigned > 0 then
    update public.maintenance_requests
    set status = 'waiting',
        updated_at = now()
    where id = p_request_id
      and status in ('open','waiting','in_progress'); -- don't reopen resolved
    return;
  end if;

  if v_completed = v_total then
    update public.maintenance_requests
    set status = 'resolved',
        updated_at = now()
    where id = p_request_id
      and status <> 'closed';
    return;
  end if;

  if v_cancelled = v_total then
    update public.maintenance_requests
    set status = 'open',
        updated_at = now()
    where id = p_request_id
      and status in ('open','waiting','in_progress'); -- don't reopen resolved
    return;
  end if;

  return;
end;
$$;


ALTER FUNCTION "public"."sync_maintenance_request_from_work_orders"("p_request_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."sync_work_order_expense_fact"("p_work_order_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  fin record;
  wo record;
  contractor_row record;
  next_state text;
begin
  if p_work_order_id is null then
    return;
  end if;

  select *
  into fin
  from public.work_order_financials
  where work_order_id = p_work_order_id
  limit 1;

  if not found then
    delete from public.maintenance_expenses
    where source = 'work_order_invoice'
      and source_key = p_work_order_id::text;
    return;
  end if;

  select *
  into wo
  from public.work_orders
  where id = p_work_order_id
  limit 1;

  if not found then
    return;
  end if;

  if coalesce(fin.rejected_at, null) is not null then
    next_state := 'rejected';
  elsif coalesce(fin.approved_at, null) is not null or lower(coalesce(fin.quote_status, '')) = 'approved' then
    next_state := 'approved';
  elsif lower(coalesce(fin.quote_status, '')) = 'submitted' then
    next_state := 'submitted';
  else
    next_state := 'draft';
  end if;

  if coalesce(fin.invoice_amount, 0) <= 0 then
    delete from public.maintenance_expenses
    where source = 'work_order_invoice'
      and source_key = p_work_order_id::text;
    return;
  end if;

  if wo.contractor_user_id is not null then
    select id, name
    into contractor_row
    from public.contractors c
    where c.account_id = wo.account_id
      and c.user_id = wo.contractor_user_id
    limit 1;
  end if;

  insert into public.maintenance_expenses (
    account_id,
    property_id,
    work_order_id,
    maintenance_request_id,
    vendor_id,
    vendor_name,
    category,
    approval_state,
    amount,
    currency,
    expense_date,
    posted_at,
    source,
    source_key,
    notes
  )
  values (
    wo.account_id,
    wo.property_id,
    wo.id,
    wo.maintenance_request_id,
    contractor_row.id,
    coalesce(wo.contractor_name, contractor_row.name),
    'general_repair',
    next_state,
    fin.invoice_amount,
    coalesce(fin.invoice_currency, 'GBP'),
    coalesce(fin.invoice_issued_at::date, fin.approved_at::date, current_date),
    coalesce(fin.invoice_issued_at, fin.approved_at, now()),
    'work_order_invoice',
    wo.id::text,
    fin.quote_notes
  )
  on conflict (source, source_key)
  do update set
    account_id = excluded.account_id,
    property_id = excluded.property_id,
    work_order_id = excluded.work_order_id,
    maintenance_request_id = excluded.maintenance_request_id,
    vendor_id = excluded.vendor_id,
    vendor_name = excluded.vendor_name,
    approval_state = excluded.approval_state,
    amount = excluded.amount,
    currency = excluded.currency,
    expense_date = excluded.expense_date,
    posted_at = excluded.posted_at,
    notes = excluded.notes,
    updated_at = now();
end;
$$;


ALTER FUNCTION "public"."sync_work_order_expense_fact"("p_work_order_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."tenant_activity_feed"("p_account_id" "uuid", "p_tenant_id" "uuid", "p_limit" integer DEFAULT 40) RETURNS TABLE("event_key" "text", "event_type" "text", "occurred_at" timestamp with time zone, "title" "text", "detail" "text", "status" "text", "link_path" "text", "source_table" "text", "source_id" "uuid")
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with cfg as (
    select greatest(1, least(coalesce(p_limit, 40), 100)) as max_items
  ),
  authz as (
    select
      p_account_id as account_id,
      public.assert_tenant_scope_access(p_account_id, p_tenant_id) as tenant_id
  ),
  tenant_scope as (
    select
      t.id,
      t.account_id,
      t.property_id,
      t.name,
      t.created_at
    from public.tenants t
    cross join authz a
    where t.account_id = a.account_id
      and t.id = a.tenant_id
  ),
  lease_rows as (
    select
      l.id,
      l.lease_start_date,
      l.lease_end_date,
      l.renewal_status,
      p.address as property_label
    from public.leases l
    join tenant_scope ts on ts.id = l.tenant_id
    left join public.properties p on p.id = l.property_id
  ),
  payment_rows as (
    select
      p.id,
      p.amount,
      p.status,
      p.due_date,
      p.paid_at,
      p.created_at
    from public.payments p
    join tenant_scope ts on ts.id = p.tenant_id
    where p.account_id = p_account_id
  ),
  request_rows as (
    select
      mr.id,
      mr.title,
      mr.status,
      mr.priority,
      mr.created_at,
      mr.updated_at
    from public.maintenance_requests mr
    join tenant_scope ts on ts.id = mr.reported_by_tenant_id
    where mr.account_id = p_account_id
  ),
  work_order_rows as (
    select
      wo.id,
      wo.maintenance_request_id,
      wo.status,
      wo.contractor_name,
      wo.created_at,
      wo.updated_at
    from public.work_orders wo
    join request_rows rr on rr.id = wo.maintenance_request_id
    where wo.account_id = p_account_id
  ),
  work_order_audit_rows as (
    select
      wal.id,
      wal.work_order_id,
      wal.action,
      wal.old_value,
      wal.new_value,
      wal.created_at
    from public.work_order_audit_log wal
    join work_order_rows wor on wor.id = wal.work_order_id
  ),
  document_rows as (
    select
      d.id,
      d.name,
      d.created_at
    from public.documents d
    join tenant_scope ts on ts.id = d.tenant_id
    where d.account_id = p_account_id
      and coalesce(d.upload_status, 'uploaded') = 'uploaded'
  ),
  notification_rows as (
    select
      n.id,
      n.title,
      n.body,
      n.type,
      n.entity_type,
      n.entity_id,
      n.link_path,
      n.created_at
    from public.notifications n
    where n.account_id = p_account_id
      and (
        (lower(coalesce(n.entity_type, '')) in ('tenant', 'tenants') and n.entity_id = p_tenant_id)
        or (lower(coalesce(n.entity_type, '')) in ('payment', 'payments') and n.entity_id in (select id from payment_rows))
        or (lower(coalesce(n.entity_type, '')) in ('maintenance_request', 'maintenance_requests') and n.entity_id in (select id from request_rows))
        or (lower(coalesce(n.entity_type, '')) in ('work_order', 'work_orders') and n.entity_id in (select id from work_order_rows))
        or (n.metadata->>'tenant_id' = p_tenant_id::text)
      )
  ),
  document_audit_rows as (
    select
      dal.id,
      dal.action,
      dal.document_id,
      dal.performed_at,
      d.name
    from public.document_audit_log dal
    join document_rows d on d.id = dal.document_id
    where dal.account_id = p_account_id
  ),
  activity_rows as (
    select
      al.id,
      al.entity_type,
      al.entity_id,
      al.action,
      al.field,
      al.old_value,
      al.new_value,
      al.actor_role,
      al.created_at
    from public.activity_log al
    left join tenant_scope ts on ts.id = al.entity_id and lower(coalesce(al.entity_type, '')) in ('tenant', 'tenants')
    where al.account_id = p_account_id
      and (
        ts.id is not null
        or (al.meta->>'property_id') = (select property_id::text from tenant_scope limit 1)
      )
  ),
  unioned as (
    select
      'tenant-created-' || ts.id::text as event_key,
      'tenant_created'::text as event_type,
      ts.created_at as occurred_at,
      'Tenant record created'::text as title,
      coalesce(p.address, '') as detail,
      ''::text as status,
      ('/tenants/' || ts.id::text) as link_path,
      'tenants'::text as source_table,
      ts.id as source_id
    from tenant_scope ts
    left join public.properties p on p.id = ts.property_id

    union all

    select
      'lease-start-' || lr.id::text,
      'lease_start',
      lr.lease_start_date::timestamp at time zone 'UTC',
      'Lease started',
      coalesce(lr.property_label, ''),
      coalesce(lr.renewal_status, ''),
      ('/tenants/' || p_tenant_id::text),
      'leases',
      lr.id
    from lease_rows lr
    where lr.lease_start_date is not null

    union all

    select
      'lease-end-' || lr.id::text,
      'lease_end',
      lr.lease_end_date::timestamp at time zone 'UTC',
      'Lease end recorded',
      coalesce(lr.property_label, ''),
      coalesce(lr.renewal_status, ''),
      ('/tenants/' || p_tenant_id::text),
      'leases',
      lr.id
    from lease_rows lr
    where lr.lease_end_date is not null

    union all

    select
      'payment-paid-' || pr.id::text,
      'payment_paid',
      pr.paid_at,
      'Rent payment recorded',
      coalesce(pr.amount::text, ''),
      coalesce(pr.status, ''),
      '/tenant/payments',
      'payments',
      pr.id
    from payment_rows pr
    where pr.paid_at is not null

    union all

    select
      'payment-overdue-' || pr.id::text,
      'payment_overdue',
      coalesce(pr.due_date::timestamp at time zone 'UTC', pr.created_at),
      'Rent became overdue',
      coalesce(pr.amount::text, ''),
      coalesce(pr.status, ''),
      '/tenant/payments',
      'payments',
      pr.id
    from payment_rows pr
    where lower(coalesce(pr.status, '')) in ('overdue', 'zaległe')

    union all

    select
      'payment-scheduled-' || pr.id::text,
      'payment_scheduled',
      coalesce(pr.due_date::timestamp at time zone 'UTC', pr.created_at),
      'Rent charge scheduled',
      coalesce(pr.amount::text, ''),
      coalesce(pr.status, ''),
      '/tenant/payments',
      'payments',
      pr.id
    from payment_rows pr
    where pr.paid_at is null

    union all

    select
      'request-' || rr.id::text,
      'maintenance_request',
      rr.created_at,
      'Maintenance request submitted',
      coalesce(rr.title, ''),
      coalesce(rr.status, rr.priority, ''),
      '/maintenance-inbox',
      'maintenance_requests',
      rr.id
    from request_rows rr

    union all

    select
      'request-status-' || ar.id::text,
      'request_status_changed',
      ar.created_at,
      'Request status changed',
      coalesce(nullif(ar.new_value::text, ''), nullif(ar.field, ''), ''),
      coalesce(ar.actor_role, ''),
      '/maintenance-inbox',
      'activity_log',
      ar.id
    from activity_rows ar
    where lower(coalesce(ar.entity_type, '')) in ('maintenance_request', 'maintenance_requests')
      and (
        lower(coalesce(ar.field, '')) = 'status'
        or lower(coalesce(ar.action, '')) = 'status_change'
      )

    union all

    select
      'work-order-opened-' || wor.id::text,
      'work_order_opened',
      coalesce(wor.created_at, wor.updated_at),
      'Work order opened',
      coalesce(wor.contractor_name, ''),
      coalesce(wor.status, ''),
      ('/work-orders/' || wor.id::text),
      'work_orders',
      wor.id
    from work_order_rows wor
    where lower(coalesce(wor.status, '')) not in ('completed', 'zakończone')

    union all

    select
      'work-order-completed-' || wor.id::text,
      'work_order_completed',
      coalesce(wor.updated_at, wor.created_at),
      'Work order completed',
      coalesce(wor.contractor_name, ''),
      coalesce(wor.status, ''),
      ('/work-orders/' || wor.id::text),
      'work_orders',
      wor.id
    from work_order_rows wor
    where lower(coalesce(wor.status, '')) in ('completed', 'zakończone')

    union all

    select
      'work-order-assigned-' || woar.id::text,
      'contractor_assigned',
      woar.created_at,
      'Contractor assigned',
      coalesce(wor.contractor_name, ''),
      coalesce(wor.status, ''),
      ('/work-orders/' || wor.id::text),
      'work_order_audit_log',
      wor.id
    from work_order_audit_rows woar
    join work_order_rows wor on wor.id = woar.work_order_id
    where lower(coalesce(woar.action, '')) like '%assign%'
       or lower(coalesce(woar.action, '')) like '%contractor%'

    union all

    select
      'work-order-action-' || woar.id::text,
      case
        when lower(coalesce(woar.action, '')) like '%complete%' then 'work_order_completed'
        else 'work_order_action'
      end,
      woar.created_at,
      case
        when lower(coalesce(woar.action, '')) like '%complete%' then 'Work completed'
        else 'Work order updated'
      end,
      coalesce(woar.action, ''),
      coalesce(wor.status, ''),
      ('/work-orders/' || wor.id::text),
      'work_order_audit_log',
      wor.id
    from work_order_audit_rows woar
    join work_order_rows wor on wor.id = woar.work_order_id
    where not (
      lower(coalesce(woar.action, '')) like '%assign%'
      or lower(coalesce(woar.action, '')) like '%contractor%'
      or lower(coalesce(woar.action, '')) in ('create', 'insert')
    )

    union all

    select
      'document-uploaded-' || dr.id::text,
      'document_uploaded',
      dr.created_at,
      'Document uploaded',
      coalesce(dr.name, ''),
      ''::text,
      ('/documents?tenant=' || p_tenant_id::text),
      'documents',
      dr.id
    from document_rows dr

    union all

    select
      'document-audit-' || dar.id::text,
      'document_audit',
      dar.performed_at,
      case
        when upper(coalesce(dar.action, '')) = 'DELETE' then 'Document deleted'
        else 'Document updated'
      end,
      coalesce(dar.name, ''),
      coalesce(dar.action, ''),
      ('/documents?tenant=' || p_tenant_id::text),
      'document_audit_log',
      dar.document_id
    from document_audit_rows dar

    union all

    select
      'notification-' || nr.id::text,
      'notification_sent',
      nr.created_at,
      coalesce(nullif(nr.title, ''), 'Notification sent'),
      coalesce(nr.body, ''),
      coalesce(nr.type, ''),
      coalesce(nr.link_path, '/tenants/' || p_tenant_id::text),
      'notifications',
      nr.id
    from notification_rows nr

    union all

    select
      'activity-' || ar.id::text,
      'activity_log',
      ar.created_at,
      case
        when lower(coalesce(ar.entity_type, '')) in ('tenant', 'tenants') then 'Tenant activity'
        when lower(coalesce(ar.entity_type, '')) in ('property', 'properties') then 'Property activity'
        when lower(coalesce(ar.entity_type, '')) in ('work_order', 'work_orders') then 'Work order activity'
        when lower(coalesce(ar.entity_type, '')) in ('maintenance_request', 'maintenance_requests') then 'Maintenance activity'
        when lower(coalesce(ar.entity_type, '')) in ('payment', 'payments') then 'Payment activity'
        else 'Operational activity'
      end,
      coalesce(ar.field, ''),
      coalesce(ar.actor_role, ''),
      case
        when lower(coalesce(ar.entity_type, '')) in ('work_order', 'work_orders') and ar.entity_id is not null then '/work-orders/' || ar.entity_id::text
        else '/tenants/' || p_tenant_id::text
      end,
      'activity_log',
      ar.id
    from activity_rows ar
  )
  select
    u.event_key,
    u.event_type,
    u.occurred_at,
    u.title,
    u.detail,
    u.status,
    u.link_path,
    u.source_table,
    u.source_id
  from unioned u
  where u.occurred_at is not null
  order by u.occurred_at desc, u.event_key
  limit (select max_items from cfg);
$$;


ALTER FUNCTION "public"."tenant_activity_feed"("p_account_id" "uuid", "p_tenant_id" "uuid", "p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."tenant_id_for_account"("p_account_id" "uuid") RETURNS "uuid"
    LANGUAGE "sql" STABLE
    AS $$
  select t.id
  from public.tenants t
  where t.account_id = p_account_id
    and t.user_id = auth.uid()
    and t.archived_at is null
  limit 1
$$;


ALTER FUNCTION "public"."tenant_id_for_account"("p_account_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."tg_activity_log_maintenance_requests"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'auth'
    AS $$
declare
  v_meta jsonb;
begin
  if (tg_op = 'INSERT') then
    v_meta := jsonb_build_object(
      'table', 'maintenance_requests',
      'property_id', new.property_id,
      'reported_by_tenant_id', new.reported_by_tenant_id
    );

    perform public.activity_log_write(
      new.account_id,
      'maintenance_request',
      new.id,
      'created',
      null, null, null,
      v_meta
    );
    return new;

  elsif (tg_op = 'UPDATE') then
    v_meta := jsonb_build_object(
      'table', 'maintenance_requests',
      'property_id', new.property_id,
      'reported_by_tenant_id', new.reported_by_tenant_id
    );

    if coalesce(old.status,'') <> coalesce(new.status,'') then
      perform public.activity_log_write(
        new.account_id,
        'maintenance_request',
        new.id,
        'status_change',
        'status',
        old.status::text,
        new.status::text,
        v_meta
      );
      return new;
    end if;

    if coalesce(old.priority,'') <> coalesce(new.priority,'') then
      perform public.activity_log_write(
        new.account_id,
        'maintenance_request',
        new.id,
        'updated',
        'priority',
        old.priority::text,
        new.priority::text,
        v_meta
      );
      return new;
    end if;

    perform public.activity_log_write(
      new.account_id,
      'maintenance_request',
      new.id,
      'updated',
      null, null, null,
      v_meta
    );
    return new;

  elsif (tg_op = 'DELETE') then
    v_meta := jsonb_build_object(
      'table', 'maintenance_requests',
      'property_id', old.property_id,
      'reported_by_tenant_id', old.reported_by_tenant_id
    );

    perform public.activity_log_write(
      old.account_id,
      'maintenance_request',
      old.id,
      'deleted',
      null, null, null,
      v_meta
    );
    return old;
  end if;

  return coalesce(new, old);
end;
$$;


ALTER FUNCTION "public"."tg_activity_log_maintenance_requests"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."tg_activity_log_work_orders"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'auth'
    AS $$
declare
  v_meta jsonb;
  v_action text;
begin
  if (tg_op = 'INSERT') then
    v_meta := jsonb_build_object(
      'table', 'work_orders',
      'property_id', new.property_id,
      'maintenance_request_id', new.maintenance_request_id,
      'contractor_user_id', new.contractor_user_id
    );

    perform public.activity_log_write(
      new.account_id,
      'work_order',
      new.id,
      'created',
      null, null, null,
      v_meta
    );
    return new;

  elsif (tg_op = 'UPDATE') then
    v_meta := jsonb_build_object(
      'table', 'work_orders',
      'property_id', new.property_id,
      'maintenance_request_id', new.maintenance_request_id,
      'contractor_user_id', new.contractor_user_id
    );

    -- Status change
    if coalesce(old.status,'') <> coalesce(new.status,'') then
      perform public.activity_log_write(
        new.account_id,
        'work_order',
        new.id,
        'status_change',
        'status',
        old.status::text,
        new.status::text,
        v_meta
      );
      return new;
    end if;

    -- Contractor assignment change (optional but useful)
    if coalesce(old.contractor_user_id::text,'') <> coalesce(new.contractor_user_id::text,'') then
      perform public.activity_log_write(
        new.account_id,
        'work_order',
        new.id,
        'updated',
        'contractor_user_id',
        old.contractor_user_id::text,
        new.contractor_user_id::text,
        v_meta
      );
      return new;
    end if;

    -- Minimal generic update (fallback)
    perform public.activity_log_write(
      new.account_id,
      'work_order',
      new.id,
      'updated',
      null, null, null,
      v_meta
    );
    return new;

  elsif (tg_op = 'DELETE') then
    v_meta := jsonb_build_object(
      'table', 'work_orders',
      'property_id', old.property_id,
      'maintenance_request_id', old.maintenance_request_id,
      'contractor_user_id', old.contractor_user_id
    );

    perform public.activity_log_write(
      old.account_id,
      'work_order',
      old.id,
      'deleted',
      null, null, null,
      v_meta
    );
    return old;
  end if;

  return coalesce(new, old);
end;
$$;


ALTER FUNCTION "public"."tg_activity_log_work_orders"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."tg_audit_basic"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'auth'
    AS $$
declare
  v_account_id uuid;
  v_entity_type text := tg_argv[0];
begin
  v_account_id := coalesce(new.account_id, old.account_id);

  if tg_op = 'INSERT' then
    insert into public.activity_log(account_id, entity_type, entity_id, action, actor_user_id, actor_role, meta)
    values (
      v_account_id,
      v_entity_type,
      new.id,
      'created',
      auth.uid(),
      public.account_role_for(v_account_id),
      jsonb_build_object('table', tg_table_name)
    );
    return new;
  end if;

  if tg_op = 'DELETE' then
    insert into public.activity_log(account_id, entity_type, entity_id, action, actor_user_id, actor_role, meta)
    values (
      v_account_id,
      v_entity_type,
      old.id,
      'deleted',
      auth.uid(),
      public.account_role_for(v_account_id),
      jsonb_build_object('table', tg_table_name)
    );
    return old;
  end if;

  -- UPDATE
  if coalesce(new.status::text,'') <> coalesce(old.status::text,'') then
    insert into public.activity_log(account_id, entity_type, entity_id, action, field, old_value, new_value, actor_user_id, actor_role)
    values (
      v_account_id,
      v_entity_type,
      new.id,
      'status_changed',
      'status',
      old.status::text,
      new.status::text,
      auth.uid(),
      public.account_role_for(v_account_id)
    );
  else
    insert into public.activity_log(account_id, entity_type, entity_id, action, actor_user_id, actor_role)
    values (
      v_account_id,
      v_entity_type,
      new.id,
      'updated',
      auth.uid(),
      public.account_role_for(v_account_id)
    );
  end if;

  return new;
end;
$$;


ALTER FUNCTION "public"."tg_audit_basic"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."tg_capture_payment_events"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  next_event_type text;
  next_old_status text;
  next_new_status text;
  next_payment_id uuid;
  next_account_id uuid;
  next_property_id uuid;
  next_tenant_id uuid;
  next_amount numeric(12, 2);
  next_event_at timestamptz;
  next_metadata jsonb;
begin
  if tg_op = 'DELETE' then
    next_event_type := 'payment_deleted';
    next_old_status := old.status;
    next_new_status := null;
    next_payment_id := null;
    next_account_id := old.account_id;
    next_property_id := old.property_id;
    next_tenant_id := old.tenant_id;
    next_amount := old.amount;
    next_event_at := now();
    next_metadata := jsonb_build_object(
      'payment_id', old.id,
      'due_date', old.due_date,
      'paid_at', old.paid_at
    );
  elsif tg_op = 'INSERT' then
    next_event_type := case
      when new.paid_at is not null or lower(coalesce(new.status, '')) = 'paid' then 'payment_paid'
      else 'payment_created'
    end;
    next_old_status := null;
    next_new_status := new.status;
    next_payment_id := new.id;
    next_account_id := new.account_id;
    next_property_id := new.property_id;
    next_tenant_id := new.tenant_id;
    next_amount := new.amount;
    next_event_at := coalesce(new.paid_at, new.created_at, now());
    next_metadata := jsonb_build_object(
      'due_date', new.due_date,
      'paid_at', new.paid_at
    );
  else
    next_event_type := case
      when old.paid_at is distinct from new.paid_at and new.paid_at is not null then 'payment_paid'
      when lower(coalesce(old.status, '')) is distinct from lower(coalesce(new.status, ''))
        and lower(coalesce(new.status, '')) in ('overdue', 'zaległe', 'zalegle') then 'payment_overdue'
      when lower(coalesce(old.status, '')) is distinct from lower(coalesce(new.status, ''))
        and lower(coalesce(old.status, '')) = 'paid'
        and coalesce(new.paid_at, null) is null then 'payment_reopened'
      when old.amount is distinct from new.amount or old.due_date is distinct from new.due_date then 'payment_updated'
      else 'payment_status_changed'
    end;
    next_old_status := old.status;
    next_new_status := new.status;
    next_payment_id := new.id;
    next_account_id := new.account_id;
    next_property_id := new.property_id;
    next_tenant_id := new.tenant_id;
    next_amount := new.amount;
    next_event_at := coalesce(new.paid_at, now());
    next_metadata := jsonb_build_object(
      'due_date', new.due_date,
      'paid_at', new.paid_at,
      'old_due_date', old.due_date,
      'old_paid_at', old.paid_at
    );
  end if;

  insert into public.payment_events (
    payment_id,
    account_id,
    property_id,
    tenant_id,
    event_type,
    event_at,
    old_status,
    new_status,
    amount,
    actor_source,
    metadata
  ) values (
    next_payment_id,
    next_account_id,
    next_property_id,
    next_tenant_id,
    next_event_type,
    coalesce(next_event_at, now()),
    next_old_status,
    next_new_status,
    next_amount,
    'db_trigger',
    coalesce(next_metadata, '{}'::jsonb)
  );

  if tg_op = 'DELETE' then
    return old;
  end if;
  return new;
end;
$$;


ALTER FUNCTION "public"."tg_capture_payment_events"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."tg_create_lease_on_application_approved"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_existing uuid;
begin
  if (tg_op = 'UPDATE')
     and (new.status = 'approved')
     and (old.status is distinct from new.status) then

    select id into v_existing
    from public.leases
    where application_id = new.id
    limit 1;

    if v_existing is not null then
      return new;
    end if;

    if exists (
      select 1 from public.leases
      where property_id = new.property_id
        and status = 'active'
    ) then
      raise exception 'Cannot approve: active lease already exists for this property';
    end if;

    insert into public.leases (
      account_id,
      property_id,
      tenant_id,
      application_id,
      status,
      created_by,
      created_at,
      updated_at
    )
    values (
      new.account_id,
      new.property_id,
      new.tenant_id,
      new.id,
      'draft',     -- ✅ changed from active → draft
      auth.uid(),
      now(),
      now()
    );

    -- Optional legacy sync:
    update public.tenants
    set property_id = new.property_id
    where id = new.tenant_id;
  end if;

  return new;
end;
$$;


ALTER FUNCTION "public"."tg_create_lease_on_application_approved"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."tg_documents_set_created_by"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
begin
  if new.created_by_user_id is null then
    new.created_by_user_id := coalesce(new.uploaded_by, auth.uid());
  end if;
  return new;
end;
$$;


