CREATE OR REPLACE FUNCTION "public"."tg_guard_work_orders_contractor_updates"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
begin
  -- If not a logged-in context, do nothing special
  if auth.uid() is null then
    return new;
  end if;

  -- Only enforce guardrail when the updating user is the contractor on the row
  -- AND they are NOT an account member (owner/admin/staff). Contractors typically are not.
  if (new.contractor_user_id is not null)
     and (auth.uid() = new.contractor_user_id)
     and (not public.is_account_member(new.account_id)) then

    -- Block changes to "protected" columns
    if (new.account_id            is distinct from old.account_id) or
       (new.property_id           is distinct from old.property_id) or
       (new.maintenance_request_id is distinct from old.maintenance_request_id) or
       (new.contractor_user_id    is distinct from old.contractor_user_id) or
       (new.contractor_name       is distinct from old.contractor_name) or
       (new.contractor_phone      is distinct from old.contractor_phone) or
       (new.quote_amount          is distinct from old.quote_amount) or
       (new.invoice_amount        is distinct from old.invoice_amount) or
       (new.created_by            is distinct from old.created_by) or
       (new.created_at            is distinct from old.created_at) then
      raise exception 'Contractor may only update: status, notes, scheduled_at';
    end if;

    -- Optional: enforce allowed transitions (keep it simple)
    -- You can expand later (e.g. prevent going from completed -> in_progress).
    if new.status not in ('assigned','in_progress','completed','cancelled') then
      raise exception 'Invalid work order status: %', new.status;
    end if;
  end if;

  return new;
end;
$$;


ALTER FUNCTION "public"."tg_guard_work_orders_contractor_updates"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."tg_payments_set_status"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
begin
  -- Keep void untouched unless explicitly changed
  if coalesce(new.status,'') = 'void' then
    return new;
  end if;

  if new.paid_at is not null then
    new.status := 'paid';
  elsif new.due_date is not null and new.due_date < current_date then
    new.status := 'overdue';
  else
    new.status := 'due';
  end if;

  return new;
end;
$$;


