CREATE OR REPLACE FUNCTION "public"."tg_prevent_blocked_transitions"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
begin
  if lower(coalesce(new.from_status,'')) = 'blocked'
     or lower(coalesce(new.to_status,'')) = 'blocked' then
    raise exception 'blocked is deprecated and must not be used';
  end if;

  -- normalize
  new.from_status := lower(trim(new.from_status));
  new.to_status   := lower(trim(new.to_status));
  return new;
end;
$$;


