CREATE OR REPLACE FUNCTION "public"."tg_set_reported_by_tenant"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_tenant_id uuid;
begin
  -- Find the active tenant row for this user + property + account
  select t.id
    into v_tenant_id
  from public.tenants t
  where t.user_id = auth.uid()
    and t.archived_at is null
    and t.status = any (array['active'::text, 'accepted_pending_signing'::text])
    and t.property_id = new.property_id
    and t.account_id  = new.account_id
  order by t.created_at desc
  limit 1;

  -- If user is a tenant for this property/account:
  if v_tenant_id is not null then
    -- If they tried to spoof a different tenant id, block it
    if new.reported_by_tenant_id is not null and new.reported_by_tenant_id <> v_tenant_id then
      raise exception 'Invalid reported_by_tenant_id (spoof attempt)'
        using errcode = '42501';
    end if;

    -- Auto-set it if missing
    new.reported_by_tenant_id := coalesce(new.reported_by_tenant_id, v_tenant_id);
  end if;

  return new;
end;
$$;


