CREATE OR REPLACE FUNCTION "public"."tg_work_order_ack_defaults"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
declare
  has_contractor boolean;
  contractor_changed boolean;
begin
  has_contractor := new.contractor_user_id is not null or nullif(coalesce(new.contractor_name, ''), '') is not null;
  contractor_changed := tg_op = 'INSERT';
  if tg_op = 'UPDATE' then
    contractor_changed := contractor_changed
      or old.contractor_user_id is distinct from new.contractor_user_id
      or coalesce(old.contractor_name, '') is distinct from coalesce(new.contractor_name, '');
  end if;

  if not has_contractor then
    new.assigned_at := null;
    new.acknowledged_at := null;
    new.acknowledgement_due_at := null;
    new.acknowledgement_status := 'not_required';
    return new;
  end if;

  if contractor_changed then
    new.assigned_at := coalesce(new.assigned_at, now());
    if tg_op = 'UPDATE' and old.acknowledged_at is distinct from new.acknowledged_at then
      null;
    elsif tg_op = 'UPDATE' and (
      old.contractor_user_id is distinct from new.contractor_user_id
      or coalesce(old.contractor_name, '') is distinct from coalesce(new.contractor_name, '')
    ) then
      new.acknowledged_at := null;
      new.acknowledgement_status := 'pending';
      new.acknowledgement_due_at := now() + interval '48 hours';
    end if;
  end if;

  new.assigned_at := coalesce(new.assigned_at, now());
  new.acknowledgement_due_at := coalesce(new.acknowledgement_due_at, new.assigned_at + interval '48 hours');

  if new.acknowledged_at is not null then
    new.acknowledgement_status := 'acknowledged';
  else
    new.acknowledgement_status := coalesce(nullif(new.acknowledgement_status, ''), 'pending');
  end if;

  return new;
end;
$$;


ALTER FUNCTION "public"."tg_work_order_ack_defaults"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."tg_work_orders_block_contractor_edits"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
declare
  is_staff boolean;
begin
  is_staff := public.account_role_for(NEW.account_id) = any (array['owner','admin','staff']);
  if is_staff then
    return NEW;
  end if;

  -- block protected fields for contractor updates
  if (NEW.account_id is distinct from OLD.account_id)
    or (NEW.property_id is distinct from OLD.property_id)
    or (NEW.maintenance_request_id is distinct from OLD.maintenance_request_id)
    or (NEW.contractor_user_id is distinct from OLD.contractor_user_id)
    or (NEW.contractor_name is distinct from OLD.contractor_name)
    or (NEW.contractor_phone is distinct from OLD.contractor_phone)
    or (NEW.quote_amount is distinct from OLD.quote_amount)
    or (NEW.created_by is distinct from OLD.created_by)
    or (NEW.created_at is distinct from OLD.created_at)
  then
    raise exception 'Contractor cannot modify protected fields';
  end if;

  return NEW;
end;
$$;


ALTER FUNCTION "public"."tg_work_orders_block_contractor_edits"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."tg_work_orders_enforce_status_transition"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
declare
  v_old text := lower(coalesce(old.status, 'assigned'));
  v_new text := lower(coalesce(new.status, 'assigned'));
begin
  -- Only enforce when status is changing
  if v_new = v_old then
    return new;
  end if;

  -- Basic allowed set guard (extra safety)
  if v_new not in ('assigned','in_progress','completed','blocked','cancelled') then
    raise exception 'Invalid work order status: %', new.status
      using errcode = '23514'; -- check_violation
  end if;

  -- Transition rules
  if v_old = 'assigned' then
    if v_new not in ('in_progress','blocked','cancelled') then
      raise exception 'Invalid transition: % -> %', old.status, new.status
        using errcode = '23514';
    end if;

  elsif v_old = 'in_progress' then
    if v_new not in ('completed','blocked','cancelled') then
      raise exception 'Invalid transition: % -> %', old.status, new.status
        using errcode = '23514';
    end if;

  elsif v_old = 'blocked' then
    if v_new not in ('in_progress','cancelled') then
      raise exception 'Invalid transition: % -> %', old.status, new.status
        using errcode = '23514';
    end if;

  elsif v_old in ('completed','cancelled') then
    -- Terminal states
    raise exception 'Cannot change status once %', old.status
      using errcode = '23514';

  else
    -- Unknown old status (legacy rows) — force user to move into a valid path
    -- Allow only into assigned/in_progress/blocked/cancelled (not straight to completed)
    if v_new not in ('assigned','in_progress','blocked','cancelled') then
      raise exception 'Invalid transition: % -> %', old.status, new.status
        using errcode = '23514';
    end if;
  end if;

  return new;
end;
$$;


ALTER FUNCTION "public"."tg_work_orders_enforce_status_transition"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."tg_work_orders_guard_status_transition"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
declare
  old_s text := coalesce(old.status,'');
  new_s text := coalesce(new.status,'');
begin
  if new_s = old_s then
    return new;
  end if;

  if new_s not in ('assigned','in_progress','completed','blocked','cancelled') then
    raise exception 'Invalid work_orders.status: %', new_s;
  end if;

  if old_s = 'assigned' then
    if new_s not in ('in_progress','blocked','cancelled') then
      raise exception 'Invalid transition: % -> %', old_s, new_s;
    end if;

  elsif old_s = 'in_progress' then
    if new_s not in ('completed','blocked','cancelled') then
      raise exception 'Invalid transition: % -> %', old_s, new_s;
    end if;

  elsif old_s = 'blocked' then
    if new_s not in ('assigned','in_progress','cancelled') then
      raise exception 'Invalid transition: % -> %', old_s, new_s;
    end if;

  elsif old_s in ('completed','cancelled') then
    raise exception 'Cannot change status after %', old_s;

  end if;

  return new;
end;
$$;


ALTER FUNCTION "public"."tg_work_orders_guard_status_transition"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."trg_work_orders_status_notify"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_account_id uuid;
  v_members uuid[];
  v_contractor uuid;
  v_new_label text;
  v_old_label text;
begin
  -- Only fire when status actually changes
  if tg_op <> 'UPDATE' then
    return new;
  end if;

  if new.status is not distinct from old.status then
    return new;
  end if;

  v_account_id := new.account_id;
  if v_account_id is null then
    return new;
  end if;

  -- Polish labels (fallback handled in helper)
  select d.label into v_new_label
  from public.work_order_status_definitions d
  where lower(d.status) = lower(new.status)
  limit 1;

  select d.label into v_old_label
  from public.work_order_status_definitions d
  where lower(d.status) = lower(old.status)
  limit 1;

  -- Recipients: all account members
  select array_agg(am.user_id)
    into v_members
  from public.account_members am
  where am.account_id = v_account_id;

  if v_members is not null and array_length(v_members, 1) is not null then
    perform public.upsert_work_order_status_notifications(
      p_account_id        => v_account_id,
      p_recipient_user_ids=> v_members,
      p_work_order_id     => new.id,
      p_link_path         => '/work-orders/' || new.id::text,
      p_new_status        => new.status,
      p_old_status        => old.status,
      p_new_label         => v_new_label,
      p_old_label         => v_old_label,
      p_throttle_seconds  => 90
    );
  end if;

  -- Contractor recipient (separate link path)
  v_contractor := new.contractor_user_id;
  if v_contractor is not null then
    perform public.upsert_work_order_status_notifications(
      p_account_id        => v_account_id,
      p_recipient_user_ids=> array[v_contractor],
      p_work_order_id     => new.id,
      p_link_path         => '/contractor/jobs/' || new.id::text,
      p_new_status        => new.status,
      p_old_status        => old.status,
      p_new_label         => v_new_label,
      p_old_label         => v_old_label,
      p_throttle_seconds  => 90
    );
  end if;

  return new;
end;
$$;


ALTER FUNCTION "public"."trg_work_orders_status_notify"() OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."accounts" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "name" "text" NOT NULL,
    "created_by" "uuid" DEFAULT "auth"."uid"() NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "language" "text" DEFAULT 'pl'::"text" NOT NULL,
    "is_root" boolean DEFAULT false NOT NULL,
    "is_disabled" boolean DEFAULT false NOT NULL,
    "disabled_at" timestamp with time zone,
    "subscription_status" "text",
    "subscription_plan" "text",
    "subscription_renews_at" timestamp with time zone,
    "billing_locked_at" timestamp with time zone,
    "country_code" "text" DEFAULT 'PL'::"text" NOT NULL,
    "currency" "text" DEFAULT 'PLN'::"text" NOT NULL,
    CONSTRAINT "accounts_country_code_check" CHECK (("country_code" ~ '^[A-Z]{2}$'::"text")),
    CONSTRAINT "accounts_currency_check" CHECK (("currency" = ANY (ARRAY['PLN'::"text", 'EUR'::"text", 'GBP'::"text", 'USD'::"text", 'CZK'::"text", 'CHF'::"text", 'DKK'::"text", 'SEK'::"text", 'NOK'::"text", 'HUF'::"text", 'RON'::"text", 'BGN'::"text", 'CAD'::"text", 'AUD'::"text"]))),
    CONSTRAINT "accounts_language_check" CHECK (("language" = ANY (ARRAY['pl'::"text", 'en'::"text", 'de'::"text"])))
);


ALTER TABLE "public"."accounts" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."update_account_localization"("p_account_id" "uuid", "p_country_code" "text", "p_currency" "text", "p_language" "text") RETURNS "public"."accounts"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
declare
  v_row public.accounts;
begin
  if coalesce(public.account_role_for(p_account_id), '') not in ('owner', 'admin') then
    raise exception 'Not permitted';
  end if;

  if p_country_code !~ '^[A-Z]{2}$' then
    raise exception 'Invalid country_code: must be two uppercase letters (ISO 3166-1 alpha-2)';
  end if;

  if p_currency not in (
    'PLN','EUR','GBP','USD',
    'CZK','CHF','DKK','SEK','NOK',
    'HUF','RON','BGN','CAD','AUD'
  ) then
    raise exception 'Unsupported currency: %', p_currency;
  end if;

  if p_language not in ('pl','en','de') then
    raise exception 'Unsupported language: %', p_language;
  end if;

  update public.accounts
  set country_code = p_country_code,
      currency     = p_currency,
      language     = p_language
  where id = p_account_id
  returning * into v_row;

  return v_row;
end;
$_$;


ALTER FUNCTION "public"."update_account_localization"("p_account_id" "uuid", "p_country_code" "text", "p_currency" "text", "p_language" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."update_account_role_permissions"("p_account_id" "uuid", "p_role_id" "uuid", "p_permission_keys" "text"[] DEFAULT ARRAY[]::"text"[]) RETURNS TABLE("role_id" "uuid", "name" "text", "permission_keys" "text"[], "is_system" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
#variable_conflict use_column
declare
  v_account_id uuid;
  v_role_name text;
begin
  v_account_id := public.assert_manage_account_access(p_account_id);

  if p_role_id is null then
    raise exception 'role_id is required';
  end if;

  select r.name
    into v_role_name
  from public.roles r
  where r.id = p_role_id
    and r.account_id = v_account_id;

  if v_role_name is null then
    raise exception 'Role not found in this account';
  end if;

  if lower(trim(v_role_name)) in ('owner', 'admin', 'staff') then
    raise exception 'System role permissions cannot be changed via this flow';
  end if;

  delete from public.role_permissions rp
  where rp.role_id = p_role_id;

  insert into public.role_permissions (role_id, permission_key)
  select p_role_id, lower(trim(permission_key))
  from unnest(coalesce(p_permission_keys, array[]::text[])) permission_key
  where trim(coalesce(permission_key, '')) <> ''
  on conflict (role_id, permission_key) do nothing;

  return query
  select
    r.id as role_id,
    r.name,
    coalesce(
      array_agg(distinct lower(trim(rp.permission_key)) order by lower(trim(rp.permission_key)))
        filter (where rp.permission_key is not null),
      array[]::text[]
    ) as permission_keys,
    false as is_system
  from public.roles r
  left join public.role_permissions rp
    on rp.role_id = r.id
  where r.id = p_role_id
  group by r.id, r.name;
end;
$$;


ALTER FUNCTION "public"."update_account_role_permissions"("p_account_id" "uuid", "p_role_id" "uuid", "p_permission_keys" "text"[]) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."update_lease_audit_status"("p_id" "uuid", "p_account_id" "uuid", "p_status" "text", "p_summary" "text" DEFAULT NULL::"text") RETURNS SETOF "public"."lease_audits"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_account_id uuid := public.assert_manage_account_access(p_account_id);
  v_now        timestamptz := now();
begin
  perform public.assert_account_feature_access(v_account_id, 'ai_lease_auditor');

  return query
  update public.lease_audits
  set
    status       = p_status,
    summary      = case when p_summary is not null
                        then nullif(trim(p_summary), '')
                        else summary end,
    completed_at = case when p_status = 'complete' then v_now else completed_at end,
    updated_at   = v_now
  where id         = p_id
    and account_id = v_account_id
  returning *;
end;
$$;


