CREATE OR REPLACE FUNCTION "public"."update_marketplace_job_status"("p_account_id" "uuid", "p_marketplace_job_id" "uuid", "p_status" "text", "p_payload" "jsonb" DEFAULT '{}'::"jsonb") RETURNS SETOF "public"."external_marketplace_jobs"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_account_id uuid;
  v_job public.external_marketplace_jobs%rowtype;
  v_previous_status text;
begin
  v_account_id := public.assert_manage_account_access(p_account_id);

  if p_status not in (
    'draft',
    'ready_to_submit',
    'submitted',
    'acknowledged',
    'matched',
    'quote_received',
    'appointment_scheduled',
    'in_progress',
    'completed',
    'cancelled',
    'failed',
    'manual_follow_up'
  ) then
    raise exception 'Unsupported marketplace job status';
  end if;

  select j.status
  into v_previous_status
  from public.external_marketplace_jobs j
  where j.id = p_marketplace_job_id
    and j.account_id = v_account_id;

  update public.external_marketplace_jobs j
  set status = p_status,
      last_synced_at = now(),
      last_error = case
        when p_status = 'submitted' then ''
        when p_status in ('failed', 'manual_follow_up') then coalesce(
          nullif(coalesce(p_payload->>'error', ''), ''),
          nullif(coalesce(p_payload->>'message', ''), ''),
          j.last_error
        )
        else j.last_error
      end,
      response_payload = case
        when p_payload is null or p_payload = '{}'::jsonb then j.response_payload
        else p_payload
      end,
      updated_by = auth.uid(),
      updated_at = now()
  where j.id = p_marketplace_job_id
    and j.account_id = v_account_id
  returning *
  into v_job;

  if v_job.id is null then
    raise exception 'Marketplace job not found' using errcode = 'P0002';
  end if;

  insert into public.external_marketplace_events (
    marketplace_job_id,
    account_id,
    work_order_id,
    event_type,
    payload,
    actor_user_id
  )
  values (
    v_job.id,
    v_job.account_id,
    v_job.work_order_id,
    'status_updated',
    jsonb_build_object(
      'status', v_job.status,
      'payload', coalesce(p_payload, '{}'::jsonb)
    ),
    auth.uid()
  );

  perform public.activity_log_write(
    v_job.account_id,
    'work_order',
    v_job.work_order_id,
    'marketplace_job_status_changed',
    'status',
    v_previous_status,
    v_job.status,
    jsonb_build_object(
      'table', 'external_marketplace_jobs',
      'marketplace_job_id', v_job.id,
      'provider_key', v_job.provider_key,
      'status', v_job.status,
      'payload', coalesce(p_payload, '{}'::jsonb)
    )
  );

  perform public.marketplace_notify_managers(
    v_job.account_id,
    v_job.work_order_id,
    'marketplace_handoff_status_changed',
    'Marketplace handoff status changed',
    coalesce(v_job.title, 'Work order handoff') || ' status: ' || v_job.status,
    jsonb_build_object(
      'marketplace_job_id', v_job.id,
      'provider_key', v_job.provider_key,
      'status', v_job.status,
      'old_status', v_previous_status
    )
  );

  return query
  select *
  from public.external_marketplace_jobs j
  where j.id = v_job.id;
end;
$$;


ALTER FUNCTION "public"."update_marketplace_job_status"("p_account_id" "uuid", "p_marketplace_job_id" "uuid", "p_status" "text", "p_payload" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."update_payment"("p_account_id" "uuid", "p_payment_id" "uuid", "p_amount" numeric DEFAULT NULL::numeric, "p_due_date" "date" DEFAULT NULL::"date", "p_notes" "text" DEFAULT NULL::"text") RETURNS "public"."payments"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_row public.payments;
begin
  select * into v_row
  from public.payments
  where id = p_payment_id
    and account_id = p_account_id;

  if v_row.id is null then
    raise exception 'Payment not found';
  end if;

  if coalesce(public.account_role_for(v_row.account_id), '') not in ('owner', 'admin') then
    raise exception 'Not allowed';
  end if;

  -- A-3: prevent silent ledger mutation — amount is immutable once paid
  if v_row.paid_at is not null
     and p_amount is not null
     and p_amount <> v_row.amount then
    raise exception
      'Cannot change the amount of a paid payment. Void it and create a new payment instead.';
  end if;

  update public.payments
  set
    amount   = coalesce(p_amount,   amount),
    due_date = coalesce(p_due_date, due_date),
    notes    = case when p_notes is not null then p_notes else notes end
  where id = p_payment_id
    and account_id = p_account_id
  returning * into v_row;

  return v_row;
end;
$$;


ALTER FUNCTION "public"."update_payment"("p_account_id" "uuid", "p_payment_id" "uuid", "p_amount" numeric, "p_due_date" "date", "p_notes" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."update_payment_status_on_due"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'extensions'
    AS $$
BEGIN
  IF NEW.status = 'Oczekujące'
     AND NEW.due_date < CURRENT_DATE THEN
    NEW.status := 'Zaległe';
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."update_payment_status_on_due"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."update_pet_request_status"("p_request_id" "uuid", "p_account_id" "uuid", "p_status" "text", "p_decision_date" "date" DEFAULT NULL::"date", "p_refusal_reason" "text" DEFAULT NULL::"text", "p_insurance_required" boolean DEFAULT NULL::boolean, "p_notes" "text" DEFAULT NULL::"text") RETURNS "public"."pet_requests"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_uid        uuid := auth.uid();
  v_row        public.pet_requests;
  v_old_status text;
begin
  if v_uid is null then raise exception 'Not authenticated'; end if;
  perform public.assert_account_feature_access(p_account_id, 'renters_rights_readiness');
  if not public.is_account_manager(p_account_id, v_uid) then
    raise exception 'Access denied';
  end if;

  if p_status not in ('received','under_review','approved','refused','withdrawn') then
    raise exception 'Invalid status: %', p_status;
  end if;

  -- Refusal reason is mandatory when refusing a request.
  if p_status = 'refused'
     and (p_refusal_reason is null or trim(p_refusal_reason) = '') then
    raise exception 'A refusal reason is required when refusing a pet request';
  end if;

  select status into v_old_status
  from public.pet_requests
  where id = p_request_id and account_id = p_account_id;

  if not found then
    raise exception 'Pet request not found';
  end if;

  update public.pet_requests
  set
    status             = p_status,
    decision_date      = case
                           when p_status in ('approved','refused')
                           then coalesce(p_decision_date, current_date)
                           else decision_date
                         end,
    refusal_reason     = case
                           when p_status = 'refused' then p_refusal_reason
                           else refusal_reason
                         end,
    insurance_required = case
                           when p_insurance_required is not null then p_insurance_required
                           else insurance_required
                         end,
    notes              = coalesce(p_notes, notes),
    updated_at         = now()
  where id = p_request_id and account_id = p_account_id
  returning * into v_row;

  perform public.log_security_event(
    p_account_id, 'pet_request_status_changed', 'pet_request', p_request_id,
    jsonb_build_object('old_status', v_old_status, 'new_status', p_status)
  );

  return v_row;
end;
$$;


ALTER FUNCTION "public"."update_pet_request_status"("p_request_id" "uuid", "p_account_id" "uuid", "p_status" "text", "p_decision_date" "date", "p_refusal_reason" "text", "p_insurance_required" boolean, "p_notes" "text") OWNER TO "postgres";


