CREATE TABLE IF NOT EXISTS "public"."document_signature_provider_settings" (
    "account_id" "uuid" NOT NULL,
    "provider" "text" DEFAULT 'docuseal'::"text" NOT NULL,
    "provider_base_url" "text",
    "default_signature_template_id" "text",
    "is_enabled" boolean DEFAULT false NOT NULL,
    "webhook_configured" boolean DEFAULT false NOT NULL,
    "configured_by" "uuid",
    "configured_at" timestamp with time zone,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "document_signature_provider_settings_base_url_https" CHECK ((("provider_base_url" IS NULL) OR ("provider_base_url" ~* '^https://'::"text"))),
    CONSTRAINT "document_signature_provider_settings_provider_check" CHECK (("provider" = ANY (ARRAY['docuseal'::"text", 'opensign'::"text", 'libresign'::"text", 'manual'::"text"])))
);


ALTER TABLE "public"."document_signature_provider_settings" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."upsert_document_signature_provider_settings"("p_account_id" "uuid", "p_provider" "text", "p_provider_base_url" "text" DEFAULT NULL::"text", "p_default_signature_template_id" "text" DEFAULT NULL::"text", "p_is_enabled" boolean DEFAULT false, "p_webhook_configured" boolean DEFAULT false, "p_actor_user_id" "uuid" DEFAULT "auth"."uid"()) RETURNS "public"."document_signature_provider_settings"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor uuid := auth.uid();
  v_settings public.document_signature_provider_settings;
  v_provider text := lower(trim(coalesce(p_provider, 'docuseal')));
  v_provider_base_url text := nullif(trim(coalesce(p_provider_base_url, '')), '');
begin
  if v_actor is null then raise exception 'Not authenticated'; end if;
  if p_actor_user_id is not null and p_actor_user_id <> v_actor then raise exception 'Actor mismatch'; end if;
  if p_account_id is null then raise exception 'account_id is required'; end if;
  if not public.can_manage_document_packets(p_account_id, v_actor) then raise exception 'Not permitted'; end if;
  if v_provider not in ('docuseal', 'opensign', 'libresign', 'manual') then raise exception 'Unsupported signature provider'; end if;
  if v_provider_base_url is not null and v_provider_base_url !~* '^https://' then
    raise exception 'Signature provider base URL must use HTTPS';
  end if;

  insert into public.document_signature_provider_settings (
    account_id,
    provider,
    provider_base_url,
    default_signature_template_id,
    is_enabled,
    webhook_configured,
    configured_by,
    configured_at
  )
  values (
    p_account_id,
    v_provider,
    v_provider_base_url,
    nullif(trim(coalesce(p_default_signature_template_id, '')), ''),
    coalesce(p_is_enabled, false),
    coalesce(p_webhook_configured, false),
    v_actor,
    now()
  )
  on conflict (account_id)
  do update set
    provider = excluded.provider,
    provider_base_url = excluded.provider_base_url,
    default_signature_template_id = excluded.default_signature_template_id,
    is_enabled = excluded.is_enabled,
    webhook_configured = excluded.webhook_configured,
    configured_by = excluded.configured_by,
    configured_at = now()
  returning * into v_settings;

  return v_settings;
end;
$$;


ALTER FUNCTION "public"."upsert_document_signature_provider_settings"("p_account_id" "uuid", "p_provider" "text", "p_provider_base_url" "text", "p_default_signature_template_id" "text", "p_is_enabled" boolean, "p_webhook_configured" boolean, "p_actor_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."upsert_marketplace_integration_setting"("p_account_id" "uuid", "p_provider_key" "text", "p_enabled" boolean DEFAULT false, "p_configuration" "jsonb" DEFAULT '{}'::"jsonb") RETURNS TABLE("provider_key" "text", "enabled" boolean, "configuration" "jsonb", "updated_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_account_id uuid;
begin
  v_account_id := public.assert_manage_account_access(p_account_id);

  if not exists (
    select 1
    from public.marketplace_providers mp
    where mp.provider_key = p_provider_key
  ) then
    raise exception 'Unknown marketplace provider';
  end if;

  insert into public.marketplace_integration_settings (
    account_id,
    provider_key,
    enabled,
    configuration
  )
  values (
    v_account_id,
    p_provider_key,
    coalesce(p_enabled, false),
    coalesce(p_configuration, '{}'::jsonb)
  )
  on conflict on constraint marketplace_integration_settings_pkey do update
  set enabled = excluded.enabled,
      configuration = excluded.configuration,
      updated_at = now();

  return query
  select
    s.provider_key,
    s.enabled,
    s.configuration,
    s.updated_at
  from public.marketplace_integration_settings s
  where s.account_id = v_account_id
    and s.provider_key = p_provider_key;
end;
$$;


ALTER FUNCTION "public"."upsert_marketplace_integration_setting"("p_account_id" "uuid", "p_provider_key" "text", "p_enabled" boolean, "p_configuration" "jsonb") OWNER TO "postgres";


