CREATE OR REPLACE FUNCTION "public"."upsert_security_anomaly_alert"("p_account_id" "uuid", "p_alert_type" "text", "p_severity" "text", "p_title" "text", "p_summary" "text", "p_actor_user_id" "uuid" DEFAULT NULL::"uuid", "p_entity_type" "text" DEFAULT NULL::"text", "p_entity_id" "uuid" DEFAULT NULL::"uuid", "p_dedupe_key" "text" DEFAULT NULL::"text", "p_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_alert_id uuid;
  v_alert_type text := lower(trim(coalesce(p_alert_type, '')));
  v_severity text := lower(trim(coalesce(p_severity, 'action')));
  v_dedupe_key text;
begin
  if p_account_id is null then
    raise exception 'Missing account id';
  end if;

  if auth.role() is distinct from 'service_role' then
    if auth.uid() is null then
      raise exception 'Not authenticated' using errcode = '42501';
    end if;

    perform public.assert_manage_account_access(p_account_id);
  end if;

  if nullif(v_alert_type, '') is null then
    raise exception 'Missing alert type';
  end if;

  if nullif(trim(coalesce(p_title, '')), '') is null then
    raise exception 'Missing title';
  end if;

  if nullif(trim(coalesce(p_summary, '')), '') is null then
    raise exception 'Missing summary';
  end if;

  if v_severity not in ('info', 'action', 'urgent') then
    v_severity := 'action';
  end if;

  v_dedupe_key := v_alert_type || ':' || coalesce(p_actor_user_id::text, 'account') || ':' || coalesce(p_entity_id::text, 'na');

  update public.security_anomaly_alerts saa
  set
    severity = v_severity,
    actor_user_id = coalesce(p_actor_user_id, saa.actor_user_id),
    entity_type = coalesce(p_entity_type, saa.entity_type),
    entity_id = coalesce(p_entity_id, saa.entity_id),
    title = p_title,
    summary = p_summary,
    metadata = coalesce(p_metadata, '{}'::jsonb),
    alert_count = saa.alert_count + 1,
    last_seen_at = now(),
    resolved_at = null,
    resolved_by_user_id = null,
    resolution_note = null,
    status = case
      when lower(saa.status) = 'resolved' then 'open'
      else saa.status
    end
  where saa.account_id = p_account_id
    and saa.dedupe_key = v_dedupe_key
    and lower(saa.status) in ('open', 'acknowledged')
  returning saa.id into v_alert_id;

  if v_alert_id is not null then
    return v_alert_id;
  end if;

  insert into public.security_anomaly_alerts (
    account_id,
    alert_type,
    severity,
    status,
    actor_user_id,
    entity_type,
    entity_id,
    title,
    summary,
    metadata,
    dedupe_key
  )
  values (
    p_account_id,
    v_alert_type,
    v_severity,
    'open',
    p_actor_user_id,
    p_entity_type,
    p_entity_id,
    p_title,
    p_summary,
    coalesce(p_metadata, '{}'::jsonb),
    v_dedupe_key
  )
  returning id into v_alert_id;

  return v_alert_id;
end;
$$;


ALTER FUNCTION "public"."upsert_security_anomaly_alert"("p_account_id" "uuid", "p_alert_type" "text", "p_severity" "text", "p_title" "text", "p_summary" "text", "p_actor_user_id" "uuid", "p_entity_type" "text", "p_entity_id" "uuid", "p_dedupe_key" "text", "p_metadata" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."upsert_security_anomaly_alert"("p_account_id" "uuid", "p_alert_type" "text", "p_severity" "text", "p_title" "text", "p_summary" "text", "p_actor_user_id" "uuid", "p_entity_type" "text", "p_entity_id" "uuid", "p_dedupe_key" "text", "p_metadata" "jsonb") IS 'Creates or refreshes an active internal security anomaly alert using a dedupe key to avoid alert storms.';



CREATE OR REPLACE FUNCTION "public"."upsert_work_order_status_notifications"("p_account_id" "uuid", "p_recipient_user_ids" "uuid"[], "p_work_order_id" "uuid", "p_link_path" "text", "p_new_status" "text", "p_old_status" "text", "p_new_label" "text", "p_old_label" "text", "p_throttle_seconds" integer DEFAULT 90) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_now timestamptz := now();
  v_rid uuid;
  v_existing_id uuid;
  v_to_insert uuid[] := '{}';
  v_title text := 'Zmieniono status zlecenia';
  v_body  text := 'Status: ' || coalesce(nullif(p_new_label,''), replace(coalesce(p_new_status,''), '_', ' ')) ||
                  case
                    when p_old_status is null then ''
                    else ' (poprzednio: ' || coalesce(nullif(p_old_label,''), replace(coalesce(p_old_status,''), '_', ' ')) || ')'
                  end;
  v_metadata jsonb := jsonb_build_object(
    'status', p_new_status,
    'old_status', p_old_status,
    'status_label', p_new_label,
    'old_status_label', p_old_label,
    'work_order_id', p_work_order_id
  );
begin
  if p_account_id is null or p_work_order_id is null then
    return;
  end if;

  if p_recipient_user_ids is null or array_length(p_recipient_user_ids, 1) is null then
    return;
  end if;

  foreach v_rid in array p_recipient_user_ids loop
    -- Find recent notification for this recipient + entity within throttle window
    select n.id
      into v_existing_id
    from public.notifications n
    where n.account_id = p_account_id
      and n.recipient_user_id = v_rid
      and n.type = 'work_order_status_changed'
      and n.entity_type = 'work_order'
      and n.entity_id = p_work_order_id
      and n.created_at >= (v_now - make_interval(secs => p_throttle_seconds))
    order by n.created_at desc
    limit 1;

    if v_existing_id is not null then
      -- Update instead of inserting a new one (throttle behavior)
      update public.notifications
         set title = v_title,
             body = v_body,
             link_path = p_link_path,
             metadata = coalesce(metadata, '{}'::jsonb) || v_metadata,
             -- keep read state as-is; if unread, it stays unread.
             updated_at = v_now
       where id = v_existing_id;
    else
      -- Queue for insert
      v_to_insert := v_to_insert || v_rid;
    end if;

    v_existing_id := null;
  end loop;

  -- Insert new notifications for any recipients that didn't have a recent one
  if array_length(v_to_insert, 1) is not null then
    perform public.create_notifications_system(
      p_account_id,
      v_to_insert,
      'work_order_status_changed',
      v_title,
      v_body,
      'work_order',
      p_work_order_id,
      p_link_path,
      v_metadata
    );
  end if;
end;
$$;


