CREATE OR REPLACE FUNCTION "public"."user_can_manage_account"("p_account_id" "uuid") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select coalesce((
    public.user_is_root_operator()
    or public.account_member_effective_role(p_account_id, auth.uid()) in ('owner', 'admin', 'staff')
  ), false);
$$;


ALTER FUNCTION "public"."user_can_manage_account"("p_account_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."user_has_support_account_capability"("p_account_id" "uuid", "p_capability" "text") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select exists (
    select 1
    from public.support_account_capabilities sac
    where sac.user_id = auth.uid()
      and sac.account_id = p_account_id
      and lower(trim(sac.capability)) = lower(trim(coalesce(p_capability, '')))
      and sac.revoked_at is null
      and (sac.expires_at is null or sac.expires_at > now())
  );
$$;


ALTER FUNCTION "public"."user_has_support_account_capability"("p_account_id" "uuid", "p_capability" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."user_has_support_account_capability"("p_account_id" "uuid", "p_capability" "text") IS 'Returns whether the signed-in user has an explicit future-support capability for the given account.';



CREATE OR REPLACE FUNCTION "public"."user_is_root_operator"() RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select exists (
    select 1
    from public.account_members am
    join public.accounts a on a.id = am.account_id
    where am.user_id = auth.uid()
      and coalesce(a.is_root, false) = true
      and public.account_member_effective_role(am.account_id, am.user_id) = 'owner'
  );
$$;


ALTER FUNCTION "public"."user_is_root_operator"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."validate_custom_field_value"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_definition public.custom_field_definitions%rowtype;
  v_populated_count integer := 0;
begin
  select *
    into v_definition
  from public.custom_field_definitions cfd
  where cfd.id = new.definition_id;

  if v_definition.id is null then
    raise exception 'Custom field definition not found';
  end if;

  if new.account_id <> v_definition.account_id then
    raise exception 'Custom field value account does not match its definition';
  end if;

  v_populated_count :=
    (case when new.text_value is null then 0 else 1 end) +
    (case when new.number_value is null then 0 else 1 end) +
    (case when new.date_value is null then 0 else 1 end);

  if v_populated_count <> 1 then
    raise exception 'Exactly one custom field value column must be populated';
  end if;

  case lower(trim(v_definition.field_type))
    when 'text' then
      if new.text_value is null or new.number_value is not null or new.date_value is not null then
        raise exception 'Text custom fields must use text_value only';
      end if;
    when 'number' then
      if new.number_value is null or new.text_value is not null or new.date_value is not null then
        raise exception 'Number custom fields must use number_value only';
      end if;
    when 'date' then
      if new.date_value is null or new.text_value is not null or new.number_value is not null then
        raise exception 'Date custom fields must use date_value only';
      end if;
    else
      raise exception 'Unsupported custom field type';
  end case;

  case lower(trim(v_definition.entity_type))
    when 'property' then
      if not exists (
        select 1
        from public.properties p
        where p.id = new.entity_id
          and p.account_id = new.account_id
      ) then
        raise exception 'Custom field entity must be an in-scope property';
      end if;
    when 'tenant' then
      if not exists (
        select 1
        from public.tenants t
        where t.id = new.entity_id
          and t.account_id = new.account_id
      ) then
        raise exception 'Custom field entity must be an in-scope tenant';
      end if;
    else
      raise exception 'Unsupported custom field entity type';
  end case;

  return new;
end;
$$;


ALTER FUNCTION "public"."validate_custom_field_value"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."void_document_packet"("p_packet_id" "uuid", "p_actor_user_id" "uuid" DEFAULT "auth"."uid"()) RETURNS "public"."document_packets"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor uuid := auth.uid();
  v_packet public.document_packets;
begin
  if v_actor is null then raise exception 'Not authenticated'; end if;
  if p_actor_user_id is not null and p_actor_user_id <> v_actor then raise exception 'Actor mismatch'; end if;

  select * into v_packet from public.document_packets where id = p_packet_id;
  if not found then raise exception 'Packet not found'; end if;
  if not public.can_manage_document_packets(v_packet.account_id, v_actor) then raise exception 'Not permitted'; end if;
  if v_packet.status = 'completed' then raise exception 'Completed packet cannot be voided'; end if;

  update public.document_packets
  set status = 'voided',
      voided_at = now()
  where id = p_packet_id
  returning * into v_packet;

  update public.document_packet_recipients
  set status = 'voided'
  where packet_id = p_packet_id
    and status <> 'completed';

  insert into public.document_packet_events (account_id, packet_id, actor_user_id, event_type, message)
  values (v_packet.account_id, v_packet.id, v_actor, 'voided', 'Agreement packet voided');

  return v_packet;
end;
$$;


ALTER FUNCTION "public"."void_document_packet"("p_packet_id" "uuid", "p_actor_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."void_payment"("p_payment_id" "uuid", "p_account_id" "uuid" DEFAULT NULL::"uuid") RETURNS "public"."payments"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_pay  public.payments;
  v_role text;
begin
  select * into v_pay
  from public.payments
  where id = p_payment_id
    and (p_account_id is null or account_id = p_account_id);

  if not found then
    raise exception 'Payment not found';
  end if;

  v_role := public.account_role_for(v_pay.account_id);
  if coalesce(v_role, '') not in ('owner', 'admin') then
    raise exception 'Not permitted';
  end if;

  update public.payments
  set status  = 'void',
      paid_at = null
  where id = p_payment_id
  returning * into v_pay;

  return v_pay;
end;
$$;


ALTER FUNCTION "public"."void_payment"("p_payment_id" "uuid", "p_account_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."withdraw_application"("p_application_id" "uuid", "p_cancel_linked_draft_lease" boolean DEFAULT true) RETURNS "public"."rental_applications"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_app record;
  v_lease record;
  v_out public.rental_applications;
begin
  if p_application_id is null then
    raise exception 'application_id is required';
  end if;

  select a.* into v_app
  from public.rental_applications a
  where a.id = p_application_id;

  if not found then
    raise exception 'Application not found';
  end if;

  if public.account_role_for(v_app.account_id) not in ('owner','admin','staff') then
    raise exception 'Not permitted';
  end if;

  if v_app.status in ('withdrawn','rejected') then
    select * into v_out from public.rental_applications where id = p_application_id;
    return v_out;
  end if;

  if v_app.status = 'approved' then
    raise exception 'Cannot withdraw an approved application';
  end if;

  if exists (
    select 1
    from public.leases l
    where (l.application_id = v_app.id or l.property_id = v_app.property_id)
      and l.status = 'active'
  ) then
    raise exception 'Cannot withdraw: an active lease exists for this property/application';
  end if;

  if p_cancel_linked_draft_lease then
    select * into v_lease
    from public.leases l
    where l.application_id = v_app.id
    limit 1;

    if found and v_lease.status = 'draft' then
      update public.leases
      set status = 'cancelled',
          updated_at = now()
      where id = v_lease.id;

      update public.tenants
      set property_id = null
      where id = v_app.tenant_id
        and property_id = v_app.property_id;
    end if;
  end if;

  update public.rental_applications
  set status = 'withdrawn',
      updated_at = now()
  where id = v_app.id
  returning * into v_out;

  return v_out;
end;
$$;


ALTER FUNCTION "public"."withdraw_application"("p_application_id" "uuid", "p_cancel_linked_draft_lease" boolean) OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."work_order_financials" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "account_id" "uuid" NOT NULL,
    "work_order_id" "uuid" NOT NULL,
    "quote_amount" numeric(12,2),
    "quote_currency" "text" DEFAULT 'PLN'::"text",
    "quote_notes" "text",
    "quote_submitted_at" timestamp with time zone,
    "quote_submitted_by" "uuid",
    "quote_status" "text" DEFAULT 'draft'::"text" NOT NULL,
    "invoice_amount" numeric(12,2),
    "invoice_currency" "text" DEFAULT 'PLN'::"text",
    "invoice_issued_at" timestamp with time zone,
    "invoice_due_at" timestamp with time zone,
    "approved_at" timestamp with time zone,
    "approved_by" "uuid",
    "rejected_at" timestamp with time zone,
    "rejected_by" "uuid",
    "rejection_reason" "text",
    "created_at" timestamp with time zone DEFAULT "now"(),
    "updated_at" timestamp with time zone DEFAULT "now"(),
    CONSTRAINT "quote_status_check" CHECK (("quote_status" = ANY (ARRAY['draft'::"text", 'submitted'::"text", 'approved'::"text", 'rejected'::"text"])))
);


ALTER TABLE "public"."work_order_financials" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."wo_fin_approve_quote"("p_work_order_id" "uuid") RETURNS "public"."work_order_financials"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_uid uuid := auth.uid();
  v_account_id uuid;
  v_row public.work_order_financials;
begin
  if v_uid is null then
    raise exception using
      errcode = '28000',
      message = 'Not authenticated',
      detail = public.security_failure_context('wo_fin_approve_quote', 'missing_auth', null, 'work_order', p_work_order_id),
      hint = 'Authenticate as an in-account manager before approving a quote.';
  end if;

  v_account_id := public.work_order_account_id(p_work_order_id);
  if v_account_id is null then
    raise exception using
      errcode = 'P0002',
      message = 'Work order not found',
      detail = public.security_failure_context('wo_fin_approve_quote', 'work_order_not_found', null, 'work_order', p_work_order_id),
      hint = 'Use an existing work order identifier before approving a quote.';
  end if;

  if not public.is_account_manager(v_account_id, v_uid) then
    raise exception using
      errcode = '42501',
      message = 'Not allowed (manager only)',
      detail = public.security_failure_context('wo_fin_approve_quote', 'manager_only', v_account_id, 'work_order', p_work_order_id),
      hint = 'Only owner, admin, or staff members for the same account can approve a contractor quote.';
  end if;

  update public.work_order_financials
  set
    quote_status = 'approved',
    approved_at = now(),
    approved_by = v_uid,
    rejected_at = null,
    rejected_by = null,
    rejection_reason = null
  where work_order_id = p_work_order_id
    and quote_status = 'submitted'
  returning * into v_row;

  if v_row.id is null then
    raise exception using
      errcode = '22023',
      message = 'Cannot approve quote (status must be submitted)',
      detail = public.security_failure_context('wo_fin_approve_quote', 'invalid_quote_state', v_account_id, 'work_order', p_work_order_id),
      hint = 'Only submitted quotes can be approved.';
  end if;

  return v_row;
end;
$$;


ALTER FUNCTION "public"."wo_fin_approve_quote"("p_work_order_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."wo_fin_reject_quote"("p_work_order_id" "uuid", "p_reason" "text") RETURNS "public"."work_order_financials"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_uid uuid := auth.uid();
  v_account_id uuid;
  v_row public.work_order_financials;
begin
  if v_uid is null then
    raise exception using
      errcode = '28000',
      message = 'Not authenticated',
      detail = public.security_failure_context('wo_fin_reject_quote', 'missing_auth', null, 'work_order', p_work_order_id),
      hint = 'Authenticate as an in-account manager before rejecting a quote.';
  end if;

  v_account_id := public.work_order_account_id(p_work_order_id);
  if v_account_id is null then
    raise exception using
      errcode = 'P0002',
      message = 'Work order not found',
      detail = public.security_failure_context('wo_fin_reject_quote', 'work_order_not_found', null, 'work_order', p_work_order_id),
      hint = 'Use an existing work order identifier before rejecting a quote.';
  end if;

  if not public.is_account_manager(v_account_id, v_uid) then
    raise exception using
      errcode = '42501',
      message = 'Not allowed (manager only)',
      detail = public.security_failure_context('wo_fin_reject_quote', 'manager_only', v_account_id, 'work_order', p_work_order_id),
      hint = 'Only owner, admin, or staff members for the same account can reject a contractor quote.';
  end if;

  update public.work_order_financials
  set
    quote_status = 'rejected',
    rejected_at = now(),
    rejected_by = v_uid,
    rejection_reason = p_reason
  where work_order_id = p_work_order_id
    and quote_status = 'submitted'
  returning * into v_row;

  if v_row.id is null then
    raise exception using
      errcode = '22023',
      message = 'Cannot reject quote (status must be submitted)',
      detail = public.security_failure_context('wo_fin_reject_quote', 'invalid_quote_state', v_account_id, 'work_order', p_work_order_id),
      hint = 'Only submitted quotes can be rejected.';
  end if;

  return v_row;
end;
$$;


ALTER FUNCTION "public"."wo_fin_reject_quote"("p_work_order_id" "uuid", "p_reason" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."wo_fin_set_invoice_amount"("p_work_order_id" "uuid", "p_invoice_amount" numeric) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_account_id uuid;
begin
  select account_id into v_account_id
  from public.work_orders
  where id = p_work_order_id;

  if v_account_id is null then
    raise exception 'Work order not found';
  end if;

  if not public.has_account_role(v_account_id, array['owner','admin','staff']) then
    raise exception 'Not allowed';
  end if;

  update public.work_order_financials
    set invoice_amount = p_invoice_amount,
        updated_at = now()
  where work_order_id = p_work_order_id;

  if not found then
    raise exception 'No financial record for this work order';
  end if;
end $$;


