CREATE OR REPLACE FUNCTION "public"."wo_fin_set_quote_draft"("p_work_order_id" "uuid", "p_quote_amount" numeric) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_account_id uuid;
begin
  select account_id into v_account_id
  from public.work_orders
  where id = p_work_order_id;

  if v_account_id is null then
    raise exception 'Work order not found';
  end if;

  if not public.has_account_role(v_account_id, array['owner','admin','staff']) then
    raise exception 'Not allowed';
  end if;

  insert into public.work_order_financials (account_id, work_order_id, quote_amount, quote_status, updated_at)
  values (v_account_id, p_work_order_id, p_quote_amount, 'draft', now())
  on conflict (work_order_id) do update
    set quote_amount = excluded.quote_amount,
        quote_status = 'draft',
        updated_at = now();
end $$;


