    LANGUAGE "sql" STABLE
    AS $$
  select wo.account_id
  from public.work_orders wo
  where wo.id = p_work_order_id
$$;


ALTER FUNCTION "public"."work_order_account_id"("p_work_order_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."work_order_allowed_actions"("p_work_order_id" "uuid") RETURNS "text"[]
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_status text;
  v_account_id uuid;
  v_property_id uuid;
  v_is_member boolean;
  v_is_tenant boolean;
  v_actions text[];
begin
  select
    lower(coalesce(status, 'assigned')),
    account_id,
    property_id
  into
    v_status,
    v_account_id,
    v_property_id
  from public.work_orders
  where id = p_work_order_id;

  if v_account_id is null then
    return array[]::text[];
  end if;

  v_is_member := public.is_account_member(v_account_id);

  v_is_tenant := exists (
    select 1
    from public.tenants t
    where t.user_id = auth.uid()
      and t.archived_at is null
      and t.status = any(array['active','accepted_pending_signing'])
      and t.property_id = v_property_id
  );

  -- Tenant → only cancellation request
  if v_is_tenant and not v_is_member then
    if v_status in ('completed','cancelled') then
      return array[]::text[];
    end if;

    return array['cancelled']::text[];
  end if;

  -- Members only beyond this point
  if not v_is_member then
    return array[]::text[];
  end if;

  if v_status in ('completed','cancelled') then
    return array[]::text[];
  end if;

  select coalesce(array_agg(t.to_status order by t.to_status), array[]::text[])
  into v_actions
  from public.work_order_status_transitions t
  where lower(t.from_status) = v_status
    and lower(t.to_status) <> 'blocked';

  return v_actions;
end;
$$;


ALTER FUNCTION "public"."work_order_allowed_actions"("p_work_order_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."work_order_allowed_actions_bulk"("p_work_order_ids" "uuid"[]) RETURNS TABLE("work_order_id" "uuid", "actions" "text"[])
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  select
    wo.id as work_order_id,
    public.work_order_allowed_actions(wo.id) as actions
  from public.work_orders wo
  where wo.id = any(p_work_order_ids)
    and (
      public.is_account_member(wo.account_id)
      or exists (
        select 1
        from public.tenants t
        where t.user_id = auth.uid()
          and t.archived_at is null
          and t.status = any(array['active','accepted_pending_signing'])
          and t.property_id = wo.property_id
      )
    );
$$;


ALTER FUNCTION "public"."work_order_allowed_actions_bulk"("p_work_order_ids" "uuid"[]) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."work_order_approve_tenant_cancellation"("p_work_order_id" "uuid") RETURNS "public"."work_orders"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_wo public.work_orders;
  v_can_transition boolean;
begin
  select * into v_wo
  from public.work_orders
  where id = p_work_order_id;

  if not found then
    raise exception 'Work order not found: %', p_work_order_id using errcode = 'P0002';
  end if;

  if not public.can_access_account(v_wo.account_id) then
    raise exception 'Only account members can approve cancellations' using errcode = '42501';
  end if;

  if not public.work_order_has_pending_cancel_request(p_work_order_id) then
    raise exception 'No pending tenant cancellation request' using errcode = 'P0001';
  end if;

  select exists (
    select 1
    from public.work_order_status_transitions t
    where t.from_status = v_wo.status
      and t.to_status   = 'cancelled'
  ) into v_can_transition;

  if not v_can_transition then
    raise exception 'Cannot cancel from current status: %', v_wo.status using errcode = 'P0001';
  end if;

  insert into public.work_order_audit_log (
    work_order_id, account_id, actor_user_id, action, old_value, new_value
  )
  values (
    v_wo.id, v_wo.account_id, auth.uid(), 'tenant_cancellation_approved',
    jsonb_build_object('status', v_wo.status),
    jsonb_build_object('status', 'cancelled')
  );

  -- do the change
  perform public.work_order_set_status(p_work_order_id, 'cancelled', true);

  -- return the updated row
  select * into v_wo
  from public.work_orders
  where id = p_work_order_id;

  return v_wo;
end;
$$;


ALTER FUNCTION "public"."work_order_approve_tenant_cancellation"("p_work_order_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."work_order_assign_contractor"("p_work_order_id" "uuid", "p_contractor_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_account_id uuid;
  v_contractor_user_id uuid;
  v_name text;
  v_phone text;
begin
  if p_work_order_id is null or p_contractor_id is null then
    raise exception 'Missing work order id or contractor id';
  end if;

  select wo.account_id
    into v_account_id
  from public.work_orders wo
  where wo.id = p_work_order_id;

  if v_account_id is null then
    raise exception 'Work order not found';
  end if;

  if not public.user_can_manage_account(v_account_id) then
    raise exception 'Access denied' using errcode = '42501';
  end if;

  select c.user_id, c.name, c.phone
    into v_contractor_user_id, v_name, v_phone
  from public.contractors c
  where c.id = p_contractor_id
    and c.account_id = v_account_id
    and coalesce(c.active, true) = true;

  if v_contractor_user_id is null then
    raise exception 'Contractor not found/active for this account';
  end if;

  update public.work_orders wo
     set contractor_user_id = v_contractor_user_id,
         contractor_name    = coalesce(v_name, wo.contractor_name),
         contractor_phone   = coalesce(v_phone, wo.contractor_phone),
         updated_at         = now()
   where wo.id = p_work_order_id;
end;
$$;


ALTER FUNCTION "public"."work_order_assign_contractor"("p_work_order_id" "uuid", "p_contractor_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."work_order_assign_contractor"("p_work_order_id" "uuid", "p_contractor_id" "uuid") IS 'Assigns an active in-account contractor to a work order after enforcing manager/root account access.';



