CREATE OR REPLACE FUNCTION "public"."work_order_create"("p_account_id" "uuid", "p_property_id" "uuid", "p_maintenance_request_id" "uuid" DEFAULT NULL::"uuid", "p_contractor_id" "uuid" DEFAULT NULL::"uuid", "p_contractor_name" "text" DEFAULT NULL::"text", "p_contractor_phone" "text" DEFAULT NULL::"text", "p_scheduled_at" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_notes" "text" DEFAULT NULL::"text") RETURNS "public"."work_orders"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_user_id uuid;
  v_contractor_user_id uuid;
  v_name text;
  v_phone text;
  v_row public.work_orders;
begin
  if p_account_id is null then raise exception 'Missing account_id'; end if;
  if p_property_id is null then raise exception 'Missing property_id'; end if;

  v_user_id := auth.uid();
  if v_user_id is null then
    raise exception 'Not authenticated';
  end if;

  -- If contractor selected from directory, resolve user_id + name/phone
  if p_contractor_id is not null then
    select c.user_id, c.name, c.phone
      into v_contractor_user_id, v_name, v_phone
    from public.contractors c
    where c.id = p_contractor_id
      and c.account_id = p_account_id
      and coalesce(c.active, true) = true;
  end if;

  insert into public.work_orders (
    account_id,
    property_id,
    maintenance_request_id,
    contractor_user_id,
    contractor_name,
    contractor_phone,
    status,
    scheduled_at,
    notes,
    created_by,
    created_at,
    updated_at
  )
  values (
    p_account_id,
    p_property_id,
    p_maintenance_request_id,
    v_contractor_user_id,
    coalesce(v_name, p_contractor_name),
    coalesce(v_phone, p_contractor_phone),
    'assigned',
    p_scheduled_at,
    p_notes,
    v_user_id,
    now(),
    now()
  )
  returning * into v_row;

  return v_row;
end;
$$;


