CREATE OR REPLACE VIEW "public"."tenant_my_issues" AS
 SELECT "id" AS "maintenance_request_id",
    "account_id",
    "property_id",
    "title",
    "status" AS "maintenance_status",
    "priority",
    "created_at",
    ( SELECT "wo"."status"
           FROM "public"."work_orders" "wo"
          WHERE ("wo"."maintenance_request_id" = "mr"."id")
          ORDER BY "wo"."created_at" DESC
         LIMIT 1) AS "latest_work_order_status",
    ( SELECT "wo"."id"
           FROM "public"."work_orders" "wo"
          WHERE ("wo"."maintenance_request_id" = "mr"."id")
          ORDER BY "wo"."created_at" DESC
         LIMIT 1) AS "latest_work_order_id"
   FROM "public"."maintenance_requests" "mr"
  WHERE (EXISTS ( SELECT 1
           FROM "public"."tenants" "t"
          WHERE (("t"."user_id" = "auth"."uid"()) AND ("t"."archived_at" IS NULL) AND ("t"."status" = ANY (ARRAY['active'::"text", 'accepted_pending_signing'::"text"])) AND ("t"."property_id" = "mr"."property_id"))));


ALTER VIEW "public"."tenant_my_issues" OWNER TO "postgres";


